function randomString()
	local length = math.random(10, 20)
	local array = {}

	for i = 1, length do
		array[i] = string.char(math.random(32, 126))
	end

	return table.concat(array)
end

do
	local bridge = _G.__SIRIUS_IY_BRIDGE or {}
	_G.__SIRIUS_IY_BRIDGE = bridge
	bridge.pendingCommands = bridge.pendingCommands or {}

	function getSiriusIntegratedIYSearchTokens(fallbackTokens)
		if type(bridge.cmds) == "table" then
			if type(bridge.searchTokens) ~= "table" or #bridge.searchTokens == 0 then
				local tokens = {}
				local seen = {}

				for _, command in pairs(bridge.cmds) do
					if type(command) == "table" then
						local commandName = tostring(command.NAME or ""):lower()

						if commandName ~= "" and not seen[commandName] then
							seen[commandName] = true
							table.insert(tokens, commandName)
						end

						if type(command.ALIAS) == "table" then
							for _, alias in pairs(command.ALIAS) do
								alias = tostring(alias or ""):lower()

								if alias ~= "" and not seen[alias] then
									seen[alias] = true
									table.insert(tokens, alias)
								end
							end
						end
					end
				end

				table.sort(tokens)
				bridge.searchTokens = tokens
			end

			if #bridge.searchTokens > 0 then
				return bridge.searchTokens
			end
		end

		return fallbackTokens or {}
	end

	function runIntegratedIYCommand(commandText, speaker)
		commandText = tostring(commandText or ""):gsub("^%s+", ""):gsub("%s+$", "")
		if commandText == "" then return end

		if type(bridge.execCmd) == "function" then
			local success, err = pcall(bridge.execCmd, commandText, speaker or localPlayer, true)
			if not success then
				warn("Infinite Yield command failed: "..tostring(err))
			end
			return
		end

		if type(execCmd) == "function" then
			local success, err = pcall(execCmd, commandText, speaker or localPlayer)
			if not success then
				warn("Infinite Yield command failed: "..tostring(err))
			end
			return
		end

		table.insert(bridge.pendingCommands, {commandText, speaker or localPlayer})
	end

	local function flushPendingIntegratedIYCommands()
		if type(bridge.execCmd) ~= "function" then
			return
		end

		for _, pending in ipairs(bridge.pendingCommands or {}) do
			pcall(bridge.execCmd, pending[1], pending[2] or localPlayer, true)
		end
		bridge.pendingCommands = {}
	end

	if not bridge.loading and not bridge.loaded then
		bridge.loading = true

		task.spawn(function()
			local success, result = pcall(function()
				return game:HttpGet("https://raw.githubusercontent.com/EdgeIY/infiniteyield/master/source")
			end)

			if not success then
				warn("Failed to fetch Infinite Yield: "..tostring(result))
				bridge.loading = false
				return
			end

			if type(loadstring) ~= "function" then
				warn("loadstring is unavailable; Infinite Yield was not started")
				bridge.loading = false
				return
			end

			result = result:gsub("Main%.ResetOnSpawn = false", "Main.ResetOnSpawn = false\n    Main.Enabled = false")
			result = result:gsub(
				"elseif COREGUI:FindFirstChild%(\"RobloxGui\"%) then\n    PARENT = COREGUI%.RobloxGui",
				[[elseif COREGUI:FindFirstChild("RobloxGui") then
    local Main = Instance.new("ScreenGui")
    Main.Name = randomString()
    Main.ResetOnSpawn = false
    Main.DisplayOrder = MAX_DISPLAY_ORDER
    Main.Enabled = false
    Main.Parent = COREGUI.RobloxGui
    PARENT = Main]],
				1
			)
			result = result:gsub("if %(Key==prefix%) then", "if false and (Key==prefix) then", 1)

			local chunk, loadErr = loadstring(result, "=IntegratedInfiniteYield")
			if not chunk then
				warn("Failed to compile Infinite Yield: "..tostring(loadErr))
				bridge.loading = false
				return
			end

			if type(setfenv) == "function" then
				local baseEnv = (type(getfenv) == "function" and getfenv()) or _G
				bridge.env = setmetatable({
					_G = _G,
					shared = shared,
					script = script,
				}, {__index = baseEnv})
				pcall(setfenv, chunk, bridge.env)
			end

			local runOk, runErr = pcall(chunk)
			if not runOk then
				warn("Failed to start Infinite Yield: "..tostring(runErr))
				bridge.loading = false
				return
			end

			local runtime = type(bridge.env) == "table" and bridge.env or _G
			bridge.execCmd = runtime.execCmd
			bridge.cmds = runtime.cmds
			bridge.loaded = type(bridge.execCmd) == "function"
			bridge.loading = false
			runtime.queueteleport = false
			runtime.KeepInfYield = false
			runtime.notify = function() end

			pcall(function()
				if typeof(runtime.PARENT) == "Instance" and runtime.PARENT:IsA("ScreenGui") then
					runtime.PARENT.Enabled = false
				end
				if typeof(runtime.ScaledHolder) == "Instance" then
					runtime.ScaledHolder.Visible = false
				end
				if typeof(runtime.Holder) == "Instance" then
					runtime.Holder.Visible = false
				end
				if typeof(runtime.Notification) == "Instance" then
					runtime.Notification.Visible = false
				end
				if typeof(runtime.Tooltip) == "Instance" then
					runtime.Tooltip.Visible = false
				end
			end)

			bridge.searchTokens = getSiriusIntegratedIYSearchTokens({})
			flushPendingIntegratedIYCommands()
			end)
		end
	end

