characterRuntime.layoutAligned = false
if characterRuntime.walkInAirEnabled == nil then
	characterRuntime.walkInAirEnabled = false
end

function characterRuntime.getRootPart(character)
	if not character then
		return nil
	end

	return character:FindFirstChild("HumanoidRootPart")
		or character:FindFirstChild("UpperTorso")
		or character:FindFirstChild("Torso")
end

function characterRuntime.clearInvisibilityConnections()
	if characterRuntime.invisibilityFixConn then
		characterRuntime.invisibilityFixConn:Disconnect()
		characterRuntime.invisibilityFixConn = nil
	end

	if characterRuntime.invisibilityDeathConn then
		characterRuntime.invisibilityDeathConn:Disconnect()
		characterRuntime.invisibilityDeathConn = nil
	end
end

function characterRuntime.restoreInvisibility()
	if not characterRuntime.invisibilityEnabled and not characterRuntime.invisibilityOriginalCharacter then
		characterRuntime.clearInvisibilityConnections()
		return
	end

	characterRuntime.invisibilityEnabled = false
	characterRuntime.clearInvisibilityConnections()

	local originalCharacter = characterRuntime.invisibilityOriginalCharacter
	local invisibleCharacter = characterRuntime.invisibilityProxyCharacter
	local currentCamera = workspace.CurrentCamera or camera
	local proxyRoot = characterRuntime.getRootPart(invisibleCharacter)
	local originalRoot = characterRuntime.getRootPart(originalCharacter)
	local restoreCFrame = proxyRoot and proxyRoot.CFrame or originalRoot and originalRoot.CFrame

	if originalRoot and restoreCFrame then
		originalRoot.CFrame = restoreCFrame
	end

	if invisibleCharacter and invisibleCharacter.Parent then
		invisibleCharacter:Destroy()
	end

	if originalCharacter then
		localPlayer.Character = originalCharacter
		originalCharacter.Parent = workspace

		local animate = originalCharacter:FindFirstChild("Animate")
		if animate then
			animate.Disabled = true
			task.wait()
			animate.Disabled = false
		end

		local humanoid = originalCharacter:FindFirstChildOfClass("Humanoid")
		if currentCamera and humanoid then
			currentCamera.CameraType = Enum.CameraType.Custom
			currentCamera.CameraSubject = humanoid
		end
	end

	characterRuntime.invisibilityOriginalCharacter = nil
	characterRuntime.invisibilityProxyCharacter = nil
end

function characterRuntime.applyInvisibility(enabled)
	if not enabled then
		characterRuntime.restoreInvisibility()
		return
	end

	if characterRuntime.invisibilityEnabled then
		return
	end

	local player = localPlayer
	local character = player.Character
	local humanoid = character and character:FindFirstChildOfClass("Humanoid")
	local rootPart = characterRuntime.getRootPart(character)
	if not character or not humanoid or not rootPart then
		error("Character is not ready for Invisibility")
	end

	character.Archivable = true
	local invisibleCharacter = character:Clone()
	if not invisibleCharacter then
		error("Failed to clone character for Invisibility")
	end

	invisibleCharacter.Name = ""
	invisibleCharacter.Parent = lighting
	for _, instance in ipairs(invisibleCharacter:GetDescendants()) do
		if instance:IsA("BasePart") then
			instance.Transparency = instance.Name == "HumanoidRootPart" and 1 or 0.5
		end
	end

	characterRuntime.invisibilityEnabled = true
	characterRuntime.invisibilityOriginalCharacter = character
	characterRuntime.invisibilityProxyCharacter = invisibleCharacter
	characterRuntime.clearInvisibilityConnections()

	local currentCamera = workspace.CurrentCamera or camera
	local cameraCFrame = currentCamera and currentCamera.CFrame
	local characterCFrame = rootPart.CFrame

	character:MoveTo(Vector3.new(0, math.pi * 1000000, 0))
	if currentCamera then
		currentCamera.CameraType = Enum.CameraType.Scriptable
	end
	task.wait(0.2)
	if currentCamera then
		currentCamera.CameraType = Enum.CameraType.Custom
		if cameraCFrame then
			currentCamera.CFrame = cameraCFrame
		end
	end

	character.Parent = lighting
	invisibleCharacter.Parent = workspace

	local invisibleRoot = characterRuntime.getRootPart(invisibleCharacter)
	if invisibleRoot then
		invisibleRoot.CFrame = characterCFrame
	end

	player.Character = invisibleCharacter

	local invisibleHumanoid = invisibleCharacter:FindFirstChildOfClass("Humanoid")
	if currentCamera and invisibleHumanoid then
		currentCamera.CameraSubject = invisibleHumanoid
	end

	local animate = invisibleCharacter:FindFirstChild("Animate")
	if animate then
		animate.Disabled = true
		task.wait()
		animate.Disabled = false
	end

	characterRuntime.invisibilityDeathConn = invisibleHumanoid and invisibleHumanoid.Died:Connect(function()
		characterRuntime.restoreInvisibility()
	end) or nil

	characterRuntime.invisibilityFixConn = runService.Stepped:Connect(function()
		if not characterRuntime.invisibilityEnabled then return end

		pcall(function()
			local activeRoot = characterRuntime.getRootPart(player.Character)
			if not activeRoot then return end

			local voidHeight = workspace.FallenPartsDestroyHeight
			local belowVoid = tostring(voidHeight):find("-", 1, true) and activeRoot.Position.Y <= voidHeight
			local aboveVoid = not tostring(voidHeight):find("-", 1, true) and activeRoot.Position.Y >= voidHeight
			if belowVoid or aboveVoid then
				characterRuntime.restoreInvisibility()
			end
		end)
	end)

	if notify then
		notify("Invisibility", "You now appear invisible to other players")
	end
end

function characterRuntime.clearWalkInAirLane()
	if characterRuntime.walkInAirPart and characterRuntime.walkInAirPart.Parent then
		characterRuntime.walkInAirPart:Destroy()
	end
	characterRuntime.walkInAirPart = nil
	characterRuntime.walkInAirCharacter = nil
	characterRuntime.walkInAirY = nil
end

function characterRuntime.destroyGhostVisual()
	local model = characterRuntime.ghostProxyModel
	if model and model.Parent then
		model:Destroy()
	end
	characterRuntime.ghostProxyModel = nil
	characterRuntime.ghostProxyRoot = nil
end

function characterRuntime.createGhostVisual(character)
	characterRuntime.destroyGhostVisual()
	do
		local ghostModel = Instance.new("Model")
		ghostModel.Name = "SiriusGhostSpectateSubject"

		local focusPart = Instance.new("Part")
		focusPart.Name = "SpectateSubject"
		focusPart.Anchored = true
		focusPart.CanCollide = false
		focusPart.CanTouch = false
		focusPart.CanQuery = false
		focusPart.Massless = true
		focusPart.CastShadow = false
		focusPart.Transparency = 1
		focusPart.Size = Vector3.new(2, 2, 2)
		focusPart.CFrame = characterRuntime.ghostCharacterCFrame or characterRuntime.ghostCameraCFrame or CFrame.new()
		focusPart.Parent = ghostModel

		ghostModel.PrimaryPart = focusPart
		ghostModel.Parent = workspace

		characterRuntime.ghostProxyModel = ghostModel
		characterRuntime.ghostProxyRoot = focusPart
		return
	end

	local ghostModel
	local core

	if character then
		local oldArchivable = character.Archivable
		character.Archivable = true
		local cloned
		pcall(function()
			cloned = character:Clone()
		end)
		character.Archivable = oldArchivable

		if cloned and cloned:IsA("Model") then
			ghostModel = cloned
			ghostModel.Name = "SiriusGhostSpectateAvatar"
			core = ghostModel:FindFirstChild("HumanoidRootPart") or ghostModel.PrimaryPart or ghostModel:FindFirstChildWhichIsA("BasePart")

			for _, instance in ipairs(ghostModel:GetDescendants()) do
				if instance:IsA("Script") or instance:IsA("LocalScript") or instance:IsA("ModuleScript") or instance:IsA("Tool") then
					instance:Destroy()
				elseif instance:IsA("BasePart") then
					instance.Anchored = true
					instance.CanCollide = false
					instance.CanTouch = false
					instance.CanQuery = false
					instance.Massless = true
					instance.CastShadow = true
					instance.LocalTransparencyModifier = 0
					if instance.Name == "HumanoidRootPart" then
						instance.Transparency = 1
					else
						instance.Transparency = math.clamp(math.max(instance.Transparency, 0.48), 0, 0.86)
					end
				elseif instance:IsA("Decal") or instance:IsA("Texture") then
					instance.Transparency = math.clamp(instance.Transparency + 0.18, 0, 1)
				elseif instance:IsA("BillboardGui") then
					instance.Enabled = false
				end
			end

			local ghostHumanoid = ghostModel:FindFirstChildOfClass("Humanoid")
			if ghostHumanoid then
				ghostHumanoid.DisplayDistanceType = Enum.HumanoidDisplayDistanceType.None
				ghostHumanoid.HealthDisplayType = Enum.HumanoidHealthDisplayType.AlwaysOff
				ghostHumanoid.PlatformStand = true
				ghostHumanoid.AutoRotate = false
			end

			if core then
				ghostModel.PrimaryPart = core
			end
		end
	end

	if not ghostModel or not core then
		ghostModel = Instance.new("Model")
		ghostModel.Name = "SiriusGhostSpectateAvatar"

		core = Instance.new("Part")
		core.Name = "HumanoidRootPart"
		core.Anchored = true
		core.CanCollide = false
		core.CanTouch = false
		core.CanQuery = false
		core.Massless = true
		core.CastShadow = false
		core.Material = Enum.Material.SmoothPlastic
		core.Color = Color3.fromRGB(12, 12, 16)
		core.Size = Vector3.new(2.1, 2.8, 1.2)
		core.Transparency = 0.42
		core.Parent = ghostModel

		ghostModel.PrimaryPart = core
	end

	ghostModel.Parent = workspace

	characterRuntime.ghostProxyModel = ghostModel
	characterRuntime.ghostProxyRoot = core

	local auraAttachment = Instance.new("Attachment")
	auraAttachment.Name = "SiriusGhostAuraAttachment"
	auraAttachment.Position = Vector3.new(0, 0.2, 0)
	auraAttachment.Parent = core

	local darkAura = Instance.new("ParticleEmitter")
	darkAura.Name = "SiriusGhostDarkAura"
	darkAura.Texture = "rbxasset://textures/particles/smoke_main.dds"
	darkAura.Rate = 88
	darkAura.Lifetime = NumberRange.new(1, 2.15)
	darkAura.Speed = NumberRange.new(0.3, 2.5)
	darkAura.SpreadAngle = Vector2.new(360, 360)
	darkAura.Rotation = NumberRange.new(0, 360)
	darkAura.RotSpeed = NumberRange.new(-40, 40)
	darkAura.Drag = 1.6
	darkAura.Acceleration = Vector3.new(0, 4.4, 0)
	darkAura.LockedToPart = true
	darkAura.LightEmission = 0
	darkAura.LightInfluence = 0.1
	darkAura.Color = ColorSequence.new({
		ColorSequenceKeypoint.new(0, Color3.fromRGB(10, 10, 14)),
		ColorSequenceKeypoint.new(0.4, Color3.fromRGB(20, 18, 33)),
		ColorSequenceKeypoint.new(0.75, Color3.fromRGB(38, 24, 56)),
		ColorSequenceKeypoint.new(1, Color3.fromRGB(9, 9, 12)),
	})
	darkAura.Transparency = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.2),
		NumberSequenceKeypoint.new(0.35, 0.45),
		NumberSequenceKeypoint.new(0.8, 0.7),
		NumberSequenceKeypoint.new(1, 1),
	})
	darkAura.Size = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 1.1),
		NumberSequenceKeypoint.new(0.35, 2.4),
		NumberSequenceKeypoint.new(1, 4.2),
	})
	darkAura.Parent = auraAttachment

	local mistAura = Instance.new("ParticleEmitter")
	mistAura.Name = "SiriusGhostMistAura"
	mistAura.Texture = "rbxasset://textures/particles/sparkles_main.dds"
	mistAura.Rate = 18
	mistAura.Lifetime = NumberRange.new(0.65, 1.25)
	mistAura.Speed = NumberRange.new(0.1, 0.8)
	mistAura.SpreadAngle = Vector2.new(360, 360)
	mistAura.Rotation = NumberRange.new(0, 360)
	mistAura.RotSpeed = NumberRange.new(-110, 110)
	mistAura.Drag = 0.8
	mistAura.Acceleration = Vector3.new(0, 2.7, 0)
	mistAura.LockedToPart = true
	mistAura.LightEmission = 0.05
	mistAura.LightInfluence = 0
	mistAura.Color = ColorSequence.new({
		ColorSequenceKeypoint.new(0, Color3.fromRGB(64, 40, 93)),
		ColorSequenceKeypoint.new(1, Color3.fromRGB(24, 16, 40)),
	})
	mistAura.Transparency = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.35),
		NumberSequenceKeypoint.new(0.55, 0.65),
		NumberSequenceKeypoint.new(1, 1),
	})
	mistAura.Size = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.2),
		NumberSequenceKeypoint.new(1, 0.7),
	})
	mistAura.Parent = auraAttachment

	local highlight = Instance.new("Highlight")
	highlight.Name = "SiriusGhostAvatarHighlight"
	highlight.Adornee = ghostModel
	highlight.DepthMode = Enum.HighlightDepthMode.Occluded
	highlight.FillColor = Color3.fromRGB(215, 224, 235)
	highlight.OutlineColor = Color3.fromRGB(255, 255, 255)
	highlight.FillTransparency = 0.9
	highlight.OutlineTransparency = 0.56
	highlight.Parent = ghostModel
end

function characterRuntime.applyGhostCharacterVisual(character)
	if not character then return end

	characterRuntime.ghostPartStates = characterRuntime.ghostPartStates or {}

	for _, instance in ipairs(character:GetDescendants()) do
		if instance:IsA("BasePart") then
			if not characterRuntime.ghostPartStates[instance] then
				characterRuntime.ghostPartStates[instance] = {
					LocalTransparencyModifier = instance.LocalTransparencyModifier,
					CanCollide = instance.CanCollide,
					CanTouch = instance.CanTouch,
					CanQuery = instance.CanQuery,
					CastShadow = instance.CastShadow,
					Massless = instance.Massless,
				}
			end

			instance.LocalTransparencyModifier = instance.Name == "HumanoidRootPart" and 1 or 0.48
			instance.CanCollide = false
			instance.CanTouch = false
			instance.CanQuery = false
			instance.CastShadow = true
			instance.Massless = true
		elseif instance:IsA("Decal") or instance:IsA("Texture") then
			if not characterRuntime.ghostPartStates[instance] then
				characterRuntime.ghostPartStates[instance] = {
					Transparency = instance.Transparency,
				}
			end

			local originalTransparency = characterRuntime.ghostPartStates[instance].Transparency or instance.Transparency
			instance.Transparency = math.clamp(originalTransparency + 0.28, 0, 1)
		end
	end

	local highlight = character:FindFirstChild("SiriusGhostOutline")
	if not highlight then
		highlight = Instance.new("Highlight")
		highlight.Name = "SiriusGhostOutline"
		highlight.Parent = character
	end

	highlight.Adornee = character
	highlight.DepthMode = Enum.HighlightDepthMode.Occluded
	highlight.FillColor = Color3.fromRGB(215, 224, 235)
	highlight.OutlineColor = Color3.fromRGB(255, 255, 255)
	highlight.FillTransparency = 0.88
	highlight.OutlineTransparency = 0.74
end

function characterRuntime.restoreGhostCharacterVisual(character)
	local partStates = characterRuntime.ghostPartStates
	if partStates then
		for instance, state in pairs(partStates) do
			if instance and instance.Parent and state then
				pcall(function()
					if instance:IsA("BasePart") then
						if state.LocalTransparencyModifier ~= nil then
							instance.LocalTransparencyModifier = state.LocalTransparencyModifier
						end
						if state.CanCollide ~= nil then instance.CanCollide = state.CanCollide end
						if state.CanTouch ~= nil then instance.CanTouch = state.CanTouch end
						if state.CanQuery ~= nil then instance.CanQuery = state.CanQuery end
						if state.CastShadow ~= nil then instance.CastShadow = state.CastShadow end
						if state.Massless ~= nil then instance.Massless = state.Massless end
					elseif instance:IsA("Decal") or instance:IsA("Texture") then
						if state.Transparency ~= nil then
							instance.Transparency = state.Transparency
						end
					end
				end)
			end
		end
	end

	if character then
		local outline = character:FindFirstChild("SiriusGhostOutline")
		if outline then
			outline:Destroy()
		end
	end

	characterRuntime.ghostPartStates = nil
end

function characterRuntime.applyGhostMode(enabled)
	local wasEnabled = characterRuntime.ghostModeEnabled == true
	characterRuntime.ghostModeEnabled = enabled and true or false
	local character = localPlayer.Character
	local rootPart = characterRuntime.getRootPart(character)
	local humanoid = character and character:FindFirstChildOfClass("Humanoid")
	local currentCamera = workspace.CurrentCamera or camera
	local oldOutline = character and character:FindFirstChild("SiriusGhostOutline")

	if characterRuntime.ghostModeEnabled then
		if oldOutline then
			oldOutline:Destroy()
		end

		characterRuntime.restoreGhostCharacterVisual(character)
		characterRuntime.destroyGhostVisual()

		if rootPart then
			characterRuntime.ghostSavedRootCFrame = rootPart.CFrame
			characterRuntime.ghostSavedRootAnchored = rootPart.Anchored
			characterRuntime.ghostCameraCFrame = rootPart.CFrame
			characterRuntime.ghostCharacterCFrame = rootPart.CFrame
			rootPart.Anchored = true
			rootPart.AssemblyLinearVelocity = Vector3.zero
			rootPart.AssemblyAngularVelocity = Vector3.zero
		end

		characterRuntime.createGhostVisual(character)
		if characterRuntime.ghostProxyModel and characterRuntime.ghostCharacterCFrame then
			pcall(function()
				characterRuntime.ghostProxyModel:PivotTo(characterRuntime.ghostCharacterCFrame)
			end)
		end

		if humanoid then
			characterRuntime.ghostSavedAutoRotate = humanoid.AutoRotate
			characterRuntime.ghostSavedPlatformStand = humanoid.PlatformStand
			humanoid.AutoRotate = false
			humanoid.PlatformStand = true
			pcall(function()
				humanoid:ChangeState(Enum.HumanoidStateType.Physics)
			end)
		end

		if currentCamera then
			characterRuntime.ghostSavedCameraType = currentCamera.CameraType
			characterRuntime.ghostSavedCameraSubject = currentCamera.CameraSubject
			characterRuntime.ghostCameraCFrame = rootPart and rootPart.CFrame or currentCamera.CFrame
			characterRuntime.ghostCharacterCFrame = rootPart and rootPart.CFrame or currentCamera.CFrame

			local look = currentCamera.CFrame.LookVector
			characterRuntime.ghostPitch = math.asin(math.clamp(look.Y, -1, 1))
			characterRuntime.ghostYaw = math.atan2(-look.X, -look.Z)

			currentCamera.CameraType = Enum.CameraType.Custom
			if characterRuntime.ghostProxyRoot then
				currentCamera.CameraSubject = characterRuntime.ghostProxyRoot
			elseif rootPart then
				currentCamera.CameraSubject = rootPart
			elseif humanoid then
				currentCamera.CameraSubject = humanoid
			end
		end

		characterRuntime.ghostSavedMouseBehavior = userInputService.MouseBehavior
		characterRuntime.ghostSavedMouseIconEnabled = userInputService.MouseIconEnabled
		userInputService.MouseBehavior = Enum.MouseBehavior.Default
		userInputService.MouseIconEnabled = true

		if not wasEnabled and notify then
			notify("Ghost Mode", "W A S D move, Space/E up, Shift/Q down, normal camera rotate/zoom, Ctrl boost, Alt slow")
		end
	else
		if oldOutline then
			oldOutline:Destroy()
		end

		if rootPart then
			rootPart.CFrame = characterRuntime.ghostSavedRootCFrame or rootPart.CFrame
			rootPart.AssemblyLinearVelocity = Vector3.zero
			rootPart.AssemblyAngularVelocity = Vector3.zero
			if characterRuntime.ghostSavedRootAnchored ~= nil then
				rootPart.Anchored = characterRuntime.ghostSavedRootAnchored
			else
				rootPart.Anchored = false
			end
		end

		if humanoid then
			if characterRuntime.ghostSavedAutoRotate ~= nil then
				humanoid.AutoRotate = characterRuntime.ghostSavedAutoRotate
			else
				humanoid.AutoRotate = true
			end
			if characterRuntime.ghostSavedPlatformStand ~= nil then
				humanoid.PlatformStand = characterRuntime.ghostSavedPlatformStand
			else
				humanoid.PlatformStand = false
			end
			pcall(function()
				humanoid:ChangeState(Enum.HumanoidStateType.Running)
			end)
		end

		characterRuntime.restoreGhostCharacterVisual(character)

		if currentCamera then
			currentCamera.CameraType = characterRuntime.ghostSavedCameraType or Enum.CameraType.Custom
			if humanoid then
				currentCamera.CameraSubject = humanoid
			elseif rootPart then
				currentCamera.CameraSubject = rootPart
			else
				currentCamera.CameraSubject = characterRuntime.ghostSavedCameraSubject
			end
		end

		userInputService.MouseBehavior = characterRuntime.ghostSavedMouseBehavior or Enum.MouseBehavior.Default
		if characterRuntime.ghostSavedMouseIconEnabled ~= nil then
			userInputService.MouseIconEnabled = characterRuntime.ghostSavedMouseIconEnabled
		else
			userInputService.MouseIconEnabled = true
		end

		characterRuntime.destroyGhostVisual()
		characterRuntime.ghostCameraCFrame = nil
		characterRuntime.ghostCharacterCFrame = nil
	end
end

function characterRuntime.updateGhostMode(deltaTime)
	if not characterRuntime.ghostModeEnabled then
		return
	end

	local currentCamera = workspace.CurrentCamera or camera
	if not currentCamera then
		return
	end

	local character = localPlayer.Character
	local rootPart = characterRuntime.getRootPart(character)
	local humanoid = character and character:FindFirstChildOfClass("Humanoid")
	if not character or not rootPart then
		return
	end

	local dt = deltaTime or (1 / 60)
	local moveVector = Vector3.zero
	local function ghostKeyDown(settingName, fallbackKeyCode)
		local keyCode = fallbackKeyCode
		if type(checkSetting) == "function" then
			local setting = checkSetting(settingName, keybindCategoryName) or checkSetting(settingName, "Keybinds")
			local customName = setting and setting.current or nil
			if customName and customName ~= "" and Enum.KeyCode[customName] then
				keyCode = Enum.KeyCode[customName]
			end
		end
		return userInputService:IsKeyDown(keyCode)
	end

	if ghostKeyDown("Ghost Forward", Enum.KeyCode.W) then moveVector += Vector3.new(0, 0, -1) end
	if ghostKeyDown("Ghost Backward", Enum.KeyCode.S) then moveVector += Vector3.new(0, 0, 1) end
	if ghostKeyDown("Ghost Left", Enum.KeyCode.A) then moveVector += Vector3.new(-1, 0, 0) end
	if ghostKeyDown("Ghost Right", Enum.KeyCode.D) then moveVector += Vector3.new(1, 0, 0) end
	if ghostKeyDown("Ghost Up", Enum.KeyCode.E) then moveVector += Vector3.new(0, 1, 0) end
	if ghostKeyDown("Ghost Down", Enum.KeyCode.Q) then moveVector += Vector3.new(0, -1, 0) end

	local speed = characterRuntime.ghostMoveSpeed or 96
	if ghostKeyDown("Ghost Boost", Enum.KeyCode.LeftControl) then
		speed *= 2
	end
	if ghostKeyDown("Ghost Slow", Enum.KeyCode.LeftAlt) then
		speed *= 0.35
	end

	currentCamera.CameraType = Enum.CameraType.Custom
	if not characterRuntime.ghostProxyModel then
		characterRuntime.createGhostVisual(character)
	end
	if characterRuntime.ghostProxyRoot then
		currentCamera.CameraSubject = characterRuntime.ghostProxyRoot
	elseif rootPart then
		currentCamera.CameraSubject = rootPart
	elseif humanoid then
		currentCamera.CameraSubject = humanoid
	end

	rootPart.Anchored = true
	rootPart.AssemblyLinearVelocity = Vector3.zero
	rootPart.AssemblyAngularVelocity = Vector3.zero
	if characterRuntime.ghostSavedRootCFrame then
		rootPart.CFrame = characterRuntime.ghostSavedRootCFrame
	end
	if humanoid then
		humanoid.AutoRotate = false
		humanoid.PlatformStand = true
		pcall(function()
			humanoid:ChangeState(Enum.HumanoidStateType.Physics)
		end)
	end

	local baseCFrame = characterRuntime.ghostCharacterCFrame or rootPart.CFrame
	local position = baseCFrame.Position
	local cameraLook = currentCamera.CFrame.LookVector
	local cameraRight = currentCamera.CFrame.RightVector
	local cameraUp = Vector3.new(0, 1, 0)
	local flatLook = Vector3.new(cameraLook.X, 0, cameraLook.Z)
	if flatLook.Magnitude <= 0.001 then
		flatLook = Vector3.new(-baseCFrame.LookVector.X, 0, -baseCFrame.LookVector.Z)
	end
	if flatLook.Magnitude <= 0.001 then
		flatLook = Vector3.new(0, 0, -1)
	end
	flatLook = flatLook.Unit
	characterRuntime.ghostPitch = math.asin(math.clamp(cameraLook.Y, -1, 1))
	characterRuntime.ghostYaw = math.atan2(-flatLook.X, -flatLook.Z)

	if moveVector.Magnitude > 0 then
		moveVector = moveVector.Unit
		local worldMove =
			(cameraRight * moveVector.X)
			+ (cameraUp * moveVector.Y)
			+ (cameraLook * -moveVector.Z)
		if worldMove.Magnitude > 0 then
			worldMove = worldMove.Unit
		end
		position += worldMove * speed * dt
	end

	local leanPitch = 0
	local leanRoll = 0
	if moveVector.Magnitude > 0 then
		leanPitch = math.clamp(-moveVector.Z * math.rad(12), math.rad(-12), math.rad(12))
		leanRoll = math.clamp(-moveVector.X * math.rad(10), math.rad(-10), math.rad(10))
	end

	local characterCFrame = CFrame.new(position) * CFrame.fromOrientation(0, characterRuntime.ghostYaw, 0) * CFrame.Angles(leanPitch, 0, leanRoll)
	characterRuntime.ghostCharacterCFrame = characterCFrame
	characterRuntime.ghostCameraCFrame = CFrame.new(position) * CFrame.fromOrientation(0, characterRuntime.ghostYaw, 0)
	if characterRuntime.ghostProxyModel then
		pcall(function()
			characterRuntime.ghostProxyModel:PivotTo(characterCFrame)
		end)
	end
end

function characterRuntime.applyGravitySetting(value)
	local gravityValue = math.clamp(tonumber(value) or workspace.Gravity, 0, 500)
	workspace.Gravity = gravityValue

	if gravityValue <= 1 then
		if not characterRuntime.zeroGravityJumpConn then
			characterRuntime.zeroGravityJumpConn = userInputService.JumpRequest:Connect(function()
				local character = localPlayer.Character
				local humanoid = character and character:FindFirstChildOfClass("Humanoid")
				local rootPart = characterRuntime.getRootPart(character)
				if not humanoid or humanoid.Health <= 0 or not rootPart then
					return
				end

				local velocity = rootPart.AssemblyLinearVelocity
				local jumpBoost = characterRuntime.zeroGravityJumpBoost or 52
				rootPart.AssemblyLinearVelocity = Vector3.new(velocity.X, jumpBoost, velocity.Z)
			end)
		end
	else
		if characterRuntime.zeroGravityJumpConn then
			characterRuntime.zeroGravityJumpConn:Disconnect()
			characterRuntime.zeroGravityJumpConn = nil
		end
	end
end

function characterRuntime.applyAntiVoid(enabled)
	if characterRuntime.antiVoidLoop then
		characterRuntime.antiVoidLoop:Disconnect()
		characterRuntime.antiVoidLoop = nil
	end

	if not enabled then
		return
	end

	characterRuntime.antiVoidOriginDestroyHeight = characterRuntime.antiVoidOriginDestroyHeight or workspace.FallenPartsDestroyHeight
	task.wait()

	characterRuntime.antiVoidLoop = runService.Stepped:Connect(function()
		local character = localPlayer.Character
		local root = characterRuntime.getRootPart(character)
		if root and root.Position.Y <= characterRuntime.antiVoidOriginDestroyHeight + 25 then
			root.Velocity = root.Velocity + Vector3.new(0, 250, 0)
		end
	end)
end

function characterRuntime.applyShaders(enabled)
	characterRuntime.shadersEnabled = enabled and true or false

	local colorCorrection = lighting:FindFirstChild("SiriusShaderColorCorrection")
	if not colorCorrection then
		colorCorrection = Instance.new("ColorCorrectionEffect")
		colorCorrection.Name = "SiriusShaderColorCorrection"
		colorCorrection.Parent = lighting
	end

	local bloom = lighting:FindFirstChild("SiriusShaderBloom")
	if not bloom then
		bloom = Instance.new("BloomEffect")
		bloom.Name = "SiriusShaderBloom"
		bloom.Parent = lighting
	end

	colorCorrection.Enabled = characterRuntime.shadersEnabled
	bloom.Enabled = characterRuntime.shadersEnabled

	if characterRuntime.shadersEnabled then
		colorCorrection.Contrast = 0.24
		colorCorrection.Saturation = 0.18
		colorCorrection.Brightness = 0.04
		colorCorrection.TintColor = Color3.fromRGB(244, 248, 255)

		bloom.Intensity = 0.18
		bloom.Threshold = 1.15
		bloom.Size = 22
	else
		colorCorrection.Contrast = 0
		colorCorrection.Saturation = 0
		colorCorrection.Brightness = 0
		colorCorrection.TintColor = Color3.fromRGB(255, 255, 255)

		bloom.Intensity = 0
		bloom.Threshold = 2
		bloom.Size = 0
	end
end

function characterRuntime.getWalkInAirStandingY(character, rootPart)
	if not rootPart then
		return nil
	end

	local raycastParams = RaycastParams.new()
	raycastParams.FilterType = Enum.RaycastFilterType.Exclude
	local filterInstances = {}
	if character then
		table.insert(filterInstances, character)
	end
	if characterRuntime.walkInAirPart then
		table.insert(filterInstances, characterRuntime.walkInAirPart)
	end
	raycastParams.FilterDescendantsInstances = filterInstances
	raycastParams.IgnoreWater = true

	local result = workspace:Raycast(rootPart.Position, Vector3.new(0, -24, 0), raycastParams)
	if result then
		return result.Position.Y
	end

	local humanoid = character and character:FindFirstChildOfClass("Humanoid")
	local rootHalfHeight = rootPart.Size.Y * 0.5
	return rootPart.Position.Y - rootHalfHeight - (humanoid and humanoid.HipHeight or 2)
end

function characterRuntime.ensureWalkInAirLane(character)
	if not characterRuntime.walkInAirEnabled then
		characterRuntime.clearWalkInAirLane()
		return nil
	end

	local lane = characterRuntime.walkInAirPart
	if lane and characterRuntime.walkInAirCharacter ~= character then
		lane:Destroy()
		lane = nil
	end

	if not lane or not lane.Parent then
		lane = Instance.new("Part")
		lane.Name = "SiriusWalkInAirLane"
		lane.Anchored = true
		lane.CanCollide = true
		lane.CanTouch = false
		lane.CanQuery = false
		lane.Transparency = 1
		lane.CastShadow = false
		lane.Material = Enum.Material.SmoothPlastic
		lane.Size = Vector3.new(100000, 1, 100000)
		lane.Parent = workspace
		characterRuntime.walkInAirPart = lane
		characterRuntime.walkInAirCharacter = character
	end

	return lane
end

function characterRuntime.updateWalkInAir(character, rootPart)
	if not characterRuntime.walkInAirEnabled then
		characterRuntime.clearWalkInAirLane()
		return
	end

	if not character or not rootPart then
		characterRuntime.clearWalkInAirLane()
		return
	end

	local lane = characterRuntime.ensureWalkInAirLane(character)
	if not lane then
		return
	end

	if characterRuntime.walkInAirY == nil then
		characterRuntime.walkInAirY = characterRuntime.getWalkInAirStandingY(character, rootPart)
	end

	local floorY = characterRuntime.walkInAirY or rootPart.Position.Y
	lane.CFrame = CFrame.new(rootPart.Position.X, floorY - (lane.Size.Y * 0.5), rootPart.Position.Z)
end

function characterRuntime.getClosestPlayerTarget()
	local localCharacter = localPlayer.Character
	local localRoot = characterRuntime.getRootPart(localCharacter)
	if not localRoot then
		return nil
	end

	local visibleClosestDistance = math.huge
	local hiddenClosestDistance = math.huge
	local visibleClosestTarget = nil
	local hiddenClosestTarget = nil

	for _, player in ipairs(players:GetPlayers()) do
		if player ~= localPlayer then
			local character = player.Character
			local humanoid = character and character:FindFirstChildOfClass("Humanoid")
			local rootPart = characterRuntime.getRootPart(character)
			local head = character and character:FindFirstChild("Head")

			if humanoid and humanoid.Health > 0 and rootPart and head then
				local distance = (rootPart.Position - localRoot.Position).Magnitude
				local headTip = head.Position + Vector3.new(0, math.max(0.5, head.Size.Y * 0.55), 0)
				local targetData = {
					player = player,
					character = character,
					humanoid = humanoid,
					rootPart = rootPart,
					head = head,
					headTip = headTip,
				}

				if characterRuntime.isTargetVisibleInPOV(character, headTip) then
					if distance < visibleClosestDistance then
						visibleClosestDistance = distance
						visibleClosestTarget = targetData
					end
				elseif distance < hiddenClosestDistance then
					hiddenClosestDistance = distance
					hiddenClosestTarget = targetData
				end
			end
		end
	end

	return visibleClosestTarget or hiddenClosestTarget
end

function characterRuntime.getPredictedAimPoint(targetData)
	if not targetData or not targetData.headTip then
		return nil
	end

	local rootPart = targetData.rootPart
	if not rootPart then
		return targetData.headTip
	end

	local distance = (rootPart.Position - camera.CFrame.Position).Magnitude
	local lead = math.clamp((distance / (80 + distance)) * 0.22, 0, 0.28)
	local velocity = rootPart.AssemblyLinearVelocity or Vector3.zero
	return targetData.headTip + (velocity * lead)
end

function characterRuntime.getClosestPlayerHeadTip()
	local targetData = characterRuntime.getClosestPlayerTarget()
	return targetData and targetData.headTip or nil
end

function characterRuntime.ensureAuraObjects()
	local character = localPlayer.Character
	local rootPart = characterRuntime.getRootPart(character)
	if not character or not rootPart then
		return nil
	end

	local auraFolder = character:FindFirstChild("SiriusMajesticAura")
	if not auraFolder then
		auraFolder = Instance.new("Folder")
		auraFolder.Name = "SiriusMajesticAura"
		auraFolder.Parent = character
	end

	local baseAttachment = auraFolder:FindFirstChild("BaseAttachment")
	if not baseAttachment then
		baseAttachment = Instance.new("Attachment")
		baseAttachment.Name = "BaseAttachment"
		baseAttachment.Position = Vector3.new(0, -1.35, 0)
		baseAttachment.Parent = rootPart
	end

	local crownAttachment = auraFolder:FindFirstChild("CrownAttachment")
	if not crownAttachment then
		crownAttachment = Instance.new("Attachment")
		crownAttachment.Name = "CrownAttachment"
		crownAttachment.Position = Vector3.new(0, 2.75, 0)
		crownAttachment.Parent = rootPart
	end

	local sparkEmitter = auraFolder:FindFirstChild("SparkEmitter")
	if not sparkEmitter then
		sparkEmitter = Instance.new("ParticleEmitter")
		sparkEmitter.Name = "SparkEmitter"
		sparkEmitter.Texture = "rbxasset://textures/particles/sparkles_main.dds"
		sparkEmitter.LightEmission = 1
		sparkEmitter.LightInfluence = 0
		sparkEmitter.LockedToPart = true
		sparkEmitter.SpreadAngle = Vector2.new(360, 360)
		sparkEmitter.Rotation = NumberRange.new(0, 360)
		sparkEmitter.RotSpeed = NumberRange.new(-180, 180)
		sparkEmitter.VelocityInheritance = 0.12
		sparkEmitter.Enabled = false
		sparkEmitter.Parent = baseAttachment
	end

	local mistEmitter = auraFolder:FindFirstChild("MistEmitter")
	if not mistEmitter then
		mistEmitter = Instance.new("ParticleEmitter")
		mistEmitter.Name = "MistEmitter"
		mistEmitter.Texture = "rbxasset://textures/particles/smoke_main.dds"
		mistEmitter.LightEmission = 0.8
		mistEmitter.LightInfluence = 0
		mistEmitter.LockedToPart = true
		mistEmitter.SpreadAngle = Vector2.new(360, 360)
		mistEmitter.Rotation = NumberRange.new(0, 360)
		mistEmitter.RotSpeed = NumberRange.new(-70, 70)
		mistEmitter.Enabled = false
		mistEmitter.Parent = baseAttachment
	end

	local starEmitter = auraFolder:FindFirstChild("StarEmitter")
	if not starEmitter then
		starEmitter = Instance.new("ParticleEmitter")
		starEmitter.Name = "StarEmitter"
		starEmitter.Texture = "rbxasset://textures/particles/sparkles_main.dds"
		starEmitter.LightEmission = 1
		starEmitter.LightInfluence = 0
		starEmitter.LockedToPart = true
		starEmitter.SpreadAngle = Vector2.new(360, 360)
		starEmitter.Rotation = NumberRange.new(0, 360)
		starEmitter.RotSpeed = NumberRange.new(-50, 50)
		starEmitter.Enabled = false
		starEmitter.Parent = crownAttachment
	end

	local auraBeam = auraFolder:FindFirstChild("AuraBeam")
	if not auraBeam then
		auraBeam = Instance.new("Beam")
		auraBeam.Name = "AuraBeam"
		auraBeam.Attachment0 = baseAttachment
		auraBeam.Attachment1 = crownAttachment
		auraBeam.FaceCamera = true
		auraBeam.LightEmission = 1
		auraBeam.LightInfluence = 0
		auraBeam.Transparency = NumberSequence.new({
			NumberSequenceKeypoint.new(0, 0.35),
			NumberSequenceKeypoint.new(0.5, 0.15),
			NumberSequenceKeypoint.new(1, 0.35),
		})
		auraBeam.Enabled = false
		auraBeam.Parent = auraFolder
	end

	local auraLight = auraFolder:FindFirstChild("AuraLight")
	if not auraLight then
		auraLight = Instance.new("PointLight")
		auraLight.Name = "AuraLight"
		auraLight.Enabled = false
		auraLight.Range = 0
		auraLight.Brightness = 0
		auraLight.Shadows = false
		auraLight.Parent = rootPart
	end

	local auraHighlight = character:FindFirstChild("SiriusAuraHighlight")
	if not auraHighlight then
		auraHighlight = Instance.new("Highlight")
		auraHighlight.Name = "SiriusAuraHighlight"
		auraHighlight.Adornee = character
		auraHighlight.DepthMode = Enum.HighlightDepthMode.Occluded
		auraHighlight.FillTransparency = 1
		auraHighlight.OutlineTransparency = 1
		auraHighlight.Enabled = false
		auraHighlight.Parent = character
	end

	return {
		baseAttachment = baseAttachment,
		crownAttachment = crownAttachment,
		sparkEmitter = sparkEmitter,
		mistEmitter = mistEmitter,
		starEmitter = starEmitter,
		auraBeam = auraBeam,
		auraLight = auraLight,
		auraHighlight = auraHighlight,
	}
end

function characterRuntime.applyClientAura(value)
	characterRuntime.clientAuraStrength = math.clamp(tonumber(value) or 0, 0, 100)

	local auraObjects = characterRuntime.ensureAuraObjects()
	if not auraObjects then
		return
	end

	local sparkEmitter = auraObjects.sparkEmitter
	local mistEmitter = auraObjects.mistEmitter
	local starEmitter = auraObjects.starEmitter
	local auraBeam = auraObjects.auraBeam
	local auraLight = auraObjects.auraLight
	local auraHighlight = auraObjects.auraHighlight

	if characterRuntime.clientAuraStrength <= 0 then
		sparkEmitter.Enabled = false
		sparkEmitter.Rate = 0
		mistEmitter.Enabled = false
		mistEmitter.Rate = 0
		starEmitter.Enabled = false
		starEmitter.Rate = 0
		auraBeam.Enabled = false
		auraLight.Enabled = false
		auraLight.Range = 0
		auraLight.Brightness = 0
		auraHighlight.Enabled = false
		auraHighlight.FillTransparency = 1
		auraHighlight.OutlineTransparency = 1
		return
	end

	local alpha = characterRuntime.clientAuraStrength / 100

	sparkEmitter.Enabled = true
	sparkEmitter.Rate = 35 + (alpha * 280)
	sparkEmitter.Lifetime = NumberRange.new(0.55, 1 + alpha)
	sparkEmitter.Speed = NumberRange.new(2 + alpha * 5, 6 + alpha * 12)
	sparkEmitter.Drag = 1.1 - math.min(alpha * 0.6, 0.55)
	sparkEmitter.Acceleration = Vector3.new(0, 10 + alpha * 22, 0)
	sparkEmitter.Size = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.25 + alpha * 0.7),
		NumberSequenceKeypoint.new(0.45, 0.8 + alpha * 2.2),
		NumberSequenceKeypoint.new(1, 0),
	})
	sparkEmitter.Transparency = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.08),
		NumberSequenceKeypoint.new(0.55, 0.22),
		NumberSequenceKeypoint.new(1, 1),
	})

	mistEmitter.Enabled = true
	mistEmitter.Rate = 10 + (alpha * 60)
	mistEmitter.Lifetime = NumberRange.new(1.1, 2.1 + alpha)
	mistEmitter.Speed = NumberRange.new(0.6 + alpha * 1.5, 1.6 + alpha * 4.2)
	mistEmitter.Drag = 1.7
	mistEmitter.Acceleration = Vector3.new(0, 3 + alpha * 8, 0)
	mistEmitter.Size = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 1 + alpha * 1.5),
		NumberSequenceKeypoint.new(0.5, 2.4 + alpha * 3.4),
		NumberSequenceKeypoint.new(1, 0),
	})
	mistEmitter.Transparency = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.72),
		NumberSequenceKeypoint.new(0.6, 0.84),
		NumberSequenceKeypoint.new(1, 1),
	})

	starEmitter.Enabled = true
	starEmitter.Rate = 6 + (alpha * 54)
	starEmitter.Lifetime = NumberRange.new(0.8, 1.7)
	starEmitter.Speed = NumberRange.new(0.4 + alpha * 1.4, 1.8 + alpha * 3.2)
	starEmitter.Drag = 0.4
	starEmitter.Acceleration = Vector3.new(0, 5 + alpha * 10, 0)
	starEmitter.Size = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.18 + alpha * 0.45),
		NumberSequenceKeypoint.new(0.3, 0.45 + alpha * 1.2),
		NumberSequenceKeypoint.new(1, 0),
	})
	starEmitter.Transparency = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.02),
		NumberSequenceKeypoint.new(0.4, 0.18),
		NumberSequenceKeypoint.new(1, 1),
	})

	auraBeam.Enabled = true
	auraBeam.Width0 = 0.8 + (alpha * 1.25)
	auraBeam.Width1 = 0.22 + (alpha * 0.5)

	auraLight.Enabled = true
	auraLight.Range = 10 + (alpha * 22)
	auraLight.Brightness = 2 + (alpha * 6)

	auraHighlight.Enabled = true
	auraHighlight.FillTransparency = math.clamp(0.9 - (alpha * 0.46), 0.28, 0.9)
	auraHighlight.OutlineTransparency = math.clamp(0.48 - (alpha * 0.38), 0.06, 0.48)
end

function characterRuntime.clearAutoFindPath()
	if characterRuntime.autoFindMoveConn then
		characterRuntime.autoFindMoveConn:Disconnect()
		characterRuntime.autoFindMoveConn = nil
	end
	characterRuntime.autoFindWaypoints = nil
	characterRuntime.autoFindWaypointIndex = 1
	characterRuntime.autoFindTargetUserId = nil
	characterRuntime.autoFindLastTargetPosition = nil
	characterRuntime.autoFindLastPosition = nil
	characterRuntime.autoFindLastMoveTick = 0
	characterRuntime.autoFindMoveTarget = nil
	characterRuntime.autoFindForceRepath = false
	characterRuntime.autoFindLockedTarget = nil
	characterRuntime.autoFindStuckTimer = 0
	characterRuntime.autoFindStuckPhase = 0
	characterRuntime.autoFindStuckPhaseTime = 0
	characterRuntime.autoFindMoveFired = false
	characterRuntime.autoFindPeekLast = 0
	characterRuntime.autoFindPeekActive = false
	characterRuntime.autoFindPathTimer = 0
end

function characterRuntime.isTargetVisibleInPOV(targetCharacter, targetHeadTip)
	if not targetCharacter or not targetHeadTip then
		return false
	end

	local currentCamera = workspace.CurrentCamera or camera
	if not currentCamera then
		return false
	end

	local localCharacter = localPlayer.Character
	local rayParams = RaycastParams.new()
	rayParams.FilterType = Enum.RaycastFilterType.Blacklist
	rayParams.FilterDescendantsInstances = localCharacter and {localCharacter} or {}

	local origin = currentCamera.CFrame.Position
	local direction = targetHeadTip - origin
	if direction.Magnitude <= 0.01 then
		return true
	end

	local hit = workspace:Raycast(origin, direction, rayParams)
	if not hit then
		return true
	end

	return hit.Instance and hit.Instance:IsDescendantOf(targetCharacter) or false
end

function characterRuntime.isHeadTipOnScreen(targetHeadTip)
	local currentCamera = workspace.CurrentCamera or camera
	if not currentCamera or not targetHeadTip then
		return false
	end

	local viewportPos, onScreen = currentCamera:WorldToViewportPoint(targetHeadTip)
	if not onScreen or viewportPos.Z <= 0 then
		return false
	end

	local viewportSize = currentCamera.ViewportSize
	return viewportPos.X >= 0 and viewportPos.X <= viewportSize.X
		and viewportPos.Y >= 0 and viewportPos.Y <= viewportSize.Y
end

function characterRuntime.getClosestOnScreenVisibleTarget()
	local localCharacter = localPlayer.Character
	local localRoot = characterRuntime.getRootPart(localCharacter)
	if not localRoot then
		return nil
	end

	local closestDistance = math.huge
	local closestPlayer = nil

	for _, player in ipairs(players:GetPlayers()) do
		if player ~= localPlayer then
			local character = player.Character
			local humanoid = character and character:FindFirstChildOfClass("Humanoid")
			local rootPart = characterRuntime.getRootPart(character)
			local head = character and character:FindFirstChild("Head")

			if humanoid and humanoid.Health > 0 and rootPart then
				local focusPart = head or rootPart
				local yOffset = head and math.max(0.5, head.Size.Y * 0.55) or 1.5
				local headTip = focusPart.Position + Vector3.new(0, yOffset, 0)
				if characterRuntime.isHeadTipOnScreen(headTip) then
					local distance = (rootPart.Position - localRoot.Position).Magnitude
					if distance < closestDistance then
						closestDistance = distance
						closestPlayer = player
					end
				end
			end
		end
	end

	return closestPlayer
end

function characterRuntime.getClosestStrictVisibleTargetData()
	local localCharacter = localPlayer.Character
	local localRoot = characterRuntime.getRootPart(localCharacter)
	if not localRoot then
		return nil
	end

	local closestDistance = math.huge
	local closestTargetData = nil

	for _, player in ipairs(players:GetPlayers()) do
		if player ~= localPlayer then
			local character = player.Character
			local humanoid = character and character:FindFirstChildOfClass("Humanoid")
			local rootPart = characterRuntime.getRootPart(character)
			local head = character and character:FindFirstChild("Head")
			if humanoid and humanoid.Health > 0 and rootPart and head then
				local headTip = head.Position + Vector3.new(0, math.max(0.5, head.Size.Y * 0.55), 0)
				if characterRuntime.isHeadTipOnScreen(headTip) and characterRuntime.isTargetVisibleInPOV(character, headTip) then
					local distance = (rootPart.Position - localRoot.Position).Magnitude
					if distance < closestDistance then
						closestDistance = distance
						closestTargetData = {
							player = player,
							character = character,
							humanoid = humanoid,
							rootPart = rootPart,
							head = head,
							headTip = headTip,
						}
					end
				end
			end
		end
	end

	return closestTargetData
end

function characterRuntime.updateTargetScan(deltaTime)
	characterRuntime.scanTimer = (characterRuntime.scanTimer or 0) + (deltaTime or 0)
	if characterRuntime.scanTimer < 0.08 then
		return
	end
	characterRuntime.scanTimer = 0

	local localCharacter = localPlayer.Character
	local localRoot = characterRuntime.getRootPart(localCharacter)
	if not localRoot then
		characterRuntime.scanTargetPlayer = nil
		characterRuntime.scanTargetData = nil
		characterRuntime.scanDistance = math.huge
		characterRuntime.scanIsLOS = false
		characterRuntime.scanIsOnScreen = false
		return
	end

	local bestVisible, bestVisibleD2 = nil, math.huge
	local bestInFov, bestInFovD2 = nil, math.huge
	local bestAny, bestAnyD2 = nil, math.huge
	local full360 = true

	for _, player in ipairs(players:GetPlayers()) do
		if player ~= localPlayer then
			local character = player.Character
			local humanoid = character and character:FindFirstChildOfClass("Humanoid")
			local rootPart = characterRuntime.getRootPart(character)
			local head = character and character:FindFirstChild("Head")
			if humanoid and humanoid.Health > 0 and rootPart and head then
				local headTip = head.Position + Vector3.new(0, math.max(0.5, head.Size.Y * 0.55), 0)
				local deltaVector = rootPart.Position - localRoot.Position
				local distanceSquared = deltaVector.X * deltaVector.X + deltaVector.Y * deltaVector.Y + deltaVector.Z * deltaVector.Z
				local targetData = {
					player = player,
					character = character,
					humanoid = humanoid,
					rootPart = rootPart,
					head = head,
					headTip = headTip,
				}

				if distanceSquared < bestAnyD2 then
					bestAnyD2 = distanceSquared
					bestAny = targetData
				end

				local inFov = true
				if not full360 then
					local look = camera.CFrame.LookVector
					local direction = (headTip - camera.CFrame.Position).Unit
					local angle = math.deg(math.acos(math.clamp(look:Dot(direction), -1, 1)))
					inFov = angle <= 90
				end

				if inFov then
					if distanceSquared < bestInFovD2 then
						bestInFovD2 = distanceSquared
						bestInFov = targetData
					end
					if distanceSquared < bestVisibleD2 and characterRuntime.isTargetVisibleInPOV(character, headTip) then
						bestVisibleD2 = distanceSquared
						bestVisible = targetData
					end
				end
			end
		end
	end

	local selected = bestVisible or bestInFov or bestAny
	if selected then
		characterRuntime.scanTargetPlayer = selected.player
		characterRuntime.scanTargetData = selected
		if bestVisible and selected.player == bestVisible.player then
			characterRuntime.scanDistance = math.sqrt(bestVisibleD2)
			characterRuntime.scanIsLOS = true
		elseif bestInFov and selected.player == bestInFov.player then
			characterRuntime.scanDistance = math.sqrt(bestInFovD2)
			characterRuntime.scanIsLOS = false
		else
			characterRuntime.scanDistance = math.sqrt(bestAnyD2)
			characterRuntime.scanIsLOS = false
		end
		characterRuntime.scanIsOnScreen = characterRuntime.isHeadTipOnScreen(selected.headTip)
	else
		characterRuntime.scanTargetPlayer = nil
		characterRuntime.scanTargetData = nil
		characterRuntime.scanDistance = math.huge
		characterRuntime.scanIsLOS = false
		characterRuntime.scanIsOnScreen = false
	end
end

function characterRuntime.primeTargetScan()
	characterRuntime.scanTimer = 1
	characterRuntime.updateTargetScan(1)
end

function characterRuntime.setAutoAimAssist(value)
	value = tonumber(value) or 0
	characterRuntime.autoAimAssistStrength = math.clamp(value, 0, 100)

	if characterRuntime.autoAimAssistStrength <= 0 then
		characterRuntime.currentAutoAimTarget = nil
	else
		characterRuntime.primeTargetScan()
	end
end

function characterRuntime.setAutoFindEnabled(enabled)
	characterRuntime.autoFindEnabled = enabled and true or false
	characterRuntime.clearAutoFindPath()

	if characterRuntime.autoFindEnabled then
		characterRuntime.autoFindForceRepath = true
		characterRuntime.primeTargetScan()
	end
end

function characterRuntime.isPlayerAlive(player)
	if not player or not player.Character then
		return false
	end
	local humanoid = player.Character:FindFirstChildOfClass("Humanoid")
	return humanoid and humanoid.Health > 0 or false
end

function characterRuntime.autoFindIssueMoveTo(humanoid, position, force)
	if not humanoid or not position then
		return
	end

	local now = os.clock()
	local previousTarget = characterRuntime.autoFindMoveTarget
	if not force and previousTarget and (previousTarget - position).Magnitude <= 1.2 and (now - (characterRuntime.autoFindLastMoveTick or 0)) < 0.12 then
		return
	end

	if characterRuntime.autoFindMoveConn then
		characterRuntime.autoFindMoveConn:Disconnect()
		characterRuntime.autoFindMoveConn = nil
	end

	characterRuntime.autoFindMoveTarget = position
	characterRuntime.autoFindLastMoveTick = now
	characterRuntime.autoFindMoveFired = false
	humanoid:MoveTo(position)
	characterRuntime.autoFindMoveConn = humanoid.MoveToFinished:Connect(function()
		characterRuntime.autoFindMoveFired = true
		characterRuntime.autoFindMoveTarget = nil
		if characterRuntime.autoFindMoveConn then
			characterRuntime.autoFindMoveConn:Disconnect()
			characterRuntime.autoFindMoveConn = nil
		end
	end)
end

function characterRuntime.autoFindDoJump(humanoid)
	if not humanoid then
		return
	end

	local now = os.clock()
	if now - (characterRuntime.autoFindJumpLast or 0) < 0.12 then
		return
	end

	characterRuntime.autoFindJumpLast = now
	humanoid:ChangeState(Enum.HumanoidStateType.Jumping)

	local vim = nil
	pcall(function()
		vim = game:GetService("VirtualInputManager")
	end)
	if vim and vim.SendKeyEvent then
		pcall(function()
			vim:SendKeyEvent(true, Enum.KeyCode.Space, false, game)
		end)
		task.delay(0.09, function()
			pcall(function()
				vim:SendKeyEvent(false, Enum.KeyCode.Space, false, game)
			end)
		end)
	end
end

function characterRuntime.autoFindProbeWall(rootPart, character, distance)
	local probeDistance = distance or 2.6
	if not rootPart then
		return { jump = false, wall = false }
	end

	local direction = Vector3.new(camera.CFrame.LookVector.X, 0, camera.CFrame.LookVector.Z)
	if direction.Magnitude < 0.001 then
		direction = Vector3.new(rootPart.CFrame.LookVector.X, 0, rootPart.CFrame.LookVector.Z)
	end
	if direction.Magnitude < 0.001 then
		direction = Vector3.new(0, 0, -1)
	else
		direction = direction.Unit
	end

	local rayParams = RaycastParams.new()
	rayParams.FilterType = Enum.RaycastFilterType.Blacklist
	rayParams.FilterDescendantsInstances = character and {character} or {}

	local lowHit = workspace:Raycast(rootPart.Position + Vector3.new(0, 0.6, 0), direction * probeDistance, rayParams)
	local midHit = workspace:Raycast(rootPart.Position + Vector3.new(0, 2.4, 0), direction * probeDistance, rayParams)
	local highHit = workspace:Raycast(rootPart.Position + Vector3.new(0, 4.2, 0), direction * probeDistance, rayParams)

	return {
		jump = (lowHit ~= nil and highHit == nil),
		wall = (lowHit ~= nil and midHit ~= nil),
	}
end

function characterRuntime.clickAtScreenCenter()
	local currentCamera = workspace.CurrentCamera or camera
	local centerX, centerY = nil, nil
	if currentCamera then
		centerX = math.floor(currentCamera.ViewportSize.X * 0.5)
		centerY = math.floor(currentCamera.ViewportSize.Y * 0.5)
	end

	if centerX and centerY and type(mousemoveabs) == "function" and type(mouse1press) == "function" and type(mouse1release) == "function" then
		pcall(mousemoveabs, centerX, centerY)
		pcall(mouse1press)
		pcall(mouse1release)
		if type(mouse1click) == "function" then
			pcall(mouse1click)
		end
		return true
	end

	if centerX and centerY and type(mousemoverel) == "function" and type(mouse1press) == "function" and type(mouse1release) == "function" then
		local cursor = userInputService:GetMouseLocation()
		pcall(mousemoverel, centerX - cursor.X, centerY - cursor.Y)
		pcall(mouse1press)
		pcall(mouse1release)
		if type(mouse1click) == "function" then
			pcall(mouse1click)
		end
		return true
	end

	if centerX and centerY then
		local vim = nil
		pcall(function()
			vim = game:GetService("VirtualInputManager")
		end)
		if vim and vim.SendMouseButtonEvent then
			pcall(function()
				vim:SendMouseButtonEvent(centerX, centerY, 0, true, game, 1)
				vim:SendMouseButtonEvent(centerX, centerY, 0, false, game, 1)
			end)
			return true
		end
	end

	if type(mouse1press) == "function" and type(mouse1release) == "function" then
		pcall(mouse1press)
		pcall(mouse1release)
		if type(mouse1click) == "function" then
			pcall(mouse1click)
		end
		return true
	end

	if type(mouse1click) == "function" then
		pcall(mouse1click)
		return true
	end

	return false
end

function characterRuntime.nextAutoClickInterval()
	return math.max(0.016, 1 / 12)
end

function characterRuntime.executeAutoClickSpam()
	local mousePosition = userInputService:GetMouseLocation()
	local vim = nil
	pcall(function()
		vim = game:GetService("VirtualInputManager")
	end)

	if vim and vim.SendMouseButtonEvent then
		pcall(function()
			vim:SendMouseButtonEvent(math.floor(mousePosition.X), math.floor(mousePosition.Y), 0, true, game, 1)
			vim:SendMouseButtonEvent(math.floor(mousePosition.X), math.floor(mousePosition.Y), 0, false, game, 1)
		end)
		return true
	end

	if type(mouse1press) == "function" and type(mouse1release) == "function" then
		pcall(mouse1press)
		pcall(mouse1release)
		return true
	end

	if type(mouse1click) == "function" then
		pcall(mouse1click)
		return true
	end

	return characterRuntime.clickAtScreenCenter()
end

function characterRuntime.rebuildAutoFindPath(rootPosition, targetPosition, targetUserId)
	local pathConfigs = {
		{ radius = 2.1, jumpHeight = 9, slope = 65, spacing = 1.6 },
		{ radius = 1.4, jumpHeight = 11, slope = 78, spacing = 1.2 },
		{ radius = 0.7, jumpHeight = 14, slope = 89, spacing = 0.9 },
	}

	local builtWaypoints = nil
	for _, config in ipairs(pathConfigs) do
		local path = pathfindingService:CreatePath({
			AgentRadius = config.radius,
			AgentHeight = 5,
			AgentCanJump = true,
			AgentCanClimb = true,
			AgentJumpHeight = config.jumpHeight,
			AgentMaxSlope = config.slope,
			WaypointSpacing = config.spacing,
		})

		local success = pcall(function()
			path:ComputeAsync(rootPosition, targetPosition)
		end)

		if success and path.Status == Enum.PathStatus.Success then
			local waypoints = path:GetWaypoints()
			if waypoints and #waypoints > 1 then
				builtWaypoints = waypoints
				break
			end
		end
	end

	if not builtWaypoints then
		characterRuntime.autoFindWaypoints = nil
		characterRuntime.autoFindWaypointIndex = 1
		characterRuntime.autoFindTargetUserId = targetUserId
		return false
	end

	characterRuntime.autoFindWaypoints = builtWaypoints
	characterRuntime.autoFindWaypointIndex = (#builtWaypoints > 1) and 2 or 1
	characterRuntime.autoFindTargetUserId = targetUserId
	return true
end

function characterRuntime.updateAutoFind(character, humanoid, rootPart, flightEnabled, deltaTime)
	local dt = deltaTime or (1 / 60)
	local ARRIVE = 4
	local PATH_CD = 1.05
	local STUCK_CD = 0.32
	local STUCK_DIST = 0.75
	local JUMP_H = 1.5
	local PEEK_IV = 2.4

	if not characterRuntime.autoFindEnabled then
		if humanoid and rootPart then
			humanoid:MoveTo(rootPart.Position)
		end
		if characterRuntime.autoFindMoveConn then
			characterRuntime.autoFindMoveConn:Disconnect()
			characterRuntime.autoFindMoveConn = nil
		end
		characterRuntime.autoFindStuckTimer = 0
		characterRuntime.autoFindStuckPhase = 0
		characterRuntime.autoFindStuckPhaseTime = 0
		characterRuntime.autoFindPeekLast = 0
		characterRuntime.autoFindPeekActive = false
		characterRuntime.autoFindMoveTarget = nil
		return
	end

	if flightEnabled then
		return
	end

	if not character or not humanoid or humanoid.Health <= 0 or not rootPart then
		return
	end

	local visTarget = characterRuntime.scanTargetPlayer
	local visIsLOS = characterRuntime.scanIsLOS == true

	if visIsLOS and visTarget then
		humanoid:MoveTo(rootPart.Position)
		if characterRuntime.autoFindMoveConn then
			characterRuntime.autoFindMoveConn:Disconnect()
			characterRuntime.autoFindMoveConn = nil
		end
		characterRuntime.autoFindStuckTimer = 0
		characterRuntime.autoFindStuckPhase = 0
		characterRuntime.autoFindStuckPhaseTime = 0
		characterRuntime.autoFindPeekLast = 0
		characterRuntime.autoFindPeekActive = false
		characterRuntime.autoFindMoveTarget = nil
		return
	end

	if characterRuntime.autoFindLockedTarget and not characterRuntime.isPlayerAlive(characterRuntime.autoFindLockedTarget) then
		characterRuntime.autoFindLockedTarget = nil
		characterRuntime.autoFindWaypoints = nil
		characterRuntime.autoFindWaypointIndex = 1
		characterRuntime.autoFindForceRepath = false
		characterRuntime.autoFindStuckTimer = 0
		characterRuntime.autoFindStuckPhase = 0
		characterRuntime.autoFindStuckPhaseTime = 0
		characterRuntime.autoFindPathTimer = 0
		characterRuntime.autoFindMoveTarget = nil
		if characterRuntime.autoFindMoveConn then
			characterRuntime.autoFindMoveConn:Disconnect()
			characterRuntime.autoFindMoveConn = nil
		end
	end

	if not characterRuntime.autoFindLockedTarget then
		if visTarget then
			characterRuntime.autoFindLockedTarget = visTarget
			characterRuntime.autoFindWaypoints = nil
			characterRuntime.autoFindWaypointIndex = 1
			characterRuntime.autoFindPathTimer = 0
			characterRuntime.autoFindStuckTimer = 0
			characterRuntime.autoFindStuckPhase = 0
			characterRuntime.autoFindStuckPhaseTime = 0
			characterRuntime.autoFindForceRepath = true
		else
			return
		end
	end

	local targetPlayer = characterRuntime.autoFindLockedTarget
	if not targetPlayer or targetPlayer.Parent ~= players then
		return
	end

	local targetCharacter = targetPlayer.Character
	local targetRoot = characterRuntime.getRootPart(targetCharacter)
	if not targetRoot then
		return
	end

	local targetPosition = targetRoot.Position
	local directDistance = (targetPosition - rootPart.Position).Magnitude
	if directDistance <= ARRIVE then
		if characterRuntime.autoFindMoveConn then
			characterRuntime.autoFindMoveConn:Disconnect()
			characterRuntime.autoFindMoveConn = nil
		end
		humanoid:MoveTo(rootPart.Position)
		characterRuntime.autoFindStuckTimer = 0
		characterRuntime.autoFindStuckPhase = 0
		characterRuntime.autoFindStuckPhaseTime = 0
		return
	end

	if not characterRuntime.autoFindLastPosition then
		characterRuntime.autoFindLastPosition = rootPart.Position
	end

	characterRuntime.autoFindStuckTimer = (characterRuntime.autoFindStuckTimer or 0) + dt
	if characterRuntime.autoFindStuckTimer >= STUCK_CD then
		characterRuntime.autoFindStuckTimer = 0
		local movedDistance = (rootPart.Position - characterRuntime.autoFindLastPosition).Magnitude
		characterRuntime.autoFindLastPosition = rootPart.Position
		if movedDistance < STUCK_DIST and (characterRuntime.autoFindStuckPhase or 0) == 0 then
			characterRuntime.autoFindStuckPhase = math.random(1, 6)
			characterRuntime.autoFindStuckPhaseTime = 0
			characterRuntime.autoFindForceRepath = true
			if characterRuntime.autoFindMoveConn then
				characterRuntime.autoFindMoveConn:Disconnect()
				characterRuntime.autoFindMoveConn = nil
			end
		elseif movedDistance >= STUCK_DIST then
			characterRuntime.autoFindStuckPhase = 0
		end
	end

	if (characterRuntime.autoFindStuckPhase or 0) ~= 0 then
		characterRuntime.autoFindStuckPhaseTime = (characterRuntime.autoFindStuckPhaseTime or 0) + dt
		local phase = characterRuntime.autoFindStuckPhase
		local phaseTime = characterRuntime.autoFindStuckPhaseTime

		local fwd = Vector3.new(camera.CFrame.LookVector.X, 0, camera.CFrame.LookVector.Z)
		if fwd.Magnitude < 0.001 then
			fwd = Vector3.new(rootPart.CFrame.LookVector.X, 0, rootPart.CFrame.LookVector.Z)
		end
		if fwd.Magnitude < 0.001 then
			fwd = Vector3.new(0, 0, -1)
		else
			fwd = fwd.Unit
		end
		local right = Vector3.new(fwd.Z, 0, -fwd.X)
		local base = rootPart.Position

		if phase == 1 then
			humanoid:MoveTo(base + (fwd * 4))
			characterRuntime.autoFindDoJump(humanoid)
			if phaseTime > 0.65 then characterRuntime.autoFindStuckPhase = 0 end
		elseif phase == 2 then
			humanoid:MoveTo(base - (right * 3) + (fwd * 3))
			characterRuntime.autoFindDoJump(humanoid)
			if phaseTime > 0.6 then characterRuntime.autoFindStuckPhase = 0 end
		elseif phase == 3 then
			humanoid:MoveTo(base + (right * 3) + (fwd * 3))
			characterRuntime.autoFindDoJump(humanoid)
			if phaseTime > 0.6 then characterRuntime.autoFindStuckPhase = 0 end
		elseif phase == 4 then
			humanoid:MoveTo(base - (fwd * 4))
			if phaseTime > 0.5 then
				characterRuntime.autoFindStuckPhase = 0
				characterRuntime.autoFindForceRepath = true
			end
		elseif phase == 5 then
			humanoid:MoveTo(base - (right * 2) - (fwd * 2))
			characterRuntime.autoFindDoJump(humanoid)
			if phaseTime > 0.55 then
				characterRuntime.autoFindStuckPhase = 0
				characterRuntime.autoFindForceRepath = true
			end
		elseif phase == 6 then
			humanoid:MoveTo(base + Vector3.new(0, 6, 0) + (fwd * 2))
			characterRuntime.autoFindDoJump(humanoid)
			task.delay(0.18, function()
				characterRuntime.autoFindDoJump(humanoid)
			end)
			if phaseTime > 0.6 then characterRuntime.autoFindStuckPhase = 0 end
		end
		return
	end

	characterRuntime.autoFindPathTimer = (characterRuntime.autoFindPathTimer or 0) + dt
	local targetMoved = 0
	if characterRuntime.autoFindLastTargetPosition then
		targetMoved = (targetPosition - characterRuntime.autoFindLastTargetPosition).Magnitude
	end

	local shouldRepath = characterRuntime.autoFindForceRepath
		or characterRuntime.autoFindPathTimer >= PATH_CD
		or targetMoved >= 5
		or type(characterRuntime.autoFindWaypoints) ~= "table"
		or #characterRuntime.autoFindWaypoints == 0

	if shouldRepath then
		characterRuntime.autoFindPathTimer = 0
		characterRuntime.autoFindLastTargetPosition = targetPosition
		local success = characterRuntime.rebuildAutoFindPath(rootPart.Position, targetPosition, targetPlayer.UserId)
		characterRuntime.autoFindForceRepath = false
		if success and type(characterRuntime.autoFindWaypoints) == "table" and #characterRuntime.autoFindWaypoints > 1 then
			local idx = math.clamp(characterRuntime.autoFindWaypointIndex or 2, 2, #characterRuntime.autoFindWaypoints)
			characterRuntime.autoFindWaypointIndex = idx
			characterRuntime.autoFindIssueMoveTo(humanoid, characterRuntime.autoFindWaypoints[idx].Position)
		else
			characterRuntime.autoFindWaypoints = nil
			characterRuntime.autoFindWaypointIndex = 1
			characterRuntime.autoFindIssueMoveTo(humanoid, targetPosition)
		end
	end

	characterRuntime.autoFindPeekLast = (characterRuntime.autoFindPeekLast or 0) + dt
	if characterRuntime.autoFindPeekLast >= PEEK_IV and not characterRuntime.autoFindPeekActive then
		characterRuntime.autoFindPeekLast = 0
		characterRuntime.autoFindPeekActive = true
		characterRuntime.autoFindDoJump(humanoid)
		task.delay(0.65, function()
			characterRuntime.autoFindPeekActive = false
		end)
	end

	local waypoints = characterRuntime.autoFindWaypoints
	local wpIdx = characterRuntime.autoFindWaypointIndex or 1

	if type(waypoints) == "table" and #waypoints > 0 and wpIdx <= #waypoints then
		local waypoint = waypoints[wpIdx]
		local deltaVector = waypoint.Position - rootPart.Position
		local flatDistance = Vector3.new(deltaVector.X, 0, deltaVector.Z).Magnitude
		local deltaY = waypoint.Position.Y - rootPart.Position.Y

		if flatDistance <= 2.6 or characterRuntime.autoFindMoveFired then
			characterRuntime.autoFindMoveFired = false
			wpIdx += 1
			characterRuntime.autoFindWaypointIndex = wpIdx
			if wpIdx <= #waypoints then
				characterRuntime.autoFindIssueMoveTo(humanoid, waypoints[wpIdx].Position)
			end
			return
		end

		local now = os.clock()
		if not characterRuntime.autoFindMoveConn or (now - (characterRuntime.autoFindLastMoveTick or 0)) >= 0.22 then
			characterRuntime.autoFindIssueMoveTo(humanoid, waypoint.Position)
		end
		local wall = characterRuntime.autoFindProbeWall(rootPart, character, 2.5)
		if waypoint.Action == Enum.PathWaypointAction.Jump or deltaY > JUMP_H or wall.jump then
			characterRuntime.autoFindDoJump(humanoid)
		end
		if wall.wall and waypoint.Action ~= Enum.PathWaypointAction.Jump then
			characterRuntime.autoFindForceRepath = true
		end
	else
		characterRuntime.autoFindIssueMoveTo(humanoid, targetPosition)
		local wall = characterRuntime.autoFindProbeWall(rootPart, character, 2.2)
		if wall.jump or wall.wall then
			characterRuntime.autoFindDoJump(humanoid)
		end
	end
end

function characterRuntime.destroyClickTeleportTool()
	if characterRuntime.clickTeleportConn then
		characterRuntime.clickTeleportConn:Disconnect()
		characterRuntime.clickTeleportConn = nil
	end

	if characterRuntime.clickTeleportTool and characterRuntime.clickTeleportTool.Parent then
		characterRuntime.clickTeleportTool:Destroy()
	end
	characterRuntime.clickTeleportTool = nil

	local backpack = localPlayer:FindFirstChildOfClass("Backpack")
	if backpack then
		local backpackTool = backpack:FindFirstChild("Click Teleport Tool")
		if backpackTool then
			backpackTool:Destroy()
		end
	end

	local character = localPlayer.Character
	if character then
		local equippedTool = character:FindFirstChild("Click Teleport Tool")
		if equippedTool then
			equippedTool:Destroy()
		end
	end
end

function characterRuntime.ensureClickTeleportTool()
	if not characterRuntime.clickTeleportEnabled then
		characterRuntime.destroyClickTeleportTool()
		return
	end

	local backpack = localPlayer:FindFirstChildOfClass("Backpack")
	if not backpack then
		return
	end

	local tool = characterRuntime.clickTeleportTool
	if tool and tool.Parent and (tool.Parent == backpack or tool.Parent == localPlayer.Character) then
		return
	end

	characterRuntime.destroyClickTeleportTool()

	tool = Instance.new("Tool")
	tool.Name = "Click Teleport Tool"
	tool.RequiresHandle = false
	tool.CanBeDropped = false
	tool.ToolTip = "Click to teleport"
	tool.Parent = backpack

	characterRuntime.clickTeleportConn = tool.Activated:Connect(function()
		local character = localPlayer.Character
		local rootPart = characterRuntime.getRootPart(character)
		local hit = mouse and mouse.Hit
		if rootPart and hit then
			rootPart.CFrame = CFrame.new(hit.X, hit.Y + 3, hit.Z, select(4, rootPart.CFrame:components()))
		end
	end)

	characterRuntime.clickTeleportTool = tool
end

