	siriusName = "Sirius",
	releaseType = "Stable",
	betaControl = {
		endpoint = "https://siriusx.vercel.app/api/beta/control",
		clientIdFile = "beta-client-id.srs",
		clientId = nil,
		disabled = false,
		message = "",
