characterRuntime.characterScrollFadeReady = false
characterRuntime.characterScrollFadeBound = false
characterRuntime.characterScrollFadeOverlay = nil
characterRuntime.characterScrollTopFade = nil
characterRuntime.characterScrollBottomFade = nil
characterRuntime.characterScrollFadeState = nil
characterRuntime.characterScrollFadeBase = setmetatable({}, {__mode = "k"})
characterRuntime.characterHeaderBase = nil
characterRuntime.characterScrollHeaderIcon = nil
characterRuntime.characterScrollHeaderTitle = nil
characterRuntime.characterScrollHeaderActive = false
characterRuntime.characterScrollHeaderToken = 0

function characterRuntime.ensureCharacterPanelScrollFade()
	if not characterPanel or not characterPanel:FindFirstChild("Interactions") then return end
	if characterRuntime.characterScrollFadeReady then return end

	local interactions = characterPanel.Interactions
	if not interactions:IsA("ScrollingFrame") then return end

	for _, name in ipairs({"CharacterScrollFadeOverlay", "CharacterScrollFadeMask", "CharacterScrollTopFade", "CharacterScrollBottomFade"}) do
		local oldFade = characterPanel:FindFirstChild(name)
		if oldFade then
			oldFade:Destroy()
		end

		local oldScrollFade = interactions:FindFirstChild(name)
		if oldScrollFade then
			oldScrollFade:Destroy()
		end
	end

	local overlay = Instance.new("Frame")
	overlay.Name = "CharacterScrollFadeOverlay"
	overlay.AnchorPoint = Vector2.new(0, 0)
	overlay.Position = UDim2.new(0, 0, 0, 0)
	overlay.Size = UDim2.new(1, 0, 1, 0)
	overlay.BackgroundTransparency = 1
	overlay.BorderSizePixel = 0
	overlay.ClipsDescendants = true
	overlay.Active = false
	overlay.ZIndex = 100000
	overlay.Parent = characterPanel

	pcall(function()
		overlay.Selectable = false
	end)
	pcall(function()
		overlay.Interactable = false
	end)

	local overlayCorner = Instance.new("UICorner")
	local panelCorner = characterPanel:FindFirstChildOfClass("UICorner")
	overlayCorner.CornerRadius = panelCorner and panelCorner.CornerRadius or UDim.new(0, 18)
	overlayCorner.Parent = overlay

	local function createFade(name, isTop)
		local fade = Instance.new("Frame")
		fade.Name = name
		fade.AnchorPoint = Vector2.new(0, isTop and 0 or 1)
		fade.Position = isTop and UDim2.new(0, 0, 0, 0) or UDim2.new(0, 0, 1, 0)
		fade.Size = UDim2.new(1, 0, 0, isTop and 72 or 86)
		fade.BackgroundColor3 = characterPanel.BackgroundColor3
		fade.BackgroundTransparency = 1
		fade.BorderSizePixel = 0
		fade.ClipsDescendants = true
		fade.Active = false
		fade.Visible = false
		fade.ZIndex = overlay.ZIndex + 1
		fade.Parent = overlay

		pcall(function()
			fade.Selectable = false
		end)
		pcall(function()
			fade.Interactable = false
		end)

		local fadeCorner = Instance.new("UICorner")
		fadeCorner.CornerRadius = overlayCorner.CornerRadius
		fadeCorner.Parent = fade

		local gradient = Instance.new("UIGradient")
		gradient.Rotation = isTop and 90 or -90
		gradient.Transparency = NumberSequence.new({
			NumberSequenceKeypoint.new(0, 0),
			NumberSequenceKeypoint.new(0.12, 0.02),
			NumberSequenceKeypoint.new(0.28, 0.16),
			NumberSequenceKeypoint.new(0.54, 0.58),
			NumberSequenceKeypoint.new(0.84, 0.94),
			NumberSequenceKeypoint.new(1, 1),
		})
		gradient.Parent = fade

		return fade
	end

	characterRuntime.characterScrollFadeOverlay = overlay
	characterRuntime.characterScrollTopFade = createFade("CharacterScrollTopFade", true)
	characterRuntime.characterScrollBottomFade = createFade("CharacterScrollBottomFade", false)
	characterRuntime.characterScrollFadeState = {Top = -1, Bottom = -1}
	characterRuntime.characterScrollFadeReady = true
end

function characterRuntime.positionCharacterPanelScrollFade()
	if not characterPanel or not characterPanel:FindFirstChild("Interactions") then return end

	local interactions = characterPanel.Interactions
	if not interactions:IsA("ScrollingFrame") then return end
	if not characterRuntime.characterScrollFadeOverlay then return end

	characterRuntime.characterScrollFadeOverlay.Position = UDim2.new(0, 0, 0, 0)
	characterRuntime.characterScrollFadeOverlay.Size = UDim2.new(1, 0, 1, 0)

	if characterRuntime.characterScrollTopFade then
		characterRuntime.characterScrollTopFade.Position = UDim2.new(0, 0, 0, 0)
	end

	if characterRuntime.characterScrollBottomFade then
		characterRuntime.characterScrollBottomFade.Position = UDim2.new(0, 0, 1, 0)
	end
end

function characterRuntime.setCharacterPanelScrollFade(frame, key, strength)
	if not frame then return end
	strength = math.clamp(strength or 0, 0, 1)

	local eased = strength * strength * (3 - 2 * strength)
	characterRuntime.characterScrollFadeState = characterRuntime.characterScrollFadeState or {Top = -1, Bottom = -1}
	if math.abs((characterRuntime.characterScrollFadeState[key] or 0) - eased) < 0.01 then return end
	characterRuntime.characterScrollFadeState[key] = eased

	if eased <= 0.012 then
		frame.BackgroundTransparency = 1
		frame.Visible = false
		return
	end

	frame.Visible = true
	frame.BackgroundTransparency = 1 - math.min(eased * 0.94, 0.94)
end

function characterRuntime.captureCharacterPanelHeaderLayout(force)
	if not characterPanel then return end

	characterRuntime.characterHeaderBase = characterRuntime.characterHeaderBase or {}
	local base = characterRuntime.characterHeaderBase

	if characterPanel:FindFirstChild("Icon") and (force or not base.IconPosition) then
		base.IconPosition = characterPanel.Icon.Position
	end

	if characterPanel:FindFirstChild("Title") and (force or not base.TitlePosition) then
		base.TitlePosition = characterPanel.Title.Position
	end
end

function characterRuntime.ensureCharacterPanelScrollHeader(animated)
	if not characterPanel or not characterPanel:FindFirstChild("Interactions") then return end

	local interactions = characterPanel.Interactions
	if not interactions:IsA("ScrollingFrame") then return end

	characterRuntime.captureCharacterPanelHeaderLayout()
	local base = characterRuntime.characterHeaderBase or {}
	local fixedIcon = characterPanel:FindFirstChild("Icon")
	local fixedTitle = characterPanel:FindFirstChild("Title")
	local headerIconPosition = base.IconPosition and UDim2.new(base.IconPosition.X.Scale, base.IconPosition.X.Offset, 0, 26)
	local headerTitlePosition = base.TitlePosition and UDim2.new(base.TitlePosition.X.Scale, base.TitlePosition.X.Offset, 0, 25)
	local active = characterRuntime.characterScrollHeaderActive == true
	local animateSwap = active and animated == true

	local scrollIcon = interactions:FindFirstChild("CharacterScrollIcon")
	if not scrollIcon and fixedIcon then
		scrollIcon = fixedIcon:Clone()
		scrollIcon.Name = "CharacterScrollIcon"
		scrollIcon.Parent = interactions
	end

	local scrollTitle = interactions:FindFirstChild("CharacterScrollTitle")
	if not scrollTitle and fixedTitle then
		scrollTitle = fixedTitle:Clone()
		scrollTitle.Name = "CharacterScrollTitle"
		scrollTitle.Parent = interactions
	end

	if scrollIcon and fixedIcon and headerIconPosition then
		scrollIcon.AnchorPoint = fixedIcon.AnchorPoint
		scrollIcon.Position = headerIconPosition
		scrollIcon.Size = fixedIcon.Size
		scrollIcon.Image = fixedIcon.Image
		scrollIcon.ImageColor3 = fixedIcon.ImageColor3
		scrollIcon.ImageTransparency = animateSwap and 1 or 0
		scrollIcon.BackgroundTransparency = fixedIcon.BackgroundTransparency
		scrollIcon.ZIndex = math.max(fixedIcon.ZIndex, interactions.ZIndex + 2)
		scrollIcon.Visible = active and characterPanel.Visible
		characterRuntime.characterScrollHeaderIcon = scrollIcon
		if active and not animateSwap then
			fixedIcon.Visible = false
		end
	end

	if scrollTitle and fixedTitle and headerTitlePosition then
		scrollTitle.AnchorPoint = fixedTitle.AnchorPoint
		scrollTitle.Position = headerTitlePosition
		scrollTitle.Size = fixedTitle.Size
		scrollTitle.Text = fixedTitle.Text
		scrollTitle.Font = fixedTitle.Font
		scrollTitle.TextSize = fixedTitle.TextSize
		scrollTitle.TextColor3 = fixedTitle.TextColor3
		scrollTitle.TextTransparency = animateSwap and 1 or 0
		scrollTitle.BackgroundTransparency = fixedTitle.BackgroundTransparency
		scrollTitle.ZIndex = math.max(fixedTitle.ZIndex, interactions.ZIndex + 2)
		scrollTitle.Visible = active and characterPanel.Visible
		characterRuntime.characterScrollHeaderTitle = scrollTitle
		if active and not animateSwap then
			fixedTitle.Visible = false
		end
	end

	if animateSwap then
		local token = characterRuntime.characterScrollHeaderToken
		local fadeIn = TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
		local fadeOut = TweenInfo.new(0.16, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)

		if fixedIcon then
			fixedIcon.Visible = true
			tweenService:Create(fixedIcon, fadeOut, {ImageTransparency = 1}):Play()
		end

		if fixedTitle then
			fixedTitle.Visible = true
			tweenService:Create(fixedTitle, fadeOut, {TextTransparency = 1}):Play()
		end

		if scrollIcon then
			scrollIcon.Visible = characterPanel.Visible
			tweenService:Create(scrollIcon, fadeIn, {ImageTransparency = 0}):Play()
		end

		if scrollTitle then
			scrollTitle.Visible = characterPanel.Visible
			tweenService:Create(scrollTitle, fadeIn, {TextTransparency = 0}):Play()
		end

		task.delay(0.18, function()
			if characterRuntime.characterScrollHeaderToken ~= token or not characterRuntime.characterScrollHeaderActive then return end

			if fixedIcon then
				fixedIcon.Visible = false
			end

			if fixedTitle then
				fixedTitle.Visible = false
			end

			if scrollIcon then
				scrollIcon.ImageTransparency = 0
			end

			if scrollTitle then
				scrollTitle.TextTransparency = 0
			end
		end)
	end
end

function characterRuntime.resetCharacterPanelHeaderScroll(forceVisible)
	if not characterPanel then return end
	characterRuntime.characterScrollHeaderActive = false
	characterRuntime.characterScrollHeaderToken = (characterRuntime.characterScrollHeaderToken or 0) + 1
	characterRuntime.captureCharacterPanelHeaderLayout()

	if characterPanel:FindFirstChild("Interactions") then
		local interactions = characterPanel.Interactions
		for _, name in ipairs({"CharacterScrollIcon", "CharacterScrollTitle"}) do
			local scrollHeader = interactions:FindFirstChild(name)
			if scrollHeader then
				scrollHeader.Visible = false
			end
		end
	end

	local base = characterRuntime.characterHeaderBase or {}
	if characterPanel:FindFirstChild("Icon") and base.IconPosition then
		characterPanel.Icon.Visible = true
		characterPanel.Icon.Position = base.IconPosition
		if forceVisible then
			characterPanel.Icon.ImageTransparency = 0
		end
	end

	if characterPanel:FindFirstChild("Title") and base.TitlePosition then
		characterPanel.Title.Visible = true
		characterPanel.Title.Position = base.TitlePosition
		if forceVisible then
			characterPanel.Title.TextTransparency = 0
		end
	end
end

function characterRuntime.activateCharacterPanelScrollHeader(animated)
	if not characterPanel or not characterPanel:FindFirstChild("Interactions") then return end
	if not characterPanel.Interactions:IsA("ScrollingFrame") then return end

	characterRuntime.characterScrollHeaderActive = true
	characterRuntime.characterScrollHeaderToken = (characterRuntime.characterScrollHeaderToken or 0) + 1
	characterRuntime.ensureCharacterPanelScrollHeader(animated)
end

function characterRuntime.applyCharacterScrollObjectFade(root, strength)
	if not root or not root:IsA("GuiObject") then return end

	characterRuntime.characterScrollFadeBase = characterRuntime.characterScrollFadeBase or setmetatable({}, {__mode = "k"})
	strength = math.clamp(strength or 0, 0, 0.9)
	local isClear = strength <= 0.012

	local function applyObject(object)
		local properties = siriusValues.transparencyProperties[object.ClassName]
		if not properties then return end

		local base = characterRuntime.characterScrollFadeBase[object]
		if not base then
			base = {}
			characterRuntime.characterScrollFadeBase[object] = base
		end

		for _, property in ipairs(properties) do
			local current = object[property]
			if base[property] == nil then
				base[property] = current
			end

			local original = base[property]
			if type(original) == "number" then
				if isClear then
					object[property] = original
				else
					object[property] = math.clamp(original + ((1 - original) * strength), 0, 1)
				end
			end
		end
	end

	applyObject(root)
	for _, descendant in ipairs(root:GetDescendants()) do
		if descendant.Name ~= "Interact" then
			applyObject(descendant)
		end
	end
end

function characterRuntime.updateCharacterPanelHeaderScroll()
	if characterRuntime.characterScrollHeaderActive then
		characterRuntime.ensureCharacterPanelScrollHeader()
	end
end

function characterRuntime.refreshCharacterPanelItemFade()
	if not characterRuntime.characterScrollFadeBase then return end

	for object, base in pairs(characterRuntime.characterScrollFadeBase) do
		if object and object.Parent and base then
			for property, value in pairs(base) do
				pcall(function()
					object[property] = value
				end)
			end
		end
	end

	characterRuntime.characterScrollFadeBase = setmetatable({}, {__mode = "k"})
end

function characterRuntime.refreshCharacterPanelScrollFade()
	if not characterPanel or not characterPanel:FindFirstChild("Interactions") then return end
	characterRuntime.ensureCharacterPanelScrollFade()

	local interactions = characterPanel.Interactions
	if not interactions:IsA("ScrollingFrame") then return end

	local maxY = math.max(0, interactions.AbsoluteCanvasSize.Y - interactions.AbsoluteWindowSize.Y)
	local currentY = interactions.CanvasPosition.Y
	local fadeRange = 98

	characterRuntime.positionCharacterPanelScrollFade()
	characterRuntime.setCharacterPanelScrollFade(characterRuntime.characterScrollTopFade, "Top", currentY / fadeRange)
	characterRuntime.setCharacterPanelScrollFade(characterRuntime.characterScrollBottomFade, "Bottom", (maxY - currentY) / fadeRange)
	characterRuntime.updateCharacterPanelHeaderScroll()
	characterRuntime.refreshCharacterPanelItemFade()

	if not characterRuntime.characterScrollFadeBound then
		characterRuntime.characterScrollFadeBound = true
		interactions:GetPropertyChangedSignal("CanvasPosition"):Connect(function()
			characterRuntime.refreshCharacterPanelScrollFade()
		end)
		interactions:GetPropertyChangedSignal("AbsoluteCanvasSize"):Connect(function()
			characterRuntime.refreshCharacterPanelScrollFade()
		end)
		interactions:GetPropertyChangedSignal("AbsoluteWindowSize"):Connect(function()
			characterRuntime.refreshCharacterPanelScrollFade()
		end)
	end
end

function characterRuntime.ensureCharacterPanelScroll()
	if not characterPanel or not characterPanel:FindFirstChild("Interactions") then return end

	if characterPanel.Interactions:IsA("ScrollingFrame") then
		characterPanel.Interactions.AnchorPoint = Vector2.new(0, 0)
		characterPanel.Interactions.Position = UDim2.new(0, 0, 0, 0)
		characterPanel.Interactions.Size = UDim2.new(1, 0, 1, 0)
		characterPanel.Interactions.BackgroundTransparency = 1
		characterPanel.Interactions.ClipsDescendants = true
		characterPanel.Interactions.Active = true
		characterPanel.Interactions.ScrollBarThickness = 3
		characterPanel.Interactions.ScrollBarImageTransparency = 1
		characterRuntime.ensureCharacterPanelScrollFade()
		return
	end

	local oldInteractions = characterPanel.Interactions
	local scroller = Instance.new("ScrollingFrame")
	scroller.Name = "Interactions"
	scroller.AnchorPoint = Vector2.new(0, 0)
	scroller.Position = UDim2.new(0, 0, 0, 0)
	scroller.Size = UDim2.new(1, 0, 1, 0)
	scroller.BackgroundColor3 = oldInteractions.BackgroundColor3
	scroller.BackgroundTransparency = 1
	scroller.BorderColor3 = oldInteractions.BorderColor3
	scroller.BorderSizePixel = oldInteractions.BorderSizePixel
	scroller.ClipsDescendants = true
	scroller.Active = true
	scroller.Visible = oldInteractions.Visible
	scroller.ZIndex = oldInteractions.ZIndex
	scroller.LayoutOrder = oldInteractions.LayoutOrder
	scroller.Rotation = oldInteractions.Rotation
	scroller.ScrollBarThickness = 3
	scroller.ScrollBarImageColor3 = Color3.fromRGB(210, 214, 220)
	scroller.ScrollBarImageTransparency = 1
	scroller.ScrollingDirection = Enum.ScrollingDirection.Y
	scroller.CanvasSize = UDim2.new(0, 0, 0, oldInteractions.AbsoluteSize.Y)
	scroller.Parent = characterPanel

	for _, child in ipairs(oldInteractions:GetChildren()) do
		child.Parent = scroller
	end

	oldInteractions:Destroy()
	characterRuntime.ensureCharacterPanelScrollFade()
end

function characterRuntime.positionCharacterPanelContent()
	if not characterPanel or not characterPanel:FindFirstChild("Interactions") then return end

	local interactions = characterPanel.Interactions
	local titleY = 58
	local contentY = 82

	local function setY(object, y)
		if object and object:IsA("GuiObject") then
			object.Position = UDim2.new(object.Position.X.Scale, object.Position.X.Offset, 0, y)
		end
	end

	setY(interactions:FindFirstChild("PropertiesTitle"), titleY)
	setY(interactions:FindFirstChild("ActionsTitle"), titleY)
	setY(interactions:FindFirstChild("Reset"), titleY - 4)
	setY(interactions:FindFirstChild("Sliders"), contentY)
	setY(interactions:FindFirstChild("Grid"), contentY)

	task.defer(function()
		if not interactions or not interactions.Parent then return end

		local grid = interactions:FindFirstChild("Grid")
		local gridLayout = grid and (grid:FindFirstChildOfClass("UIGridLayout") or grid:FindFirstChildOfClass("UIListLayout"))
		local buttonY = 194

		if grid and gridLayout then
			buttonY = math.max(buttonY, grid.Position.Y.Offset + gridLayout.AbsoluteContentSize.Y + 16)
		end

		setY(interactions:FindFirstChild("Serverhop"), buttonY)
		setY(interactions:FindFirstChild("Rejoin"), buttonY)
	end)
end

function characterRuntime.refreshCharacterPanelScroll()
	if not characterPanel or not characterPanel:FindFirstChild("Interactions") then return end

	local interactions = characterPanel.Interactions
	if not interactions:IsA("ScrollingFrame") then return end
	characterRuntime.positionCharacterPanelContent()

	local function fitHolder(holder)
		if not holder or not holder:IsA("GuiObject") then return end

		local layout = holder:FindFirstChildOfClass("UIGridLayout") or holder:FindFirstChildOfClass("UIListLayout")
		if not layout then return end

		local contentHeight = layout.AbsoluteContentSize.Y
		if contentHeight > 0 then
			holder.Size = UDim2.new(holder.Size.X.Scale, holder.Size.X.Offset, 0, contentHeight + 12)
		end
	end

	fitHolder(interactions:FindFirstChild("Grid"))
	fitHolder(interactions:FindFirstChild("Sliders"))

	task.defer(function()
		if not interactions or not interactions.Parent then return end

		local bottom = interactions.AbsoluteWindowSize.Y
		for _, child in ipairs(interactions:GetChildren()) do
			if child:IsA("GuiObject") and child.Visible and child.Name ~= "CharacterScrollFadeMask" and child.Name ~= "CharacterScrollFadeOverlay" then
				local childBottom = (child.AbsolutePosition.Y - interactions.AbsolutePosition.Y) + child.AbsoluteSize.Y
				bottom = math.max(bottom, childBottom)
			end
		end

		interactions.CanvasSize = UDim2.new(0, 0, 0, bottom + 28)
		characterRuntime.refreshCharacterPanelScrollFade()
	end)
end

