		return fallbackCommands
	end

	local function updateSuggestions(filterText)
		clearSuggestions()

		local query = tostring(filterText or ""):lower():match("^%s*(%S*)") or ""
		if query == "" then
			hideSuggestions()
			return
		end

		local count = 0
		local seen = {}
		local createdButtons = {}
		local rowHeight = 30
		local rowTextSize = 15
		local maxTextWidth = math.max(searchContainer.AbsoluteSize.X - 28, 130)

		for _, commandName in ipairs(getActiveSearchTokens()) do
			commandName = tostring(commandName or ""):lower()
			if commandName ~= "" and not seen[commandName] and commandName:find(query, 1, true) then
				seen[commandName] = true
				count += 1
				local measured = game:GetService("TextService"):GetTextSize(commandName, rowTextSize, Enum.Font.GothamMedium, Vector2.new(2000, rowHeight))
				maxTextWidth = math.max(maxTextWidth, measured.X + 14)

				local button = Instance.new("TextButton")
				button.Name = commandName
				button.Size = UDim2.new(0, maxTextWidth, 0, rowHeight)
				button.BackgroundColor3 = Color3.fromRGB(38, 38, 38)
				button.BackgroundTransparency = 1
				button.AutoButtonColor = false
				button.Text = commandName
				button.TextColor3 = Color3.fromRGB(230, 230, 235)
				button.TextTransparency = 1
				button.TextXAlignment = Enum.TextXAlignment.Left
				button.TextTruncate = Enum.TextTruncate.None
				button.TextWrapped = false
				button.Font = Enum.Font.GothamMedium
				button.TextSize = rowTextSize
				button.LayoutOrder = count
				button.ZIndex = 10006
				button.Parent = suggestions
				table.insert(createdButtons, button)

				local buttonCorner = Instance.new("UICorner")
				buttonCorner.CornerRadius = UDim.new(0, 9)
				buttonCorner.Parent = button

				button.MouseEnter:Connect(function()
					tweenService:Create(button, TweenInfo.new(0.16, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
						BackgroundTransparency = 0.88,
						TextColor3 = Color3.fromRGB(255, 255, 255)
					}):Play()
				end)

				button.MouseLeave:Connect(function()
					tweenService:Create(button, TweenInfo.new(0.16, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
						BackgroundTransparency = 1,
						TextColor3 = Color3.fromRGB(230, 230, 235)
					}):Play()
				end)

				button.MouseButton1Click:Connect(function()
					local args = input.Text:match("^%s*%S+%s+(.+)$")
					input.Text = args and (commandName.." "..args) or commandName
					input.CursorPosition = #input.Text + 1
					input:CaptureFocus()
				end)

				task.delay(count * 0.008, function()
					if button.Parent then
						tweenService:Create(button, TweenInfo.new(0.2, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {TextTransparency = 0.04}):Play()
					end
				end)

				if count >= 10 then
					break
				end
			end
		end

		if count == 0 then
			hideSuggestions()
			return
		end

		suggestions.Visible = true
		suggestionShadow.Visible = true
		suggestionScale.Scale = 0.985
		local viewportWidth = math.max(searchContainer.AbsoluteSize.X, searchContainer.Size.X.Offset, 160)
		local rowWidth = math.max(viewportWidth - 28, maxTextWidth)
		for _, button in ipairs(createdButtons) do
			button.Size = UDim2.new(0, rowWidth, 0, rowHeight)
		end
		local suggestionHeight = count * rowHeight + 28
		suggestions.CanvasPosition = Vector2.new(0, 0)
		suggestions.CanvasSize = UDim2.new(0, rowWidth + 28, 0, suggestionHeight)
		suggestionShadow.Size = UDim2.new(1, 34, 0, 34)
		suggestionShadow.ImageTransparency = 1
		tweenService:Create(suggestions, TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
			Size = UDim2.new(1, 0, 0, math.min(suggestionHeight, 286)),
			BackgroundTransparency = 0.04
		}):Play()
		tweenService:Create(suggestionScale, TweenInfo.new(0.26, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Scale = 1}):Play()
		tweenService:Create(suggestionStroke, TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.12}):Play()
		tweenService:Create(suggestionShadow, TweenInfo.new(0.26, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
			Size = UDim2.new(1, 34, 0, math.min(suggestionHeight, 286) + 34),
			ImageTransparency = 0.72
		}):Play()
	end

	local function runSearchCommand()
		local commandText = input.Text:gsub("^%s+", ""):gsub("%s+$", "")
		if commandText == "" then return end

		if type(runIntegratedIYCommand) == "function" then
			runIntegratedIYCommand(commandText, localPlayer)
		elseif type(execCmd) == "function" then
			execCmd(commandText, localPlayer)
		elseif type(queueNotification) == "function" then
			queueNotification("Command Search", "Command runtime is still loading. Try again in a second.", 4370336704)
		else
			warn("Command runtime is still loading")
		end

		input.Text = ""
	end

	CmdInput = input

	input:GetPropertyChangedSignal("Text"):Connect(function()
		if input:IsFocused() and input.Text ~= "" then
			updateSuggestions(input.Text)
		else
			hideSuggestions()
		end
	end)

	input.Focused:Connect(function()
		if not smartBarOpen then
			input:ReleaseFocus()
			return
		end

		tweenService:Create(searchContainer, TweenInfo.new(0.2), {BackgroundColor3 = Color3.fromRGB(60, 60, 60)}):Play()
		tweenService:Create(stroke, TweenInfo.new(0.2), {Color = Color3.fromRGB(255, 255, 255)}):Play()

		if input.Text ~= "" then
			updateSuggestions(input.Text)
		end
	end)

	input.FocusLost:Connect(function(enterPressed)
		tweenService:Create(searchContainer, TweenInfo.new(0.2), {BackgroundColor3 = Color3.fromRGB(45, 45, 45)}):Play()
		tweenService:Create(stroke, TweenInfo.new(0.2), {Color = Color3.fromRGB(100, 100, 100)}):Play()
		hideSuggestions()

		if enterPressed then
			runSearchCommand()
		end
	end)

	local function syncSearchVisibility()
		local isVisible = smartBar.Visible
		local transparency = smartBar.BackgroundTransparency
		local fadeFactor
		local tweenDuration

		if transparency > 0.5 then
			fadeFactor = 3
			tweenDuration = 0.1
			searchContainer.Visible = false
		else
			fadeFactor = 1.5
			tweenDuration = 0.2
			if isVisible then
				searchContainer.Visible = true
			end
		end

		local targetTransparency = transparency * fadeFactor
		if transparency == 0 then targetTransparency = 0.2 end
		if targetTransparency > 1 then targetTransparency = 1 end

		tweenService:Create(searchContainer, TweenInfo.new(tweenDuration), {BackgroundTransparency = targetTransparency}):Play()
		tweenService:Create(stroke, TweenInfo.new(tweenDuration), {Transparency = targetTransparency}):Play()
		tweenService:Create(icon, TweenInfo.new(tweenDuration), {ImageTransparency = targetTransparency}):Play()
		tweenService:Create(input, TweenInfo.new(tweenDuration), {
			TextTransparency = targetTransparency,
			PlaceholderColor3 = Color3.fromRGB(180, 180, 180)
		}):Play()

		if targetTransparency >= 1 then
			input:ReleaseFocus()
			hideSuggestions()
		end
	end

	smartBar:GetPropertyChangedSignal("Visible"):Connect(syncSearchVisibility)
	smartBar:GetPropertyChangedSignal("BackgroundTransparency"):Connect(syncSearchVisibility)
	smartBar:GetPropertyChangedSignal("AbsoluteSize"):Connect(siriusValues.syncSmartBarCommandSearchLayout)
	task.defer(siriusValues.syncSmartBarCommandSearchLayout)
	task.defer(syncSearchVisibility)
end

