-- Sirius Functions
local function checkSirius() return UI.Parent end
local function getPing()
	local success, value = pcall(function()
		return statsService.Network.ServerStatsItem["Data Ping"]:GetValue()
	end)

	return math.clamp((success and tonumber(value)) or 60, 10, 700)
end
local function checkFolder()
	if typeof(isfolder) ~= "function" or typeof(makefolder) ~= "function" then return end

	pcall(function()
		local root = siriusValues.siriusFolder
		local assets = root.."/Assets"
		local icons = assets.."/Icons"
		local music = root.."/Music"

		if not isfolder(root) then makefolder(root) end
		if not isfolder(assets) then makefolder(assets) end
		if not isfolder(icons) then makefolder(icons) end
		if not isfolder(music) then
			makefolder(music)
			if typeof(writefile) == "function" then
				writefile(music.."/readme.txt", "Hey there! Place your MP3 or other audio files in this folder, and have the ability to play them through the Sirius Music UI!")
			end
		end
	end)
end
local function isPanel(name) return not table.find({"Home", "Music", "Settings"}, name) end

local function fetchFromCDN(path, write, savePath)
	pcall(function()
		checkFolder()

		local file = game:HttpGet(siriusValues.cdn..path) or nil
		if not file then return end
		if not write then return file end
		if typeof(writefile) ~= "function" then return end


		writefile(siriusValues.siriusFolder.."/"..savePath, file)

		return
	end)
end

local function fetchIcon(iconName)
	pcall(function()
		checkFolder()

		local pathCDN = siriusValues.icons..iconName..".png"
		local path = siriusValues.siriusFolder.."/Assets/"..iconName..".png"

		if not isfile(path) then
			local file = game:HttpGet(pathCDN)
			if not file then return end

			writefile(path, file)
		end

		local imageToReturn = getcustomasset(path)

		return imageToReturn
	end)
end

local function storeOriginalText(element)
	if originalTextValues[element] == nil then
		originalTextValues[element] = element.Text
	end
end

local function undoAnonymousChanges()
	for element, originalText in pairs(originalTextValues) do
		element.Text = originalText
	end
end

local function isHighlightEnabledFor(playerName)
	return siriusValues.actions[6].enabled or locatedPlayers[playerName] == true
end

local function createEsp(player)
	if player == localPlayer or not checkSirius() then
		return
	end

	local highlight = Instance.new("Highlight")
	highlight.FillTransparency = 1
	highlight.OutlineTransparency = 0
	highlight.OutlineColor = Color3.new(1,1,1)
	highlight.Adornee = player.Character
	highlight.Name = player.Name
	highlight.Enabled = isHighlightEnabledFor(player.Name)
	highlight.Parent = espContainer

	if espConnections[player] then
		espConnections[player]:Disconnect()
	end
	espConnections[player] = player.CharacterAdded:Connect(function(character)
		if not checkSirius() then return end
		task.wait()
		highlight.Adornee = character
	end)
end

local function makeDraggable(object)
	local dragging = false
	local relative = nil
	local activeInput = nil
	local pointerPosition = nil

	local offset = Vector2.zero
	local screenGui = object:FindFirstAncestorWhichIsA("ScreenGui")
	if screenGui and screenGui.IgnoreGuiInset then
		offset += guiService:GetGuiInset()
	end

	local function getPointerPosition(input)
		if input and input.UserInputType == Enum.UserInputType.Touch then
			return Vector2.new(input.Position.X, input.Position.Y)
		end

		return userInputService:GetMouseLocation()
	end

	object.InputBegan:Connect(function(input, processed)
		if processed then return end

		local inputType = input.UserInputType.Name
		if inputType == "MouseButton1" or inputType == "Touch" then
			activeInput = input
			pointerPosition = getPointerPosition(input)
			relative = object.AbsolutePosition + object.AbsoluteSize * object.AnchorPoint - pointerPosition
			dragging = true
		end
	end)

	local inputChanged = userInputService.InputChanged:Connect(function(input)
		if not dragging then return end
		if activeInput and activeInput.UserInputType == Enum.UserInputType.Touch and input ~= activeInput then return end
		if input.UserInputType ~= Enum.UserInputType.MouseMovement and input.UserInputType ~= Enum.UserInputType.Touch then return end

		pointerPosition = getPointerPosition(input)
	end)

	local inputEnded = userInputService.InputEnded:Connect(function(input)
		if not dragging then return end

		local inputType = input.UserInputType.Name
		if inputType == "MouseButton1" or inputType == "Touch" then
			dragging = false
			activeInput = nil
			pointerPosition = nil
		end
	end)

	local renderStepped = runService.RenderStepped:Connect(function()
		if dragging then
			local position = (pointerPosition or getPointerPosition(activeInput)) + relative + offset
			object.Position = UDim2.fromOffset(position.X, position.Y)
		end
	end)

	object.Destroying:Connect(function()
		inputChanged:Disconnect()
		inputEnded:Disconnect()
		renderStepped:Disconnect()
	end)
end

local function checkAction(target)
	local toReturn = {}

	for _, action in ipairs(siriusValues.actions) do
		if action.name == target then
			toReturn.action = action
			break
		end
	end

	for _, action in ipairs(characterPanel.Interactions.Grid:GetChildren()) do
		if action.name == target then
			toReturn.object = action
			break
		end
	end

	return toReturn
end

