local function checkSetting(settingTarget, categoryTarget)
	for _, category in ipairs(siriusSettings) do
		if categoryTarget then
			if category.name == categoryTarget then
				for _, setting in ipairs(category.categorySettings) do
					if setting.name == settingTarget then
						return setting
					end
				end
				return
			end
		else
			for _, setting in ipairs(category.categorySettings) do
				if setting.name == settingTarget then
					return setting
				end
			end
		end
	end

	return siriusValues.removedSettingDefaults and siriusValues.removedSettingDefaults[settingTarget]
end

function getSettingKeyCode(settingName, fallbackKeyCode)
	local setting = checkSetting(settingName, keybindCategoryName) or checkSetting(settingName, "Keybinds") or checkSetting(settingName)
	local keyCode = nil

	if setting and type(setting.current) == "string" and setting.current ~= "" then
		local keyName = string.match(setting.current, "([^+]+)$") or setting.current
		keyCode = Enum.KeyCode[keyName]
	end

	if keyCode and keyCode ~= Enum.KeyCode.Unknown then
		return keyCode
	end

	return fallbackKeyCode
end

function getFlyVerticalControlKeys()
	return getSettingKeyCode("Fly Up Key", Enum.KeyCode.Space), getSettingKeyCode("Fly Down Key", Enum.KeyCode.LeftShift)
end

local function wipeTransparency(ins, target, checkSelf, tween, duration)
	local transparencyProperties = siriusValues.transparencyProperties

	local function applyTransparency(obj)
		local properties = transparencyProperties[obj.className]

		if properties then
			local tweenProperties = {}

			for _, property in ipairs(properties) do
				tweenProperties[property] = target
			end

			for property, transparency in pairs(tweenProperties) do
				if tween then
					tweenService:Create(obj, TweenInfo.new(duration, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {[property] = transparency}):Play()
				else
					obj[property] = transparency
				end

			end
		end
	end

	if checkSelf then
		applyTransparency(ins)
	end

	for _, descendant in ipairs(ins:getDescendants()) do
		applyTransparency(descendant)
	end
end

local scrollbarFadeRegistry = {}

local function attachScrollbarFade(scrollingFrame, visibleTransparency, idleDelay)
	if not scrollingFrame or not scrollingFrame:IsA("ScrollingFrame") or scrollbarFadeRegistry[scrollingFrame] then return end

	scrollbarFadeRegistry[scrollingFrame] = true
	visibleTransparency = visibleTransparency or 0.55
	idleDelay = idleDelay or 0.65

	local fadeId = 0
	scrollingFrame.ScrollBarImageTransparency = 1

	local function hasScrollableContent()
		local canvasHeight = scrollingFrame.AbsoluteCanvasSize.Y
		local visibleHeight = scrollingFrame.AbsoluteWindowSize.Y

		return canvasHeight > visibleHeight + 6
	end

	local function fadeOutScrollbar()
		tweenService:Create(scrollingFrame, TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {ScrollBarImageTransparency = 1}):Play()
	end

	scrollingFrame:GetPropertyChangedSignal("CanvasPosition"):Connect(function()
		fadeId += 1
		local currentFade = fadeId

		if not hasScrollableContent() then
			fadeOutScrollbar()
			return
		end

		tweenService:Create(scrollingFrame, TweenInfo.new(0.12, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {ScrollBarImageTransparency = visibleTransparency}):Play()

		task.delay(idleDelay, function()
			if fadeId == currentFade then
				fadeOutScrollbar()
			end
		end)
	end)

	scrollingFrame:GetPropertyChangedSignal("CanvasSize"):Connect(function()
		if not hasScrollableContent() then
			fadeOutScrollbar()
		end
	end)
end

local settingsCategoryScrollBound = false
local settingsCategoryScrollRefreshId = 0

local function applySettingsCategoryScrollPolish(scroller)
	if not scroller then return end

	scroller.BorderSizePixel = 0
	scroller.ClipsDescendants = true
	scroller.Active = true
	scroller.ScrollingDirection = Enum.ScrollingDirection.Y
	scroller.ScrollingEnabled = true
	scroller.AutomaticCanvasSize = Enum.AutomaticSize.None
	scroller.ElasticBehavior = Enum.ElasticBehavior.WhenScrollable
	scroller.ScrollBarThickness = 0
	scroller.ScrollBarImageColor3 = Color3.fromRGB(225, 225, 225)
	scroller.ScrollBarImageTransparency = 1

	local padding = scroller:FindFirstChild("SettingsCategoryScrollPadding") or scroller:FindFirstChildOfClass("UIPadding")
	if not padding then
		padding = Instance.new("UIPadding")
		padding.Parent = scroller
	end

	padding.Name = "SettingsCategoryScrollPadding"
	padding.PaddingTop = UDim.new(0, 10)
	padding.PaddingBottom = UDim.new(0, 68)
end

local function ensureSettingsCategoryScroller()
	local current = settingsPanel:FindFirstChild("SettingTypes")
	if not current then return end

	if current:IsA("ScrollingFrame") then
		applySettingsCategoryScrollPolish(current)
		return current
	end

	local source = current
	local sourceVisible = source.Visible
	source.Name = "SettingTypesSource"
	source.Visible = false

	local scroller = Instance.new("ScrollingFrame")
	scroller.Name = "SettingTypes"
	scroller.Parent = settingsPanel
	scroller.AnchorPoint = source.AnchorPoint
	scroller.Position = source.Position
	scroller.Size = source.Size
	scroller.Visible = sourceVisible
	scroller.BackgroundTransparency = source.BackgroundTransparency
	scroller.BackgroundColor3 = source.BackgroundColor3
	scroller.ZIndex = source.ZIndex
	scroller.CanvasSize = UDim2.new(0, 0, 0, 0)

	for _, child in ipairs(source:GetChildren()) do
		child.Parent = scroller
	end

	applySettingsCategoryScrollPolish(scroller)
	return scroller
end

local function refreshSettingsCategoryScroll()
	local settingTypes = ensureSettingsCategoryScroller()
	if not settingTypes then return end

	settingsCategoryScrollRefreshId += 1
	local refreshId = settingsCategoryScrollRefreshId

	task.defer(function()
		if refreshId ~= settingsCategoryScrollRefreshId then return end
		if not settingTypes.Parent then return end

		local layout = settingTypes:FindFirstChildOfClass("UIGridLayout") or settingTypes:FindFirstChildOfClass("UIListLayout")
		if not layout then return end

		local padding = settingTypes:FindFirstChild("SettingsCategoryScrollPadding") or settingTypes:FindFirstChildOfClass("UIPadding")
		local paddingTop = padding and padding.PaddingTop.Offset or 0
		local paddingBottom = padding and padding.PaddingBottom.Offset or 0
		local contentHeight = math.ceil(layout.AbsoluteContentSize.Y + paddingTop + paddingBottom + 28)
		local windowHeight = math.max(settingTypes.AbsoluteWindowSize.Y, 1)
		settingTypes.CanvasSize = UDim2.new(0, 0, 0, math.max(contentHeight, windowHeight + 1))
		settingTypes.ScrollBarImageTransparency = 1
	end)
end

local function bindSettingsCategoryScroll()
	local settingTypes = ensureSettingsCategoryScroller()
	if not settingTypes or settingsCategoryScrollBound then return end

	settingsCategoryScrollBound = true
	local layout = settingTypes:FindFirstChildOfClass("UIGridLayout") or settingTypes:FindFirstChildOfClass("UIListLayout")

	if layout then
		layout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(refreshSettingsCategoryScroll)
	end

	settingTypes.ChildAdded:Connect(function()
		task.defer(refreshSettingsCategoryScroll)
	end)
	settingTypes.ChildRemoved:Connect(function()
		task.defer(refreshSettingsCategoryScroll)
	end)
	settingTypes:GetPropertyChangedSignal("AbsoluteWindowSize"):Connect(refreshSettingsCategoryScroll)
end

local function blurSignature(value)
	if not value then
		if lighting:FindFirstChild("SiriusBlur") then
			lighting:FindFirstChild("SiriusBlur"):Destroy()
		end
	else
		if not lighting:FindFirstChild("SiriusBlur") then
			local blurLight = Instance.new("DepthOfFieldEffect", lighting)
			blurLight.Name = "SiriusBlur"
			blurLight.Enabled = true
			blurLight.FarIntensity = 0
			blurLight.FocusDistance = 51.6
			blurLight.InFocusRadius = 50
			blurLight.NearIntensity = 0.8
		end
	end
end

local function figureNotifications()
	if checkSirius() then
		local notificationsSize = 0

		if #notifications > 0 then
			blurSignature(true)
		else
			blurSignature(false)
		end

		for i = #notifications, 1, -1 do
			local notification = notifications[i]
			if notification then
				if notificationsSize == 0 then
					notificationsSize = notification.Size.Y.Offset + 2
				else
					notificationsSize += notification.Size.Y.Offset + 5
				end
				local desiredPosition = UDim2.new(0.5, 0, 0, notificationsSize)
				if notification.Position ~= desiredPosition then
					notification:TweenPosition(desiredPosition, "Out", "Quint", 0.8, true)
				end
			end
		end	
	end
end

local contentProvider = game:GetService("ContentProvider")

local function queueNotification(Title, Description, Image)
	task.spawn(function()		
		if checkSirius() then
			local newNotification = notificationContainer.Template:Clone()
			newNotification.Parent = notificationContainer
			newNotification.Name = Title or "Unknown Title"
			newNotification.Visible = true

			newNotification.Title.Text = Title or "Unknown Title"
			newNotification.Description.Text = Description or "Unknown Description"
			newNotification.Time.Text = "now"

			-- Prepare for animation
			newNotification.AnchorPoint = Vector2.new(0.5, 1)
			newNotification.Position = UDim2.new(0.5, 0, -1, 0)
			newNotification.Size = UDim2.new(0, 320, 0, 500)
			newNotification.Description.Size = UDim2.new(0, 241, 0, 400)
			wipeTransparency(newNotification, 1, true)

			newNotification.Description.Size = UDim2.new(0, 241, 0, newNotification.Description.TextBounds.Y)
			newNotification.Size = UDim2.new(0, 100, 0, newNotification.Description.TextBounds.Y + 50)

			table.insert(notifications, newNotification)
			figureNotifications()

			local notificationSound = Instance.new("Sound")
			notificationSound.Parent = UI
			notificationSound.SoundId = "rbxassetid://255881176"
			notificationSound.Name = "notificationSound"
			notificationSound.Volume = 0.65
			notificationSound.PlayOnRemove = true
			notificationSound:Destroy()


			if not tonumber(Image) then
				newNotification.Icon.Image = 'rbxassetid://14317577326'
			else
				newNotification.Icon.Image = 'rbxassetid://'..Image or 0
			end

			newNotification:TweenPosition(UDim2.new(0.5, 0, 0, newNotification.Size.Y.Offset + 2), "Out", "Quint", 0.9, true)
			task.wait(0.1)
			tweenService:Create(newNotification, TweenInfo.new(0.8, Enum.EasingStyle.Exponential), {Size = UDim2.new(0, 320, 0, newNotification.Description.TextBounds.Y + 50)}):Play()
			task.wait(0.05)
			tweenService:Create(newNotification, TweenInfo.new(0.8, Enum.EasingStyle.Exponential), {BackgroundTransparency = 0.35}):Play()
			tweenService:Create(newNotification.UIStroke, TweenInfo.new(0.6, Enum.EasingStyle.Exponential), {Transparency = 0.7}):Play()
			task.wait(0.05)
			tweenService:Create(newNotification.Icon, TweenInfo.new(0.5, Enum.EasingStyle.Exponential), {ImageTransparency = 0}):Play()
			task.wait(0.04)
			tweenService:Create(newNotification.Title, TweenInfo.new(0.5, Enum.EasingStyle.Exponential), {TextTransparency = 0}):Play()
			task.wait(0.04)
			tweenService:Create(newNotification.Description, TweenInfo.new(0.5, Enum.EasingStyle.Exponential), {TextTransparency = 0.15}):Play()
			tweenService:Create(newNotification.Time, TweenInfo.new(0.5, Enum.EasingStyle.Exponential), {TextTransparency = 0.5}):Play()

			--neonModule:BindFrame(newNotification.BlurModule, {
			--	Transparency = 0.98,
			--	BrickColor = BrickColor.new("Institutional white")
			--})

			newNotification.Interact.MouseButton1Click:Connect(function()
				local foundNotification = table.find(notifications, newNotification)
				if foundNotification then table.remove(notifications, foundNotification) end

				tweenService:Create(newNotification, TweenInfo.new(0.35, Enum.EasingStyle.Quint, Enum.EasingDirection.In), {Position = UDim2.new(1.5, 0, 0, newNotification.Position.Y.Offset)}):Play()

				task.wait(0.4)
				newNotification:Destroy()
				figureNotifications()
				return
			end)

			local waitTime = (#newNotification.Description.Text*0.1)+2
			if waitTime <= 1 then waitTime = 2.5 elseif waitTime > 10 then waitTime = 10 end

			task.wait(waitTime)

			local foundNotification = table.find(notifications, newNotification)
			if foundNotification then table.remove(notifications, foundNotification) end

			tweenService:Create(newNotification, TweenInfo.new(0.8, Enum.EasingStyle.Quint, Enum.EasingDirection.In), {Position = UDim2.new(1.5, 0, 0, newNotification.Position.Y.Offset)}):Play()

			task.wait(1.2)
			--neonModule:UnbindFrame(newNotification.BlurModule)
			newNotification:Destroy()
			figureNotifications()
		end
	end)
end

