function siriusValues.showBetaControlOverlay(title, message, persistent)
	local parts = siriusValues.ensureBetaControlOverlay()
	siriusValues.betaControlOverlayToken = (siriusValues.betaControlOverlayToken or 0) + 1
	local token = siriusValues.betaControlOverlayToken

	UI.Enabled = true
	parts.Title.Text = tostring(title or "SIRIUS X Disabled")
	parts.Message.Text = tostring(message or "This beta build is temporarily disabled.")
	parts.Footer.Text = persistent and "Waiting for the owner to re-enable this session." or "This control was sent from the SIRIUS X website."
	if parts.ButtonRow then parts.ButtonRow.Visible = false end
	if parts.Always then parts.Always.Visible = false end
	if parts.Footer then parts.Footer.Visible = true end
	if parts.FooterLine then parts.FooterLine.Visible = true end
	parts.Root.Visible = true
	parts.Root.BackgroundTransparency = 1
	if parts.Vignette then parts.Vignette.ImageTransparency = 1 end
	parts.Shadow.ImageTransparency = 1
	parts.Card.GroupTransparency = 1
	parts.Scale.Scale = 0.94

	local fadeIn = TweenInfo.new(0.44, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	local scaleIn = TweenInfo.new(0.5, Enum.EasingStyle.Back, Enum.EasingDirection.Out)
	tweenService:Create(parts.Root, fadeIn, {BackgroundTransparency = 0.4}):Play()
	if parts.Vignette then tweenService:Create(parts.Vignette, fadeIn, {ImageTransparency = 0.45}):Play() end
	tweenService:Create(parts.Shadow, fadeIn, {ImageTransparency = 0.45}):Play()
	tweenService:Create(parts.Card, fadeIn, {GroupTransparency = 0}):Play()
	tweenService:Create(parts.Scale, scaleIn, {Scale = 1}):Play()

	if not persistent then
		task.delay(4.2, function()
			if siriusValues.betaControlOverlayToken ~= token then return end
			local currentParts = siriusValues.betaControlOverlayParts
			if not currentParts then return end

			local fadeOut = TweenInfo.new(0.32, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut)
			tweenService:Create(currentParts.Root, fadeOut, {BackgroundTransparency = 1}):Play()
			if currentParts.Vignette then tweenService:Create(currentParts.Vignette, fadeOut, {ImageTransparency = 1}):Play() end
			tweenService:Create(currentParts.Shadow, fadeOut, {ImageTransparency = 1}):Play()
			tweenService:Create(currentParts.Card, fadeOut, {GroupTransparency = 1}):Play()
			tweenService:Create(currentParts.Scale, fadeOut, {Scale = 0.94}):Play()

			task.delay(0.34, function()
				if siriusValues.betaControlOverlayToken == token and currentParts.Root then
					currentParts.Root.Visible = false
				end
			end)
		end)
	end
end

function siriusValues.showBetaControlChoiceOverlay(title, message, acceptText, declineText, onAccept, onDecline, alwaysText, onAlways)
	local parts = siriusValues.ensureBetaControlOverlay()
	siriusValues.betaControlOverlayToken = (siriusValues.betaControlOverlayToken or 0) + 1

	if siriusValues.betaControlAcceptConn then
		pcall(function() siriusValues.betaControlAcceptConn:Disconnect() end)
		siriusValues.betaControlAcceptConn = nil
	end
	if siriusValues.betaControlDeclineConn then
		pcall(function() siriusValues.betaControlDeclineConn:Disconnect() end)
		siriusValues.betaControlDeclineConn = nil
	end
	if siriusValues.betaControlAlwaysConn then
		pcall(function() siriusValues.betaControlAlwaysConn:Disconnect() end)
		siriusValues.betaControlAlwaysConn = nil
	end

	UI.Enabled = true
	parts.Title.Text = tostring(title or "SIRIUS X Request")
	parts.Message.Text = tostring(message or "The owner sent a request.")
	parts.Accept.Text = tostring(acceptText or "Accept")
	parts.Decline.Text = tostring(declineText or "Decline")
	if parts.Always then
		parts.Always.Text = tostring(alwaysText or "Always allow")
		parts.Always.Visible = type(onAlways) == "function"
	end
	if parts.Footer then parts.Footer.Visible = false end
	if parts.FooterLine then parts.FooterLine.Visible = false end
	if parts.ButtonRow then parts.ButtonRow.Visible = true end
	parts.Root.Visible = true
	parts.Root.BackgroundTransparency = 1
	if parts.Vignette then parts.Vignette.ImageTransparency = 1 end
	parts.Shadow.ImageTransparency = 1
	parts.Card.GroupTransparency = 1
	parts.Scale.Scale = 0.94

	siriusValues.betaControlAcceptConn = parts.Accept.MouseButton1Click:Connect(function()
		siriusValues.hideBetaControlOverlay()
		if type(onAccept) == "function" then
			task.spawn(onAccept)
		end
	end)
	siriusValues.betaControlDeclineConn = parts.Decline.MouseButton1Click:Connect(function()
		siriusValues.hideBetaControlOverlay()
		if type(onDecline) == "function" then
			task.spawn(onDecline)
		end
	end)
	if parts.Always and type(onAlways) == "function" then
		siriusValues.betaControlAlwaysConn = parts.Always.MouseButton1Click:Connect(function()
			siriusValues.hideBetaControlOverlay()
			task.spawn(onAlways)
		end)
	end

	local fadeIn = TweenInfo.new(0.44, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	local scaleIn = TweenInfo.new(0.5, Enum.EasingStyle.Back, Enum.EasingDirection.Out)
	tweenService:Create(parts.Root, fadeIn, {BackgroundTransparency = 0.4}):Play()
	if parts.Vignette then tweenService:Create(parts.Vignette, fadeIn, {ImageTransparency = 0.45}):Play() end
	tweenService:Create(parts.Shadow, fadeIn, {ImageTransparency = 0.45}):Play()
	tweenService:Create(parts.Card, fadeIn, {GroupTransparency = 0}):Play()
	tweenService:Create(parts.Scale, scaleIn, {Scale = 1}):Play()
end

	function siriusValues.hideBetaControlOverlay()
		if not siriusValues.betaControlOverlayParts or not siriusValues.betaControlOverlayParts.Root then return end
		siriusValues.betaControlOverlayToken = (siriusValues.betaControlOverlayToken or 0) + 1
	local token = siriusValues.betaControlOverlayToken
	local parts = siriusValues.betaControlOverlayParts
	if parts.ButtonRow then parts.ButtonRow.Visible = false end
	if parts.Always then parts.Always.Visible = false end
	if parts.Footer then parts.Footer.Visible = true end
	if parts.FooterLine then parts.FooterLine.Visible = true end

	local fadeOut = TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut)
	tweenService:Create(parts.Root, fadeOut, {BackgroundTransparency = 1}):Play()
	if parts.Vignette then tweenService:Create(parts.Vignette, fadeOut, {ImageTransparency = 1}):Play() end
	tweenService:Create(parts.Shadow, fadeOut, {ImageTransparency = 1}):Play()
	tweenService:Create(parts.Card, fadeOut, {GroupTransparency = 1}):Play()
	tweenService:Create(parts.Scale, fadeOut, {Scale = 0.94}):Play()

	task.delay(0.36, function()
		if siriusValues.betaControlOverlayToken == token and parts.Root then
			parts.Root.Visible = false
			end
		end)
	end

	function siriusValues.ensureSealJumpscareOverlay()
