		tweenService:Create(parts.Scale, TweenInfo.new(0.18, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {Scale = 1.02}):Play()

		task.delay(math.clamp(tonumber(duration) or 2.4, 1.2, 6), function()
