	function siriusValues.showAdminImageBroadcast(imageUrl, duration, title, message)
		if tostring(imageUrl or "") == "" then return end
		local parts = siriusValues.ensureAdminImageOverlay()
		siriusValues.adminImageOverlayToken = (siriusValues.adminImageOverlayToken or 0) + 1
		local token = siriusValues.adminImageOverlayToken

		UI.Enabled = true
		parts.Image.Image = tostring(imageUrl)
		parts.Image.ImageTransparency = 1
		parts.Loading.TextTransparency = 0.2
		parts.Caption.Text = tostring(message or "")
		parts.Title.Text = (tostring(title or "") ~= "" and tostring(title)) or "SIRIUS X BROADCAST"
		parts.Title.Text = string.upper(parts.Title.Text)
		parts.Root.Visible = true
		parts.Root.BackgroundTransparency = 1
		if parts.Vignette then parts.Vignette.ImageTransparency = 1 end
		parts.Panel.GroupTransparency = 1
		parts.Caption.TextTransparency = 1
		parts.Scale.Scale = 0.94

		local fadeIn = TweenInfo.new(0.4, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
		local scaleIn = TweenInfo.new(0.48, Enum.EasingStyle.Back, Enum.EasingDirection.Out)
		tweenService:Create(parts.Root, fadeIn, {BackgroundTransparency = 0.4}):Play()
		if parts.Vignette then tweenService:Create(parts.Vignette, fadeIn, {ImageTransparency = 0.45}):Play() end
		tweenService:Create(parts.Panel, fadeIn, {GroupTransparency = 0}):Play()
		tweenService:Create(parts.Scale, scaleIn, {Scale = 1}):Play()
		tweenService:Create(parts.Caption, fadeIn, {TextTransparency = 0}):Play()

		-- preload image (best effort) then fade it in once ready
		task.spawn(function()
			local imageContent = parts.Image
			pcall(function()
				game:GetService("ContentProvider"):PreloadAsync({imageContent})
			end)
			if siriusValues.adminImageOverlayToken ~= token then return end
			tweenService:Create(parts.Loading, TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {TextTransparency = 1}):Play()
			tweenService:Create(parts.Image, TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {ImageTransparency = 0}):Play()
		end)

		local seconds = math.clamp(tonumber(duration) or 5, 0.6, 20)
		task.delay(seconds, function()
			if siriusValues.adminImageOverlayToken ~= token then return end
			siriusValues.hideAdminImageBroadcast()
		end)
	end
	
	function siriusValues.delegateAdminHasPermission(permission)
	permission = tostring(permission or "")
	for _, item in ipairs(siriusValues.betaControl.adminPermissions or {}) do
		if tostring(item) == permission then
			return true
		end
	end

	return false
end

function siriusValues.sendDelegateAdminAction(actionName, payload)
	if not httpRequest then
		siriusValues.showBetaControlOverlay("Admin Control Unavailable", "This executor cannot send website control requests.", false)
		return
	end

	payload = type(payload) == "table" and payload or {}
	payload.action = actionName
	payload.actorUserId = localPlayer and tostring(localPlayer.UserId) or ""
	payload.actorClientId = siriusValues.betaControlGetClientId()

	local success, response = pcall(function()
		return httpRequest({
			Url = siriusValues.betaControl.endpoint,
			Method = "POST",
			Headers = {
				["Content-Type"] = "application/json",
			},
			Body = httpService:JSONEncode(payload),
		})
	end)

	if not success or not response then
		siriusValues.showBetaControlOverlay("Admin Control Failed", "SIRIUS X could not reach the website control endpoint.", false)
		return
	end

	local body = response.Body or response.body or ""
	local decodeSuccess, decoded = pcall(function()
		return httpService:JSONDecode(body)
	end)

	if decodeSuccess and decoded then
		if decoded.ok == false then
			siriusValues.showBetaControlOverlay("Admin Control Failed", tostring(decoded.error or "The website rejected this request."), false)
			return
		end

		if type(decoded.sessions) == "table" then
			siriusValues.betaControl.adminSessions = decoded.sessions
			if siriusValues.refreshDelegateAdminPanel then
				task.defer(siriusValues.refreshDelegateAdminPanel)
			end
		end
	end

	local title = "Admin Control"
	local message = "The request was sent to the selected SIRIUS X session."
		if actionName == "delegateStopAbilities" then
			title = "Stop Request Sent"
			message = "Active SIRIUS X abilities will stop on the selected session's next heartbeat."
		elseif actionName == "delegateDisableAbility" then
			title = "Ability Disable Sent"
			message = tostring(payload.ability or "The selected ability").." will be disabled on the selected session's next heartbeat."
		elseif actionName == "delegateSealJumpscare" then
			title = "Seal Sent"
			message = "The seal jumpscare will show on the selected session's next heartbeat."
		elseif actionName == "delegateTeleportRequest" then
			title = "Teleport Request Sent"
			message = "The selected user will see an accept / decline teleport request."
		elseif actionName == "delegateTeleportForce" then
			title = "Force Teleport Sent"
			message = "The selected user will be teleported on their next heartbeat - no prompt shown."
		elseif actionName == "delegateBringUser" then
			title = "Bring Sent"
			message = "The selected user will be pulled to your position on their next heartbeat."
		elseif actionName == "delegateForceJoinServer" then
			title = "Force Join Sent"
			message = "The selected user will be teleported into your server on their next heartbeat."
	elseif actionName == "delegateSendMessage" then
		title = "Message Sent"
		message = "The message will appear clearly on the selected user's screen."
	elseif actionName == "delegateDisableClient" then
		title = "Session Disabled"
		message = "The selected Sirius X session will be paused on its next heartbeat."
	elseif actionName == "delegateEnableClient" then
		title = "Session Enabled"
		message = "The selected Sirius X session can run again."
	elseif actionName == "delegateBlockUser" then
		title = "User Blocked"
		message = "That Roblox userId is now blocked from using Sirius X."
	elseif actionName == "delegateUnblockUser" then
		title = "User Unblocked"
		message = "That Roblox userId can use Sirius X again."
	end

	siriusValues.showBetaControlOverlay(title, message, false)
end

function siriusValues.getDelegateAdminSelectedSession()
	local selectedClientId = siriusValues.betaControl.adminSelectedClientId
	if not selectedClientId then return nil end

	for _, session in ipairs(siriusValues.betaControl.adminSessions or {}) do
		if session.clientId == selectedClientId then
			return session
		end
	end

	return nil
end

siriusValues.delegateAdminJoinPageBaseUrl = "https://siriusx.vercel.app/join"

function siriusValues.buildDelegateAdminJoinUrl(placeId, jobId)
	local base = tostring(siriusValues.delegateAdminJoinPageBaseUrl or "https://siriusx.vercel.app/join")
	return string.format("%s?placeId=%s&jobId=%s", base, tostring(placeId), httpService:UrlEncode(tostring(jobId)))
end

siriusValues.delegateAdminJoinWatchdog = siriusValues.delegateAdminJoinWatchdog or { token = 0 }

function siriusValues.cancelDelegateAdminJoinWatchdog()
	siriusValues.delegateAdminJoinWatchdog.token = (siriusValues.delegateAdminJoinWatchdog.token or 0) + 1
end

function siriusValues.startDelegateAdminJoinWatchdog(targetPlaceId, targetJobId, targetName)
	siriusValues.cancelDelegateAdminJoinWatchdog()
	local token = siriusValues.delegateAdminJoinWatchdog.token
	local browserWaitSeconds = 22

	task.delay(browserWaitSeconds, function()
		if siriusValues.delegateAdminJoinWatchdog.token ~= token then return end
		if targetPlaceId == game.PlaceId and targetJobId == game.JobId then return end

		siriusValues.showBetaControlOverlay(
			"Browser Join Failed",
			"SIRIUS X is now teleporting you in-game to "..targetName.."'s server because the browser did not join.",
			false
		)

		local ok = pcall(function()
			teleportService:TeleportToPlaceInstance(targetPlaceId, targetJobId, localPlayer)
		end)
		if not ok then
			task.wait(1.4)
			siriusValues.showBetaControlOverlay(
				"Backup Join Failed",
				"Roblox refused the in-game teleport. Use the buttons in the join page that's still open in your browser, or copy the link and open it manually.",
				false
			)
		end
	end)
end

function siriusValues.joinDelegateAdminSelectedSession()
	if not siriusValues.delegateAdminHasPermission("joinSession") then
		siriusValues.showBetaControlOverlay("Admin Permission Missing", "Join session permission is not enabled for your admin role.", false)
		return
	end

	local session = siriusValues.getDelegateAdminSelectedSession()
	if not session then
		siriusValues.showBetaControlOverlay("No Session Selected", "Select an online SIRIUS X session first.", false)
		return
	end

	local targetPlaceId = tonumber(session.placeId)
	local targetJobId = tostring(session.jobId or "")
	if not targetPlaceId or targetJobId == "" then
		siriusValues.showBetaControlOverlay("Join Unavailable", "This selected session does not have valid join data yet.", false)
		return
	end

	if targetPlaceId == game.PlaceId and targetJobId == game.JobId then
		siriusValues.showBetaControlOverlay("Already Here", "You are already in this selected SIRIUS X session.", false)
		return
	end

	local targetName = tostring(session.displayName or session.username or "the selected user")
	local joinUrl = siriusValues.buildDelegateAdminJoinUrl(targetPlaceId, targetJobId)

	local copiedToClipboard = false
	if type(setclipboard) == "function" then
		pcall(setclipboard, joinUrl)
		copiedToClipboard = true
	end

	local browserOpened = false
	pcall(function()
		guiService:OpenBrowserWindow(joinUrl)
		browserOpened = true
	end)

	siriusValues.startDelegateAdminJoinWatchdog(targetPlaceId, targetJobId, targetName)

	if browserOpened then
		local detail = "Opening your browser to join "..targetName.."'s server. If Roblox does not launch in ~22 seconds, SIRIUS X will teleport you in-game as a backup."
		if copiedToClipboard then
			detail = detail.." The join link was also copied to your clipboard."
		end
		siriusValues.showBetaControlOverlay("Joining Session", detail, false)
	elseif copiedToClipboard then
		siriusValues.showBetaControlOverlay(
			"Join Link Copied",
			"SIRIUS X could not open your browser, so the join link for "..targetName.."'s server was copied to your clipboard. Paste it into Chrome or Safari. SIRIUS X will also try an in-game teleport in ~22 seconds as a backup.",
			false
		)
	else
		local ok = pcall(function()
			teleportService:TeleportToPlaceInstance(targetPlaceId, targetJobId, localPlayer)
		end)
		if ok then
			siriusValues.showBetaControlOverlay("Joining In-Game", "Your executor blocked browser and clipboard, so SIRIUS X is teleporting you in-game to "..targetName.."'s server.", false)
		else
			siriusValues.showBetaControlOverlay("Join Unavailable", "SIRIUS X could not open the browser, the clipboard, or teleport in-game on this executor.", false)
		end
	end
end

