		local function makeActionButton(parent, name, text, fill)
			local button = Instance.new("TextButton")
			button.Name = name
			if parent.Name == "Actions" then
				button.Size = UDim2.new(1/5, -5, 1, 0)
			elseif parent.Name == "MovementActions" then
				button.Size = UDim2.new(1/6, -5, 1, 0)
			else
				button.Size = UDim2.new(0.2, -5, 1, 0)
			end
			button.BackgroundColor3 = fill or Color3.fromRGB(28, 28, 32)
			button.BackgroundTransparency = 0
			button.BorderSizePixel = 0
			button.AutoButtonColor = false
			button.Text = text
			button.TextColor3 = Color3.fromRGB(244, 244, 248)
			button.TextSize = 12
			button.FontFace = Font.new("rbxasset://fonts/families/GothamSSm.json", Enum.FontWeight.Bold)
			button.ZIndex = parent.ZIndex + 1
			button.Parent = parent

			local buttonCorner = Instance.new("UICorner")
			buttonCorner.CornerRadius = UDim.new(0, 11)
			buttonCorner.Parent = button

			local buttonStroke = Instance.new("UIStroke")
			buttonStroke.Color = Color3.fromRGB(86, 86, 92)
			buttonStroke.Transparency = 0.32
			buttonStroke.Thickness = 1
			buttonStroke.Parent = button

			local buttonScale = Instance.new("UIScale")
			buttonScale.Scale = 1
			buttonScale.Parent = button

			local hoverIn = TweenInfo.new(0.18, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
			local hoverOut = TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
			local pressIn = TweenInfo.new(0.08, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
			local pressOut = TweenInfo.new(0.16, Enum.EasingStyle.Back, Enum.EasingDirection.Out)

			button.MouseEnter:Connect(function()
				tweenService:Create(button, hoverIn, {BackgroundTransparency = 0.06}):Play()
				tweenService:Create(buttonStroke, hoverIn, {Transparency = 0.1}):Play()
				tweenService:Create(buttonScale, hoverIn, {Scale = 1.025}):Play()
			end)
			button.MouseLeave:Connect(function()
				tweenService:Create(button, hoverOut, {BackgroundTransparency = 0}):Play()
				tweenService:Create(buttonStroke, hoverOut, {Transparency = 0.32}):Play()
				tweenService:Create(buttonScale, hoverOut, {Scale = 1}):Play()
			end)
			button.MouseButton1Down:Connect(function()
				tweenService:Create(buttonScale, pressIn, {Scale = 0.94}):Play()
			end)
			button.MouseButton1Up:Connect(function()
				tweenService:Create(buttonScale, pressOut, {Scale = 1.025}):Play()
			end)

			return button
		end

