	local function readAdminOriginCoords()
		local character = localPlayer and localPlayer.Character
		local root = character and character:FindFirstChild("HumanoidRootPart")
		if not root then return nil, nil, nil end
		local p = root.Position
		return p.X, p.Y, p.Z
	end

	local function readSelectedSessionCoords()
		local session = siriusValues.getDelegateAdminSelectedSession()
		if not session then return nil end
		local x = tonumber(session.x)
		local y = tonumber(session.y)
		local z = tonumber(session.z)
		if x and y and z then return x, y, z end
		return nil
	end

	teleportForceButton.MouseButton1Click:Connect(function()
		if not siriusValues.delegateAdminHasPermission("teleportForce") then
			siriusValues.showBetaControlOverlay("Admin Permission Missing", "Force teleport permission is not enabled for your admin role.", false)
			return
		end
		local clientId = siriusValues.betaControl.adminSelectedClientId
		if not clientId then
			siriusValues.showBetaControlOverlay("No Session Selected", "Select an online SIRIUS X session first.", false)
			return
		end
		local x, y, z
		local override = {}
		for value in tostring(coordsBox.Text or ""):gmatch("[^,%s]+") do
			table.insert(override, tonumber(value))
		end
		if override[1] and override[2] and override[3] then
			x, y, z = override[1], override[2], override[3]
		else
			x, y, z = readAdminOriginCoords()
		end
		if not (x and y and z) then
			siriusValues.showBetaControlOverlay("No Coordinates", "Enter override coords or be alive with a HumanoidRootPart so SIRIUS X can pull your position.", false)
			return
		end
		siriusValues.sendDelegateAdminAction("delegateTeleportForce", {
			clientId = clientId,
			title = "Admin Teleport",
			message = "A SIRIUS X admin teleported your character.",
			x = x,
			y = y,
			z = z,
		})
	end)

