	return siriusValues.delegateAdminPanelParts
end

function siriusValues.refreshDelegateAdminPanel()
	local parts = siriusValues.delegateAdminPanelParts
	if not parts or not parts.Root or not parts.Root.Parent then
		return
	end

	parts.Role.Text = siriusValues.betaControl.adminRole ~= "" and siriusValues.betaControl.adminRole or "Support Admin"

	for _, child in ipairs(parts.List:GetChildren()) do
		if child:IsA("TextButton") then
			child:Destroy()
		end
	end

	local sessions = type(siriusValues.betaControl.adminSessions) == "table" and siriusValues.betaControl.adminSessions or {}
	local selectedClientId = siriusValues.betaControl.adminSelectedClientId
	local selectedSession = nil

	for _, session in ipairs(sessions) do
		if session.clientId == selectedClientId then
			selectedSession = session
			break
		end
	end

	if not selectedSession then
		for _, session in ipairs(sessions) do
			if session.clientId ~= siriusValues.betaControl.clientId then
				selectedSession = session
				selectedClientId = session.clientId
				break
			end
		end
	end

	siriusValues.betaControl.adminSelectedClientId = selectedClientId

	if selectedSession then
		parts.Selected.Text = "Selected: "..tostring(selectedSession.displayName or selectedSession.username or selectedSession.userId or selectedSession.clientId)
		if parts.Location then
			local sx, sy, sz = tonumber(selectedSession.x), tonumber(selectedSession.y), tonumber(selectedSession.z)
			if sx and sy and sz then
				parts.Location.Text = string.format("Position %d, %d, %d  |  HP %s", math.floor(sx), math.floor(sy), math.floor(sz),
					selectedSession.health and tostring(math.floor(tonumber(selectedSession.health) or 0)) or "?")
			else
				parts.Location.Text = "Position not reported yet (waiting on heartbeat)"
			end
		end
	else
		parts.Selected.Text = #sessions > 0 and "Select an online session." or "No live SIRIUS X sessions are visible yet."
		if parts.Location then parts.Location.Text = "" end
	end

	for index, session in ipairs(sessions) do
		local row = Instance.new("TextButton")
		row.Name = "Session_"..index
		row.Size = UDim2.new(1, 0, 0, 44)
		row.BackgroundColor3 = session.clientId == selectedClientId and Color3.fromRGB(34, 34, 34) or Color3.fromRGB(22, 22, 22)
		row.BackgroundTransparency = session.clientId == selectedClientId and 0.04 or 0.18
		row.BorderSizePixel = 0
		row.AutoButtonColor = false
		row.Text = ""
		row.LayoutOrder = index
		row.ZIndex = parts.List.ZIndex + 1
		row.Parent = parts.List

		local rowCorner = Instance.new("UICorner")
		rowCorner.CornerRadius = UDim.new(0, 12)
		rowCorner.Parent = row

		local rowStroke = Instance.new("UIStroke")
		rowStroke.Color = session.clientId == selectedClientId and Color3.fromRGB(104, 104, 104) or Color3.fromRGB(54, 54, 54)
		rowStroke.Transparency = session.clientId == selectedClientId and 0.28 or 0.64
		rowStroke.Thickness = 1
		rowStroke.Parent = row

		local name = Instance.new("TextLabel")
		name.BackgroundTransparency = 1
		name.Position = UDim2.new(0, 13, 0, 5)
		name.Size = UDim2.new(1, -92, 0, 20)
		name.FontFace = Font.new("rbxasset://fonts/families/GothamSSm.json", Enum.FontWeight.Bold)
		name.Text = tostring(session.displayName or session.username or "Unknown")
		name.TextColor3 = Color3.fromRGB(238, 238, 238)
		name.TextSize = 13
		name.TextXAlignment = Enum.TextXAlignment.Left
		name.TextTruncate = Enum.TextTruncate.AtEnd
		name.ZIndex = row.ZIndex + 1
		name.Parent = row

		local meta = Instance.new("TextLabel")
		meta.BackgroundTransparency = 1
		meta.Position = UDim2.new(0, 13, 0, 24)
