function siriusValues.openDelegateAdminPanel()
	if not siriusValues.betaControl.adminEnabled then
		siriusValues.showBetaControlOverlay("Admin Access Inactive", "This SIRIUS X account does not currently have delegated admin access.", false)
		return
	end

	local parts = siriusValues.ensureDelegateAdminPanel()
	siriusValues.refreshDelegateAdminPanel()
	parts.Root.Visible = true
	parts.Root.GroupTransparency = 1
	parts.Scale.Scale = 0.92
	parts.Root.Position = UDim2.new(0.5, 0, 1, -64)

	tweenService:Create(parts.Root, TweenInfo.new(0.32, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
		GroupTransparency = 0,
		Position = UDim2.new(0.5, 0, 1, -94),
	}):Play()
	tweenService:Create(parts.Scale, TweenInfo.new(0.4, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {Scale = 1}):Play()
end

function siriusValues.closeDelegateAdminPanel()
	local parts = siriusValues.delegateAdminPanelParts
	if not parts or not parts.Root then return end
	local token = (siriusValues.delegateAdminPanelToken or 0) + 1
	siriusValues.delegateAdminPanelToken = token

	tweenService:Create(parts.Root, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut), {
		GroupTransparency = 1,
		Position = UDim2.new(0.5, 0, 1, -64),
	}):Play()
	tweenService:Create(parts.Scale, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut), {Scale = 0.92}):Play()

	task.delay(0.24, function()
		if siriusValues.delegateAdminPanelToken == token and parts.Root then
			parts.Root.Visible = false
		end
	end)
end

function siriusValues.ensureDelegateAdminButton()
	local existing = smartBar.Buttons:FindFirstChild("AdminControl")
	if existing then
		return existing
	end

	local template = smartBar.Buttons:FindFirstChild("Music") or smartBar.Buttons:FindFirstChild("Settings") or smartBar.Buttons:FindFirstChildWhichIsA("ImageButton") or smartBar.Buttons:FindFirstChildWhichIsA("TextButton")
	if not template then
		return nil
	end

	local button = template:Clone()
	button.Name = "AdminControl"
	button.Visible = true
	button.Position = UDim2.new(math.min((template.Position.X.Scale or 0.5) + 0.095, 0.58), 0, smartBarOpen and 0.5 or 1.3, 0)
	button.Size = smartBarOpen and UDim2.new(0, 36, 0, 36) or UDim2.new(0, 30, 0, 30)
	button.BackgroundColor3 = Color3.fromRGB(35, 39, 42)
	button.BackgroundTransparency = smartBarOpen and 0 or 1
	button.Parent = smartBar.Buttons

	if button:FindFirstChild("UIGradient") then
		button.UIGradient.Color = ColorSequence.new({
			ColorSequenceKeypoint.new(0, Color3.fromRGB(48, 53, 58)),
			ColorSequenceKeypoint.new(1, Color3.fromRGB(24, 27, 30))
		})
	end
	if button:FindFirstChild("UIStroke") and button.UIStroke:FindFirstChild("UIGradient") then
		button.UIStroke.UIGradient.Color = ColorSequence.new({
			ColorSequenceKeypoint.new(0, Color3.fromRGB(132, 142, 150)),
			ColorSequenceKeypoint.new(1, Color3.fromRGB(64, 70, 76))
		})
	end
	if button:FindFirstChild("Icon") then
		button.Icon.Image = "rbxassetid://6031280882"
		button.Icon.ImageColor3 = Color3.fromRGB(255, 255, 255)
		button.Icon.ImageTransparency = smartBarOpen and 0 or 1
	end
	if button:FindFirstChild("UIStroke") then
		button.UIStroke.Transparency = smartBarOpen and 0 or 1
	end

	local clickTarget = button:FindFirstChild("Interact") or button
	if clickTarget and clickTarget:IsA("GuiButton") then
		clickTarget.MouseButton1Click:Connect(function()
			if not siriusValues.betaControl.adminEnabled then return end
			local parts = siriusValues.delegateAdminPanelParts
			if parts and parts.Root and parts.Root.Visible then
				siriusValues.closeDelegateAdminPanel()
			else
				siriusValues.openDelegateAdminPanel()
			end
		end)
	end

	button.MouseEnter:Connect(function()
		if button:FindFirstChild("UIStroke") then
			tweenService:Create(button.UIStroke, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {Transparency = 0.08}):Play()
		end
		if button:FindFirstChild("Icon") then
			tweenService:Create(button.Icon, TweenInfo.new(0.18, Enum.EasingStyle.Quint), {ImageTransparency = 0}):Play()
		end
	end)
	button.MouseLeave:Connect(function()
		if button:FindFirstChild("UIStroke") then
			tweenService:Create(button.UIStroke, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {Transparency = smartBarOpen and 0 or 1}):Play()
		end
		if button:FindFirstChild("Icon") then
			tweenService:Create(button.Icon, TweenInfo.new(0.18, Enum.EasingStyle.Quint), {ImageTransparency = smartBarOpen and 0 or 1}):Play()
		end
	end)

	return button
end

function siriusValues.syncDelegateAdminUi()
	if siriusValues.betaControl.adminEnabled then
		local button = siriusValues.ensureDelegateAdminButton()
		if button then
			button.Visible = true
		end
		if siriusValues.delegateAdminPanelParts then
			siriusValues.refreshDelegateAdminPanel()
		end
	else
		siriusValues.closeDelegateAdminPanel()
		local button = smartBar.Buttons:FindFirstChild("AdminControl")
		if button then
			button:Destroy()
		end
		siriusValues.betaControl.adminSelectedClientId = nil
	end

	if smartBarOpen then
		tweenService:Create(smartBar, TweenInfo.new(0.24, Enum.EasingStyle.Quint), {Size = siriusValues.getResponsiveSmartBarSize(true)}):Play()
	else
		smartBar.Size = siriusValues.getResponsiveSmartBarSize(false)
	end

	if siriusValues.syncSmartBarCommandSearchLayout then
		siriusValues.syncSmartBarCommandSearchLayout()
	end
end

do
local spamGuard = {
	keywords = {
		{"blox", "pink", "robux"},
		{"blox", "pink", "reward"},
		{"friend", "used", "robux"},
		{"your", "friend", "reward"},
		{"free", "robux", "claim"},
		{"free", "robux", "reward"},
	},
	scamDomains = {
		"blox.pink",
		"blox.land",
		"bloxflip",
		"rbxflip",
		"rbxgold",
		"rbxwild",
		"robuxfree",
		"free-robux",
		"freebobux",
		"discord.gg",
		"discord.com/invite"
	},
	setup = false,
	lastNotify = 0,
	lastMessages = {},
	lastReports = {},
	processedObjects = setmetatable({}, {__mode = "k"}),
}

function spamGuard:notify()
	local spamNotifs = checkSetting("Spam Notifications")
	if spamNotifs and not spamNotifs.current then
		return
	end

	local now = os.clock()
	local cooldownSetting = checkSetting("Chat Safety Alert Cooldown")
	local cooldown = math.clamp(tonumber(cooldownSetting and cooldownSetting.current) or 3, 1, 15)
	if now - self.lastNotify < cooldown then
		return
	end

	self.lastNotify = now
	task.defer(function()
		queueNotification("Chat Spam Blocked", "Filtered a suspected spam bot message.", 4384402990)
	end)
end

function spamGuard:isEnabled()
	local antiSpam = checkSetting("Anti-Spam Bot")
	return antiSpam and antiSpam.current
end

function spamGuard:normalize(message)
	local lower = string.lower(tostring(message or ""))
	lower = lower:gsub("0", "o"):gsub("1", "i"):gsub("3", "e"):gsub("4", "a"):gsub("5", "s"):gsub("7", "t")
	lower = lower:gsub("[%c]", " "):gsub("%s+", " ")
	return lower
end

function spamGuard:parseList(raw)
	local list = {}
	raw = tostring(raw or ""):gsub("[\r\n;|]+", ",")
	for token in string.gmatch(raw, "([^,]+)") do
		token = string.lower(string.gsub(token, "^%s*(.-)%s*$", "%1"))
		if token ~= "" then
			table.insert(list, token)
		end
	end
	return list
end

function spamGuard:matchesCustomKeyword(lower)
	local setting = checkSetting("Custom Blocked Chat Keywords")
	local keywords = self:parseList(setting and setting.current or "")
	if #keywords == 0 then return false end

	local wordMessage = " "..string.gsub(lower, "[%p%c%s]+", " ").." "
	for _, keyword in ipairs(keywords) do
		if #keyword <= 3 and string.match(keyword, "^%w+$") then
			if string.find(wordMessage, " "..keyword.." ", 1, true) then
				return true
			end
		elseif string.find(lower, keyword, 1, true) then
			return true
		end
	end

	return false
end

function spamGuard:hasSuspiciousLink(lower, compact)
	local linkSetting = checkSetting("Block Suspicious Links")
	if linkSetting and not linkSetting.current then return false end

	local hasUrl = string.find(lower, "https?://") or string.find(lower, "www%.") or string.find(lower, "%w+%.%w+")
	for _, domain in ipairs(self.scamDomains) do
		local domainCompact = string.gsub(domain, "[^%w]", "")
		if string.find(lower, domain, 1, true) or string.find(compact, domainCompact, 1, true) then
			return true
		end
	end

	if hasUrl and (string.find(compact, "robux", 1, true) or string.find(compact, "reward", 1, true) or string.find(compact, "giveaway", 1, true) or string.find(compact, "claim", 1, true)) then
		return true
	end

	if string.find(compact, "freerobux", 1, true) or string.find(compact, "claimrobux", 1, true) or string.find(compact, "getrobux", 1, true) then
		return true
	end

	return false
end

function spamGuard:isSpam(message)
	local lower = self:normalize(message)
	if lower == "" then
		return false
	end

	local compact = string.gsub(lower, "[^%w]", "")

	if self:matchesCustomKeyword(lower) then
		return true
	end

	if self:hasSuspiciousLink(lower, compact) then
		return true
	end

	local normalized = lower:gsub("[%p%c]", " "):gsub("%s+", " ")
	local tokens = {}
	for word in string.gmatch(normalized, "%S+") do
		tokens[word] = true
	end

	local function hasAll(words)
		for _, word in ipairs(words) do
			if not tokens[word] then
				return false
			end
		end
		return true
	end

	for _, words in ipairs(self.keywords) do
		if hasAll(words) then
			return true
		end
	end

	return false
end

function spamGuard:isRepeated(playerOrUserId, message)
	local setting = checkSetting("Repeated Message Filter")
	if setting and not setting.current then return false end

	local key = "unknown"
	if typeof(playerOrUserId) == "Instance" and playerOrUserId:IsA("Player") then
		key = tostring(playerOrUserId.UserId)
	elseif playerOrUserId ~= nil then
		key = tostring(playerOrUserId)
	end

	local normalized = self:normalize(message):gsub("[%p%c]", " "):gsub("%s+", " ")
	normalized = string.gsub(normalized, "^%s*(.-)%s*$", "%1")
	if string.len(normalized) < 5 then return false end

	local now = os.clock()
	local last = self.lastMessages[key]
	if last and last.Text == normalized and now - last.Time <= 8 then
		last.Count += 1
		last.Time = now
		return last.Count >= 3
	end

	self.lastMessages[key] = {Text = normalized, Time = now, Count = 1}
	return false
end

function spamGuard:evaluate(playerOrUserId, message)
	if not self:isEnabled() then return false end
	if self:isSpam(message) then return true, "spam" end
	if self:isRepeated(playerOrUserId, message) then return true, "repeat" end
	return false
end

function spamGuard:destroy(object)
	if not object or self.processedObjects[object] then
		return false
	end

	self.processedObjects[object] = true

	pcall(function()
		local parent = object.Parent
		if parent and parent:IsA("Frame") then
			self.processedObjects[parent] = true
			parent.Visible = false
		elseif object:IsA("GuiObject") then
			object.Visible = false
		end
	end)

	return true
end

function spamGuard:inspect(object)
	if not object or not self:isEnabled() then
		return false
	end

	if (object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox")) and self:isSpam(object.Text or "") then
		return self:destroy(object)
	end

	for _, descendant in ipairs(object:GetDescendants()) do
		if (descendant:IsA("TextLabel") or descendant:IsA("TextButton") or descendant:IsA("TextBox")) and self:isSpam(descendant.Text or "") then
			if self:destroy(descendant) then
				return true
			end
		end
	end

	return false
end

function spamGuard:scrub()
	if not self:isEnabled() then
		return
	end

	local chatGuis = {}
	local legacyChat = coreGui:FindFirstChild("Chat")
	local experienceChat = coreGui:FindFirstChild("ExperienceChat")
	if legacyChat then table.insert(chatGuis, legacyChat) end
	if experienceChat then table.insert(chatGuis, experienceChat) end

	for _, chatGui in ipairs(chatGuis) do
		for _, descendant in ipairs(chatGui:GetDescendants()) do
			if (descendant:IsA("TextLabel") or descendant:IsA("TextButton") or descendant:IsA("TextBox")) and self:isSpam(descendant.Text or "") then
				self:destroy(descendant)
			end
		end
	end
end

function spamGuard:report(userId)
	local reportSetting = checkSetting("Auto-Report Spam")
	if not reportSetting or not reportSetting.current or not userId then
		return
	end

	local target = players:GetPlayerByUserId(userId)
	if not target or target == localPlayer then
		return
	end

	local now = os.clock()
	if self.lastReports[target.UserId] and now - self.lastReports[target.UserId] < 45 then
		return
	end
	self.lastReports[target.UserId] = now

	pcall(function()
		players:ReportAbuse(target, "Scamming", "Auto-report: spam/scam message detected.")
	end)
end

function spamGuard:setupScrubber()
	if self.setup then
		return
	end

	self.setup = true

	local function hookChatGui(chatGui)
		if not chatGui then
			return
		end

		chatGui.DescendantAdded:Connect(function(descendant)
			if not self:isEnabled() then
				return
			end

			if descendant:IsA("TextLabel") or descendant:IsA("TextButton") or descendant:IsA("TextBox") then
				task.defer(function()
					if self:isSpam(descendant.Text or "") and self:destroy(descendant) then
						self:notify()
					end
				end)
			end
		end)
	end

	task.spawn(function()
		hookChatGui(coreGui:WaitForChild("Chat", 5))
	end)

	task.spawn(function()
		hookChatGui(coreGui:WaitForChild("ExperienceChat", 5))
	end)

	task.defer(function()
		self:scrub()
	end)
end

task.spawn(function()
	spamGuard:setupScrubber()
end)

if getMessage then
	getMessage.OnClientEvent:Connect(function(packet)
		if not spamGuard:isEnabled() then
			return
		end

		local text = (packet and packet.Message) or ""
		local userId = packet and (packet.SpeakerUserId or packet.FromSpeakerUserId or packet.UserId)
		if not userId and packet and packet.FromSpeaker then
			local speaker = players:FindFirstChild(packet.FromSpeaker)
			userId = speaker and speaker.UserId
		end

		local flagged, reason = spamGuard:evaluate(userId, text)
		if text == "" or not flagged then
			return
		end

		if reason ~= "repeat" then
			spamGuard:report(userId)
		end
		spamGuard:notify()
		task.spawn(function()
			spamGuard:scrub()
		end)
	end)
end

do
	local textChatService = game:FindFirstChildOfClass("TextChatService")
	if textChatService then
		textChatService.MessageReceived:Connect(function(message)
			if not spamGuard:isEnabled() or not message then
				return
			end

			local text = message.Text or ""
			local textSource = message.TextSource
			local flagged, reason = spamGuard:evaluate(textSource and textSource.UserId, text)
			if not flagged then
				return
			end

			if reason ~= "repeat" then
				spamGuard:report(textSource and textSource.UserId)
			end
			spamGuard:notify()
			task.spawn(function()
				spamGuard:scrub()
			end)
		end)
	end
end

siriusValues.spamGuard = spamGuard

end

