	function siriusValues.getPlayerActionPickerRootSize()
		local rootSize = camera and camera.ViewportSize or Vector2.new(1280, 720)
		pcall(function()
			if UI.AbsoluteSize.X > 0 and UI.AbsoluteSize.Y > 0 then
				rootSize = UI.AbsoluteSize
			end
		end)
		return rootSize
	end
	local function clampPlayerActionPickerSize(size)
		local rootSize = siriusValues.getPlayerActionPickerRootSize()
		local availableWidth = math.max(300, rootSize.X - 40)
		local availableHeight = math.max(320, rootSize.Y - 72)
		local minWidth = math.min(playerActionPickerMinSize.X, availableWidth)
		local minHeight = math.min(playerActionPickerMinSize.Y, availableHeight)
		local maxWidth = math.max(minWidth, math.min(playerActionPickerMaxSize.X, availableWidth))
		local maxHeight = math.max(minHeight, math.min(playerActionPickerMaxSize.Y, availableHeight))

		return Vector2.new(
			math.clamp(size.X, minWidth, maxWidth),
			math.clamp(size.Y, minHeight, maxHeight)
		)
	end
	local function offsetUDim2(position, xOffset, yOffset)
		return UDim2.new(
			position.X.Scale,
			position.X.Offset + (xOffset or 0),
			position.Y.Scale,
			position.Y.Offset + (yOffset or 0)
		)
	end
	local function getSpectateTogglePickerGeometry()
		return UDim2.new(0.5, 0, 0, 18 + spectateToggleSize.Y * 0.5), spectateToggleSize
	end
	local function getPlayerActionPickerGeometry()
		playerActionPickerCurrentSize = clampPlayerActionPickerSize(playerActionPickerCurrentSize)
		return UDim2.new(0.5, 0, 0.5, 0), playerActionPickerCurrentSize
	end
	local function getSelectActionIcon(iconName)
		if selectActionIconCache[iconName] then
			return selectActionIconCache[iconName]
		end

		local url = selectActionIconUrls[iconName] or ""
		local resolvedIcon = url
		pcall(function()
			if typeof(getcustomasset) ~= "function" or typeof(writefile) ~= "function" or typeof(game.HttpGet) ~= "function" then return end

			local folder = "SIRIUSXIcons"
			if typeof(makefolder) == "function" then
				if typeof(isfolder) == "function" then
					if not isfolder(folder) then
						makefolder(folder)
					end
				else
					pcall(makefolder, folder)
				end
			end

			local filePath = folder.."/"..(selectActionIconFiles[iconName] or (iconName..".png"))
			if typeof(isfile) ~= "function" or not isfile(filePath) then
				writefile(filePath, game:HttpGet(url))
			end

			resolvedIcon = getcustomasset(filePath)
		end)

		selectActionIconCache[iconName] = resolvedIcon
		return resolvedIcon
	end
