	local function applySpectateMorphGeometry(parts, position, size, shadowExtra, shadowYOffset)
		local extra = shadowExtra or 54
		local yOffset = shadowYOffset or 12
		parts.Shell.Position = position
		parts.Shell.Size = UDim2.fromOffset(size.X, size.Y)
		parts.Shadow.Position = offsetUDim2(position, 0, yOffset)
		parts.Shadow.Size = UDim2.fromOffset(size.X + extra, size.Y + extra)
	end

	local function playSpectateGhostMorph(fromPosition, fromSize, toPosition, toSize, duration, style, onComplete)
		cancelSpectateMorphTweens()
		spectateMorphState.token += 1
		local token = spectateMorphState.token
		spectateMorphState.active = true

		local parts = ensureSpectateMorphGhost()
		local toToggle = style == "to-toggle"
		parts.Root.Visible = true
		parts.Root.GroupTransparency = 0
		parts.Shell.BackgroundColor3 = siriusValues.selectActionStyle.panel
		parts.Shell.BackgroundTransparency = toToggle and 0 or 0.55
		parts.Stroke.Transparency = toToggle and 0.34 or 0.72
		parts.Shadow.ImageTransparency = toToggle and 0.82 or 0.95
		applySpectateMorphGeometry(parts, fromPosition, fromSize, toToggle and 58 or 34, toToggle and 12 or 6)

		local info = TweenInfo.new(duration, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut)
		playSpectateMorphTween(parts.Shell, info, {
			Position = toPosition,
			Size = UDim2.fromOffset(toSize.X, toSize.Y),
			BackgroundTransparency = toToggle and 0.55 or 0
		})
		playSpectateMorphTween(parts.Shadow, info, {
			Position = offsetUDim2(toPosition, 0, toToggle and 6 or 12),
			Size = UDim2.fromOffset(toSize.X + (toToggle and 34 or 58), toSize.Y + (toToggle and 34 or 58)),
			ImageTransparency = toToggle and 0.95 or 0.82
		})
		playSpectateMorphTween(parts.Stroke, info, {
			Transparency = toToggle and 0.72 or 0.34
		})

		task.delay(duration + 0.02, function()
			if token ~= spectateMorphState.token then return end
			parts.Root.Visible = false
			parts.Root.GroupTransparency = 1
			spectateMorphState.active = false
			if onComplete then
				onComplete(token)
			end
		end)

		return token
	end
