	end)

	function profileInfoTools.FormatDuration(seconds)
		seconds = math.max(0, math.floor(seconds or 0))
		if seconds < 60 then
			return "Just Joined"
		end

		local minutes = math.floor(seconds / 60)
		if minutes < 60 then
			return tostring(minutes).."m"
		end

		local hours = math.floor(minutes / 60)
		minutes = minutes % 60
		return tostring(hours).."h "..tostring(minutes).."m"
	end

	function profileInfoTools.FormatAccountAge(days)
		days = math.max(0, math.floor(days or 0))
		if days >= 365 then
			local years = math.floor(days / 365)
			local months = math.floor((days % 365) / 30)
			return tostring(years).."y "..tostring(months).."mos"
		elseif days >= 30 then
			return tostring(math.floor(days / 30)).."mos"
		end

		return tostring(days).."d"
	end

	function profileInfoTools.GetRole(targetPlayer)
		local role
		pcall(function()
			if game.CreatorType == Enum.CreatorType.User and targetPlayer.UserId == game.CreatorId then
				role = "Owner"
			elseif game.CreatorType == Enum.CreatorType.Group then
				local groupRole = targetPlayer:GetRoleInGroup(game.CreatorId)
				if groupRole and groupRole ~= "" and groupRole ~= "Guest" then
					role = groupRole
				end
			end
		end)

		if role then return role end
		if targetPlayer.Team then
			return targetPlayer.Team.Name
		end
		return "Neutral"
	end

	function profileInfoTools.Refresh(parts, targetPlayer)
		if not parts or not targetPlayer then return end

		profileInfoTools.SessionStarts[targetPlayer] = profileInfoTools.SessionStarts[targetPlayer] or os.clock()

		if parts.ProfileCard then
			parts.ProfileCard.BackgroundColor3 = siriusValues.selectActionStyle.panel
			parts.ProfileCard.BackgroundTransparency = 1
		end
		if parts.ProfileStroke then
			parts.ProfileStroke.Color = siriusValues.selectActionStyle.stroke
			parts.ProfileStroke.Transparency = 0.72
		end
		if parts.ProfileAvatar then
			parts.ProfileAvatar.Image = "https://www.roblox.com/headshot-thumbnail/image?userId="..targetPlayer.UserId.."&width=420&height=420&format=png"
			parts.ProfileAvatar.ImageTransparency = 0
		end
		if parts.ProfileAvatarStroke then
			parts.ProfileAvatarStroke.Transparency = 0.48
		end
		if parts.ProfileName then
			parts.ProfileName.Text = targetPlayer.DisplayName
			parts.ProfileName.TextTransparency = 0
		end
		if parts.ProfileHandle then
			parts.ProfileHandle.Text = "@"..targetPlayer.Name
			parts.ProfileHandle.TextTransparency = 0
		end
		if parts.ProfilePlaytimeValue then
			parts.ProfilePlaytimeValue.Text = profileInfoTools.FormatDuration(os.clock() - profileInfoTools.SessionStarts[targetPlayer])
		end
		if parts.ProfileAccountAgeValue then
			parts.ProfileAccountAgeValue.Text = profileInfoTools.FormatAccountAge(targetPlayer.AccountAge)
		end
		if parts.ProfileRoleValue then
			parts.ProfileRoleValue.Text = profileInfoTools.GetRole(targetPlayer)
		end
	end
