			end
		end
	end

local function setPlayerActionPickerTransparency(value)
	if not playerActionPicker then return end

	for _, obj in ipairs(playerActionPicker:GetDescendants()) do
		if obj:IsA("TextLabel") or obj:IsA("TextButton") or obj:IsA("TextBox") then
			obj.TextTransparency = value
		elseif obj:IsA("ImageLabel") or obj:IsA("ImageButton") then
			obj.ImageTransparency = value
		end

		if obj:IsA("UIStroke") then
			obj.Transparency = value
		end
	end
end

local function getSpectateHumanoid(player)
	if not player or not players:FindFirstChild(player.Name) then return nil end

	local character = player.Character or workspace:FindFirstChild(player.Name)
	if not character then return nil end

	return character:FindFirstChildOfClass("Humanoid") or character:FindFirstChild("Humanoid")
end

local function smoothlySetCameraSubject(humanoid, duration, targetFov)
	if not humanoid or not humanoid.Parent then return end

	local root = humanoid.Parent:FindFirstChild("HumanoidRootPart") or humanoid.Parent:FindFirstChild("Head") or humanoid.Parent.PrimaryPart
	if not root then
		camera.CameraType = Enum.CameraType.Custom
		camera.CameraSubject = humanoid
		if targetFov then
			if spectateCameraFovTween then spectateCameraFovTween:Cancel() end
			spectateCameraFovTween = tweenService:Create(camera, TweenInfo.new(duration or 0.45, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {FieldOfView = targetFov})
			spectateCameraFovTween:Play()
		end
		return
	end

	spectateCameraToken += 1
	local token = spectateCameraToken
	local startCFrame = camera.CFrame
	local lookVector = startCFrame.LookVector
	if lookVector.Magnitude < 0.1 then
		lookVector = Vector3.new(0, 0, -1)
	end
	lookVector = lookVector.Unit

	local focus = root.Position + Vector3.new(0, 2.35, 0)
	local distance = math.clamp((startCFrame.Position - focus).Magnitude, 10, 16)
	local travelTime = duration or 0.68
	local started = os.clock()
	local useZoomDistance = targetFov and targetFov < camera.FieldOfView

	camera.CameraType = Enum.CameraType.Scriptable
	if targetFov then
		if spectateCameraFovTween then spectateCameraFovTween:Cancel() end
		spectateCameraFovTween = tweenService:Create(camera, TweenInfo.new(travelTime, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {FieldOfView = targetFov})
		spectateCameraFovTween:Play()
	end

	task.spawn(function()
		while token == spectateCameraToken and humanoid and humanoid.Parent do
			local elapsed = os.clock() - started
			local alpha = math.clamp(elapsed / travelTime, 0, 1)
			local eased = 0.5 - math.cos(alpha * math.pi) * 0.5
			local currentRoot = humanoid.Parent:FindFirstChild("HumanoidRootPart") or humanoid.Parent:FindFirstChild("Head") or humanoid.Parent.PrimaryPart
			if not currentRoot then break end

			local currentFocus = currentRoot.Position + Vector3.new(0, 2.35, 0)
			local goalDistance = useZoomDistance and math.max(8.5, distance - 2) or distance
			local goal = CFrame.new(currentFocus - (lookVector * goalDistance), currentFocus)
			camera.CFrame = startCFrame:Lerp(goal, eased)

			if alpha >= 1 then
				break
			end

			runService.RenderStepped:Wait()
		end

		if token ~= spectateCameraToken then return end
		if humanoid and humanoid.Parent then
			camera.CameraSubject = humanoid
			runService.RenderStepped:Wait()
			if token ~= spectateCameraToken then return end
			camera.CameraType = Enum.CameraType.Custom
		end
	end)
end

local function restoreLocalCamera()
	local humanoid = getSpectateHumanoid(localPlayer)
	if humanoid then
		smoothlySetCameraSubject(humanoid, 0.5, spectateState.restoreFov or camera.FieldOfView)
	end
end

local function smoothlySpectateHumanoid(humanoid)
	local targetFov = math.max(58, math.min(68, (spectateState.restoreFov or camera.FieldOfView) - 4))
	smoothlySetCameraSubject(humanoid, 0.56, targetFov)
end

