	stopSpectating = function(reason)
	if not spectateState.active then return end

	spectateState.token += 1
	local token = spectateState.token
	local targetPlayer = spectateState.targetPlayer
	local shouldRestorePicker = reason == nil and targetPlayer and players:FindFirstChild(targetPlayer.Name)

	if spectateState.characterConnection then spectateState.characterConnection:Disconnect() end
	if spectateState.removingConnection then spectateState.removingConnection:Disconnect() end
	spectateState.characterConnection = nil
	spectateState.removingConnection = nil
	spectateState.active = false
	spectateState.targetPlayer = nil

	local function finishCameraRestore()
		restoreLocalCamera()
		task.delay(0.55, function()
			if token == spectateState.token then
				spectateState.restoreFov = nil
			end
		end)
	end

	if spectateBar then
		if shouldRestorePicker then
			local restoreFade = 0.07
			local restoreInfo = TweenInfo.new(restoreFade, Enum.EasingStyle.Sine, Enum.EasingDirection.In)
				tweenService:Create(spectateBar, restoreInfo, {
					GroupTransparency = 1,
					BackgroundTransparency = 1
				}):Play()
			if spectateBarParts.Shadow then
				tweenService:Create(spectateBarParts.Shadow, restoreInfo, {
					ImageTransparency = 1
				}):Play()
			end
			if spectateBarParts.Scale then tweenService:Create(spectateBarParts.Scale, restoreInfo, {Scale = 0.985}):Play() end

			task.delay(restoreFade + 0.03, function()
				if token == spectateState.token and spectateBar then
					spectateBar.Visible = false
					resetSpectateBarGeometry()
				end
				if token == spectateState.token and shouldRestorePicker and targetPlayer and players:FindFirstChild(targetPlayer.Name) then
					finishCameraRestore()
					openPlayerActionPicker(targetPlayer, "spectate-toggle")
				end
			end)
		else
			local closeFade = 0.16
			tweenService:Create(spectateBar, TweenInfo.new(closeFade, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {
				GroupTransparency = 1,
				BackgroundTransparency = 1
			}):Play()
			if spectateBarParts.Shadow then
				tweenService:Create(spectateBarParts.Shadow, TweenInfo.new(closeFade, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {
					ImageTransparency = 1
				}):Play()
			end
			if spectateBarParts.Scale then tweenService:Create(spectateBarParts.Scale, TweenInfo.new(closeFade, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {Scale = 0.975}):Play() end

			task.delay(closeFade + 0.02, function()
				if token == spectateState.token and spectateBar then
					spectateBar.Visible = false
					resetSpectateBarGeometry()
					finishCameraRestore()
				end
			end)
		end
	else
		finishCameraRestore()
	end

	if reason then
		queueNotification("Spectate Ended", reason)
	end
end

local function startSpectating(targetPlayer, morphFromPicker)
	if not targetPlayer or targetPlayer == localPlayer then return end

	local humanoid = getSpectateHumanoid(targetPlayer)
	if not humanoid then
		queueNotification("Spectate Unavailable", "Sirius cannot find "..targetPlayer.DisplayName.."'s character right now.")
		return
	end

	if spectateState.active then
		spectateState.token += 1
		if spectateState.characterConnection then spectateState.characterConnection:Disconnect() end
		if spectateState.removingConnection then spectateState.removingConnection:Disconnect() end
		spectateState.characterConnection = nil
		spectateState.removingConnection = nil
		spectateState.active = false
		spectateState.targetPlayer = nil
	end

	spectateState.token += 1
	local token = spectateState.token
	spectateState.active = true
	spectateState.targetPlayer = targetPlayer
	spectateState.restoreFov = spectateState.restoreFov or camera.FieldOfView
	smoothlySpectateHumanoid(humanoid)

	spectateState.characterConnection = targetPlayer.CharacterAdded:Connect(function()
		task.wait(0.25)
		if spectateState.active and spectateState.targetPlayer == targetPlayer then
			local newHumanoid = getSpectateHumanoid(targetPlayer)
			if newHumanoid then
				smoothlySpectateHumanoid(newHumanoid)
			end
		end
	end)

	spectateState.removingConnection = players.PlayerRemoving:Connect(function(removingPlayer)
		if removingPlayer == targetPlayer then
			stopSpectating(targetPlayer.DisplayName.." left the server.")
		end
	end)

	ensureSpectateBar()
	spectateBar.Visible = true
	resetSpectateBarGeometry()
		spectateBar.BackgroundTransparency = 1
		spectateBar.GroupTransparency = 1
	if spectateBarParts.Scale then
		spectateBarParts.Scale.Scale = morphFromPicker and 1 or 0.975
	end
	spectateBarParts.Avatar.Image = "https://www.roblox.com/headshot-thumbnail/image?userId="..targetPlayer.UserId.."&width=420&height=420&format=png"
	spectateBarParts.TargetName.Text = targetPlayer.DisplayName
		spectateBarParts.LiveGlow.Size = UDim2.new(0, 32, 0, 32)
		spectateBarParts.LiveGlow.ImageTransparency = 0.58
		spectateBarParts.LiveDot.Size = UDim2.new(0, 10, 0, 10)
		spectateBarParts.LiveDot.BackgroundTransparency = 0
		spectateBarParts.Status.BackgroundTransparency = 1
		spectateBarParts.StatusStroke.Transparency = 1
		if spectateBarParts.MainPill then
			spectateBarParts.MainPill.BackgroundTransparency = 0.6
		end
		spectateBarParts.Close.BackgroundTransparency = 0.48
		spectateBarParts.Close.TextTransparency = 0.08
		if spectateBarParts.CloseStroke then
			spectateBarParts.CloseStroke.Transparency = 0.72
		end
		spectateBarParts.Avatar.ImageTransparency = 0
		spectateBarParts.AvatarStroke.Transparency = 0.48
		spectateBarParts.Eyebrow.TextTransparency = 1
		spectateBarParts.TargetName.TextTransparency = 0
		spectateBarParts.Shadow.ImageTransparency = 1
		spectateBarParts.Stroke.Transparency = 0.74

	local openFade = morphFromPicker and 0.10 or 0.18
	local openInfo = TweenInfo.new(openFade, morphFromPicker and Enum.EasingStyle.Sine or Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	tweenService:Create(spectateBar, openInfo, {
		GroupTransparency = 0,
		BackgroundTransparency = 1
	}):Play()
	if spectateBarParts.Scale then
		tweenService:Create(spectateBarParts.Scale, openInfo, {Scale = 1}):Play()
	end
	if spectateBarParts.Shadow then
		tweenService:Create(spectateBarParts.Shadow, openInfo, {ImageTransparency = 0.95}):Play()
	end

	task.spawn(function()
		task.wait(morphFromPicker and 0.11 or 0.3)
		while spectateState.active and spectateState.token == token and spectateBarParts.LiveDot and spectateBarParts.LiveGlow do
			tweenService:Create(spectateBarParts.LiveGlow, TweenInfo.new(0.58, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {ImageTransparency = 0.34, Size = UDim2.new(0, 40, 0, 40)}):Play()
			tweenService:Create(spectateBarParts.LiveDot, TweenInfo.new(0.58, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {Size = UDim2.new(0, 11, 0, 11), BackgroundTransparency = 0}):Play()
			task.wait(0.58)
			if not spectateState.active or spectateState.token ~= token then break end
			tweenService:Create(spectateBarParts.LiveGlow, TweenInfo.new(0.58, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {ImageTransparency = 0.72, Size = UDim2.new(0, 26, 0, 26)}):Play()
			tweenService:Create(spectateBarParts.LiveDot, TweenInfo.new(0.58, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {Size = UDim2.new(0, 9, 0, 9), BackgroundTransparency = 0.02}):Play()
			task.wait(0.58)
		end
	end)

	queueNotification("Spectating", "Now watching "..targetPlayer.DisplayName..".")
end

local function ensureTrackingFolder()
	if trackingFolder then return trackingFolder end

	trackingFolder = Instance.new("Folder")
	trackingFolder.Name = "SiriusTracking"
	trackingFolder.Parent = UI

	return trackingFolder
end

local _picker = {}

function _picker.getTrackingRoot(player)
	if not player or not players:FindFirstChild(player.Name) then return nil end

	local character = player.Character or workspace:FindFirstChild(player.Name)
	if not character then return nil end

	return character:FindFirstChild("HumanoidRootPart") or character:FindFirstChild("Head") or character.PrimaryPart
end

local function getTrackingDelta(targetPlayer)
	local localRoot = _picker.getTrackingRoot(localPlayer)
	local targetRoot = _picker.getTrackingRoot(targetPlayer)

	if not localRoot or not targetRoot then return nil end

	return targetRoot.Position - localRoot.Position
end

local function hasDrawingTracerSupport()
	return typeof(Drawing) == "table" and typeof(Drawing.new) == "function"
end

local function removeTracerObject(object)
	if not object then return end
	pcall(function()
		if typeof(object.Remove) == "function" then
			object:Remove()
		elseif typeof(object.Destroy) == "function" then
			object:Destroy()
		end
	end)
end

local function getTracerColor(targetPlayer)
	if targetPlayer and targetPlayer.Team and localPlayer.Team and targetPlayer.Team == localPlayer.Team then
		return Color3.new(0, 1, 0)
	end

	return Color3.new(1, 0, 0)
end

local function cleanupTracerLoopIfIdle()
	if next(playerTracers) ~= nil then return end

	if tracerRenderConnection then
		tracerRenderConnection:Disconnect()
		tracerRenderConnection = nil
	end

	if tracerRemovingConnection then
		tracerRemovingConnection:Disconnect()
		tracerRemovingConnection = nil
	end
end

local function destroyPlayerTracer(targetPlayer)
	if not targetPlayer then return end

	local tracer = playerTracers[targetPlayer]
	if not tracer then return end

	playerTracers[targetPlayer] = nil
	removeTracerObject(tracer.Line)
	removeTracerObject(tracer.Outline)
	cleanupTracerLoopIfIdle()
end

local function updatePlayerTracers()
	if not checkSirius() then
		for targetPlayer in pairs(playerTracers) do
			destroyPlayerTracer(targetPlayer)
		end
		return
	end

	local viewportSize = camera.ViewportSize
	local origin = Vector2.new(viewportSize.X * 0.5, viewportSize.Y * 0.5)

	for targetPlayer, tracer in pairs(playerTracers) do
		local visible = false
		if targetPlayer and players:FindFirstChild(targetPlayer.Name) then
			local root = _picker.getTrackingRoot(targetPlayer)
			local character = targetPlayer.Character
			local humanoid = character and character:FindFirstChildOfClass("Humanoid")
			if root and (not humanoid or humanoid.Health > 0) then
				local screenPoint, onScreen = camera:WorldToViewportPoint(root.Position)
				if onScreen and screenPoint.Z > 0 then
					local destination = Vector2.new(screenPoint.X, screenPoint.Y)
					local color = getTracerColor(targetPlayer)

					if tracer.Outline then
						tracer.Outline.From = origin
						tracer.Outline.To = destination
						tracer.Outline.Color = Color3.new(0, 0, 0)
						tracer.Outline.Thickness = 3
						tracer.Outline.Transparency = 0.58
						tracer.Outline.Visible = true
					end
					if tracer.Line then
						tracer.Line.From = origin
						tracer.Line.To = destination
						tracer.Line.Color = color
						tracer.Line.Thickness = 1.4
						tracer.Line.Transparency = 0.9
						tracer.Line.Visible = true
					end

					visible = true
				end
			end
		else
			destroyPlayerTracer(targetPlayer)
		end

		if not visible then
			if tracer.Line then tracer.Line.Visible = false end
			if tracer.Outline then tracer.Outline.Visible = false end
		end
	end
end

local function ensureTracerRenderLoop()
	if tracerRenderConnection then return end

	tracerRenderConnection = runService.RenderStepped:Connect(updatePlayerTracers)
	if not tracerRemovingConnection then
		tracerRemovingConnection = players.PlayerRemoving:Connect(destroyPlayerTracer)
	end
end

local function setPlayerTracer(targetPlayer, enabled)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then
		return false
	end

	if not enabled then
		destroyPlayerTracer(targetPlayer)
		return false
	end

	if playerTracers[targetPlayer] then
		return true
	end

	if not hasDrawingTracerSupport() then
		if not tracerUnavailableNotified then
			tracerUnavailableNotified = true
			queueNotification("Tracer Unavailable", "Your executor does not support Drawing lines.")
		end
		return false
	end

	local outline = Drawing.new("Line")
	outline.Visible = false
	outline.Color = Color3.new(0, 0, 0)
	outline.Thickness = 3
	outline.Transparency = 0.58

	local line = Drawing.new("Line")
	line.Visible = false
	line.Color = getTracerColor(targetPlayer)
	line.Thickness = 1.4
	line.Transparency = 0.9

	playerTracers[targetPlayer] = {
		Line = line,
		Outline = outline
	}

	ensureTracerRenderLoop()
	return true
end

local function togglePlayerTracer(targetPlayer)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then return false end

	local wantsEnable = playerTracers[targetPlayer] == nil
	local enabled = setPlayerTracer(targetPlayer, wantsEnable)
	if wantsEnable and not enabled then
		return false
	end

	queueNotification(
		enabled and "Tracer Enabled" or "Tracer Disabled",
		enabled and ("Drawing a live tracer to "..targetPlayer.DisplayName..".") or (targetPlayer.DisplayName.."'s tracer was removed.")
	)
	return enabled
end

local hiddenPlayerTools = {}

function hiddenPlayerTools.RememberOriginal(state, object, property)
	if not state or not object then return false end

	local originals = state.Originals
	if not originals then
		originals = {}
		state.Originals = originals
	end

	local objectOriginals = originals[object]
	if not objectOriginals then
		objectOriginals = {}
		originals[object] = objectOriginals
	end

	if objectOriginals[property] == nil then
		local success, value = pcall(function()
			return object[property]
		end)
		if not success then return false end
		objectOriginals[property] = value
	end

	return true
end

function hiddenPlayerTools.SetObjectProperty(state, object, property, value)
	if not hiddenPlayerTools.RememberOriginal(state, object, property) then return end

	pcall(function()
		object[property] = value
	end)
end

function hiddenPlayerTools.ApplyObject(state, object)
	if not state or not object then return end

	if object:IsA("BasePart") then
		hiddenPlayerTools.SetObjectProperty(state, object, "LocalTransparencyModifier", 1)
	elseif object:IsA("Decal") or object:IsA("Texture") then
		hiddenPlayerTools.SetObjectProperty(state, object, "Transparency", 1)
	elseif object:IsA("BillboardGui") or object:IsA("SurfaceGui") or object:IsA("ParticleEmitter") or object:IsA("Trail") or object:IsA("Beam") or object:IsA("Highlight") or object:IsA("Fire") or object:IsA("Smoke") or object:IsA("Sparkles") then
		hiddenPlayerTools.SetObjectProperty(state, object, "Enabled", false)
	end
end

function hiddenPlayerTools.RestoreState(state)
	if not state or not state.Originals then return end

	for object, properties in pairs(state.Originals) do
		if object and object.Parent then
			for property, value in pairs(properties) do
				pcall(function()
					object[property] = value
				end)
			end
		end
	end

	state.Originals = {}
end

function hiddenPlayerTools.DisconnectCharacter(state)
	if state and state.DescendantAddedConnection then
		state.DescendantAddedConnection:Disconnect()
		state.DescendantAddedConnection = nil
	end
end

function hiddenPlayerTools.ApplyCharacter(targetPlayer)
	local state = hiddenPlayers[targetPlayer]
	if not state then return end

	local character = targetPlayer and targetPlayer.Character
	if not character then return end

	if state.Character ~= character then
		hiddenPlayerTools.DisconnectCharacter(state)
		hiddenPlayerTools.RestoreState(state)
		state.Character = character
	end

	for _, object in ipairs(character:GetDescendants()) do
		hiddenPlayerTools.ApplyObject(state, object)
	end

	if not state.DescendantAddedConnection then
		state.DescendantAddedConnection = character.DescendantAdded:Connect(function(object)
			task.defer(function()
				if hiddenPlayers[targetPlayer] == state and state.Character == character then
					hiddenPlayerTools.ApplyObject(state, object)
				end
			end)
		end)
	end
end

function hiddenPlayerTools.Destroy(targetPlayer)
	local state = targetPlayer and hiddenPlayers[targetPlayer]
	if not state then return end

	hiddenPlayers[targetPlayer] = nil
	hiddenPlayerTools.DisconnectCharacter(state)
	if state.CharacterAddedConnection then state.CharacterAddedConnection:Disconnect() end
	if state.RemovingConnection then state.RemovingConnection:Disconnect() end
	hiddenPlayerTools.RestoreState(state)
end

function hiddenPlayerTools.Set(targetPlayer, enabled)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then
		return false
	end

	if not enabled then
		hiddenPlayerTools.Destroy(targetPlayer)
		return false
	end

	local state = hiddenPlayers[targetPlayer]
	if not state then
		state = {
			Originals = {},
			Character = nil,
			CharacterAddedConnection = nil,
			DescendantAddedConnection = nil,
			RemovingConnection = nil
		}
		hiddenPlayers[targetPlayer] = state

		state.CharacterAddedConnection = targetPlayer.CharacterAdded:Connect(function()
			task.wait(0.2)
			if hiddenPlayers[targetPlayer] == state then
				hiddenPlayerTools.ApplyCharacter(targetPlayer)
			end
		end)

		state.RemovingConnection = players.PlayerRemoving:Connect(function(removingPlayer)
			if removingPlayer == targetPlayer then
				hiddenPlayerTools.Destroy(targetPlayer)
			end
		end)
	end

	hiddenPlayerTools.ApplyCharacter(targetPlayer)
	return hiddenPlayers[targetPlayer] ~= nil
end

function hiddenPlayerTools.Toggle(targetPlayer)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then return false end

	local enabled = hiddenPlayerTools.Set(targetPlayer, hiddenPlayers[targetPlayer] == nil)
	queueNotification(
		enabled and "Hide Enabled" or "Hide Disabled",
		enabled and (targetPlayer.DisplayName.." is hidden locally.") or (targetPlayer.DisplayName.." is visible again.")
	)
	return enabled
end

playerActionPickerParts.TeleportToSelected = function(targetPlayer)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then return false end

	local localCharacter = localPlayer.Character
	local localRoot = localCharacter and localCharacter:FindFirstChild("HumanoidRootPart")
	local targetCharacter = targetPlayer.Character
	local targetRoot = targetCharacter and targetCharacter:FindFirstChild("HumanoidRootPart")
	if not localRoot or not targetRoot then
		queueNotification("Teleport Failed", targetPlayer.DisplayName.." is unavailable right now.")
		return false
	end

	pcall(function()
		localRoot.AssemblyLinearVelocity = Vector3.zero
		localRoot.AssemblyAngularVelocity = Vector3.zero
		localRoot.Velocity = Vector3.zero
		localRoot.RotVelocity = Vector3.zero
	end)

	local behindTarget = targetRoot.CFrame * CFrame.new(0, 1.5, 3)
	localRoot.CFrame = CFrame.new(behindTarget.Position, targetRoot.Position)
	queueNotification("Teleported", "Moved to "..targetPlayer.DisplayName..".")
	return true
end

