function wieldingTools.GetLocalRoot()
	local character = localPlayer.Character
	local humanoid = character and character:FindFirstChildOfClass("Humanoid")
	local root = character and character:FindFirstChild("HumanoidRootPart")
	return character, humanoid, root
end

function wieldingTools.GetTargetRoot(targetPlayer)
	local character = targetPlayer and targetPlayer.Character
	return character and character:FindFirstChild("HumanoidRootPart")
end

function wieldingTools.ZeroRoot(root)
	if not root then return end
	pcall(function()
		root.Velocity = Vector3.zero
		root.RotVelocity = Vector3.zero
		root.AssemblyLinearVelocity = Vector3.zero
		root.AssemblyAngularVelocity = Vector3.zero
	end)
end

function wieldingTools.SetPhysicsRoot(root, targetRoot)
	if not root then return end
	if typeof(sethiddenproperty) == "function" then
		pcall(function()
			sethiddenproperty(root, "PhysicsRepRootPart", targetRoot or root)
		end)
	end
end

function wieldingTools.Stop(silent)
	local active = wieldingTools.Active
	if not active then return false end

	wieldingTools.Active = nil
	if active.Connection then
		active.Connection:Disconnect()
	end

	local _, _, root = wieldingTools.GetLocalRoot()
	if root then
		if active.SavedCFrame then
			root.CFrame = active.SavedCFrame
		end
		wieldingTools.ZeroRoot(root)
		wieldingTools.SetPhysicsRoot(root, root)
	end

	if not silent then
		queueNotification("Wielding Disabled", active.Label.." stopped.")
	end
	return false
end

function wieldingTools.IsActive(targetPlayer, abilityName)
	local active = wieldingTools.Active
	return active ~= nil and active.TargetPlayer == targetPlayer and active.AbilityName == abilityName
end

function wieldingTools.GetActiveName(targetPlayer)
	local active = wieldingTools.Active
	if active and active.TargetPlayer == targetPlayer then
		return active.AbilityName
	end
	return nil
end

function wieldingTools.Toggle(targetPlayer, abilityName)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then return false end
	local ability = wieldingTools.Abilities[abilityName]
	if not ability then return false end

	if wieldingTools.IsActive(targetPlayer, abilityName) then
		return wieldingTools.Stop(false)
	end

	wieldingTools.Stop(true)

	local _, _, root = wieldingTools.GetLocalRoot()
	local targetRoot = wieldingTools.GetTargetRoot(targetPlayer)
	if not root or not targetRoot then
		queueNotification("Wielding Failed", "Target character is unavailable.")
		return false
	end

	local active = {
		AbilityName = abilityName,
		Label = ability.Label,
		TargetPlayer = targetPlayer,
		SavedCFrame = root.CFrame,
		Connection = nil
	}
	wieldingTools.Active = active

	active.Connection = runService.Heartbeat:Connect(function()
		if wieldingTools.Active ~= active then return end
		if not targetPlayer or not players:FindFirstChild(targetPlayer.Name) then
			wieldingTools.Stop(true)
			return
		end

		local _, _, playerRoot = wieldingTools.GetLocalRoot()
		local currentTargetRoot = wieldingTools.GetTargetRoot(targetPlayer)
		if not playerRoot or not currentTargetRoot then return end

		if ability.Mode == "cframe" then
			playerRoot.CFrame = currentTargetRoot.CFrame * (ability.OffsetCFrame or CFrame.new())
			wieldingTools.ZeroRoot(playerRoot)
		else
			local offset = ability.Offset or Vector3.zero
			playerRoot.CFrame = CFrame.new(currentTargetRoot.Position + offset) * CFrame.Angles(-math.pi / 2, 0, 0)
			local velocity = ability.Velocity or Vector3.zero
			pcall(function()
				playerRoot.Velocity = velocity
				playerRoot.RotVelocity = velocity
				playerRoot.AssemblyLinearVelocity = velocity
				playerRoot.AssemblyAngularVelocity = velocity
			end)
		end

		wieldingTools.SetPhysicsRoot(playerRoot, currentTargetRoot)
	end)

	queueNotification("Wielding Enabled", ability.Label.." is active on "..targetPlayer.DisplayName..".")
	return true
end

function wieldingTools.Rocket(targetPlayer, power, label)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then return false end

	local _, _, root = wieldingTools.GetLocalRoot()
	local targetRoot = wieldingTools.GetTargetRoot(targetPlayer)
	if not root or not targetRoot then
		queueNotification("Wielding Failed", "Target character is unavailable.")
		return false
	end

	wieldingTools.Stop(true)
	wieldingTools.RocketToken += 1
	local token = wieldingTools.RocketToken
	local savedCFrame = root.CFrame
	local rocketConnection
	rocketConnection = runService.Heartbeat:Connect(function()
		if token ~= wieldingTools.RocketToken then
			if rocketConnection then rocketConnection:Disconnect() end
			return
		end

		local _, _, playerRoot = wieldingTools.GetLocalRoot()
		local currentTargetRoot = wieldingTools.GetTargetRoot(targetPlayer)
		if not playerRoot or not currentTargetRoot then return end

		local targetBelow = currentTargetRoot.Position + Vector3.new(0, -3, 0)
		playerRoot.CFrame = CFrame.new(targetBelow, targetBelow + Vector3.new(0, 1, 0))
		pcall(function()
			playerRoot.Velocity = Vector3.new(0, power or 50, 0)
			playerRoot.RotVelocity = Vector3.zero
			playerRoot.AssemblyLinearVelocity = Vector3.new(0, power or 50, 0)
			playerRoot.AssemblyAngularVelocity = Vector3.zero
		end)
		wieldingTools.SetPhysicsRoot(playerRoot, currentTargetRoot)
	end)

	task.delay(0.22, function()
		if token ~= wieldingTools.RocketToken then return end
		if rocketConnection then rocketConnection:Disconnect() end
		local _, _, playerRoot = wieldingTools.GetLocalRoot()
		if playerRoot then
			playerRoot.CFrame = savedCFrame
			wieldingTools.ZeroRoot(playerRoot)
			wieldingTools.SetPhysicsRoot(playerRoot, playerRoot)
		end
	end)

	queueNotification("Wielding", (label or "Rocket Target").." fired at "..targetPlayer.DisplayName..".")
	return true
end

local function setPlayerActionSwitchVisual(switch, switchStroke, knob, enabled, animated)
	if not switch then return end
	local switchGoal = {
		BackgroundColor3 = enabled and siriusValues.selectActionStyle.switchActive or siriusValues.selectActionStyle.switch
	}
	local strokeGoal = {
		Color = enabled and siriusValues.selectActionStyle.switchStrokeActive or siriusValues.selectActionStyle.switchStroke,
		Transparency = enabled and 0.12 or 0.28
	}
	local knobGoal = {
		Position = enabled and UDim2.new(1, -13, 0.5, 0) or UDim2.new(0, 13, 0.5, 0),
		BackgroundColor3 = enabled and Color3.fromRGB(245, 245, 245) or Color3.fromRGB(110, 110, 110)
	}

	if animated then
		local info = TweenInfo.new(0.18, Enum.EasingStyle.Sine, Enum.EasingDirection.Out)
		tweenService:Create(switch, info, switchGoal):Play()
		if switchStroke then tweenService:Create(switchStroke, info, strokeGoal):Play() end
		if knob then tweenService:Create(knob, info, knobGoal):Play() end
		return
	end

	for property, value in pairs(switchGoal) do switch[property] = value end
	if switchStroke then
		for property, value in pairs(strokeGoal) do switchStroke[property] = value end
	end
	if knob then
		for property, value in pairs(knobGoal) do knob[property] = value end
	end
end

local function refreshWieldingActionRows(targetPlayer, animated)
	if not playerActionPickerParts.WieldRows then return end

	for _, rowParts in pairs(playerActionPickerParts.WieldRows) do
		if rowParts.Switch then
			setPlayerActionSwitchVisual(
				rowParts.Switch,
				rowParts.SwitchStroke,
				rowParts.Knob,
				wieldingTools.IsActive(targetPlayer, rowParts.AbilityName),
				animated
			)
		end
	end
end

function _picker.destroyTrackingBadge(targetPlayer)
	if not targetPlayer then return end

	local existing = trackingBadges[targetPlayer]
	if existing then
		trackingBadges[targetPlayer] = nil
		tweenService:Create(existing, TweenInfo.new(0.16, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {Size = UDim2.fromOffset(0, 0)}):Play()
		task.delay(0.18, function()
			if existing then
				existing:Destroy()
			end
		end)
	end

	if trackingConnections[targetPlayer] then
		for _, connection in ipairs(trackingConnections[targetPlayer]) do
			if connection then connection:Disconnect() end
		end
		trackingConnections[targetPlayer] = nil
	end
end

function _picker.closeLiveTrackPanel(restorePicker)
	if not liveTrackState.active and (not liveTrackPanel or not liveTrackPanel.Visible) then return end

	liveTrackState.token += 1
	local token = liveTrackState.token
	local targetPlayer = liveTrackState.targetPlayer
	local shouldRestorePicker = restorePicker
	if shouldRestorePicker == nil then
		shouldRestorePicker = liveTrackState.returnToPicker
	end
	liveTrackState.active = false
	liveTrackState.targetPlayer = nil
	liveTrackState.returnToPicker = false

	if liveTrackState.renderConnection then liveTrackState.renderConnection:Disconnect() end
	if liveTrackState.characterConnection then liveTrackState.characterConnection:Disconnect() end
	if liveTrackState.removingConnection then liveTrackState.removingConnection:Disconnect() end
	liveTrackState.renderConnection = nil
	liveTrackState.characterConnection = nil
	liveTrackState.removingConnection = nil

	if liveTrackPanel then
		local closeWidth = math.max(220, (liveTrackPanel.AbsoluteSize.X > 0 and liveTrackPanel.AbsoluteSize.X or liveTrackCurrentSize.X) - 34)
		local closeSize = UDim2.fromOffset(closeWidth, 18)
		local closeShadowSize = UDim2.fromOffset(closeWidth + 40, 54)
		local contentFadeTween = TweenInfo.new(0.14, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
		local panelCloseTween = TweenInfo.new(0.3, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut)
		local panelFadeTween = TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.In)

		tweenService:Create(liveTrackPanel, contentFadeTween, {
			GroupTransparency = 1
		}):Play()
		tweenService:Create(liveTrackPanel, panelCloseTween, {
			Size = closeSize
		}):Play()
		tweenService:Create(liveTrackPanel, panelFadeTween, {
			BackgroundTransparency = 1
		}):Play()
		if liveTrackParts.Stroke then
			tweenService:Create(liveTrackParts.Stroke, panelFadeTween, {Transparency = 1}):Play()
		end
		if liveTrackParts.Scale then
			tweenService:Create(liveTrackParts.Scale, panelCloseTween, {Scale = 1}):Play()
		end
		if liveTrackParts.Shadow then
			tweenService:Create(liveTrackParts.Shadow, panelFadeTween, {ImageTransparency = 1}):Play()
		end
		if liveTrackParts.OuterShadow then
			tweenService:Create(liveTrackParts.OuterShadow, panelCloseTween, {
				Position = getLiveTrackShadowPosition(liveTrackCurrentPosition, 16),
				Size = closeShadowSize
			}):Play()
			tweenService:Create(liveTrackParts.OuterShadow, panelFadeTween, {ImageTransparency = 1}):Play()
		end

		task.delay(0.32, function()
			if token == liveTrackState.token and liveTrackPanel then
				liveTrackPanel.Visible = false
				liveTrackPanel.BackgroundTransparency = 0
				liveTrackPanel.GroupTransparency = 1
				applyLiveTrackSize(liveTrackCurrentSize, false)
				if liveTrackParts.Scale then
					liveTrackParts.Scale.Scale = 1
				end
				if liveTrackParts.OuterShadow then
					liveTrackParts.OuterShadow.Visible = false
				end
				if targetPlayer and shouldRestorePicker and players:FindFirstChild(targetPlayer.Name) and openPlayerActionPicker then
					openPlayerActionPicker(targetPlayer)
				end
			end
		end)
	end
end

