		local distance = Instance.new("TextLabel")
	distance.Name = "Distance"
	distance.AnchorPoint = Vector2.new(0, 1)
	distance.Position = UDim2.new(0, 34, 1, -28)
	distance.Size = UDim2.new(1, -68, 0, 40)
	distance.BackgroundTransparency = 1
	distance.Text = "Locating..."
	distance.RichText = true
	distance.TextColor3 = Color3.fromRGB(245, 245, 245)
	distance.TextXAlignment = Enum.TextXAlignment.Left
	distance.TextSize = 22
	distance.FontFace = Font.new("rbxasset://fonts/families/GothamSSm.json", Enum.FontWeight.Bold)
	distance.ZIndex = 83
	distance.Parent = liveTrackPanel

	local resizeHandle = Instance.new("ImageButton")
	resizeHandle.Name = "Resize"
	resizeHandle.AnchorPoint = Vector2.new(1, 1)
	resizeHandle.Position = UDim2.new(1, -8, 1, -8)
	resizeHandle.Size = UDim2.fromOffset(48, 48)
	resizeHandle.BackgroundTransparency = 1
	resizeHandle.BorderSizePixel = 0
	resizeHandle.Image = ""
	resizeHandle.AutoButtonColor = false
	resizeHandle.ZIndex = 88
	resizeHandle.Parent = liveTrackPanel

	local resizeIcon = Instance.new("ImageLabel")
	resizeIcon.Name = "Icon"
	resizeIcon.AnchorPoint = Vector2.new(1, 1)
	resizeIcon.Position = UDim2.new(1, 0, 1, 0)
	resizeIcon.Size = UDim2.fromOffset(18, 18)
	resizeIcon.BackgroundTransparency = 1
	resizeIcon.Image = "rbxassetid://86527207319523"
	resizeIcon.ImageColor3 = Color3.fromRGB(82, 82, 82)
	resizeIcon.ImageTransparency = 0.62
	resizeIcon.ZIndex = 89
	resizeIcon.Parent = resizeHandle

	local liveTrackResizeHover = false
	local liveTrackResizeDragging = false
	local liveTrackResizeStartPointer
	local liveTrackResizeStartSize
		local liveTrackResizeTargetSize = liveTrackCurrentSize
		local liveTrackResizeVisualSize = liveTrackCurrentSize
		local liveTrackResizeConnection
		local liveTrackDragging = false
		local liveTrackDragInput
		local liveTrackDragStartPointer
		local liveTrackDragStartPosition

	local function getLiveTrackPointer(input)
		if input and input.UserInputType == Enum.UserInputType.Touch then
			return Vector2.new(input.Position.X, input.Position.Y)
		end

		return userInputService:GetMouseLocation()
	end

		local function getLiveTrackScreenMax()
		local rootSize = UI.AbsoluteSize
		if rootSize.X <= 0 or rootSize.Y <= 0 then
			rootSize = camera.ViewportSize
		end

			return Vector2.new(
				math.clamp(rootSize.X - 80, liveTrackMinSize.X, liveTrackMaxSize.X),
				math.clamp(rootSize.Y - 80, liveTrackMinSize.Y, liveTrackMaxSize.Y)
			)
		end

		local function beginLiveTrackDrag(input)
			if liveTrackResizeDragging then return end
			liveTrackDragging = true
			liveTrackDragInput = input
			liveTrackDragStartPointer = getLiveTrackPointer(input)
			liveTrackDragStartPosition = liveTrackCurrentPosition
		end

		local function updateLiveTrackDrag(input)
			if not liveTrackDragging or liveTrackResizeDragging or not liveTrackDragStartPointer or not liveTrackDragStartPosition then return end

			local pointer = getLiveTrackPointer(input)
			local delta = pointer - liveTrackDragStartPointer
			setLiveTrackPosition(UDim2.new(
				liveTrackDragStartPosition.X.Scale,
				liveTrackDragStartPosition.X.Offset + delta.X,
				liveTrackDragStartPosition.Y.Scale,
				liveTrackDragStartPosition.Y.Offset + delta.Y
			), 20)
		end

		local function endLiveTrackDrag()
			if not liveTrackDragging then return end
			liveTrackDragging = false
			liveTrackDragInput = nil
			liveTrackDragStartPointer = nil
			liveTrackDragStartPosition = nil
		end

		local function bindLiveTrackDrag(object)
			object.InputBegan:Connect(function(input)
				if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
					beginLiveTrackDrag(input)
				end
			end)

			object.InputChanged:Connect(function(input)
				if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then
					liveTrackDragInput = input
				end
			end)
		end

	local function setLiveTrackResizeVisual(mode)
		local size = 18
		local color = Color3.fromRGB(82, 82, 82)
		local transparency = 0.62

		if mode == "drag" then
			size = 23
			color = Color3.fromRGB(112, 112, 112)
			transparency = 0.08
		elseif mode == "hover" then
			size = 21
			color = Color3.fromRGB(98, 98, 98)
			transparency = 0.28
		end

		tweenService:Create(resizeIcon, TweenInfo.new(0.16, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
			Size = UDim2.fromOffset(size, size),
			ImageColor3 = color,
			ImageTransparency = transparency
		}):Play()
	end

	local function stopLiveTrackResizeLoop()
		if liveTrackResizeConnection then
			liveTrackResizeConnection:Disconnect()
			liveTrackResizeConnection = nil
		end
	end

	local function startLiveTrackResizeLoop()
		stopLiveTrackResizeLoop()
		liveTrackResizeVisualSize = liveTrackCurrentSize

		liveTrackResizeConnection = runService.RenderStepped:Connect(function(deltaTime)
			local targetSize = clampLiveTrackSize(liveTrackResizeTargetSize)
			local alpha = 1 - math.exp(-deltaTime * 28)
			liveTrackResizeVisualSize = liveTrackResizeVisualSize + ((targetSize - liveTrackResizeVisualSize) * alpha)
			applyLiveTrackSize(liveTrackResizeVisualSize, false)

			if not liveTrackResizeDragging and (liveTrackResizeVisualSize - targetSize).Magnitude <= 0.45 then
				applyLiveTrackSize(targetSize, false)
				stopLiveTrackResizeLoop()
			end
		end)
	end

	local function beginLiveTrackResize(input)
		liveTrackResizeDragging = true
		liveTrackResizeStartPointer = getLiveTrackPointer(input)
		liveTrackResizeStartSize = liveTrackCurrentSize
		liveTrackResizeTargetSize = liveTrackCurrentSize
		liveTrackResizeVisualSize = liveTrackCurrentSize
		setLiveTrackResizeVisual("drag")
		startLiveTrackResizeLoop()
	end

	local function updateLiveTrackResize(input)
		if not liveTrackResizeDragging or not liveTrackResizeStartPointer or not liveTrackResizeStartSize then return end

		local pointer = getLiveTrackPointer(input)
		local delta = pointer - liveTrackResizeStartPointer
		local maxSize = getLiveTrackScreenMax()
		liveTrackResizeTargetSize = Vector2.new(
			math.clamp(liveTrackResizeStartSize.X + (delta.X * 2), liveTrackMinSize.X, maxSize.X),
			math.clamp(liveTrackResizeStartSize.Y + (delta.Y * 2), liveTrackMinSize.Y, maxSize.Y)
		)
	end

	local function endLiveTrackResize()
		if not liveTrackResizeDragging then return end
		liveTrackResizeDragging = false
		setLiveTrackResizeVisual(liveTrackResizeHover and "hover" or "idle")
	end

	resizeHandle.MouseEnter:Connect(function()
		liveTrackResizeHover = true
		if not liveTrackResizeDragging then
			setLiveTrackResizeVisual("hover")
		end
	end)

	resizeHandle.MouseLeave:Connect(function()
		liveTrackResizeHover = false
		if not liveTrackResizeDragging then
			setLiveTrackResizeVisual("idle")
		end
	end)

		resizeHandle.InputBegan:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
				beginLiveTrackResize(input)
			end
		end)

		bindLiveTrackDrag(dragArea)
		bindLiveTrackDrag(eyebrow)
		bindLiveTrackDrag(name)

		userInputService.InputChanged:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then
				if liveTrackDragging and (not liveTrackDragInput or input == liveTrackDragInput or input.UserInputType == Enum.UserInputType.Touch) then
					updateLiveTrackDrag(input)
				end
				if liveTrackResizeDragging then
					updateLiveTrackResize(input)
				end
			end
		end)

		userInputService.InputEnded:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
				endLiveTrackDrag()
				endLiveTrackResize()
			end
		end)

		close.MouseButton1Click:Connect(_picker.closeLiveTrackPanel)

	liveTrackParts = {
		Scale = scale,
		OuterShadow = outerShadow,
		Shadow = shadow,
			Stroke = stroke,
			Eyebrow = eyebrow,
				TargetName = name,
				Canvas = directionCanvas,
				Direction = directionViewport,
					DirectionScale = directionScale,
					LiveTrackCamera = liveTrackCamera,
					Arrow = arrow,
					Circle = nearbyCircle,
					Bound = nearbyBound,
					BoundScale = nearbyBoundScale,
					Distance = distance,
					Pin = pin,
					Close = close,
					ResizeHandle = resizeHandle,
					ResizeIcon = resizeIcon
	}

	return liveTrackPanel
end

	local function getTrackObjectCFrame(targetPlayer)
		local root = _picker.getTrackingRoot(targetPlayer)
		if not root then return nil end
		return root.CFrame
	end

	local function getGuideDistance(targetPlayer)
		local objCFrame = getTrackObjectCFrame(targetPlayer)
		if not objCFrame or not camera then return nil end

		local offset = objCFrame.Position - camera.CFrame.Position
		local distance = math.round(offset.Magnitude)
		local relative = camera.CFrame:VectorToObjectSpace(offset)
		local x, y, z = relative.X, relative.Y, relative.Z
		local absX, absY, absZ = math.abs(x), math.abs(y), math.abs(z)
		local direction

		if absZ >= absX and absZ >= absY then
			direction = z > 0 and "behind" or "ahead"
		elseif absX >= absY and absX >= absZ then
			direction = x > 0 and "to your right" or "to your left"
		else
			direction = y > 0 and "above" or "below"
		end

		return distance, direction, objCFrame
	end

	local function pointLiveTrackArrow(objCFrame)
		if not objCFrame or not liveTrackParts.Arrow then return end
		local offset = objCFrame.Position - camera.CFrame.Position
		if offset.Magnitude <= 0 then return end

		local direction = offset.Unit
		local lookAt = CFrame.new(Vector3.zero, direction)
		local rotated = lookAt * CFrame.Angles(0, math.rad(90), 0)
		tweenService:Create(liveTrackParts.Arrow, TweenInfo.new(0.18, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
			CFrame = rotated
		}):Play()
	end

	local function updateLiveTrackReadout(targetPlayer, deltaTime)
		if not liveTrackPanel or not liveTrackState.active then return end

			local distance, direction, objCFrame = getGuideDistance(targetPlayer)
			if not distance or not objCFrame then
				liveTrackParts.Distance.Text = "Target unavailable"
				if liveTrackParts.Arrow then
					tweenService:Create(liveTrackParts.Arrow, TweenInfo.new(0.16, Enum.EasingStyle.Sine), {
						Size = Vector3.zero,
						Transparency = 1
					}):Play()
				end
				if liveTrackParts.Canvas then
					liveTrackParts.Canvas.BackgroundTransparency = 1
				end
				if liveTrackParts.DirectionScale then
					liveTrackParts.DirectionScale.Scale = 1
				end
				if liveTrackParts.Circle then
					tweenService:Create(liveTrackParts.Circle, TweenInfo.new(0.16, Enum.EasingStyle.Sine), {
						ImageTransparency = 1
					}):Play()
				end
				if liveTrackParts.Bound then
					tweenService:Create(liveTrackParts.Bound, TweenInfo.new(0.16, Enum.EasingStyle.Sine), {
						Size = UDim2.fromScale(0, 0),
						ImageTransparency = 1
					}):Play()
				end
				if liveTrackParts.BoundScale then
					tweenService:Create(liveTrackParts.BoundScale, TweenInfo.new(0.16, Enum.EasingStyle.Sine), {Scale = 0}):Play()
				end
				return
			end

		if liveTrackParts.LiveTrackCamera and liveTrackParts.Arrow then
			local focus = liveTrackParts.Arrow.CFrame.Position
			local goal = CFrame.new(focus - (camera.CFrame.LookVector * 8), focus)
			liveTrackParts.LiveTrackCamera.CFrame = liveTrackParts.LiveTrackCamera.CFrame:Lerp(goal, math.min(1, (deltaTime or 0.016) * 20))
		end

		if distance > 20 then
				pointLiveTrackArrow(objCFrame)
					liveTrackParts.Distance.Text = string.format("%d studs <font color=\"rgb(150,150,150)\">%s</font>", distance, direction)
					if liveTrackParts.Arrow then
						tweenService:Create(liveTrackParts.Arrow, TweenInfo.new(0.18, Enum.EasingStyle.Sine), {
							Size = Vector3.new(0.98, 0.05, 0.86),
							Transparency = 0
						}):Play()
					end
				if liveTrackParts.Canvas then
					liveTrackParts.Canvas.BackgroundTransparency = 1
			end
			if liveTrackParts.DirectionScale then
				tweenService:Create(liveTrackParts.DirectionScale, TweenInfo.new(0.18, Enum.EasingStyle.Sine), {Scale = 1}):Play()
			end
			if liveTrackParts.Circle then
				tweenService:Create(liveTrackParts.Circle, TweenInfo.new(0.18, Enum.EasingStyle.Sine), {
					ImageTransparency = 1
				}):Play()
			end
			if liveTrackParts.Bound then
				tweenService:Create(liveTrackParts.Bound, TweenInfo.new(0.18, Enum.EasingStyle.Sine), {
					Size = UDim2.fromScale(0, 0),
					ImageTransparency = 1
				}):Play()
			end
			if liveTrackParts.BoundScale then
				tweenService:Create(liveTrackParts.BoundScale, TweenInfo.new(0.18, Enum.EasingStyle.Sine), {Scale = 0}):Play()
			end
		else
			liveTrackParts.Distance.Text = "Nearby"
			if liveTrackParts.Arrow then
				tweenService:Create(liveTrackParts.Arrow, TweenInfo.new(0.18, Enum.EasingStyle.Sine), {
						Size = Vector3.zero,
						Transparency = 1
					}):Play()
				end
			if liveTrackParts.Canvas then
				liveTrackParts.Canvas.BackgroundTransparency = 1
			end
			if liveTrackParts.DirectionScale then
				tweenService:Create(liveTrackParts.DirectionScale, TweenInfo.new(0.18, Enum.EasingStyle.Sine), {Scale = 1}):Play()
			end
			if liveTrackParts.Circle then
				tweenService:Create(liveTrackParts.Circle, TweenInfo.new(0.22, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
					ImageTransparency = 0
				}):Play()
			end
			if liveTrackParts.Bound then
				tweenService:Create(liveTrackParts.Bound, TweenInfo.new(0.22, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
					Size = UDim2.fromOffset(60, 60),
					ImageTransparency = 0.5
				}):Play()
			end
			if liveTrackParts.BoundScale then
				tweenService:Create(liveTrackParts.BoundScale, TweenInfo.new(0.22, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
					Scale = distance * 0.15
				}):Play()
			end
	end

	if liveTrackParts.Direction then
		liveTrackParts.Direction.BackgroundTransparency = 1
	end
end

function _picker.openLiveTrackPanel(targetPlayer, returnToPicker)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then return end

	ensureLiveTrackPanel()
	liveTrackState.token += 1
	local token = liveTrackState.token
	liveTrackState.active = true
	liveTrackState.targetPlayer = targetPlayer
	liveTrackState.returnToPicker = returnToPicker == true

	if liveTrackState.renderConnection then liveTrackState.renderConnection:Disconnect() end
	if liveTrackState.characterConnection then liveTrackState.characterConnection:Disconnect() end
	if liveTrackState.removingConnection then liveTrackState.removingConnection:Disconnect() end

	liveTrackParts.TargetName.Text = targetPlayer.DisplayName
	liveTrackPanel.Visible = true
	local liveTrackOpenSize = clampLiveTrackSize(liveTrackCurrentSize)
	local liveTrackOpenShadowSize = getLiveTrackShadowSize(liveTrackOpenSize)
	local liveTrackStartSize = Vector2.new(
		math.max(220, liveTrackOpenSize.X - 42),
		math.max(18, math.min(42, liveTrackOpenSize.Y * 0.08))
	)
	liveTrackPanel.Size = UDim2.fromOffset(liveTrackStartSize.X, liveTrackStartSize.Y)
	liveTrackPanel.Position = liveTrackCurrentPosition
	liveTrackPanel.BackgroundTransparency = 1
	if liveTrackParts.OuterShadow then
		liveTrackParts.OuterShadow.Visible = true
		liveTrackParts.OuterShadow.ImageTransparency = 1
		liveTrackParts.OuterShadow.Position = getLiveTrackShadowPosition(liveTrackCurrentPosition, 10)
		liveTrackParts.OuterShadow.Size = UDim2.fromOffset(liveTrackStartSize.X + 38, liveTrackStartSize.Y + 36)
	end
	liveTrackPanel.GroupTransparency = 1
	liveTrackParts.Scale.Scale = 1
	if liveTrackParts.Stroke then
		liveTrackParts.Stroke.Transparency = 1
	end
	if liveTrackParts.Shadow then
		liveTrackParts.Shadow.ImageTransparency = 1
	end
	updateLiveTrackReadout(targetPlayer)

	local panelOpenTween = TweenInfo.new(0.46, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	local panelFadeTween = TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	local contentTween = TweenInfo.new(0.32, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	tweenService:Create(liveTrackPanel, panelOpenTween, {
		Size = UDim2.fromOffset(liveTrackOpenSize.X, liveTrackOpenSize.Y)
	}):Play()
	tweenService:Create(liveTrackPanel, panelFadeTween, {
		BackgroundTransparency = 0
	}):Play()
	if liveTrackParts.Shadow then
		tweenService:Create(liveTrackParts.Shadow, panelFadeTween, {
			ImageTransparency = 1
		}):Play()
	end
	if liveTrackParts.Stroke then
		tweenService:Create(liveTrackParts.Stroke, panelFadeTween, {Transparency = 0.48}):Play()
	end
	if liveTrackParts.OuterShadow then
		tweenService:Create(liveTrackParts.OuterShadow, panelOpenTween, {
			Size = UDim2.fromOffset(liveTrackOpenShadowSize.X, liveTrackOpenShadowSize.Y),
			Position = getLiveTrackShadowPosition(liveTrackCurrentPosition, 20)
		}):Play()
		tweenService:Create(liveTrackParts.OuterShadow, panelFadeTween, {
			ImageTransparency = 0.78
		}):Play()
	end

	task.delay(0.1, function()
		if token == liveTrackState.token and liveTrackState.active and liveTrackPanel then
			tweenService:Create(liveTrackPanel, contentTween, {GroupTransparency = 0}):Play()
		end
	end)

		liveTrackState.renderConnection = runService.RenderStepped:Connect(function(deltaTime)
			if token ~= liveTrackState.token or not liveTrackState.active then return end
			updateLiveTrackReadout(targetPlayer, deltaTime)
		end)

	liveTrackState.characterConnection = targetPlayer.CharacterAdded:Connect(function()
		task.wait(0.2)
		if token == liveTrackState.token and liveTrackState.active and liveTrackState.targetPlayer == targetPlayer then
			updateLiveTrackReadout(targetPlayer)
		end
	end)

	liveTrackState.removingConnection = players.PlayerRemoving:Connect(function(removingPlayer)
			if removingPlayer == targetPlayer then
				_picker.closeLiveTrackPanel(false)
				queueNotification("Live Track Ended", targetPlayer.DisplayName.." left the server.")
			end
		end)
	end

function _picker.createTrackingBadge(targetPlayer)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then return end

	ensureTrackingFolder()

	if trackingBadges[targetPlayer] then
		local root = _picker.getTrackingRoot(targetPlayer)
		if root then
			trackingBadges[targetPlayer].Adornee = root
		end
		return trackingBadges[targetPlayer]
	end

	local root = _picker.getTrackingRoot(targetPlayer)
	if not root then
		queueNotification("Track Unavailable", "Sirius cannot find "..targetPlayer.DisplayName.."'s character right now.")
		return
	end

		local badge = Instance.new("BillboardGui")
		badge.Name = "SiriusTrackBadge_"..targetPlayer.Name
		badge.Adornee = root
		badge.AlwaysOnTop = true
		badge.Size = UDim2.fromOffset(100, 100)
		badge.StudsOffsetWorldSpace = Vector3.new(0, 5, 0)
		badge.LightInfluence = 1
		badge.MaxDistance = math.huge
		badge.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
		badge.Parent = trackingFolder

		local shadow = Instance.new("ImageLabel")
		shadow.Name = "Shadow"
		shadow.AnchorPoint = Vector2.new(0.5, 0.5)
		shadow.Position = UDim2.fromScale(0.5, 0.5)
		shadow.Size = UDim2.fromOffset(70, 70)
		shadow.BackgroundTransparency = 1
		shadow.Image = "rbxassetid://122971705612181"
		shadow.ImageColor3 = Color3.fromRGB(0, 0, 0)
		shadow.ImageTransparency = 1
		shadow.ScaleType = Enum.ScaleType.Fit
		shadow.ZIndex = 1
		shadow.Parent = badge

		local shadowScale = Instance.new("UIScale")
		shadowScale.Name = "scale"
		shadowScale.Scale = 1
		shadowScale.Parent = shadow

		local button = Instance.new("ImageButton")
		button.Name = "Badge"
		button.AnchorPoint = Vector2.new(0.5, 0.5)
		button.Position = UDim2.fromScale(0.5, 0.5)
		button.Size = UDim2.fromOffset(50, 50)
		button.BackgroundTransparency = 1
		button.BorderSizePixel = 0
		button.Image = "rbxassetid://92562308197003"
		button.ImageColor3 = Color3.fromRGB(27, 27, 27)
		button.ImageTransparency = 0
		button.ScaleType = Enum.ScaleType.Slice
		button.SliceCenter = Rect.new(50, 50, 50, 50)
		button.AutoButtonColor = false
		button.ZIndex = 2
		button.Parent = shadow

		local buttonScale = Instance.new("UIScale")
		buttonScale.Scale = 0.6
		buttonScale.Parent = button

		local photo = Instance.new("ImageLabel")
		photo.Name = "Photo"
		photo.AnchorPoint = Vector2.new(0.5, 0.5)
		photo.Position = UDim2.fromScale(0.5, 0.5)
		photo.Size = UDim2.fromOffset(30, 30)
		photo.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
		photo.BackgroundTransparency = 0.9
		photo.BorderSizePixel = 0
		photo.Image = "https://www.roblox.com/headshot-thumbnail/image?userId="..targetPlayer.UserId.."&width=420&height=420&format=png"
		photo.ZIndex = 3
		photo.Parent = button

		local photoCorner = Instance.new("UICorner")
		photoCorner.CornerRadius = UDim.new(1, 0)
		photoCorner.Parent = photo

		button.MouseEnter:Connect(function()
			tweenService:Create(shadow, TweenInfo.new(0.2, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {ImageTransparency = 0.18, Size = UDim2.fromOffset(82, 82)}):Play()
			tweenService:Create(shadowScale, TweenInfo.new(0.2, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Scale = 1.08}):Play()
			tweenService:Create(buttonScale, TweenInfo.new(0.2, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Scale = 1.08}):Play()
			tweenService:Create(photo, TweenInfo.new(0.2, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Size = UDim2.fromOffset(33, 33)}):Play()
		end)

		button.MouseLeave:Connect(function()
			tweenService:Create(shadow, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {ImageTransparency = 1, Size = UDim2.fromOffset(70, 70)}):Play()
			tweenService:Create(shadowScale, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Scale = 1}):Play()
			tweenService:Create(buttonScale, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Scale = 1}):Play()
			tweenService:Create(photo, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Size = UDim2.fromOffset(30, 30)}):Play()
		end)

	button.MouseButton1Click:Connect(function()
		tweenService:Create(buttonScale, TweenInfo.new(0.08, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {Scale = 0.94}):Play()
		task.delay(0.08, function()
			if trackingBadges[targetPlayer] then
				tweenService:Create(buttonScale, TweenInfo.new(0.12, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {Scale = 1.06}):Play()
				_picker.openLiveTrackPanel(targetPlayer)
			end
		end)
	end)

	trackingBadges[targetPlayer] = badge
	trackingConnections[targetPlayer] = {
		targetPlayer.CharacterAdded:Connect(function()
			task.wait(0.2)
			local newRoot = _picker.getTrackingRoot(targetPlayer)
			if newRoot and trackingBadges[targetPlayer] then
				trackingBadges[targetPlayer].Adornee = newRoot
			end
		end),
		players.PlayerRemoving:Connect(function(removingPlayer)
			if removingPlayer == targetPlayer then
				_picker.destroyTrackingBadge(targetPlayer)
				if liveTrackState.targetPlayer == targetPlayer then
					_picker.closeLiveTrackPanel()
				end
			end
		end)
	}

	tweenService:Create(buttonScale, TweenInfo.new(0.24, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {Scale = 1}):Play()

	return badge
end

function _picker.startTrackingPlayer(targetPlayer)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then return end

	if trackingBadges[targetPlayer] then
		_picker.destroyTrackingBadge(targetPlayer)
		if liveTrackState.targetPlayer == targetPlayer then
			_picker.closeLiveTrackPanel()
		end
		queueNotification("Tracking Disabled", targetPlayer.DisplayName.."'s marker was removed.")
		return
	end

	_picker.createTrackingBadge(targetPlayer)
	queueNotification("Tracking Enabled", targetPlayer.DisplayName.." now has a live marker.")
end

function _picker.startLiveTrackingPlayer(targetPlayer, returnToPicker)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then return end

	_picker.createTrackingBadge(targetPlayer)
	_picker.openLiveTrackPanel(targetPlayer, returnToPicker)
end

function _picker.setPlayerEsp(targetPlayer, enabled)
	if not targetPlayer or targetPlayer == localPlayer then return false end

	locatedPlayers[targetPlayer.Name] = enabled == true or nil

	local highlight = espContainer and espContainer:FindFirstChild(targetPlayer.Name)
	if not highlight then
		createEsp(targetPlayer)
		highlight = espContainer and espContainer:FindFirstChild(targetPlayer.Name)
	end

	if highlight then
		highlight.Enabled = isHighlightEnabledFor(targetPlayer.Name)
	end

	return locatedPlayers[targetPlayer.Name] == true
end

function _picker.togglePlayerEsp(targetPlayer)
	if not targetPlayer or targetPlayer == localPlayer or not players:FindFirstChild(targetPlayer.Name) then return false end

	local enabled = _picker.setPlayerEsp(targetPlayer, locatedPlayers[targetPlayer.Name] ~= true)
	queueNotification(
		enabled and "ESP Enabled" or "ESP Disabled",
		enabled and (targetPlayer.DisplayName.." is now highlighted.") or (targetPlayer.DisplayName.."'s personal highlight was removed.")
	)
	return enabled
end

function _picker.updatePlayerActionPickerSelection()
	return
end

	function _picker.closePlayerActionPicker(skipRestore, afterClose)
		if type(skipRestore) == "function" then
			afterClose = skipRestore
			skipRestore = nil
		end
		if not playerActionPicker or not playerActionPickerState.open then return end

		playerActionPickerState.token += 1
		local token = playerActionPickerState.token
		playerActionPickerState.open = false
		playerActionPickerState.targetPlayer = nil
		playerActionPickerState.restorePanel = nil

			local panel = playerActionPickerParts.Panel
			local contentFadeTween = TweenInfo.new(0.14, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
			local panelCloseTween = TweenInfo.new(0.3, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut)
			local panelFadeTween = TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.In)
			local currentWidth = panel.AbsoluteSize.X > 0 and panel.AbsoluteSize.X or playerActionPickerCurrentSize.X
			local closeWidth = math.max(260, currentWidth - 28)
			local closeSize = UDim2.fromOffset(closeWidth, 18)
			local closeShadowSize = UDim2.fromOffset(closeWidth + 40, 56)

			if playerActionPickerParts.Content then
				tweenService:Create(playerActionPickerParts.Content, contentFadeTween, {
					GroupTransparency = 1
				}):Play()
			end
			tweenService:Create(panel, panelCloseTween, {
				Size = closeSize
			}):Play()
			tweenService:Create(panel, panelFadeTween, {
				BackgroundTransparency = 1
			}):Play()
			if playerActionPickerParts.Shadow then
				tweenService:Create(playerActionPickerParts.Shadow, panelCloseTween, {
					Position = UDim2.new(0.5, 0, 0.5, 16),
					Size = closeShadowSize
				}):Play()
				tweenService:Create(playerActionPickerParts.Shadow, panelFadeTween, {
					ImageTransparency = 1
				}):Play()
			end
			if playerActionPickerParts.Stroke then
				tweenService:Create(playerActionPickerParts.Stroke, panelFadeTween, {Transparency = 1}):Play()
			end
			if playerActionPickerParts.PanelScale then
				tweenService:Create(playerActionPickerParts.PanelScale, panelCloseTween, {Scale = 1}):Play()
			end

			task.delay(0.32, function()
	                if token == playerActionPickerState.token and playerActionPicker then
	                    playerActionPicker.Visible = false
					panel.Size = UDim2.fromOffset(playerActionPickerCurrentSize.X, playerActionPickerCurrentSize.Y)
					panel.BackgroundTransparency = 0
					if playerActionPickerParts.PanelScale then
						playerActionPickerParts.PanelScale.Scale = 1
					end
	                    if afterClose then
						afterClose()
					end
				end
		end)
	end

	function _picker.closePlayerActionPickerToSpectate(targetPlayer)
		if not targetPlayer or not players:FindFirstChild(targetPlayer.Name) then return end
		if spectateMorphState.active then return end
		if not playerActionPicker or not playerActionPickerState.open then
			startSpectating(targetPlayer, false)
			return
		end

		ensureSpectateBar()
		spectateBar.Visible = false
		resetSpectateBarGeometry()

		playerActionPickerState.token += 1
		local token = playerActionPickerState.token
		playerActionPickerState.open = false
		playerActionPickerState.targetPlayer = nil
		playerActionPickerState.restorePanel = nil

		local panel = playerActionPickerParts.Panel
		local content = playerActionPickerParts.Content
		local targetPosition, targetSize = getSpectateTogglePickerGeometry()
		local fadeDuration = 0.08
		local morphDuration = 0.26
		local startPosition = panel.Position
		local startSize = Vector2.new(panel.AbsoluteSize.X, panel.AbsoluteSize.Y)
		if startSize.X <= 0 or startSize.Y <= 0 then
			startPosition, startSize = getPlayerActionPickerGeometry()
		end

		if content then
			tweenService:Create(content, TweenInfo.new(fadeDuration, Enum.EasingStyle.Sine, Enum.EasingDirection.In), {
				GroupTransparency = 1
			}):Play()
		end

		task.delay(fadeDuration + 0.01, function()
			if token ~= playerActionPickerState.token or not playerActionPicker then return end

			playerActionPicker.Visible = false
			panel.Position = UDim2.new(0.5, 0, 0.5, 0)
			panel.Size = UDim2.fromOffset(playerActionPickerCurrentSize.X, playerActionPickerCurrentSize.Y)
			panel.BackgroundColor3 = siriusValues.selectActionStyle.panel
			panel.BackgroundTransparency = 0
			if playerActionPickerParts.Stroke then
				playerActionPickerParts.Stroke.Transparency = 0.18
			end
			if playerActionPickerParts.Shadow then
				playerActionPickerParts.Shadow.Position = UDim2.new(0.5, 0, 0.5, 12)
				playerActionPickerParts.Shadow.Size = UDim2.fromOffset(playerActionPickerCurrentSize.X + 58, playerActionPickerCurrentSize.Y + 58)
				playerActionPickerParts.Shadow.ImageTransparency = 0.82
			end
			if playerActionPickerParts.PanelScale then
				playerActionPickerParts.PanelScale.Scale = 1
			end

			playSpectateGhostMorph(startPosition, startSize, targetPosition, targetSize, morphDuration, "to-toggle", function()
				if token ~= playerActionPickerState.token then return end
				if targetPlayer and players:FindFirstChild(targetPlayer.Name) then
					startSpectating(targetPlayer, true)
				end
			end)
		end)
	end

	playerActionPickerParts.TeleportCallback = function(targetPlayer)
		if targetPlayer and players:FindFirstChild(targetPlayer.Name) then
			return playerActionPickerParts.TeleportToSelected(targetPlayer)
		end

		return false
	end

