		profile.RoleValue.Name = "Value"
		profile.RoleValue.Position = UDim2.new(0, 10, 0, 21)
		profile.RoleValue.Size = UDim2.new(1, -20, 0, 18)
		profile.RoleValue.BackgroundTransparency = 1
		profile.RoleValue.Text = "Neutral"
		profile.RoleValue.TextColor3 = siriusValues.selectActionStyle.text
		profile.RoleValue.TextSize = 13
		profile.RoleValue.TextXAlignment = Enum.TextXAlignment.Left
