		local pickerDragging = false
		local pickerResizing = false
		local dragStart
		local dragStartPosition
		local activeResizeInput
		local resizeHandleHover = false
		local resizeStartPointer
		local resizePointerPosition
		local resizeStartSize
		local resizeStartCenter
		local activeResizeIcon
		local resizePanelTween
		local resizeShadowTween
		local resizeSmoothConnection
		local resizeTargetCenter
		local resizeTargetSize
		local resizeVisualCenter
		local resizeVisualSize
		local resizeGuiInsetOffset = Vector2.zero
		local resetActiveResizeIcon = function() end
		local resizeStyle = {
			idleSize = UDim2.fromOffset(18, 18),
			baseSize = 20,
			growRange = 30,
			idleTransparency = 0.72,
			hoverTransparency = 0,
			pressTransparency = 0,
			color = Color3.fromRGB(59, 59, 59),
			pressColor = Color3.fromRGB(82, 82, 82),
			followSpeed = 26,
			settleSpeed = 18,
		}

		local function getPickerRootSize()
			local rootSize = camera.ViewportSize
			pcall(function()
				if UI.AbsoluteSize.X > 0 and UI.AbsoluteSize.Y > 0 then
					rootSize = UI.AbsoluteSize
				end
			end)
			return rootSize
		end

		local function isDragInput(input)
			return input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch
		end

		local function syncPickerShadow()
			if not shadow or not panel then return end
			shadow.Position = UDim2.fromOffset(panel.AbsolutePosition.X + panel.AbsoluteSize.X * 0.5, panel.AbsolutePosition.Y + panel.AbsoluteSize.Y * 0.5 + 16)
			shadow.Size = UDim2.fromOffset(panel.AbsoluteSize.X + 76, panel.AbsoluteSize.Y + 78)
		end

		local function lerpVector2(from, to, alpha)
			return from + (to - from) * alpha
		end

		local function refreshPickerGuiInsetOffset()
			resizeGuiInsetOffset = Vector2.zero
			local ownerGui = panel:FindFirstAncestorWhichIsA("ScreenGui")
			if ownerGui and ownerGui.IgnoreGuiInset then
				local inset = guiService:GetGuiInset()
				resizeGuiInsetOffset += inset
			end
		end

		local function pointerVectorFromInput(input)
			if input and input.UserInputType == Enum.UserInputType.Touch then
				return Vector2.new(input.Position.X, input.Position.Y) + resizeGuiInsetOffset
			end

			return userInputService:GetMouseLocation() + resizeGuiInsetOffset
		end

		local function currentResizePointer()
			local mouseLocation = userInputService:GetMouseLocation()
			local guiInset = guiService:GetGuiInset()
			return Vector2.new(mouseLocation.X, mouseLocation.Y - guiInset.Y)
		end

		local function resizeVisualPointerFromInput(input)
			if input and input.UserInputType == Enum.UserInputType.Touch then
				local guiInset = guiService:GetGuiInset()
				return Vector2.new(input.Position.X, input.Position.Y - guiInset.Y)
			end

			return currentResizePointer()
		end

		local function applyPickerResizeGeometry(center, size, animated)
			size = clampPlayerActionPickerSize(size)
			playerActionPickerCurrentSize = size
			if resizePanelTween then
				resizePanelTween:Cancel()
				resizePanelTween = nil
			end
			if resizeShadowTween then
				resizeShadowTween:Cancel()
				resizeShadowTween = nil
			end

			local panelGoal = {
				Position = UDim2.fromOffset(center.X, center.Y),
				Size = UDim2.fromOffset(size.X, size.Y)
			}
			local shadowGoal = {
				Position = UDim2.fromOffset(center.X, center.Y + 16),
				Size = UDim2.fromOffset(size.X + 76, size.Y + 78)
			}

			if animated then
				local resizeInfo = TweenInfo.new(0.045, Enum.EasingStyle.Sine, Enum.EasingDirection.Out)
				resizePanelTween = tweenService:Create(panel, resizeInfo, panelGoal)
				resizePanelTween:Play()
				if shadow then
					resizeShadowTween = tweenService:Create(shadow, resizeInfo, shadowGoal)
					resizeShadowTween:Play()
				end
			else
				panel.Position = panelGoal.Position
				panel.Size = panelGoal.Size
				if shadow then
					shadow.Position = shadowGoal.Position
					shadow.Size = shadowGoal.Size
				end
			end
		end

		local function stopPickerResizeSmoothing(applyFinal)
			if resizeSmoothConnection then
				resizeSmoothConnection:Disconnect()
				resizeSmoothConnection = nil
			end
			if applyFinal and resizeTargetCenter and resizeTargetSize then
				applyPickerResizeGeometry(resizeTargetCenter, resizeTargetSize, false)
			end
			resizeTargetCenter = nil
			resizeTargetSize = nil
			resizeVisualCenter = nil
			resizeVisualSize = nil
		end

		local function startPickerResizeSmoothing()
			if resizeSmoothConnection then return end
			resizeSmoothConnection = runService.RenderStepped:Connect(function(deltaTime)
				if not resizeTargetCenter or not resizeTargetSize then
					stopPickerResizeSmoothing(false)
					return
				end
				resizeVisualCenter = resizeVisualCenter or resizeTargetCenter
				resizeVisualSize = resizeVisualSize or resizeTargetSize
				local speed = pickerResizing and resizeStyle.followSpeed or resizeStyle.settleSpeed
				local alpha = math.clamp(1 - math.exp(-deltaTime * speed), 0, 1)
				resizeVisualCenter = lerpVector2(resizeVisualCenter, resizeTargetCenter, alpha)
				resizeVisualSize = lerpVector2(resizeVisualSize, resizeTargetSize, alpha)
				if (resizeVisualSize - resizeTargetSize).Magnitude <= 0.75 then
					resizeVisualCenter = resizeTargetCenter
					resizeVisualSize = resizeTargetSize
					applyPickerResizeGeometry(resizeVisualCenter, resizeVisualSize, false)
					if not pickerResizing then
						stopPickerResizeSmoothing(false)
					end
					return
				end
				applyPickerResizeGeometry(resizeVisualCenter, resizeVisualSize, false)
			end)
		end

		dragArea.InputBegan:Connect(function(input, processed)
			if processed or not isDragInput(input) then return end
			if pickerResizing then return end
			pickerDragging = true
			dragStart = Vector2.new(input.Position.X, input.Position.Y)
			dragStartPosition = panel.Position
		end)

		userInputService.InputChanged:Connect(function(input)
			if not pickerDragging or not playerActionPickerState.open then return end
			if input.UserInputType ~= Enum.UserInputType.MouseMovement and input.UserInputType ~= Enum.UserInputType.Touch then return end
			if not dragStart or not dragStartPosition then return end

			local rootSize = getPickerRootSize()
			local panelSize = panel.AbsoluteSize
			local delta = Vector2.new(input.Position.X, input.Position.Y) - dragStart
			local startCenter = Vector2.new(dragStartPosition.X.Offset, dragStartPosition.Y.Offset)

			if dragStartPosition.X.Scale ~= 0 or dragStartPosition.Y.Scale ~= 0 then
				startCenter = Vector2.new(rootSize.X * dragStartPosition.X.Scale + dragStartPosition.X.Offset, rootSize.Y * dragStartPosition.Y.Scale + dragStartPosition.Y.Offset)
			end

			local nextCenter = startCenter + delta
			nextCenter = Vector2.new(
				math.clamp(nextCenter.X, panelSize.X * 0.5 - 80, rootSize.X - panelSize.X * 0.5 + 80),
				math.clamp(nextCenter.Y, panelSize.Y * 0.5 - 40, rootSize.Y - panelSize.Y * 0.5 + 80)
			)
			panel.Position = UDim2.fromOffset(nextCenter.X, nextCenter.Y)
			syncPickerShadow()
		end)

		userInputService.InputEnded:Connect(function(input)
			if not isDragInput(input) then return end
			if activeResizeInput and activeResizeInput.UserInputType == Enum.UserInputType.Touch and input ~= activeResizeInput then
				return
			end
			pickerDragging = false
			if pickerResizing then
				pickerResizing = false
				activeResizeInput = nil
				if resizeHandleHover then
					if activeResizeIcon then
						local pointer = currentResizePointer()
						local handleSize = activeResizeIcon.Parent and activeResizeIcon.Parent.AbsoluteSize or Vector2.zero
						local relative = activeResizeIcon.Parent and (pointer - activeResizeIcon.Parent.AbsolutePosition) or Vector2.zero
						local x = 1 - math.clamp(relative.X / math.max(handleSize.X, 1), 0, 1)
						local y = 1 - math.clamp(relative.Y / math.max(handleSize.Y, 1), 0, 1)
						tweenService:Create(activeResizeIcon, TweenInfo.new(0.5, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
							ImageColor3 = resizeStyle.color,
							ImageTransparency = resizeStyle.hoverTransparency,
							Size = UDim2.fromOffset(
								math.floor(resizeStyle.baseSize + (x * resizeStyle.growRange) + 0.5),
								math.floor(resizeStyle.baseSize + (y * resizeStyle.growRange) + 0.5)
							)
						}):Play()
					end
				else
					resetActiveResizeIcon()
				end
			end
			dragStart = nil
			dragStartPosition = nil
			resizeStartPointer = nil
			resizePointerPosition = nil
			resizeStartSize = nil
			resizeStartCenter = nil
			activeResizeIcon = nil
		end)

		local function normalizedResizeCursorPosition(button, pointer)
			local sample = pointer or currentResizePointer()
			local buttonPosition = button.AbsolutePosition
			local buttonSize = button.AbsoluteSize
			local relativeX = (sample.X - buttonPosition.X) / math.max(buttonSize.X, 1)
			local relativeY = (sample.Y - buttonPosition.Y) / math.max(buttonSize.Y, 1)
			return Vector2.new(1 - math.clamp(relativeX, 0, 1), 1 - math.clamp(relativeY, 0, 1))
		end

		local function resizeIconSizeFromPointer(button, pointer)
			local normals = normalizedResizeCursorPosition(button, pointer)
			return UDim2.fromOffset(
				math.floor(resizeStyle.baseSize + (normals.X * resizeStyle.growRange) + 0.5),
				math.floor(resizeStyle.baseSize + (normals.Y * resizeStyle.growRange) + 0.5)
			)
		end

		local function setResizeHandleVisual(icon, mode, duration, pointer)
			if not icon or not icon.Parent then return end
			local goals
			if mode == "pressed" then
				goals = {
					ImageColor3 = resizeStyle.pressColor,
					ImageTransparency = resizeStyle.pressTransparency,
					Size = resizeIconSizeFromPointer(icon.Parent, pointer),
				}
			elseif mode == "hover" then
				goals = {
					ImageColor3 = resizeStyle.color,
					ImageTransparency = resizeStyle.hoverTransparency,
					Size = resizeIconSizeFromPointer(icon.Parent, pointer),
				}
			else
				goals = {
					ImageColor3 = resizeStyle.color,
					ImageTransparency = resizeStyle.idleTransparency,
					Size = resizeStyle.idleSize,
				}
			end

			local animationDuration = duration
			if animationDuration == nil then
				animationDuration = 0.5
			end
			if animationDuration == 0 then
				for property, value in pairs(goals) do
					icon[property] = value
				end
				return
			end

			tweenService:Create(icon, TweenInfo.new(animationDuration, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), goals):Play()
		end

		resetActiveResizeIcon = function()
			setResizeHandleVisual(activeResizeIcon, "idle", 0.18)
		end

		local function beginPickerResize(input, direction, icon)
			pickerDragging = false
			pickerResizing = true
			activeResizeIcon = icon
			activeResizeInput = input
			if resizePanelTween then
				resizePanelTween:Cancel()
				resizePanelTween = nil
			end
			if resizeShadowTween then
				resizeShadowTween:Cancel()
				resizeShadowTween = nil
			end
			refreshPickerGuiInsetOffset()
			resizeStartPointer = pointerVectorFromInput(input)
			resizePointerPosition = resizeStartPointer
			resizeStartSize = panel.AbsoluteSize
			local rootSize = getPickerRootSize()
			resizeStartCenter = Vector2.new(panel.Position.X.Offset, panel.Position.Y.Offset)
			if panel.Position.X.Scale ~= 0 or panel.Position.Y.Scale ~= 0 then
				resizeStartCenter = Vector2.new(
					rootSize.X * panel.Position.X.Scale + panel.Position.X.Offset,
					rootSize.Y * panel.Position.Y.Scale + panel.Position.Y.Offset
				)
			end
			resizeTargetCenter = resizeStartCenter
			resizeTargetSize = resizeStartSize
			resizeVisualCenter = resizeStartCenter
			resizeVisualSize = resizeStartSize
			startPickerResizeSmoothing()
		end

		local function createResizeHandle(name, anchor, position, iconAnchor, iconPosition, rotation, direction)
			local handle = Instance.new("ImageButton")
			handle.Name = name
			handle.AnchorPoint = anchor
			handle.Position = position
			handle.Size = UDim2.new(0, 50, 0, 50)
			handle.BackgroundTransparency = 1
			handle.BorderSizePixel = 0
			handle.AutoButtonColor = false
			handle.Image = ""
			handle.ImageTransparency = 1
			handle.Active = true
			handle.ZIndex = 83
			handle.Parent = content

			local icon = Instance.new("ImageLabel")
			icon.Name = "Icon"
			icon.AnchorPoint = iconAnchor
			icon.Position = iconPosition
			icon.Size = UDim2.fromOffset(18, 18)
			icon.BackgroundTransparency = 1
			icon.Image = "rbxassetid://86527207319523"
			icon.ImageColor3 = resizeStyle.color
			icon.ImageTransparency = resizeStyle.idleTransparency
			icon.Rotation = rotation
			icon.ScaleType = Enum.ScaleType.Slice
			icon.SliceCenter = Rect.new(51, 52, 51, 52)
			icon.SliceScale = 0.5
			icon.ZIndex = 84
			icon.Parent = handle

			handle.InputBegan:Connect(function(input, processed)
				if processed or not isDragInput(input) then return end
				beginPickerResize(input, direction, icon)
				setResizeHandleVisual(icon, "pressed", nil, resizeVisualPointerFromInput(input))
			end)

			handle.MouseEnter:Connect(function()
				resizeHandleHover = true
				if pickerResizing then return end
				setResizeHandleVisual(icon, "hover", nil, currentResizePointer())
			end)

			handle.MouseLeave:Connect(function()
				resizeHandleHover = false
				if pickerResizing then return end
				setResizeHandleVisual(icon, "idle")
			end)

			handle.InputChanged:Connect(function(input)
				if input.UserInputType ~= Enum.UserInputType.MouseMovement and input.UserInputType ~= Enum.UserInputType.Touch then return end
				if pickerResizing then return end
				setResizeHandleVisual(icon, "hover", nil, resizeVisualPointerFromInput(input))
			end)

			return handle, icon
		end

		local resizeBottomRight, resizeBottomRightIcon = createResizeHandle("ResizeBottomRight", Vector2.new(1, 1), UDim2.fromScale(1, 1), Vector2.new(1, 1), UDim2.new(1, -8, 1, -8), 0, "BottomRight")

		userInputService.InputChanged:Connect(function(input)
			if not pickerResizing or not playerActionPickerState.open then return end
			if input.UserInputType ~= Enum.UserInputType.MouseMovement and input.UserInputType ~= Enum.UserInputType.Touch then return end
			if activeResizeInput and activeResizeInput.UserInputType == Enum.UserInputType.Touch and input ~= activeResizeInput then
				return
			end
			if not resizeStartPointer or not resizeStartSize or not resizeStartCenter then return end

			local rootSize = getPickerRootSize()
			resizePointerPosition = pointerVectorFromInput(input)
			local delta = resizePointerPosition - resizeStartPointer
			local maxWidth = math.min(playerActionPickerMaxSize.X, math.max(playerActionPickerMinSize.X, rootSize.X - 80))
			local maxHeight = math.min(playerActionPickerMaxSize.Y, math.max(playerActionPickerMinSize.Y, rootSize.Y - 80))
			local nextWidth = math.clamp(resizeStartSize.X + (delta.X * 2), playerActionPickerMinSize.X, maxWidth)
			local nextHeight = math.clamp(resizeStartSize.Y + (delta.Y * 2), playerActionPickerMinSize.Y, maxHeight)
			local aspect = nextWidth / math.max(nextHeight, 1)
			if aspect > 1.16 then
				nextWidth = math.clamp(nextHeight * 1.16, playerActionPickerMinSize.X, maxWidth)
			elseif aspect < 0.62 then
				nextHeight = math.clamp(nextWidth / 0.62, playerActionPickerMinSize.Y, maxHeight)
			end
			local nextCenter = Vector2.new(
				math.clamp(resizeStartCenter.X, nextWidth * 0.5 - 80, rootSize.X - nextWidth * 0.5 + 80),
				math.clamp(resizeStartCenter.Y, nextHeight * 0.5 - 40, rootSize.Y - nextHeight * 0.5 + 80)
			)
			setResizeHandleVisual(activeResizeIcon, "pressed", nil, resizeVisualPointerFromInput(input))
			resizeTargetCenter = nextCenter
			resizeTargetSize = Vector2.new(nextWidth, nextHeight)
			startPickerResizeSmoothing()
		end)

		local actionScroll = Instance.new("ScrollingFrame")
		actionScroll.Name = "ActionScroll"
		actionScroll.Position = UDim2.new(0, 26, 0, 18)
		actionScroll.Size = UDim2.new(1, -52, 1, -36)
		actionScroll.BackgroundTransparency = 1
		actionScroll.BorderSizePixel = 0
		actionScroll.CanvasSize = UDim2.fromOffset(0, 1480)
		actionScroll.ScrollBarThickness = 0
		actionScroll.ScrollingDirection = Enum.ScrollingDirection.Y
		actionScroll.ClipsDescendants = true
		actionScroll.Active = true
		actionScroll.ZIndex = 71
		actionScroll.Parent = content

		profile.Card.Position = UDim2.new(0, 0, 0, 0)
		profile.Card.Size = UDim2.new(1, 0, 0, 150)
		profile.Card.Parent = actionScroll

		local actionScrollFadeState = {Top = -1, Bottom = -1}

		local function getActionRowFadeGroup(row)
			if not row then return nil end
			local existing = row:FindFirstChild("FadeGroup")
			if existing and existing:IsA("CanvasGroup") then
				return existing
			end

			local fadeGroup = Instance.new("CanvasGroup")
			fadeGroup.Name = "FadeGroup"
			fadeGroup.Size = UDim2.fromScale(1, 1)
			fadeGroup.BackgroundTransparency = 1
			fadeGroup.BorderSizePixel = 0
			fadeGroup.GroupTransparency = 0
			fadeGroup.ClipsDescendants = true
			fadeGroup.Active = false
			fadeGroup.ZIndex = row.ZIndex + 1
			fadeGroup.Parent = row

			for _, child in ipairs(row:GetChildren()) do
				if child ~= fadeGroup and child:IsA("GuiObject") then
					child.Parent = fadeGroup
				end
			end

			return fadeGroup
		end

		local function getActionRowVisualParent(row)
			return getActionRowFadeGroup(row) or row
		end

		local function createActionScrollBlurEdge(name, anchorPoint, position, size, direction)
			local isTop = direction == "Top"
			local edgeColor = siriusValues.selectActionStyle.panel

			local edge = Instance.new("Frame")
			edge.Name = name
			edge.AnchorPoint = anchorPoint
			edge.Position = position
			edge.Size = size
			edge.BackgroundTransparency = 1
			edge.BorderSizePixel = 0
			edge.ClipsDescendants = true
			edge.Active = false
			edge.Visible = false
			edge.ZIndex = 77
			edge.Parent = content

			siriusValues.addSelectActionCorner(edge, siriusValues.selectActionStyle.panelCorner)

			-- Soft depth halo so rows appear to sink under the edge without duplicating text.
			local blurSmear = Instance.new("ImageLabel")
			blurSmear.Name = "BlurSmear"
			blurSmear.AnchorPoint = Vector2.new(0.5, isTop and 0 or 1)
			blurSmear.Position = UDim2.new(0.5, 0, isTop and 0 or 1, 0)
			blurSmear.Size = UDim2.fromScale(1, 0.28)
			blurSmear.BackgroundTransparency = 1
			blurSmear.Image = "rbxassetid://8992230677"
			blurSmear.ImageColor3 = Color3.fromRGB(10, 10, 10)
			blurSmear.ImageTransparency = 1
			blurSmear.ScaleType = Enum.ScaleType.Slice
			blurSmear.SliceCenter = Rect.new(99, 99, 99, 99)
			blurSmear.ZIndex = 77
			blurSmear.Parent = edge

			-- Primary scrim: dissolves the scroll content cleanly into the panel colour.
			local base = Instance.new("Frame")
			base.Name = "Base"
			base.Size = UDim2.fromScale(1, 1)
			base.BackgroundColor3 = edgeColor
			base.BackgroundTransparency = 1
			base.BorderSizePixel = 0
			base.ZIndex = 78
			base.Parent = edge

			siriusValues.addSelectActionCorner(base, siriusValues.selectActionStyle.panelCorner)

			-- Solid at the very edge, easing out smoothly toward the centre of the list.
			local baseGradient = Instance.new("UIGradient")
			baseGradient.Rotation = isTop and 90 or -90
			baseGradient.Transparency = NumberSequence.new({
				NumberSequenceKeypoint.new(0, 0),
				NumberSequenceKeypoint.new(0.04, 0.01),
				NumberSequenceKeypoint.new(0.09, 0.14),
				NumberSequenceKeypoint.new(0.14, 0.42),
				NumberSequenceKeypoint.new(0.20, 0.76),
				NumberSequenceKeypoint.new(0.27, 1),
				NumberSequenceKeypoint.new(1, 1)
			})
			baseGradient.Parent = base

			-- Frosted sheen for a subtle glass read hugging the edge.
			local glass = Instance.new("Frame")
			glass.Name = "Glass"
			glass.Size = UDim2.fromScale(1, 1)
			glass.BackgroundColor3 = Color3.fromRGB(32, 32, 34)
			glass.BackgroundTransparency = 1
			glass.BorderSizePixel = 0
			glass.ZIndex = 79
			glass.Parent = edge

			siriusValues.addSelectActionCorner(glass, siriusValues.selectActionStyle.panelCorner)

			local glassGradient = Instance.new("UIGradient")
			glassGradient.Rotation = isTop and 90 or -90
			glassGradient.Transparency = NumberSequence.new({
				NumberSequenceKeypoint.new(0, 0.86),
				NumberSequenceKeypoint.new(0.16, 0.96),
				NumberSequenceKeypoint.new(1, 1)
			})
			glassGradient.Parent = glass

			-- Hairline catch-light that tapers off toward the sides.
			local highlight = Instance.new("Frame")
			highlight.Name = "Highlight"
			highlight.AnchorPoint = Vector2.new(0.5, isTop and 0 or 1)
			highlight.Position = UDim2.new(0.5, 0, isTop and 0 or 1, 0)
			highlight.Size = UDim2.new(1, -22, 0, 1)
			highlight.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
			highlight.BackgroundTransparency = 1
			highlight.BorderSizePixel = 0
			highlight.ZIndex = 80
			highlight.Parent = edge

			local highlightGradient = Instance.new("UIGradient")
			highlightGradient.Transparency = NumberSequence.new({
				NumberSequenceKeypoint.new(0, 1),
				NumberSequenceKeypoint.new(0.5, 0),
				NumberSequenceKeypoint.new(1, 1)
			})
			highlightGradient.Parent = highlight

			return edge
		end

		local actionScrollTopFade = createActionScrollBlurEdge(
			"ActionScrollTopBlur",
			Vector2.new(0, 0),
			UDim2.new(0, 0, 0, 0),
			UDim2.fromScale(1, 1),
			"Top"
		)

		local actionScrollBottomFade = createActionScrollBlurEdge(
			"ActionScrollBottomBlur",
			Vector2.new(0, 0),
			UDim2.new(0, 0, 0, 0),
			UDim2.fromScale(1, 1),
			"Bottom"
		)

		local function setActionScrollFade(frame, key, strength)
			strength = math.clamp(strength or 0, 0, 1)
			-- Smoothstep so the edge eases in as content leaves the boundary,
			-- instead of ramping in linearly with the raw scroll distance.
			local eased = strength * strength * (3 - 2 * strength)
			if math.abs((actionScrollFadeState[key] or 0) - eased) < 0.01 then return end
			actionScrollFadeState[key] = eased

			local base = frame:FindFirstChild("Base")
			local blurSmear = frame:FindFirstChild("BlurSmear")
			local glass = frame:FindFirstChild("Glass")
			local highlight = frame:FindFirstChild("Highlight")

			if eased <= 0.012 then
				if base then base.BackgroundTransparency = 1 end
				if blurSmear then blurSmear.ImageTransparency = 1 end
				if glass then glass.BackgroundTransparency = 1 end
				if highlight then highlight.BackgroundTransparency = 1 end
				frame.Visible = false
				return
			end

			frame.Visible = true
			-- The scrim hides clipping while the glass/shadow layers give a soft-focus edge.
			if base then base.BackgroundTransparency = 1 - math.min(eased * 0.98, 0.98) end
			if blurSmear then blurSmear.ImageTransparency = 1 end
			if glass then glass.BackgroundTransparency = 1 - (eased * 0.035) end
			if highlight then highlight.BackgroundTransparency = 1 - (eased * 0.035) end
		end

		local actionScrollBlurRows = {}

		local function setActionRowEdgeBlur(rowState, strength)
			local row = rowState.Row
			if not row or not row.Parent then return end

			if rowState.Blur then
				rowState.Blur.Visible = false
				rowState.Blur.ImageTransparency = 1
				rowState.Blur.BackgroundTransparency = 1
			end
			if rowState.BlurContent then
				rowState.BlurContent.Visible = false
			end

			local fadeGroup = rowState.FadeGroup
			if not fadeGroup or not fadeGroup.Parent then
				fadeGroup = getActionRowFadeGroup(row)
				rowState.FadeGroup = fadeGroup
			end
			if not fadeGroup then return end

			strength = math.clamp(strength or 0, 0, 1)
			local eased = strength * strength * (3 - 2 * strength)
			local targetTransparency = math.clamp(eased * 0.72, 0, 0.72)
			if math.abs((rowState.FadeStrength or -1) - targetTransparency) < 0.018 then return end

			rowState.FadeStrength = targetTransparency
			row.Active = targetTransparency < 0.68
			if rowState.FadeTween then
				rowState.FadeTween:Cancel()
			end
			rowState.FadeTween = tweenService:Create(fadeGroup, TweenInfo.new(0.12, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
				GroupTransparency = targetTransparency
			})
			rowState.FadeTween:Play()
		end

		local function registerActionScrollBlurRow(row)
			if not row then return end

			local blur = row:FindFirstChild("EdgeBlur")
			if blur then
				blur:Destroy()
			end

			local blurContent = row:FindFirstChild("EdgeBlurContent")
			if blurContent then
				blurContent:Destroy()
			end

			row.ClipsDescendants = true
			local fadeGroup = getActionRowFadeGroup(row)
			table.insert(actionScrollBlurRows, {
				Row = row,
				FadeGroup = fadeGroup,
				FadeStrength = -1,
				Switch = row:FindFirstChild("Switch", true),
				Knob = row:FindFirstChild("Knob", true),
				Strength = -1,
				FadeTween = nil
			})
		end

		local function refreshActionScrollBlurRows()
			if not actionScroll or not actionScroll.Parent then return end
			local viewportTop = actionScroll.AbsolutePosition.Y
			local viewportBottom = viewportTop + actionScroll.AbsoluteWindowSize.Y
			local edgeRange = 96

			for _, rowState in ipairs(actionScrollBlurRows) do
				local row = rowState.Row
				if row and row.Parent then
					rowState.Switch = row:FindFirstChild("Switch", true)
					rowState.Knob = row:FindFirstChild("Knob", true)

					local rowTop = row.AbsolutePosition.Y
					local rowBottom = rowTop + row.AbsoluteSize.Y
					local topStrength = (viewportTop + edgeRange - rowTop) / edgeRange
					local bottomStrength = (rowBottom - (viewportBottom - edgeRange)) / edgeRange
					local strength = math.max(topStrength, bottomStrength, 0)
					setActionRowEdgeBlur(rowState, strength)
				end
			end
		end

		local function refreshActionScrollFades()
			if not actionScroll or not actionScroll.Parent then return end
			local maxY = math.max(0, actionScroll.AbsoluteCanvasSize.Y - actionScroll.AbsoluteWindowSize.Y)
			local currentY = actionScroll.CanvasPosition.Y
			local fadeRange = 76
			setActionScrollFade(actionScrollTopFade, "Top", currentY / fadeRange)
			setActionScrollFade(actionScrollBottomFade, "Bottom", (maxY - currentY) / fadeRange)
			refreshActionScrollBlurRows()
		end

		actionScroll:GetPropertyChangedSignal("CanvasPosition"):Connect(refreshActionScrollFades)
		actionScroll:GetPropertyChangedSignal("AbsoluteCanvasSize"):Connect(refreshActionScrollFades)
		actionScroll:GetPropertyChangedSignal("AbsoluteWindowSize"):Connect(refreshActionScrollFades)
		task.defer(refreshActionScrollFades)

