		local function cloneActionRow(name, label, yPosition, accentColor, iconName, iconSize, callback)
			local clonedRow = actionRow:Clone()
			clonedRow.Name = name
			clonedRow.Position = UDim2.new(0, 0, 0, yPosition)
			clonedRow.Parent = actionScroll

			local clonedStroke = clonedRow:FindFirstChild("stroke")
			local clonedIcon = clonedRow:FindFirstChild("Icon", true)
			local clonedDot = clonedIcon and clonedIcon:FindFirstChild("Dot", true)
			local clonedGlyph = clonedIcon and clonedIcon:FindFirstChild("Glyph", true)
			local clonedGlyphImage = clonedIcon and clonedIcon:FindFirstChild("GlyphImage", true)
			local clonedText = clonedRow:FindFirstChild("Title", true)

			if clonedText then
				clonedText.Text = label
			end
			if clonedDot then
				clonedDot.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
				clonedDot.BackgroundTransparency = 1
			end
			if clonedGlyph then
				clonedGlyph.Text = ""
				clonedGlyph.TextTransparency = 1
				clonedGlyph.TextSize = 19
			end
			if clonedGlyphImage then
				clonedGlyphImage.Image = getSelectActionIcon(iconName)
				clonedGlyphImage.Size = UDim2.fromOffset(iconSize or 21, iconSize or 21)
				clonedGlyphImage.ImageColor3 = Color3.fromRGB(255, 255, 255)
				clonedGlyphImage.ImageTransparency = 0.04
			end

			registerActionScrollBlurRow(clonedRow)

			clonedRow.MouseEnter:Connect(function()
				if not playerActionPickerState.open then return end
				tweenService:Create(clonedRow, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {
					BackgroundColor3 = siriusValues.selectActionStyle.rowHover,
					BackgroundTransparency = 0
				}):Play()
				if clonedStroke then
					tweenService:Create(clonedStroke, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {
						Color = siriusValues.selectActionStyle.strokeHover,
						Transparency = 0.08
					}):Play()
				end
				if clonedIcon then
					tweenService:Create(clonedIcon, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {
						BackgroundColor3 = siriusValues.selectActionStyle.iconHover
					}):Play()
				end
			end)

			clonedRow.MouseLeave:Connect(function()
				tweenService:Create(clonedRow, TweenInfo.new(0.24, Enum.EasingStyle.Quint), {
					BackgroundColor3 = siriusValues.selectActionStyle.row,
					BackgroundTransparency = 0.04
				}):Play()
				if clonedStroke then
					tweenService:Create(clonedStroke, TweenInfo.new(0.24, Enum.EasingStyle.Quint), {
						Color = siriusValues.selectActionStyle.stroke,
						Transparency = 0.18
					}):Play()
				end
				if clonedIcon then
					tweenService:Create(clonedIcon, TweenInfo.new(0.24, Enum.EasingStyle.Quint), {
						BackgroundColor3 = siriusValues.selectActionStyle.icon
					}):Play()
				end
			end)

