								Position = isEnabled and UDim2.new(1, -13, 0.5, 0) or UDim2.new(0, 13, 0.5, 0),
								BackgroundColor3 = isEnabled and Color3.fromRGB(245, 245, 245) or Color3.fromRGB(110, 110, 110)
							}):Play()
						end
					end
					return
				end
				if name == "ESP" then
					if targetPlayer and players:FindFirstChild(targetPlayer.Name) then
						local isEnabled = callback(targetPlayer)
						if playerActionPickerParts.EspSwitch then
							tweenService:Create(playerActionPickerParts.EspSwitch, TweenInfo.new(0.18, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
