						if playerActionPickerParts.EspSwitchStroke then
							tweenService:Create(playerActionPickerParts.EspSwitchStroke, TweenInfo.new(0.18, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
								Color = isEnabled and siriusValues.selectActionStyle.switchStrokeActive or siriusValues.selectActionStyle.switchStroke,
								Transparency = isEnabled and 0.08 or 0.28
