						end
						if playerActionPickerParts.EspKnob then
							tweenService:Create(playerActionPickerParts.EspKnob, TweenInfo.new(0.18, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
								Position = isEnabled and UDim2.new(1, -13, 0.5, 0) or UDim2.new(0, 13, 0.5, 0),
								BackgroundColor3 = isEnabled and Color3.fromRGB(245, 245, 245) or Color3.fromRGB(110, 110, 110)
							}):Play()
						end
					end
					return
				end
				if string.sub(name, 1, 5) == "Wield" then
					if targetPlayer and players:FindFirstChild(targetPlayer.Name) then
						callback(targetPlayer)
						refreshWieldingActionRows(targetPlayer, true)
					end
