						callback(targetPlayer)
					end
				end)
			end)

			return clonedRow, clonedStroke, clonedIcon, clonedText, clonedDot, clonedGlyph, clonedGlyphImage
		end

		local trackRow, trackStroke, trackIcon, trackText, trackDot, trackGlyph, trackGlyphImage = cloneActionRow("Track", "Track", 240, Color3.fromRGB(255, 255, 255), "Track", 21, _picker.startTrackingPlayer)
