		local wieldingRows = {}
		local function addWieldingRow(abilityName, rowName, label, yPosition, iconName, hasSwitch, callback)
			local row, stroke, icon, text, dot, glyph, glyphImage = cloneActionRow(rowName, label, yPosition, Color3.fromRGB(255, 255, 255), iconName, 21, callback)
			local switch, switchStroke, knob
			if hasSwitch then
				switch, switchStroke, knob = createCompactSwitch(row)
				if text then
					text.Size = UDim2.new(1, -138, 0, 24)
				end
			end

			wieldingRows[rowName] = {
				AbilityName = abilityName,
				IconName = iconName,
				Row = row,
				Stroke = stroke,
				Icon = icon,
				Text = text,
				Dot = dot,
				Glyph = glyph,
				GlyphImage = glyphImage,
				Switch = switch,
				SwitchStroke = switchStroke,
				Knob = knob
			}
