	local pickerDragging = false
	local pickerResizing = false
	local dragOffset
	local resizeStartPosition
	local resizeStartSize
	local resizeStartTopLeft

	local function pickerRootSize()
		local rootSize = camera.ViewportSize
		pcall(function()
			if UI.AbsoluteSize.X > 0 and UI.AbsoluteSize.Y > 0 then
				rootSize = UI.AbsoluteSize
			end
		end)
		return rootSize
	end

	local function inputIsPointer(input)
		return input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch
	end

	local function normalizedResizeCursorPosition(button)
		local mouseLocation = userInputService:GetMouseLocation()
		local guiInsetY = 0
		pcall(function()
			guiInsetY = game:GetService("GuiService"):GetGuiInset().Y
		end)
		local buttonPosition = button.AbsolutePosition
		local buttonSize = button.AbsoluteSize
		local correctedMouseY = mouseLocation.Y - guiInsetY
		local relativeX = (mouseLocation.X - buttonPosition.X) / buttonSize.X
		local relativeY = (correctedMouseY - buttonPosition.Y) / buttonSize.Y
		return Vector2.new(1 - math.clamp(relativeX, 0, 1), 1 - math.clamp(relativeY, 0, 1))
	end

	local function resetResizeIcon()
		tweenService:Create(resizeIcon, TweenInfo.new(0.18, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
			Size = UDim2.fromOffset(18, 18),
			ImageColor3 = Color3.fromRGB(59, 59, 59)
		}):Play()
	end

	top.InputBegan:Connect(function(input, processed)
		if processed or not inputIsPointer(input) then return end
		local inputPosition = Vector2.new(input.Position.X, input.Position.Y)
		if inputPosition.X > close.AbsolutePosition.X - 8 then return end

		pickerDragging = true
		dragOffset = inputPosition - panel.AbsolutePosition
	end)

	resizeHandle.InputBegan:Connect(function(input, processed)
		if processed or not inputIsPointer(input) then return end

		pickerResizing = true
		resizeStartPosition = Vector2.new(input.Position.X, input.Position.Y)
		resizeStartSize = panel.AbsoluteSize
		resizeStartTopLeft = panel.AbsolutePosition
		tweenService:Create(resizeIcon, TweenInfo.new(0.12, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
			Size = UDim2.fromOffset(30, 30),
			ImageColor3 = Color3.fromRGB(72, 72, 72)
		}):Play()
	end)

	userInputService.InputEnded:Connect(function(input)
		if not inputIsPointer(input) then return end

		pickerDragging = false
		pickerResizing = false
		resetResizeIcon()
	end)

	userInputService.InputChanged:Connect(function(input)
		if not playerActionPickerState.open then return end

		if pickerDragging and not pickerResizing and (input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch) then
			local rootSize = pickerRootSize()
			local panelSize = panel.AbsoluteSize
			local mousePosition = Vector2.new(input.Position.X, input.Position.Y)
			local topLeft = mousePosition - dragOffset
			local clampedTopLeft = Vector2.new(
				math.clamp(topLeft.X, -80, rootSize.X - panelSize.X + 80),
				math.clamp(topLeft.Y, -40, rootSize.Y - panelSize.Y + 80)
			)
			local center = clampedTopLeft + panelSize / 2
			panel.Position = UDim2.fromOffset(center.X, center.Y)
		elseif pickerResizing and not pickerDragging and resizeStartPosition and resizeStartSize and resizeStartTopLeft then
			local rootSize = pickerRootSize()
			local delta = Vector2.new(input.Position.X, input.Position.Y) - resizeStartPosition
			local maxWidth = math.min(playerActionPickerMaxSize.X, math.max(playerActionPickerMinSize.X, rootSize.X - 80))
			local maxHeight = math.min(playerActionPickerMaxSize.Y, math.max(playerActionPickerMinSize.Y, rootSize.Y - 80))
			local newWidth = math.clamp(resizeStartSize.X + delta.X, playerActionPickerMinSize.X, maxWidth)
			local newHeight = math.clamp(resizeStartSize.Y + delta.Y, playerActionPickerMinSize.Y, maxHeight)
			local nextCenter = resizeStartTopLeft + Vector2.new(newWidth, newHeight) / 2
			playerActionPickerCurrentSize = clampPlayerActionPickerSize(Vector2.new(newWidth, newHeight))
			panel.Position = UDim2.fromOffset(nextCenter.X, nextCenter.Y)
			panel.Size = UDim2.fromOffset(newWidth, newHeight)
		end
	end)

	resizeHandle.MouseEnter:Connect(function()
		local normals = normalizedResizeCursorPosition(resizeHandle)
		tweenService:Create(resizeIcon, TweenInfo.new(0.18, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
			Size = UDim2.fromOffset(20 + (normals.X * 30), 20 + (normals.Y * 30)),
			ImageColor3 = Color3.fromRGB(70, 70, 70)
		}):Play()
	end)

	resizeHandle.MouseLeave:Connect(function()
		if pickerResizing then return end
		resetResizeIcon()
	end)

	resizeHandle.InputChanged:Connect(function(input)
		if input.UserInputType ~= Enum.UserInputType.MouseMovement and input.UserInputType ~= Enum.UserInputType.Touch then return end
		local normals = normalizedResizeCursorPosition(resizeHandle)
		tweenService:Create(resizeIcon, TweenInfo.new(0.14, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
			Size = UDim2.fromOffset(20 + (normals.X * 30), 20 + (normals.Y * 30)),
