			tweenService:Create(select, TweenInfo.new(0.45, Enum.EasingStyle.Quint), {Position = UDim2.new(1, -20, 0, 10), Size = UDim2.new(0, 128, 0, 70), ImageTransparency = 0.5}):Play()
