	selectButton.MouseButton1Click:Connect(function()
		local targetPlayer = playerActionPickerState.targetPlayer
		if not playerActionPickerState.selectedSpectate then
			queueNotification("Selection Failed", "Select at least 1 action.")
			return
		end

		_picker.closePlayerActionPicker()

		task.delay(0.12, function()
			if targetPlayer and players:FindFirstChild(targetPlayer.Name) then
				startSpectating(targetPlayer)
			end
		end)
	end)

	playerActionPickerParts = {
		Panel = panel,
