			SelectScale = selectScale
		}

	return playerActionPicker
end

		openPlayerActionPicker = function(targetPlayer, source, restorePanel)
		if not targetPlayer or targetPlayer == localPlayer then return end

		ensurePlayerActionPicker()

		playerActionPickerState.token += 1
		local openToken = playerActionPickerState.token
		playerActionPickerState.open = true
		playerActionPickerState.targetPlayer = targetPlayer
		playerActionPickerState.selectedSpectate = false
		playerActionPickerState.selectedTrack = false
		playerActionPickerState.selectedLiveTrack = false
		playerActionPickerState.selectedTracer = false
		playerActionPickerState.selectedHide = false
		playerActionPickerState.selectedEsp = false
		playerActionPickerState.restorePanel = nil

		local panel = playerActionPickerParts.Panel

		playerActionPicker.Visible = true
		panel.BackgroundTransparency = 1
		panel.BackgroundColor3 = siriusValues.selectActionStyle.panel
		if playerActionPickerParts.Shadow then
			playerActionPickerParts.Shadow.ImageTransparency = 1
			playerActionPickerParts.Shadow.Position = UDim2.new(0.5, 0, 0.5, 14)
		end
		if playerActionPickerParts.Stroke then
			playerActionPickerParts.Stroke.Transparency = 1
		end
		playerActionPickerParts.Content.GroupTransparency = 1
		profileInfoTools.Refresh(playerActionPickerParts, targetPlayer)
		if playerActionPickerParts.ActionScroll then
			playerActionPickerParts.ActionScroll.CanvasPosition = Vector2.zero
		end
		if playerActionPickerParts.RefreshActionScrollFades then
			task.defer(playerActionPickerParts.RefreshActionScrollFades)
		end
		if playerActionPickerParts.SpectateRow then
			playerActionPickerParts.SpectateRow.BackgroundColor3 = siriusValues.selectActionStyle.row
			playerActionPickerParts.SpectateRow.BackgroundTransparency = 0.04
		end
		if playerActionPickerParts.SpectateStroke then
			playerActionPickerParts.SpectateStroke.Color = siriusValues.selectActionStyle.stroke
			playerActionPickerParts.SpectateStroke.Transparency = 0.18
		end
		if playerActionPickerParts.SpectateIcon then
			playerActionPickerParts.SpectateIcon.BackgroundColor3 = siriusValues.selectActionStyle.icon
		end
		if playerActionPickerParts.SpectateGlyphImage then
			playerActionPickerParts.SpectateGlyphImage.Image = getSelectActionIcon("Spectate")
			playerActionPickerParts.SpectateGlyphImage.ImageTransparency = 0.04
		end
		local function resetActionRow(rowObject, strokeObject, iconObject)
			if rowObject then
				rowObject.BackgroundColor3 = siriusValues.selectActionStyle.row
				rowObject.BackgroundTransparency = 0.04
			end
			if strokeObject then
				strokeObject.Color = siriusValues.selectActionStyle.stroke
				strokeObject.Transparency = 0.18
			end
			if iconObject then
				iconObject.BackgroundColor3 = siriusValues.selectActionStyle.icon
			end
		end
		resetActionRow(playerActionPickerParts.TrackRow, playerActionPickerParts.TrackStroke, playerActionPickerParts.TrackIcon)
		resetActionRow(playerActionPickerParts.LiveTrackRow, playerActionPickerParts.LiveTrackStroke, playerActionPickerParts.LiveTrackIcon)
		resetActionRow(playerActionPickerParts.TracerRow, playerActionPickerParts.TracerStroke, playerActionPickerParts.TracerIcon)
		resetActionRow(playerActionPickerParts.HideRow, playerActionPickerParts.HideStroke, playerActionPickerParts.HideIcon)
		resetActionRow(playerActionPickerParts.EspRow, playerActionPickerParts.EspStroke, playerActionPickerParts.EspIcon)
		if playerActionPickerParts.WieldRows then
			for _, rowParts in pairs(playerActionPickerParts.WieldRows) do
				resetActionRow(rowParts.Row, rowParts.Stroke, rowParts.Icon)
				if rowParts.GlyphImage then
					rowParts.GlyphImage.Image = getSelectActionIcon(rowParts.IconName)
					rowParts.GlyphImage.ImageTransparency = 0.04
				end
				if rowParts.Dot then
					rowParts.Dot.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
					rowParts.Dot.BackgroundTransparency = 1
				end
				if rowParts.Glyph then
					rowParts.Glyph.Text = ""
					rowParts.Glyph.TextTransparency = 1
					rowParts.Glyph.TextSize = 19
				end
			end
		end
		if playerActionPickerParts.TrackGlyphImage then
			playerActionPickerParts.TrackGlyphImage.Image = getSelectActionIcon("Track")
			playerActionPickerParts.TrackGlyphImage.ImageTransparency = 0.04
		end
		if playerActionPickerParts.LiveTrackGlyphImage then
			playerActionPickerParts.LiveTrackGlyphImage.Image = getSelectActionIcon("LiveTrack")
			playerActionPickerParts.LiveTrackGlyphImage.ImageTransparency = 0.04
		end
		if playerActionPickerParts.TracerGlyphImage then
			playerActionPickerParts.TracerGlyphImage.Image = getSelectActionIcon("Tracer")
			playerActionPickerParts.TracerGlyphImage.ImageTransparency = 0.04
		end
		if playerActionPickerParts.HideGlyphImage then
			playerActionPickerParts.HideGlyphImage.Image = getSelectActionIcon("Hide")
			playerActionPickerParts.HideGlyphImage.ImageTransparency = 0.04
		end
		if playerActionPickerParts.EspGlyphImage then
			playerActionPickerParts.EspGlyphImage.Image = getSelectActionIcon("ESP")
			playerActionPickerParts.EspGlyphImage.ImageTransparency = 0.04
		end
		local isTracked = trackingBadges[targetPlayer] ~= nil
		local isTracerEnabled = playerTracers[targetPlayer] ~= nil
		local isHidden = hiddenPlayers[targetPlayer] ~= nil
		local isEspEnabled = locatedPlayers[targetPlayer.Name] == true
		refreshWieldingActionRows(targetPlayer, false)
		if playerActionPickerParts.TrackText then
			playerActionPickerParts.TrackText.Text = "Track"
