		end

		if _picker.closeLiveTrackPanel then
			pcall(_picker.closeLiveTrackPanel, false)
		end

		if _picker.closePlayerActionPicker then
			pcall(_picker.closePlayerActionPicker, true)
		end

		for targetPlayer in pairs(trackingBadges) do
			_picker.destroyTrackingBadge(targetPlayer)
		end

		for targetPlayer in pairs(playerTracers) do
			destroyPlayerTracer(targetPlayer)
		end

		for targetPlayer in pairs(hiddenPlayers) do
			hiddenPlayerTools.Destroy(targetPlayer)
		end

		if wieldingTools then
			wieldingTools.RocketToken += 1
			wieldingTools.Stop(true)
		end
	end
	playerActionSystem.isPickerOpen = function()
