local function formatMusicTime(seconds)
	seconds = math.max(0, math.floor(tonumber(seconds) or 0))
	return tostring(math.floor(seconds / 60))..":"..string.format("%02d", seconds % 60)
end

local function cleanMusicQuery(text)
	return string.gsub(string.lower(tostring(text or "")), "^%s*(.-)%s*$", "%1")
end

local function parseMusicQuery(text)
	local query = cleanMusicQuery(text)
	local key, value = string.match(query, "^(%w+)%s*:%s*(.+)$")

	if key and value then
		key = cleanMusicQuery(key)
		value = cleanMusicQuery(value)

		if key == "genre" or key == "vibe" or key == "artist" or key == "creator" or key == "source" then
			return key, value, ""
		end
	end

	return nil, nil, query
end

local function musicTrackMatches(track, key, value, plainQuery)
	if key == "genre" then
		return string.find(string.lower(track.section), "genres /", 1, true) and string.find(string.lower(track.section), value, 1, true)
	elseif key == "vibe" then
		return string.find(string.lower(track.section), "vibes /", 1, true) and string.find(string.lower(track.section), value, 1, true)
	elseif key == "artist" then
		return string.find(string.lower(track.artist), value, 1, true)
	elseif key == "creator" or key == "source" then
		return string.find(string.lower(track.creator), value, 1, true)
	end

	return plainQuery == "" or string.find(track.searchText, plainQuery, 1, true)
end

local function updateMusicProgress()
	if not musicProgressFill or not musicProgressTime then return end

	local audio = musicLibraryState.audio
	local duration = audio and audio.TimeLength or 0
	local position = audio and audio.TimePosition or 0
	local ratio = duration > 0 and math.clamp(position / duration, 0, 1) or 0
	local progressMotion = TweenInfo.new(musicLibraryState.isSeeking and 0.08 or 0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)

	tweenService:Create(musicProgressFill, progressMotion, {
		Size = UDim2.new(ratio, 0, 1, 0),
		BackgroundTransparency = duration > 0 and 0.08 or 0.38,
	}):Play()
	if musicProgressKnob then
		tweenService:Create(musicProgressKnob, progressMotion, {
			Position = UDim2.new(ratio, -1, 0, 0),
			BackgroundTransparency = duration > 0 and 0.14 or 1,
		}):Play()
	end

	local timeText = formatMusicTime(position).." / "..(duration > 0 and formatMusicTime(duration) or musicLibraryState.durationText)
	musicProgressTime.Text = timeText
	if musicNowPlayingLabel then
		musicNowPlayingLabel.Text = truncateMusicText(musicLibraryState.nowPlayingTitle or "Not Playing", 36)
	end
	if musicTopArtistLabel then
		local track = musicLibraryState.currentTrack
		musicTopArtistLabel.Text = track and truncateMusicText(track.artist.." • "..track.section, 42) or "Select a track from the library"
	end
	if musicPanel and musicPanel:FindFirstChild("Playing") then
		musicPanel.Playing.Text = truncateMusicText(musicLibraryState.nowPlayingTitle or "Not Playing", 30).."  •  "..timeText
	end
end
musicLibraryState.updateProgress = updateMusicProgress

local function seekMusicProgress(screenX)
	local audio = musicLibraryState.audio
	if not audio or not musicProgressBar or audio.TimeLength <= 0 then return end

	local ratio = math.clamp((screenX - musicProgressBar.AbsolutePosition.X) / math.max(musicProgressBar.AbsoluteSize.X, 1), 0, 1)
	audio.TimePosition = audio.TimeLength * ratio
	updateMusicProgress()
end

local function startMusicProgressLoop()
	if musicLibraryState.progressStarted then return end
	musicLibraryState.progressStarted = true

	task.spawn(function()
		while musicLibraryState.progressStarted do
			task.wait(0.2)
			updateMusicProgress()
		end
	end)
end

local function showMusicTopPlayer()
	if not musicPlayerStrip then return end
	if musicTopPlayerOpen then
		tweenService:Create(musicPlayerStrip, TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
			Position = UDim2.new(0, 18, 0, 70),
			BackgroundTransparency = 0.05,
		}):Play()
		return
	end

	musicTopPlayerOpen = true
	musicPlayerStrip.Visible = true
	musicPlayerStrip.Position = UDim2.new(0, 18, 0, 52)
	musicPlayerStrip.BackgroundTransparency = 1
	wipeTransparency(musicPlayerStrip, 1, true)

	local openMotion = TweenInfo.new(0.46, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	tweenService:Create(musicPlayerStrip, openMotion, {
		Position = UDim2.new(0, 18, 0, 70),
		BackgroundTransparency = 0.05,
	}):Play()

	for _, descendant in ipairs(musicPlayerStrip:GetDescendants()) do
		if descendant:IsA("TextButton") then
			if descendant.Name == "ProgressHitbox" then
				descendant.Text = ""
				descendant.TextTransparency = 1
				descendant.BackgroundTransparency = 1
				continue
			end
			local buttonTransparency = 1
			if descendant.Name == "Play" then
				buttonTransparency = 0.16
			elseif descendant.Name == "Forward" then
				buttonTransparency = 0.26
			end
			tweenService:Create(descendant, TweenInfo.new(0.34, Enum.EasingStyle.Quint), {
				BackgroundTransparency = buttonTransparency,
				TextTransparency = 0.04,
			}):Play()
		elseif descendant:IsA("TextLabel") then
			tweenService:Create(descendant, TweenInfo.new(0.34, Enum.EasingStyle.Quint), {TextTransparency = descendant.Name == "Time" and 0.2 or 0.04}):Play()
		elseif descendant:IsA("ImageLabel") then
			tweenService:Create(descendant, TweenInfo.new(0.34, Enum.EasingStyle.Quint), {ImageTransparency = 0.08}):Play()
		elseif descendant:IsA("Frame") then
			local targetTransparency = 1
			if descendant.Name == "ProgressBar" then
				targetTransparency = 0.24
			elseif descendant.Name == "Fill" then
				targetTransparency = musicLibraryState.currentTrack and 0.08 or 0.38
			elseif descendant.Name == "ProgressKnob" then
				targetTransparency = musicLibraryState.currentTrack and 0.14 or 1
			elseif descendant.Name == "ArtworkShell" or descendant.Name == "ButtonShell" then
				targetTransparency = 0.1
			end
			tweenService:Create(descendant, TweenInfo.new(0.34, Enum.EasingStyle.Quint), {BackgroundTransparency = targetTransparency}):Play()
		elseif descendant:IsA("UIStroke") then
			tweenService:Create(descendant, TweenInfo.new(0.34, Enum.EasingStyle.Quint), {Transparency = 0.42}):Play()
		end
	end
end

