	if not musicPlayerStrip or not musicTopPlayerOpen then return end
	musicTopPlayerOpen = false
	if stopPlayback and stopMusicTrack then
		stopMusicTrack()
	end
	if musicTopToggle and musicTopToggle.Visible then
		tweenService:Create(musicTopToggle, TweenInfo.new(0.18, Enum.EasingStyle.Quint), {
			BackgroundTransparency = 0.08,
			TextTransparency = 0.03,
		}):Play()
		if musicTopToggle:FindFirstChild("UIStroke") then
			tweenService:Create(musicTopToggle.UIStroke, TweenInfo.new(0.18, Enum.EasingStyle.Quint), {Transparency = 0.62}):Play()
		end
	end

	local closeMotion = TweenInfo.new(0.32, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut)
	tweenService:Create(musicPlayerStrip, closeMotion, {
		Position = UDim2.new(0, 18, 0, 52),
		BackgroundTransparency = 1,
	}):Play()
	task.delay(0.34, function()
		if not musicTopPlayerOpen and musicPlayerStrip then
			musicPlayerStrip.Visible = false
		end
	end)
end

