		if musicLibraryState.audio then
			if musicLibraryState.audio.Playing then
				musicLibraryState.audio:Pause()
			else
				pcall(function()
					musicLibraryState.audio:Resume()
				end)
				if not musicLibraryState.audio.Playing then
					musicLibraryState.audio:Play()
				end
			end
			musicPlayButton.Text = musicLibraryState.audio.Playing and "Ⅱ" or "▶"
			updateMusicProgress()
			updateMusicLibraryActiveRows()
		elseif musicLibraryState.renderedTracks and #musicLibraryState.renderedTracks > 0 then
			playMusicTrack(musicLibraryState.renderedTracks[1], 1)
		end
	end)

