		if not audio then return end
		local targetPosition = audio.TimePosition + 10
		if audio.TimeLength and audio.TimeLength > 0 then
			targetPosition = math.min(targetPosition, math.max(audio.TimeLength - 0.05, 0))
		end
		audio.TimePosition = math.max(targetPosition, 0)
		updateMusicProgress()
	end)

	local function wireTopPlayerButton(button)
		button.MouseEnter:Connect(function()
			tweenService:Create(button, TweenInfo.new(0.18, Enum.EasingStyle.Quint), {
				BackgroundTransparency = 0.22,
				TextTransparency = 0,
			}):Play()
		end)
		button.MouseLeave:Connect(function()
			local idleTransparency = button == musicPlayButton and 0.16 or 0.26
			tweenService:Create(button, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {
				BackgroundTransparency = idleTransparency,
				TextTransparency = 0.04,
			}):Play()
		end)
	end
	wireTopPlayerButton(musicPlayButton)
	wireTopPlayerButton(musicNextButton)

	local close = Instance.new("TextButton")
	close.Name = "Close"
	close.Parent = musicPlayerStrip
	close.BackgroundTransparency = 1
