	close.TextTransparency = 1
	close.ZIndex = 96
	close.MouseButton1Click:Connect(function()
		hideMusicTopPlayer(false)
	end)

	userInputService.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			musicLibraryState.isSeeking = false
		end
	end)
	userInputService.InputChanged:Connect(function(input)
		if not musicLibraryState.isSeeking then return end
		if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then
			seekMusicProgress(input.Position.X)
		end
	end)
end

local function ensureMusicTopToggle()
	if musicTopToggle and musicTopToggle.Parent then return end

	musicTopToggle = Instance.new("TextButton")
	musicTopToggle.Name = "MusicTopToggle"
	musicTopToggle.Parent = UI
	musicTopToggle.BackgroundColor3 = Color3.fromRGB(28, 28, 30)
	musicTopToggle.BackgroundTransparency = 1
	musicTopToggle.BorderSizePixel = 0
	musicTopToggle.Position = UDim2.new(0, 184, 0, 12)
	musicTopToggle.Size = UDim2.new(0, 46, 0, 46)
	musicTopToggle.AutoButtonColor = false
	musicTopToggle.Font = Enum.Font.GothamBold
	musicTopToggle.Text = "♫"
	musicTopToggle.TextColor3 = Color3.fromRGB(255, 255, 255)
	musicTopToggle.TextSize = 24
	musicTopToggle.TextTransparency = 1
	musicTopToggle.Visible = false
	musicTopToggle.ZIndex = 94

	local corner = Instance.new("UICorner")
	corner.CornerRadius = UDim.new(1, 0)
	corner.Parent = musicTopToggle

	local stroke = Instance.new("UIStroke")
	stroke.Color = Color3.fromRGB(216, 104, 111)
	stroke.Thickness = 1
	stroke.Transparency = 0.72
	stroke.Parent = musicTopToggle

	local gradient = Instance.new("UIGradient")
	gradient.Color = ColorSequence.new({
		ColorSequenceKeypoint.new(0, Color3.fromRGB(78, 28, 32)),
		ColorSequenceKeypoint.new(1, Color3.fromRGB(18, 18, 20)),
	})
	gradient.Rotation = 125
	gradient.Parent = musicTopToggle

	musicTopToggle.MouseEnter:Connect(function()
		tweenService:Create(musicTopToggle, TweenInfo.new(0.18, Enum.EasingStyle.Quint), {
			BackgroundTransparency = 0.02,
			TextTransparency = 0,
		}):Play()
		tweenService:Create(stroke, TweenInfo.new(0.18, Enum.EasingStyle.Quint), {Transparency = 0.42}):Play()
	end)
	musicTopToggle.MouseLeave:Connect(function()
		tweenService:Create(musicTopToggle, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {
			BackgroundTransparency = musicTopPlayerOpen and 0.02 or 0.08,
			TextTransparency = 0.03,
		}):Play()
		tweenService:Create(stroke, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {
			Transparency = musicTopPlayerOpen and 0.38 or 0.62,
		}):Play()
	end)
	musicTopToggle.MouseButton1Click:Connect(function()
		ensureMusicTopPlayer()
		if musicTopPlayerOpen then
			hideMusicTopPlayer(false)
		else
			showMusicTopPlayer()
		end
	end)
end

local function showMusicTopToggle()
	ensureMusicTopToggle()
	if musicTopToggle.Visible then
		tweenService:Create(musicTopToggle, TweenInfo.new(0.18, Enum.EasingStyle.Quint), {
			BackgroundTransparency = musicTopPlayerOpen and 0.02 or 0.08,
			TextTransparency = 0.03,
		}):Play()
		return
	end

	musicTopToggle.Visible = true
	musicTopToggle.Position = UDim2.new(0, 184, 0, -44)
	musicTopToggle.BackgroundTransparency = 1
	musicTopToggle.TextTransparency = 1
	tweenService:Create(musicTopToggle, TweenInfo.new(0.38, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
		Position = UDim2.new(0, 184, 0, 12),
		BackgroundTransparency = 0.08,
		TextTransparency = 0.03,
	}):Play()
	if musicTopToggle:FindFirstChild("UIStroke") then
		tweenService:Create(musicTopToggle.UIStroke, TweenInfo.new(0.38, Enum.EasingStyle.Quint), {Transparency = 0.62}):Play()
	end
end

local function hideMusicTopToggle()
	if not musicTopToggle or not musicTopToggle.Visible then return end
	tweenService:Create(musicTopToggle, TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut), {
		Position = UDim2.new(0, 184, 0, -44),
		BackgroundTransparency = 1,
		TextTransparency = 1,
	}):Play()
	task.delay(0.3, function()
		if musicTopToggle and not musicLibraryState.currentTrack then
			musicTopToggle.Visible = false
		end
	end)
end

local function syncMusicTopToggle()
	if musicLibraryState.currentTrack then
		showMusicTopToggle()
	else
		hideMusicTopPlayer(false)
		hideMusicTopToggle()
	end
end

local function updateMusicTopPlayerDetails(track)
	if not musicPlayerStrip then return end

	if musicNowPlayingLabel then
		musicNowPlayingLabel.Text = track and truncateMusicText(track.title, 36) or "Not Playing"
	end
	if musicTopArtistLabel then
		musicTopArtistLabel.Text = track and truncateMusicText(track.artist.." • "..track.section, 42) or "Select a track from the library"
	end
	if musicArtworkImage then
		if track and track.id then
			musicArtworkImage.Image = "rbxthumb://type=Asset&id="..track.id.."&w=150&h=150"
			tweenService:Create(musicArtworkImage, TweenInfo.new(0.24, Enum.EasingStyle.Quint), {ImageTransparency = 0.08}):Play()
		else
			tweenService:Create(musicArtworkImage, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {ImageTransparency = 1}):Play()
		end
	end
	if musicArtworkFallback then
		tweenService:Create(musicArtworkFallback, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {
			TextTransparency = track and 0.62 or 0.15,
		}):Play()
	end
end

local function setQueueHeaderText()
	for _, descendant in ipairs(musicPanel:GetDescendants()) do
		if descendant:IsA("TextLabel") and descendant.Text == "QUEUE" then
			descendant.Text = "LIBRARY"
			descendant.TextTransparency = 0.32
			break
		end
	end
end

local function updateMusicLibraryTabs()
	for section, button in pairs(musicLibraryTabButtons) do
		local selected = section == musicLibraryState.activeSection
		tweenService:Create(button, TweenInfo.new(0.24, Enum.EasingStyle.Quint), {
			BackgroundTransparency = selected and 0.15 or 0.58,
			TextTransparency = selected and 0.02 or 0.24,
		}):Play()

		if button:FindFirstChild("UIStroke") then
			tweenService:Create(button.UIStroke, TweenInfo.new(0.24, Enum.EasingStyle.Quint), {
				Transparency = selected and 0.18 or 0.75,
			}):Play()
		end
	end
end

