local musicSectionPalette = {
	Color3.fromRGB(29, 116, 182),
	Color3.fromRGB(172, 48, 137),
	Color3.fromRGB(18, 154, 113),
	Color3.fromRGB(190, 87, 28),
	Color3.fromRGB(178, 48, 59),
	Color3.fromRGB(150, 132, 12),
	Color3.fromRGB(93, 71, 166),
	Color3.fromRGB(25, 143, 156),
}

local function getMusicSectionName(section)
	local name = string.gsub(tostring(section or ""), "^.+ / ", "")
	return name ~= "" and name or tostring(section or "Music")
end

local function getMusicSectionKind(section)
	section = tostring(section or "")
	if string.find(section, "Genres /", 1, true) then
		return "GENRE"
	elseif string.find(section, "Vibes /", 1, true) then
		return "VIBE"
	elseif string.find(section, "Discover New Audio", 1, true) then
		return "DISCOVER"
	end

	return "SECTION"
end

local function countMusicSection(section)
	local count = 0
	for _, track in ipairs(musicLibraryState.library) do
		if track.section == section then
			count += 1
		end
	end
	return count
end

local function getMusicSectionAccent(section, index)
	if musicSectionAccents[section] then return musicSectionAccents[section] end
	local accent = musicSectionPalette[((index or 1) - 1) % #musicSectionPalette + 1]
	musicSectionAccents[section] = accent
	return accent
end

local function clearMusicContainer(container)
	if not container then return end
	for _, child in ipairs(container:GetChildren()) do
		if child.Name ~= "Placeholder" and not child:IsA("UIGridLayout") and not child:IsA("UIListLayout") and not child:IsA("UIPadding") then
			child:Destroy()
		end
	end
end

local function setMusicHeader(titleText, subtitleText, showBack, accent)
	if musicHeaderTitle then
		musicHeaderTitle.Text = titleText
		musicHeaderTitle.Position = showBack and UDim2.new(0.091, 0, 0.057, 0) or UDim2.new(0.045, 0, 0.057, 0)
	end
	if musicHeaderSubtitle then
		musicHeaderSubtitle.Text = subtitleText
		musicHeaderSubtitle.Position = showBack and UDim2.new(0.045, 0, 0.115, 0) or UDim2.new(0.045, 0, 0.13, 0)
	end
	if musicHeaderIcon then musicHeaderIcon.Visible = false end
	if musicBackButton then musicBackButton.Visible = showBack end
	if musicRootGradient then
		if showBack and accent then
			musicRootGradient.Color = ColorSequence.new({
				ColorSequenceKeypoint.new(0, Color3.new(0.0470588, 0.0470588, 0.0470588)),
				ColorSequenceKeypoint.new(1, accent),
			})
			musicRootGradient.Offset = Vector2.new(0, 0.65)
		else
			musicRootGradient.Color = ColorSequence.new({
				ColorSequenceKeypoint.new(0, Color3.new(0.0470588, 0.0470588, 0.0470588)),
				ColorSequenceKeypoint.new(1, Color3.new(0.0470588, 0.0470588, 0.0470588)),
			})
			musicRootGradient.Offset = Vector2.new(0, 1.05)
		end
	end
end

local function showMusicSectionCards()
	musicLibraryState.activeSection = nil
	if musicSectionGrid then
		musicSectionGrid.Visible = true
		musicSectionGrid.CanvasPosition = Vector2.new(0, 0)
	end
	if musicTrackList then
		musicTrackList.Visible = false
		clearMusicContainer(musicTrackList)
	end
	setMusicHeader("Music", "Browse the music library by genre, vibe, and trending sections.", false, Color3.fromRGB(12, 12, 12))
end

local function openMusicSection(section, accent)
	musicLibraryState.activeSection = section
	if musicSectionGrid then musicSectionGrid.Visible = false end
	if musicTrackList then
		musicTrackList.Visible = true
		musicTrackList.CanvasPosition = Vector2.new(0, 0)
	end

	local count = countMusicSection(section)
	setMusicHeader(getMusicSectionName(section), tostring(count).." tracks from "..string.lower(getMusicSectionKind(section)).." music.", true, accent or Color3.fromRGB(165, 68, 72))
	musicLibraryState.render()
end

