	trackLayout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(function()
		musicTrackList.CanvasSize = UDim2.new(0, 0, 0, math.max(trackLayout.AbsoluteContentSize.Y + 26, 340))
	end)

	local sectionCardTemplate = settingsPanel.SettingTypes:FindFirstChild("Template")
	for index, section in ipairs(musicLibraryState.sections) do
		local accent = getMusicSectionAccent(section, index)
		local card = sectionCardTemplate:Clone()
		card.Name = "Section_"..string.gsub(getMusicSectionName(section), "[^%w]", "")
		card.Parent = musicSectionGrid
		card.BackgroundTransparency = 0
		card.LayoutOrder = index
		card.Visible = true

		local hue, sat, val = Color3.toHSV(accent)
		hue = math.clamp(hue + 0.01, 0, 1)
		sat = math.clamp(sat + 0.1, 0, 1)
		val = math.clamp(val + 0.2, 0, 1)
		local strokeAccent = Color3.fromHSV(hue, sat, val)

		if card:FindFirstChild("Title") then
			card.Title.Text = string.upper(truncateMusicText(getMusicSectionName(section), 18))
			card.Title.TextTransparency = 0.2
		end
		if card:FindFirstChild("UIGradient") then
			card.UIGradient.Color = ColorSequence.new({
				ColorSequenceKeypoint.new(0, Color3.new(0.0392157, 0.0392157, 0.0392157)),
				ColorSequenceKeypoint.new(1, accent),
			})
		end
		if card:FindFirstChild("UIStroke") then
			card.UIStroke.Transparency = 0
			if card.UIStroke:FindFirstChild("UIGradient") then
				card.UIStroke.UIGradient.Color = ColorSequence.new({
					ColorSequenceKeypoint.new(0, Color3.new(0.117647, 0.117647, 0.117647)),
					ColorSequenceKeypoint.new(1, strokeAccent),
				})
			end
		end
		if card:FindFirstChild("Shadow") then
			card.Shadow.ImageTransparency = 0.66
			if card.Shadow:FindFirstChild("UIGradient") then
				card.Shadow.UIGradient.Color = ColorSequence.new({
					ColorSequenceKeypoint.new(0, Color3.new(0.117647, 0.117647, 0.117647)),
					ColorSequenceKeypoint.new(1, strokeAccent),
				})
			end
		end

		card.MouseEnter:Connect(function()
			if card:FindFirstChild("Title") then
				tweenService:Create(card.Title, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {TextTransparency = 0}):Play()
			end
			if card:FindFirstChild("UIGradient") then
				tweenService:Create(card.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.4)}):Play()
			end
			if card:FindFirstChild("UIStroke") and card.UIStroke:FindFirstChild("UIGradient") then
				tweenService:Create(card.UIStroke.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.2)}):Play()
			end
			if card:FindFirstChild("Shadow") and card.Shadow:FindFirstChild("UIGradient") then
				tweenService:Create(card.Shadow.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.2)}):Play()
			end
		end)
		card.MouseLeave:Connect(function()
			if card:FindFirstChild("Title") then
				tweenService:Create(card.Title, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {TextTransparency = 0.2}):Play()
			end
			if card:FindFirstChild("UIGradient") then
				tweenService:Create(card.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.65)}):Play()
			end
			if card:FindFirstChild("UIStroke") and card.UIStroke:FindFirstChild("UIGradient") then
				tweenService:Create(card.UIStroke.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.4)}):Play()
			end
			if card:FindFirstChild("Shadow") and card.Shadow:FindFirstChild("UIGradient") then
				tweenService:Create(card.Shadow.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.4)}):Play()
			end
		end)
		local interact = card:FindFirstChild("Interact") or card:FindFirstChildWhichIsA("TextButton", true)
		interact.MouseButton1Click:Connect(function()
			openMusicSection(section, accent)
		end)
	end

	showMusicSectionCards()
end
updateMusicLibraryActiveRows = function()
	for _, row in ipairs(getMusicLibraryList():GetChildren()) do
		if row:GetAttribute("MusicTrackId") then
			local active = musicLibraryState.currentTrack and row:GetAttribute("MusicTrackId") == musicLibraryState.currentTrack.id
			local playing = active and musicLibraryState.audio and musicLibraryState.audio.Playing
			tweenService:Create(row, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {
				BackgroundTransparency = 0.9,
				BackgroundColor3 = Color3.fromRGB(27, 27, 27),
			}):Play()

			if row:FindFirstChild("UIStroke") then
				tweenService:Create(row.UIStroke, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {
					Transparency = 0.6,
				}):Play()
			end

			local switchFrame = row:FindFirstChild("Switch")
			if switchFrame then
				switchFrame.Visible = false
			end

			local controls = row:FindFirstChild("MusicControls")
			local playButton = (controls and controls:FindFirstChild("Play")) or row:FindFirstChild("Play")

			if playButton then
				playButton.Text = "▶"
				tweenService:Create(playButton, TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
					TextColor3 = active and Color3.fromRGB(255, 255, 255) or Color3.fromRGB(226, 226, 226),
					TextTransparency = active and 0.02 or 0.16,
				}):Play()
			end
		end
	end
end

local function ensureMusicAudio()
	if musicLibraryState.audio then return musicLibraryState.audio end

	musicLibraryState.audio = Instance.new("Sound")
	musicLibraryState.audio.Parent = UI
	musicLibraryState.audio.Name = "SiriusMusicAudio"
	musicLibraryState.audio.Volume = 0.75

	return musicLibraryState.audio
end

stopMusicTrack = function()
	musicLibraryState.playGeneration += 1
	if musicLibraryState.audio then
		musicLibraryState.audio:Stop()
		musicLibraryState.audio.SoundId = ""
	end
	musicLibraryState.currentTrack = nil
	musicLibraryState.currentIndex = 0
	musicLibraryState.durationText = "--:--"
	musicLibraryState.nowPlayingTitle = "Not Playing"
	updateMusicTopPlayerDetails(nil)
	if musicPlayButton then musicPlayButton.Text = "▶" end
	syncMusicTopToggle()
	updateMusicProgress()
	updateMusicLibraryActiveRows()
end

playMusicTrack = function(track, index)
	if not track then return end

	ensureMusicTopPlayer()

	local audio = ensureMusicAudio()
	musicLibraryState.playGeneration += 1
	local thisGen = musicLibraryState.playGeneration

	musicLibraryState.currentTrack = track
	musicLibraryState.currentIndex = index or musicLibraryState.currentIndex
	musicLibraryState.durationText = track.duration ~= "" and track.duration or "--:--"
	musicLibraryState.nowPlayingTitle = track.title
	updateMusicTopPlayerDetails(track)
	syncMusicTopToggle()
	if musicTopPlayerOpen then
		showMusicTopPlayer()
	end
	audio.SoundId = track.soundId
	audio.TimePosition = 0
	audio:Play()

	if musicNowPlayingLabel then
		tweenService:Create(musicNowPlayingLabel, TweenInfo.new(0.12, Enum.EasingStyle.Quint), {TextTransparency = 0.62}):Play()
	end
	task.delay(0.08, function()
		if musicLibraryState.currentTrack ~= track then return end
		updateMusicProgress()
		if musicNowPlayingLabel then
			tweenService:Create(musicNowPlayingLabel, TweenInfo.new(0.26, Enum.EasingStyle.Quint), {TextTransparency = 0.1}):Play()
		end
	end)
	updateMusicProgress()
	task.delay(0.45, updateMusicProgress)
	if musicPlayButton then musicPlayButton.Text = "Ⅱ" end
	updateMusicLibraryActiveRows()

	if checkSetting("Now Playing Notifications").current then
		queueNotification("Now Playing", track.title.." • "..track.artist, 4400695581)
	end

	task.spawn(function()
		audio.Ended:Wait()
		if thisGen ~= musicLibraryState.playGeneration or not musicLibraryState.audio or musicLibraryState.audio.SoundId ~= track.soundId then return end
		musicLibraryState.currentTrack = nil
		musicLibraryState.currentIndex = 0
		musicLibraryState.durationText = "--:--"
		musicLibraryState.nowPlayingTitle = "Not Playing"
		updateMusicTopPlayerDetails(nil)
		if musicPlayButton then musicPlayButton.Text = "▶" end
		syncMusicTopToggle()
		updateMusicProgress()
		updateMusicLibraryActiveRows()
	end)
end

openMusicPlayerForTrack = function(track, index)
	if not track then return end

	ensureMusicTopPlayer()
	local active = musicLibraryState.currentTrack and musicLibraryState.currentTrack.id == track.id
	if active then
		local audio = ensureMusicAudio()
		if not audio.Playing then
			pcall(function()
				audio:Resume()
			end)
			if not audio.Playing then
				audio:Play()
			end
		end
		showMusicTopPlayer()
		updateMusicTopPlayerDetails(track)
		if musicPlayButton then musicPlayButton.Text = audio.Playing and "Ⅱ" or "▶" end
		updateMusicProgress()
		updateMusicLibraryActiveRows()
		return
	end

	playMusicTrack(track, index)
end

