		switchFrame.Visible = false
	end

	if row:FindFirstChild("Interact") then
		row.Interact.ZIndex = musicLibraryZIndex + 5
	end

	local controls = Instance.new("Frame")
	controls.Name = "MusicControls"
	controls.Parent = row
	controls.BackgroundTransparency = 1
	controls.Position = UDim2.new(1, -64, 0.5, -17)
	controls.Size = UDim2.new(0, 38, 0, 34)
