	local playButton = Instance.new("TextButton")
	playButton.Name = "Play"
	playButton.Parent = controls
	playButton.BackgroundTransparency = 1
	playButton.Position = UDim2.new(0, 0, 0, 0)
	playButton.Size = UDim2.new(1, 0, 1, 0)
	playButton.AutoButtonColor = false
	playButton.Font = Enum.Font.GothamBold
	playButton.Text = "▶"
	playButton.TextColor3 = Color3.fromRGB(226, 226, 226)
	playButton.TextSize = 19
	playButton.TextTransparency = 0.18
	playButton.ZIndex = musicLibraryZIndex + 10

	local function openTrackPlayer()
		openMusicPlayerForTrack(track, index)
	end

	local function wireIconHover(button)
		button.MouseEnter:Connect(function()
			tweenService:Create(button, TweenInfo.new(0.18, Enum.EasingStyle.Quint), {TextTransparency = 0}):Play()
		end)
		button.MouseLeave:Connect(function()
			updateMusicLibraryActiveRows()
		end)
	end

	wireIconHover(playButton)

	playButton.MouseButton1Click:Connect(openTrackPlayer)

	local rowTouching = false
	row.MouseEnter:Connect(function()
		if musicLibraryState.renderToken ~= token then return end
		rowTouching = true
		if stroke then
			tweenService:Create(stroke, TweenInfo.new(0.35, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.45}):Play()
		end
		tweenService:Create(row, TweenInfo.new(0.35, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.83}):Play()
	end)

	row.MouseLeave:Connect(function()
		if musicLibraryState.renderToken ~= token then return end
		rowTouching = false
		updateMusicLibraryActiveRows()
	end)

	if row:FindFirstChild("Interact") then
		row.Interact.MouseButton1Click:Connect(function()
			if stroke then
				tweenService:Create(stroke, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 1}):Play()
			end
			tweenService:Create(row, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.8}):Play()
			openTrackPlayer()
			task.wait(0.1)
			if rowTouching then
				if stroke then
					tweenService:Create(stroke, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.45}):Play()
				end
				tweenService:Create(row, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.83}):Play()
			else
				updateMusicLibraryActiveRows()
			end
		end)
	else
		row.InputBegan:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
				openTrackPlayer()
			end
		end)
	end

	task.delay(math.min(index * 0.012, 0.36), function()
		if musicLibraryState.renderToken ~= token or not row.Parent then return end
		tweenService:Create(row, TweenInfo.new(0.32, Enum.EasingStyle.Quint), {BackgroundTransparency = 0.9}):Play()
		if stroke then
			tweenService:Create(stroke, TweenInfo.new(0.32, Enum.EasingStyle.Quint), {Transparency = 0.6}):Play()
		end
		tweenService:Create(title, TweenInfo.new(0.32, Enum.EasingStyle.Quint), {TextTransparency = 0.02}):Play()
		tweenService:Create(subtitle, TweenInfo.new(0.32, Enum.EasingStyle.Quint), {TextTransparency = 0.22}):Play()
		updateMusicLibraryActiveRows()
	end)
end

