musicLibraryState.render = function()
	ensureMusicSettingsLibraryUI()
	musicLibraryState.renderToken += 1
	local token = musicLibraryState.renderToken
	local matches = {}
	local selectedSection = musicLibraryState.activeSection

	if not selectedSection then return end
	for _, track in ipairs(musicLibraryState.library) do
		if track.section == selectedSection then
			table.insert(matches, track)
		end
	end

	musicLibraryState.renderedTracks = matches
	clearMusicLibraryRows()

	if #matches == 0 then
		return
	end

	for index, track in ipairs(matches) do
		local ok = pcall(function()
			createMusicLibraryRow(track, index, token)
		end)
		if not ok then
			local brokenRow = getMusicLibraryList():FindFirstChild("LibraryTrack_"..track.id)
			if brokenRow then brokenRow:Destroy() end
			createMusicLibraryFallbackRow(track, index, token)
		end
	end

	task.defer(function()
		if musicLibraryState.renderToken ~= token then return end
		local list = getMusicLibraryList()
		local layout = list:FindFirstChildOfClass("UIListLayout")
		if layout then
			list.CanvasSize = UDim2.new(0, 0, 0, layout.AbsoluteContentSize.Y + 14)
		end
	end)
end

musicLibraryState.playNext = function()
	if #musicLibraryState.renderedTracks == 0 then
		musicLibraryState.render()
	end

	if #musicLibraryState.renderedTracks == 0 then
		if musicLibraryState.audio then musicLibraryState.audio.Playing = false musicLibraryState.audio.SoundId = "" end
		musicLibraryState.currentTrack = nil
		musicLibraryState.currentIndex = 0
		musicLibraryState.nowPlayingTitle = "Not Playing"
		if musicNowPlayingLabel then musicNowPlayingLabel.Text = "Not Playing" end
		if musicProgressTime then musicProgressTime.Text = "0:00 / --:--" end
		if musicPlayButton then musicPlayButton.Text = "▶" end
		return
	end

	local nextIndex = musicLibraryState.currentIndex + 1
	if nextIndex > #musicLibraryState.renderedTracks then nextIndex = 1 end
	playMusicTrack(musicLibraryState.renderedTracks[nextIndex], nextIndex)
end

musicLibraryState.addToQueue = function()
	if #musicLibraryState.renderedTracks == 0 then
		musicLibraryState.render()
	end

	if #musicLibraryState.renderedTracks > 0 then
		local randomIndex = math.random(1, #musicLibraryState.renderedTracks)
		playMusicTrack(musicLibraryState.renderedTracks[randomIndex], randomIndex)
	end
end

local lastMusicDevelopmentNotice = 0
local function showMusicDevelopmentNotice()
	local now = os.clock()
	if now - lastMusicDevelopmentNotice < 1.4 then
		return
	end

	lastMusicDevelopmentNotice = now
	queueNotification("Music In Development", "The Music panel is currently being rebuilt and will be available in a future Sirius X update.", 4400696294)
end

musicLibraryState.open = function()
	if true then
		if musicPanel.Visible then
			musicPanel.Visible = false
		end

		showMusicDevelopmentNotice()
		return
	end

	debounce = true
	ensureMusicSettingsLibraryUI()
	musicPanel.Visible = true
	showMusicSectionCards()

	debounce = false
end

musicLibraryState.close = function()
	debounce = true
	musicPanel.Visible = false

	debounce = false
end
end

local function createReverb(timing)
	for index, sound in next, soundInstances do
		if not sound:FindFirstChild("SiriusAudioProfile") then
			local reverb = Instance.new("EqualizerSoundEffect")

			reverb.Name = "SiriusAudioProfile"
			reverb.Parent = sound

			reverb.Enabled = false

			reverb.HighGain = 0
			reverb.LowGain = 0
			reverb.MidGain = 0
			reverb.Enabled = true

			if timing then
				tweenService:Create(reverb, TweenInfo.new(timing, Enum.EasingStyle.Exponential), {HighGain = -20}):Play()
				tweenService:Create(reverb, TweenInfo.new(timing, Enum.EasingStyle.Exponential), {LowGain = 5}):Play()
				tweenService:Create(reverb, TweenInfo.new(timing, Enum.EasingStyle.Exponential), {MidGain = -20}):Play()
			end
		end
	end
end

local function runScript(raw)
	loadstring(game:HttpGet(raw))()
end

local function syncExperienceInformation()
	siriusValues.currentCreator = creatorId

	if creatorType == Enum.CreatorType.Group then
		siriusValues.currentGroup = creatorId
		siriusValues.currentCreator = "group"
	end

	for _, gameFound in pairs(siriusValues.games) do
		if gameFound.id == placeId and gameFound.enabled then

			local minimumTier = gameFound.minimumTier

			if minimumTier == "Essential" then
				if not (Essential or Pro) then
					return
				end
			elseif minimumTier == "Pro" then
				if not Pro then
					return
				end
			end

			local rawFile = siriusValues.rawTree..gameFound.raw
			siriusValues.currentGame = gameFound

			gameDetectionPrompt.ScriptTitle.Text = gameFound.name
			gameDetectionPrompt.Layer.ScriptSubtitle.Text = gameFound.description
			gameDetectionPrompt.Thumbnail.Image = "https://assetgame.roblox.com/Game/Tools/ThumbnailAsset.ashx?aid="..tostring(placeId).."&fmt=png&wd=420&ht=420"

			gameDetectionPrompt.Size = UDim2.new(0, 550, 0, 0)
			gameDetectionPrompt.Position = UDim2.new(0.5, 0, 0, 120)
			gameDetectionPrompt.UICorner.CornerRadius = UDim.new(0, 9)
			gameDetectionPrompt.Thumbnail.UICorner.CornerRadius = UDim.new(0, 9)
			gameDetectionPrompt.ScriptTitle.Position = UDim2.new(0, 30, 0.5, 0)
			gameDetectionPrompt.Layer.Visible = false
			gameDetectionPrompt.Warning.Visible = false

			wipeTransparency(gameDetectionPrompt, 1, true)

			gameDetectionPrompt.Visible = true

			tweenService:Create(gameDetectionPrompt, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {BackgroundTransparency = 0}):Play()
			tweenService:Create(gameDetectionPrompt.Thumbnail, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {ImageTransparency = 0.4}):Play()
			tweenService:Create(gameDetectionPrompt.ScriptTitle, TweenInfo.new(0.6, Enum.EasingStyle.Quint),  {TextTransparency = 0}):Play()

			tweenService:Create(gameDetectionPrompt, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Size = UDim2.new(0, 587, 0, 44)}):Play()
			tweenService:Create(gameDetectionPrompt, TweenInfo.new(1, Enum.EasingStyle.Exponential), {Position = UDim2.new(0.5, 0, 0, 150)}):Play()

			task.wait(1)

			wipeTransparency(gameDetectionPrompt.Layer, 1, true)

			gameDetectionPrompt.Layer.Visible = true

			tweenService:Create(gameDetectionPrompt, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Size = UDim2.new(0, 473, 0, 154)}):Play()
			tweenService:Create(gameDetectionPrompt.ScriptTitle, TweenInfo.new(1, Enum.EasingStyle.Exponential), {Position = UDim2.new(0, 23, 0.352, 0)}):Play()
			tweenService:Create(gameDetectionPrompt, TweenInfo.new(1, Enum.EasingStyle.Exponential), {Position = UDim2.new(0.5, 0, 0, 200)}):Play()
			tweenService:Create(gameDetectionPrompt.UICorner, TweenInfo.new(1, Enum.EasingStyle.Exponential), {CornerRadius = UDim.new(0, 13)}):Play()
			tweenService:Create(gameDetectionPrompt.Thumbnail.UICorner, TweenInfo.new(1, Enum.EasingStyle.Exponential), {CornerRadius = UDim.new(0, 13)}):Play()
			tweenService:Create(gameDetectionPrompt.Thumbnail, TweenInfo.new(1, Enum.EasingStyle.Exponential), {ImageTransparency = 0.5}):Play()

			task.wait(0.3)
			tweenService:Create(gameDetectionPrompt.Layer.ScriptSubtitle, TweenInfo.new(0.6, Enum.EasingStyle.Quint),  {TextTransparency = 0.3}):Play()
			tweenService:Create(gameDetectionPrompt.Layer.Run, TweenInfo.new(0.6, Enum.EasingStyle.Quint),  {TextTransparency = 0}):Play()
			tweenService:Create(gameDetectionPrompt.Layer.Run.UIStroke, TweenInfo.new(0.6, Enum.EasingStyle.Quint),  {Transparency = 0.85}):Play()
			tweenService:Create(gameDetectionPrompt.Layer.Run, TweenInfo.new(0.6, Enum.EasingStyle.Quint),  {BackgroundTransparency = 0.6}):Play()

			task.wait(0.2)

			tweenService:Create(gameDetectionPrompt.Layer.Close, TweenInfo.new(0.7, Enum.EasingStyle.Exponential), {ImageTransparency = 0.6}):Play()

			task.wait(0.3)

			local function closeGameDetection()
				tweenService:Create(gameDetectionPrompt.Layer.ScriptSubtitle, TweenInfo.new(0.3, Enum.EasingStyle.Quint),  {TextTransparency = 1}):Play()
				tweenService:Create(gameDetectionPrompt.Layer.Run, TweenInfo.new(0.3, Enum.EasingStyle.Quint),  {TextTransparency = 1}):Play()
				tweenService:Create(gameDetectionPrompt.Layer.Run, TweenInfo.new(0.3, Enum.EasingStyle.Quint),  {BackgroundTransparency = 1}):Play()
				tweenService:Create(gameDetectionPrompt.Layer.Close, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {ImageTransparency = 1}):Play()
				tweenService:Create(gameDetectionPrompt.Thumbnail, TweenInfo.new(0.3, Enum.EasingStyle.Quint),  {ImageTransparency = 1}):Play()
				tweenService:Create(gameDetectionPrompt.ScriptTitle, TweenInfo.new(0.3, Enum.EasingStyle.Quint),  {TextTransparency = 1}):Play()
				tweenService:Create(gameDetectionPrompt.Layer.Run.UIStroke, TweenInfo.new(0.3, Enum.EasingStyle.Quint),  {Transparency = 1}):Play()
				task.wait(0.05)
				tweenService:Create(gameDetectionPrompt, TweenInfo.new(0.4, Enum.EasingStyle.Quint), {Size = UDim2.new(0, 400, 0, 0)}):Play()
				tweenService:Create(gameDetectionPrompt.UICorner, TweenInfo.new(0.2, Enum.EasingStyle.Exponential), {CornerRadius = UDim.new(0, 5)}):Play()
				tweenService:Create(gameDetectionPrompt.Thumbnail.UICorner, TweenInfo.new(0.2, Enum.EasingStyle.Exponential), {CornerRadius = UDim.new(0, 5)}):Play()
				task.wait(0.41)
				gameDetectionPrompt.Visible = false
			end

			gameDetectionPrompt.Layer.Run.MouseButton1Click:Connect(function()
				closeGameDetection()
				queueNotification("Running "..gameFound.name, "Now running Sirius' "..gameFound.name.." script, this may take a moment.", 4400701828)
				runScript(rawFile)

			end)

			gameDetectionPrompt.Layer.Close.MouseButton1Click:Connect(function()
				closeGameDetection()
			end)

			break
		end
	end
end

local function refreshSliderPadding(data)
	if not data or not data.object then
		return false
	end

	local interact = data.object:FindFirstChild("Interact")
	if not interact then
		return false
	end

	local left = interact.AbsolutePosition.X
	local right = left + interact.AbsoluteSize.X
	if right <= left then
		return false
	end

	data.padding = {left, right}
	return true
end

local function updateSliderPadding()
	for _, v in pairs(siriusValues.sliders) do
		refreshSliderPadding(v)
	end
end

function siriusValues.getSliderPointerX(input)
	if input and input.UserInputType == Enum.UserInputType.Touch then
		return input.Position.X
	end

	return userInputService:GetMouseLocation().X
end

local function updateSlider(data, setValue, forceValue, pointerX)
	local inverse_interpolation

	if setValue then
		setValue = math.clamp(setValue, data.values[1], data.values[2])
		inverse_interpolation = (setValue - data.values[1]) / (data.values[2] - data.values[1])
	else
		refreshSliderPadding(data)
		if not data.padding or data.padding[2] <= data.padding[1] then
			return
		end

		local posX = math.clamp(pointerX or data.pointerX or siriusValues.getSliderPointerX(), data.padding[1], data.padding[2])
		inverse_interpolation = (posX - data.padding[1]) / (data.padding[2] - data.padding[1])
	end

	tweenService:Create(data.object.Progress, TweenInfo.new(.5, Enum.EasingStyle.Quint), {Size = UDim2.new(inverse_interpolation, 0, 1, 0)}):Play()

	local value = math.floor(data.values[1] + (data.values[2] - data.values[1]) * inverse_interpolation + .5)
	data.object.Information.Text = value.." "..data.name
	data.value = value

	if data.callback and ((not setValue) or forceValue) then
		data.callback(value)
	end
end

local function resetSliders()
	for _, v in pairs(siriusValues.sliders) do
		updateSlider(v, v.default, true)
	end
end

local actionIconIdleTransparency = 0.22
local actionIconActiveTransparency = 0
local actionIconColor = Color3.fromRGB(255, 255, 255)
local actionVisualTweens = {}
local actionIconSwapIds = {}

local function applySharpIcon(icon, transparency)
	icon.ImageColor3 = actionIconColor
	icon.ImageTransparency = transparency

	pcall(function()
		icon.ScaleType = Enum.ScaleType.Fit
	end)

	pcall(function()
		icon.ResampleMode = Enum.ResamplerMode.Default
	end)
end

local function resolveActionIcon(iconSource)
	if type(iconSource) == "number" then
		local numericId = string.format("%.0f", iconSource)
		if string.len(numericId) > 11 then
			return "rbxthumb://type=Asset&id=" .. numericId .. "&w=150&h=150"
		end
		return "rbxassetid://" .. numericId
	end

	if type(iconSource) == "string" then
		if string.match(iconSource, "^%d+$") then
			if string.len(iconSource) > 11 then
				return "rbxthumb://type=Asset&id=" .. iconSource .. "&w=150&h=150"
			end
			return "rbxassetid://" .. iconSource
		end

		if string.find(iconSource, "rbxthumb://", 1, true) == 1 then
			return iconSource
		end

		if string.find(iconSource, "rbxassetid://", 1, true) == 1 then
			return iconSource
		end

		if string.find(iconSource, "https://", 1, true) == 1 or string.find(iconSource, "http://", 1, true) == 1 then
			local resolvedIcon = iconSource
			pcall(function()
				if typeof(getcustomasset) ~= "function" or typeof(writefile) ~= "function" or typeof(game.HttpGet) ~= "function" then return end

				local folder = "SIRIUSXIcons"
				if typeof(makefolder) == "function" then
					if typeof(isfolder) == "function" then
						if not isfolder(folder) then
							makefolder(folder)
						end
					else
						pcall(makefolder, folder)
					end
				end

				local fileName = iconSource:match("([^/%?]+)%.png") or "character-action-icon"
				local filePath = folder.."/"..fileName..".png"
				if typeof(isfile) ~= "function" or not isfile(filePath) then
					writefile(filePath, game:HttpGet(iconSource))
				end

				resolvedIcon = getcustomasset(filePath)
			end)
			return resolvedIcon
		end
	end

	return tostring(iconSource or "")
end

local function playActionVisualTween(object, channel, tweenInfo, properties)
	actionVisualTweens[object] = actionVisualTweens[object] or {}

	if actionVisualTweens[object][channel] then
		actionVisualTweens[object][channel]:Cancel()
	end

	local tween = tweenService:Create(object, tweenInfo, properties)
	actionVisualTweens[object][channel] = tween
	tween.Completed:Connect(function()
		if actionVisualTweens[object] and actionVisualTweens[object][channel] == tween then
			actionVisualTweens[object][channel] = nil
		end
	end)
	tween:Play()

	return tween
end

local function transitionActionIcon(icon, imageId, targetTransparency)
	actionIconSwapIds[icon] = (actionIconSwapIds[icon] or 0) + 1
	local swapId = actionIconSwapIds[icon]
	local midTransparency = math.max(targetTransparency, 0.44)

	playActionVisualTween(icon, "clarity", TweenInfo.new(0.08, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {
		ImageColor3 = actionIconColor,
		ImageTransparency = midTransparency
	})

	task.delay(0.07, function()
		if actionIconSwapIds[icon] ~= swapId then return end
		icon.Image = resolveActionIcon(imageId)
		applySharpIcon(icon, midTransparency)

		playActionVisualTween(icon, "clarity", TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
			ImageColor3 = actionIconColor,
			ImageTransparency = targetTransparency
		})
		end)
	end
	
	siriusValues.adminAbilityAliases = {
		all = "all", stopall = "all", stopabilities = "all", disableall = "all",
		noclip = "Noclip", clip = "Noclip",
		fly = "Flight", unfly = "Flight", flight = "Flight",
		fling = "Fling",
		esp = "Extrasensory Perception", extrasensory = "Extrasensory Perception", extrasensoryperception = "Extrasensory Perception",
		infjump = "Infinite Jump", infinitejump = "Infinite Jump",
		walkinair = "Walk in Air", airwalk = "Walk in Air",
		antivoid = "Anti Void",
		autofind = "Auto Find [works with auto aim]", find = "Auto Find [works with auto aim]",
		clicktp = "click teleport tool", clickteleport = "click teleport tool", clickteleporttool = "click teleport tool",
		ghost = "Ghost Mode / Spectate", ghostmode = "Ghost Mode / Spectate", spectate = "Ghost Mode / Spectate", ghostspectate = "Ghost Mode / Spectate",
		shader = "Shaders", shaders = "Shaders",
		invis = "Invisibility", invisible = "Invisibility", invisibility = "Invisibility",
		autoaim = "auto aim", aim = "auto aim",
		blur = "smooth screen blur", screenblur = "smooth screen blur", smoothscreenblur = "smooth screen blur",
	}

	function siriusValues.normaliseAdminAbilityKey(value)
		return tostring(value or ""):lower():gsub("[^%w]", "")
	end

	function siriusValues.resolveAdminAbilityName(value)
		local key = siriusValues.normaliseAdminAbilityKey(value)
		if key == "" then return nil end

		local alias = siriusValues.adminAbilityAliases[key]
		if alias then return alias end

		for _, action in ipairs(siriusValues.actions) do
			if siriusValues.normaliseAdminAbilityKey(action.name) == key then return action.name end
		end
		for _, slider in ipairs(siriusValues.sliders) do
			if siriusValues.normaliseAdminAbilityKey(slider.name) == key then return slider.name end
		end

		return nil
	end

	function siriusValues.setAdminActionVisualOff(action)
		local resolved = checkAction(action.name)
		local object = resolved and resolved.object
		if object then
			transitionActionIcon(object.Icon, action.images[2], actionIconIdleTransparency)
			playActionVisualTween(object, "surface", TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.55})
			playActionVisualTween(object.UIStroke, "stroke", TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.4})
		end
	end

	function siriusValues.disableSiriusAbilityByName(abilityName, context)
		local resolvedName = siriusValues.resolveAdminAbilityName(abilityName)
		if not resolvedName then
			return false, "Unknown ability"
		end

		if resolvedName == "all" then
			if siriusValues.stopActiveAbilitiesForModeratorDetection then
				pcall(siriusValues.stopActiveAbilitiesForModeratorDetection, context or "remote beta control")
			end
			return true, "all abilities"
		end

		for _, action in ipairs(siriusValues.actions) do
			if action.name == resolvedName then
				if action.enabled then
					action.enabled = false
					if action.callback then
						pcall(action.callback, false)
					end
				end
				siriusValues.setAdminActionVisualOff(action)
				return true, action.name
			end
		end

		for _, slider in ipairs(siriusValues.sliders) do
			if slider.name == resolvedName then
				local targetValue = slider.name == "auto aim" and 0 or slider.default
				if slider.object then
					updateSlider(slider, targetValue, true)
				else
					slider.value = targetValue
					if slider.callback then
						pcall(slider.callback, targetValue)
					end
				end
				return true, slider.name
			end
		end

		return false, "Unknown ability"
	end

	siriusValues.stopActiveAbilitiesForModeratorDetection = function(context)
		local stopped = 0
		local reason = tostring(context or "moderator/admin role was detected")

	if playerActionSystem.stopAllPlayerActions then
		pcall(playerActionSystem.stopAllPlayerActions, reason)
	end

	for _, action in ipairs(siriusValues.actions) do
		if action.enabled and not action.disableAfter and action.name ~= "Refresh" and action.name ~= "Respawn" then
			action.enabled = false
			stopped += 1

			if action.callback then
				pcall(action.callback, false)
			end

			local resolved = checkAction(action.name)
			local object = resolved and resolved.object
			if object then
				transitionActionIcon(object.Icon, action.images[2], actionIconIdleTransparency)
				playActionVisualTween(object, "surface", TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.55})
				playActionVisualTween(object.UIStroke, "stroke", TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.4})
			end
		end
	end

	pcall(function()
		characterRuntime.setAutoFindEnabled(false)
	end)
	pcall(function()
		characterRuntime.walkInAirEnabled = false
		characterRuntime.clearWalkInAirLane()
	end)
	pcall(function()
		characterRuntime.clickTeleportEnabled = false
		characterRuntime.destroyClickTeleportTool()
	end)
	pcall(function()
		if characterRuntime.ghostModeEnabled then
			characterRuntime.applyGhostMode(false)
		end
	end)
	pcall(function()
		if characterRuntime.invisibilityEnabled then
			characterRuntime.applyInvisibility(false)
		end
	end)

	if stopped > 0 and reason ~= "remote beta control" then
		queueNotification("Abilities Stopped", "Active abilities were disabled after "..reason..".", 3944670656)
	end
end

local function sortActions()	
	characterPanel.Interactions.Grid.Template.Visible = false
	characterPanel.Interactions.Sliders.Template.Visible = false

	for _, action in ipairs(siriusValues.actions) do
		if action.hidden then
			continue
		end

		local newAction = characterPanel.Interactions.Grid.Template:Clone()
		newAction.Name = action.name
		newAction.Parent = characterPanel.Interactions.Grid
		newAction.BackgroundColor3 = action.color
		newAction.UIStroke.Color = action.color
		newAction.Icon.Image = resolveActionIcon(action.images[2])
		applySharpIcon(newAction.Icon, actionIconIdleTransparency)
		newAction.Visible = true

		newAction.BackgroundTransparency = 0.8
		newAction.Transparency = 0.7


		newAction.MouseEnter:Connect(function()
			characterPanel.Interactions.ActionsTitle.Text = string.upper(action.name)
			if action.enabled or debounce then return end
			playActionVisualTween(newAction, "surface", TweenInfo.new(0.36, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.4})
			playActionVisualTween(newAction.UIStroke, "stroke", TweenInfo.new(0.42, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.6})
		end)

		newAction.MouseLeave:Connect(function()
			if action.enabled or debounce then return end
			playActionVisualTween(newAction, "surface", TweenInfo.new(0.3, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.55})
			playActionVisualTween(newAction.UIStroke, "stroke", TweenInfo.new(0.3, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.4})
		end)

		characterPanel.Interactions.Grid.MouseLeave:Connect(function()
			characterPanel.Interactions.ActionsTitle.Text = "PLAYER ACTIONS"
		end)

		newAction.Interact.MouseButton1Click:Connect(function()
			local success, response = pcall(function()
				action.enabled = not action.enabled
				action.callback(action.enabled)

				if action.enabled then
					transitionActionIcon(newAction.Icon, action.images[1], actionIconActiveTransparency)
					playActionVisualTween(newAction, "surface", TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.1})
					playActionVisualTween(newAction.UIStroke, "stroke", TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 1})

					if action.disableAfter then
						task.delay(action.disableAfter, function()
							action.enabled = false
							transitionActionIcon(newAction.Icon, action.images[2], actionIconIdleTransparency)
							playActionVisualTween(newAction, "surface", TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.55})
							playActionVisualTween(newAction.UIStroke, "stroke", TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.4})
						end)
					end

					if action.rotateWhileEnabled then
						repeat
							newAction.Icon.Rotation = 0
							tweenService:Create(newAction.Icon, TweenInfo.new(0.75, Enum.EasingStyle.Quint), {Rotation = 360}):Play()
							task.wait(1)
						until not action.enabled
						newAction.Icon.Rotation = 0
					end
				else
					transitionActionIcon(newAction.Icon, action.images[2], actionIconIdleTransparency)
					playActionVisualTween(newAction, "surface", TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.55})
					playActionVisualTween(newAction.UIStroke, "stroke", TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.4})
				end
			end)

			if not success then
				queueNotification("Action Error", "This action ('"..(action.name).."') had an error while running, please report this to the Sirius team at sirius.menu/discord", 4370336704)
				action.enabled = false
				transitionActionIcon(newAction.Icon, action.images[2], actionIconIdleTransparency)
				playActionVisualTween(newAction, "surface", TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.55})
				playActionVisualTween(newAction.UIStroke, "stroke", TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.4})
			end
		end)
	end

	if localPlayer.Character then
		if not localPlayer.Character:FindFirstChildOfClass('Humanoid').UseJumpPower then
			siriusValues.sliders[2].name = "jump height"
			siriusValues.sliders[2].default = 7.2
			siriusValues.sliders[2].values = {0, 120}
		end
	end


	for _, slider in ipairs(siriusValues.sliders) do
		local newSlider = characterPanel.Interactions.Sliders.Template:Clone()
		newSlider.Name = slider.name.." Slider"
		newSlider.Parent = characterPanel.Interactions.Sliders
		newSlider.BackgroundColor3 = slider.color
		newSlider.Progress.BackgroundColor3 = slider.color
		newSlider.UIStroke.Color = slider.color
		newSlider.Information.Text = slider.name
		newSlider.Visible = true

		slider.object = newSlider

		slider.padding = {
			newSlider.Interact.AbsolutePosition.X,
			newSlider.Interact.AbsolutePosition.X + newSlider.Interact.AbsoluteSize.X
		}

		newSlider.MouseEnter:Connect(function()
			if debounce or slider.active then return end
			tweenService:Create(newSlider, TweenInfo.new(0.4, Enum.EasingStyle.Exponential), {BackgroundTransparency = 0.85}):Play()
			tweenService:Create(newSlider.UIStroke, TweenInfo.new(0.4, Enum.EasingStyle.Exponential), {Transparency = 0.6}):Play()
			tweenService:Create(newSlider.Information, TweenInfo.new(0.4, Enum.EasingStyle.Exponential), {TextTransparency = 0.2}):Play()
		end)

		newSlider.MouseLeave:Connect(function()
			if debounce or slider.active then return end
			tweenService:Create(newSlider, TweenInfo.new(0.4, Enum.EasingStyle.Exponential), {BackgroundTransparency = 0.8}):Play()
			tweenService:Create(newSlider.UIStroke, TweenInfo.new(0.4, Enum.EasingStyle.Exponential), {Transparency = 0.5}):Play()
			tweenService:Create(newSlider.Information, TweenInfo.new(0.4, Enum.EasingStyle.Exponential), {TextTransparency = 0.3}):Play()
		end)

		newSlider.Interact.InputBegan:Connect(function(input, processed)
			if processed then return end
			if input.UserInputType ~= Enum.UserInputType.MouseButton1 and input.UserInputType ~= Enum.UserInputType.Touch then return end
			if debounce or not checkSirius() then return end

			refreshSliderPadding(slider)
			slider.active = true
			slider.activeInput = input
			slider.pointerX = siriusValues.getSliderPointerX(input)
			updateSlider(slider, nil, nil, slider.pointerX)

			tweenService:Create(slider.object, TweenInfo.new(0.4, Enum.EasingStyle.Exponential), {BackgroundTransparency = 0.9}):Play()
			tweenService:Create(slider.object.UIStroke, TweenInfo.new(0.4, Enum.EasingStyle.Exponential), {Transparency = 1}):Play()
			tweenService:Create(slider.object.Information, TweenInfo.new(0.4, Enum.EasingStyle.Exponential), {TextTransparency = 0.05}):Play()
		end)

			updateSlider(slider, slider.default)
		end

		task.defer(function()
			characterRuntime.refreshCharacterPanelScroll()
			updateSliderPadding()
		end)
	end

local function getAdaptiveHighPingThreshold()
	local adaptiveBaselinePings = siriusValues.pingProfile.adaptiveBaselinePings

	if #adaptiveBaselinePings == 0 then
		return siriusValues.pingProfile.adaptiveHighPingThreshold
	end

	table.sort(adaptiveBaselinePings)
	local median
	if #adaptiveBaselinePings % 2 == 0 then
		median = (adaptiveBaselinePings[#adaptiveBaselinePings/2] + adaptiveBaselinePings[#adaptiveBaselinePings/2 + 1]) / 2
	else
		median = adaptiveBaselinePings[math.ceil(#adaptiveBaselinePings/2)]
	end

	return median * siriusValues.pingProfile.spikeThreshold
end

local function checkHighPing()
	local recentPings = siriusValues.pingProfile.recentPings
	local adaptiveBaselinePings = siriusValues.pingProfile.adaptiveBaselinePings

	local currentPing = getPing()
	table.insert(recentPings, currentPing)

	if #recentPings > siriusValues.pingProfile.maxSamples then
		table.remove(recentPings, 1)
	end

	if #adaptiveBaselinePings < siriusValues.pingProfile.adaptiveBaselineSamples then
		if currentPing >= 350 then currentPing = 300 end

		table.insert(adaptiveBaselinePings, currentPing)

		return false
	end

	local averagePing = 0
	for _, ping in ipairs(recentPings) do
		averagePing = averagePing + ping
	end
	averagePing = averagePing / #recentPings

	if averagePing > getAdaptiveHighPingThreshold() then
		return true
	end

	return false
end

local function checkTools()
	task.wait(0.03)
	if localPlayer.Backpack and localPlayer.Character then
		if localPlayer.Backpack:FindFirstChildOfClass('Tool') or localPlayer.Character:FindFirstChildOfClass('Tool') then
			return true
		end
	else
		return false
	end
end

