	local function createServerRow(parent, y, serverData, index, isHistory)
		local row = Instance.new("Frame")
		row.Name = serverData.id or "Server"
		row.BackgroundColor3 = isHistory and Color3.fromRGB(21, 21, 21) or Color3.fromRGB(18, 18, 18)
		row.BackgroundTransparency = 0.18
