		row.Size = UDim2.new(0, 526, 0, 44)
		row.Parent = parent
		styleRow(row)

		local isCurrent = serverData.id == jobId
		local playingText = tostring(serverData.playing or "?").."/"..tostring(serverData.maxPlayers or "?")
		local title = isHistory and (serverData.label or "Previous server") or ("Server "..index)
		if isCurrent then title = title.."  CURRENT" end

		local titleLabel = createLabel(row, title, UDim2.new(0, 12, 0, 5), UDim2.new(0, 250, 0, 18), 12, 0.12)
		titleLabel.Font = Enum.Font.GothamBold
		createLabel(row, playingText.." players  id "..string.sub(tostring(serverData.id or ""), 1, 10), UDim2.new(0, 12, 0, 22), UDim2.new(0, 300, 0, 16), 11, 0.42)

		if originalSetClipboard then
			local copyButton = createButton(row, "Copy", UDim2.new(1, -144, 0, 8), UDim2.new(0, 54, 0, 28), Color3.fromRGB(44, 44, 44))
			copyButton.MouseButton1Click:Connect(function()
				originalSetClipboard(tostring(serverData.id or ""))
				queueNotification("Server ID Copied", "The server JobId is now on your clipboard.", 4400696294)
			end)
		end

		local joinButton = createButton(row, isCurrent and "Here" or "Join", UDim2.new(1, -82, 0, 8), UDim2.new(0, 66, 0, 28), isCurrent and Color3.fromRGB(42, 42, 42) or Color3.fromRGB(42, 90, 125))
		joinButton.MouseButton1Click:Connect(function()
			if isCurrent then
				return setStatus("You are already in this server.")
			end

			teleportToServer(serverData.id, "Joining server with "..playingText.." players.", serverData.playing, serverData.maxPlayers)
		end)
	end

	local function renderHistory()
		clearRows(historyRows)
		local history = loadServerHistory()

		if #history == 0 then
			createLabel(historyRows, "No previous server hops yet.", UDim2.new(0, 2, 0, 0), UDim2.new(0, 400, 0, 32), 12, 0.45)
			historyRows.Size = UDim2.new(0, 526, 0, 36)
			return 36
		end

		local y = 0
		for index, entry in ipairs(history) do
			if index > 5 then break end
			createServerRow(historyRows, y, entry, index, true)
			y = y + 50
		end

		historyRows.Size = UDim2.new(0, 526, 0, y)
		return y
	end

	local function sortServers()
		table.sort(serverResults, function(a, b)
			local aPlayers = tonumber(a.playing) or 0
			local bPlayers = tonumber(b.playing) or 0

			if sortAscending then
				return aPlayers < bPlayers
			end

			return aPlayers > bPlayers
		end)
	end

	local function renderServers()
		clearRows(serverRows)
		sortServers()

		local y = 0
		if #serverResults == 0 then
			createLabel(serverRows, "No server results yet. Run a scan or search for a player.", UDim2.new(0, 2, 0, 0), UDim2.new(0, 430, 0, 34), 12, 0.45)
			y = 40
		else
			for index, serverData in ipairs(serverResults) do
				if index > 60 then break end
				createServerRow(serverRows, y, serverData, index, false)
				y = y + 50
			end
		end

		serverRows.Size = UDim2.new(0, 526, 0, y)
		historyTitle.Position = UDim2.new(0, 16, 0, 214 + y)
		historyRows.Position = UDim2.new(0, 16, 0, 240 + y)
		local historyHeight = renderHistory()
		updateCanvas(260 + y + historyHeight)
	end

	local function scanServers(maxPages)
		activeScanId = activeScanId + 1
		local scanId = activeScanId
		serverResults = {}
		foundPlayerServer = nil
		joinFoundButton.TextTransparency = 0.55
		renderServers()

		task.spawn(function()
			local cursor
			local page = 0

			while page < maxPages do
				page = page + 1
				if activeScanId ~= scanId then return end
				setStatus("Scanning servers page "..page.."...")

				local response, err = fetchServerPage(sortAscending and "Asc" or "Desc", cursor)
				if not response then
					setStatus("Server scan failed: "..tostring(err))
					return
				end

				for _, serverData in ipairs(response.data or {}) do
					if type(serverData) == "table" and serverData.id and serverData.id ~= jobId then
						table.insert(serverResults, serverData)
					end
				end

				renderServers()
				cursor = response.nextPageCursor

				if not cursor or cursor == "" then break end
				task.wait()
			end

			setStatus("Scan complete. Found "..#serverResults.." public servers for this experience.")
		end)
	end

	local function joinEmptyServer()
		activeScanId = activeScanId + 1
		local scanId = activeScanId

		task.spawn(function()
			setStatus("Searching for a listed 0-player server...")

			for _, serverData in ipairs(serverResults) do
				if serverData.playing == 0 and serverData.id ~= jobId then
					return teleportToServer(serverData.id, "Joining a listed 0-player server.", serverData.playing, serverData.maxPlayers)
				end
			end

			local cursor
			for page = 1, 30 do
				if activeScanId ~= scanId then return end
				setStatus("Searching empty servers page "..page.."...")

				local response = fetchServerPage("Asc", cursor)
				if not response then break end

				for _, serverData in ipairs(response.data or {}) do
					if type(serverData) == "table" and serverData.id ~= jobId and serverData.playing == 0 then
						return teleportToServer(serverData.id, "Joining a listed 0-player server.", serverData.playing, serverData.maxPlayers)
					end
				end

				cursor = response.nextPageCursor
				if not cursor or cursor == "" then break end
				task.wait()
			end

			setStatus("No listed 0-player server found. Use Fresh Server to ask Roblox for a new one.")
		end)
	end

	local function searchPlayer(username)
		username = string.gsub(username or "", "^%s*(.-)%s*$", "%1")

		if username == "" then
			return setStatus("Type a username before searching.")
		end

		activeScanId = activeScanId + 1
		local scanId = activeScanId
		foundPlayerServer = nil
		joinFoundButton.TextTransparency = 0.55

		task.spawn(function()
			setStatus("Resolving username "..username.."...")
			local userId, resolvedName = getUserIdFromUsername(username)

			if not userId then
				return setStatus("Could not find that Roblox username.")
			end

			local targetHeadshot = getUserHeadshot(userId)
			if not targetHeadshot then
				return setStatus("Could not load avatar data for "..resolvedName..".")
			end

			local cursor
			local checkedServers = 0
			local batch = {}
			local batchMap = {}

			local function flushBatch()
				if #batch == 0 then return end

				local response = requestJson("https://thumbnails.roblox.com/v1/batch", "POST", batch)
				batch = {}

				if response and response.data then
					for _, thumb in ipairs(response.data) do
						if thumb.imageUrl == targetHeadshot and batchMap[thumb.requestId] then
							return batchMap[thumb.requestId]
						end
					end
				end

				batchMap = {}
			end

			for page = 1, 50 do
				if activeScanId ~= scanId then return end
				setStatus("Searching for "..resolvedName.." on public servers page "..page.."...")

				local response, err = fetchServerPage("Asc", cursor)
				if not response then
					return setStatus("Player search failed: "..tostring(err))
				end

				for _, serverData in ipairs(response.data or {}) do
					checkedServers = checkedServers + 1

					for tokenIndex, token in ipairs(serverData.playerTokens or {}) do
						local requestId = tostring(serverData.id).."|"..tokenIndex
						batchMap[requestId] = serverData
						table.insert(batch, {
							requestId = requestId,
							type = "AvatarHeadShot",
							targetId = 0,
							token = token,
							format = "Png",
							size = "48x48",
							isCircular = false
						})

						if #batch >= 100 then
							local found = flushBatch()
							if found then
								foundPlayerServer = found
								serverResults = {found}
								renderServers()
								joinFoundButton.TextTransparency = 0.08
								setStatus("Found "..resolvedName.." in a public server with "..tostring(found.playing).."/"..tostring(found.maxPlayers).." players.")
								return
							end
						end
					end
				end

				local found = flushBatch()
				if found then
					foundPlayerServer = found
					serverResults = {found}
					renderServers()
					joinFoundButton.TextTransparency = 0.08
					setStatus("Found "..resolvedName.." in a public server with "..tostring(found.playing).."/"..tostring(found.maxPlayers).." players.")
					return
				end

				cursor = response.nextPageCursor
				if not cursor or cursor == "" then break end
				task.wait()
			end

			setStatus("Could not find "..resolvedName.." after checking "..checkedServers.." public servers.")
		end)
	end

	local function getSearchText()
		local topSearchText = searchRow.InputFrame.InputBox.Text
		if topSearchText and topSearchText ~= "" then
			return topSearchText
		end

		return playerSearch.Text
	end

	scanButton.MouseButton1Click:Connect(function()
		scanServers(12)
	end)
	scanRow.Interact.MouseButton1Click:Connect(function()
		scanServers(12)
	end)

	sortButton.MouseButton1Click:Connect(function()
		sortAscending = not sortAscending
		sortButton.Text = sortAscending and "SORT: LOW" or "SORT: HIGH"
		renderServers()
	end)

	emptyButton.MouseButton1Click:Connect(joinEmptyServer)
	emptyRow.Interact.MouseButton1Click:Connect(joinEmptyServer)
	freshButton.MouseButton1Click:Connect(teleportFreshServer)
	freshRow.Interact.MouseButton1Click:Connect(teleportFreshServer)
	searchButton.MouseButton1Click:Connect(function()
		searchPlayer(getSearchText())
	end)
	searchNowRow.Interact.MouseButton1Click:Connect(function()
		searchPlayer(getSearchText())
	end)
	playerSearch.FocusLost:Connect(function(enterPressed)
		if enterPressed then
			searchPlayer(getSearchText())
		end
	end)
	searchRow.InputFrame.InputBox.FocusLost:Connect(function(enterPressed)
		playerSearch.Text = searchRow.InputFrame.InputBox.Text

		if enterPressed then
			searchPlayer(getSearchText())
		end
	end)
	joinFoundButton.MouseButton1Click:Connect(function()
		if foundPlayerServer then
			teleportToServer(foundPlayerServer.id, "Joining the found player's public server.", foundPlayerServer.playing, foundPlayerServer.maxPlayers)
		else
			setStatus("Search for a player first.")
		end
	end)
	joinFoundRow.Interact.MouseButton1Click:Connect(function()
		if foundPlayerServer then
			teleportToServer(foundPlayerServer.id, "Joining the found player's public server.", foundPlayerServer.playing, foundPlayerServer.maxPlayers)
		else
			setStatus("Search for a player first.")
		end
	end)

	renderServers()
end

