	-- Server tools are paused for now. The page intentionally shows a stable placeholder.
	--[[
	local function clearChildren(parent)
		for _, child in ipairs(parent:GetChildren()) do
			child:Destroy()
		end
	end

	local function updateCanvas()
		if not newList:IsA("ScrollingFrame") then return end

		local contentHeight = 0
		local activeLayout = newList:FindFirstChildOfClass("UIListLayout")

		if activeLayout then
			contentHeight = activeLayout.AbsoluteContentSize.Y
		end

		if contentHeight <= 0 then
			for _, dropdown in ipairs(dropdowns) do
				contentHeight = contentHeight + dropdown.row.Size.Y.Offset + 10
			end
		end

		newList.CanvasSize = UDim2.new(0, 0, 0, contentHeight + 26)
		newList.ScrollBarImageTransparency = contentHeight > newList.AbsoluteWindowSize.Y + 8 and 0.55 or 1
	end

	local function createLabel(parent, text, position, size, textSize, transparency, bold)
		local label = Instance.new("TextLabel")
		label.BackgroundTransparency = 1
		label.Font = bold and Enum.Font.GothamBold or Enum.Font.GothamMedium
		label.Text = text
		label.TextColor3 = Color3.fromRGB(238, 238, 238)
		label.TextSize = textSize or 12
		label.TextTransparency = transparency or 0.22
		label.TextXAlignment = Enum.TextXAlignment.Left
		label.TextYAlignment = Enum.TextYAlignment.Center
		label.TextWrapped = true
		label.Position = position
		label.Size = size
		label.Parent = parent

		return label
	end

	local function createButton(parent, text, position, size, color)
		local button = Instance.new("TextButton")
		button.AutoButtonColor = false
		button.BackgroundColor3 = color or Color3.fromRGB(40, 40, 40)
		button.BackgroundTransparency = 0.18
		button.Font = Enum.Font.GothamBold
		button.Text = string.upper(text)
		button.TextColor3 = Color3.fromRGB(245, 245, 245)
		button.TextSize = 11
		button.TextTransparency = 0.1
		button.Position = position
		button.Size = size
