		stroke.Parent = button

		button.MouseEnter:Connect(function()
			tweenService:Create(button, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.04}):Play()
			tweenService:Create(stroke, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.35}):Play()
		end)

		button.MouseLeave:Connect(function()
			tweenService:Create(button, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.18}):Play()
			tweenService:Create(stroke, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.64}):Play()
		end)

		return button
