	local function createDropdown(title, description, layoutOrder, defaultExpandedHeight)
		local dropdown = {
			collapsedHeight = 74,
			expandedHeight = defaultExpandedHeight,
			open = false
		}

		local row = Instance.new("Frame")
		row.Name = title
		row.LayoutOrder = layoutOrder
		row.Parent = newList
		row.Size = UDim2.new(0, 558, 0, dropdown.collapsedHeight)
		row.BackgroundColor3 = Color3.fromRGB(18, 14, 22)
		row.BackgroundTransparency = 0.1
		row.ClipsDescendants = true
		row.Visible = true
		dropdown.row = row

		local corner = Instance.new("UICorner")
		corner.CornerRadius = UDim.new(0, 8)
		corner.Parent = row

		local stroke = Instance.new("UIStroke")
		stroke.Color = Color3.fromRGB(170, 78, 190)
		stroke.Transparency = 0.52
		stroke.Parent = row
		dropdown.stroke = stroke

		local titleLabel = createLabel(row, title, UDim2.new(0, 18, 0, 10), UDim2.new(1, -70, 0, 22), 13, 0.08, true)
		local descriptionLabel = createLabel(row, description, UDim2.new(0, 18, 0, 33), UDim2.new(1, -80, 0, 30), 11, 0.42)

		local arrow = Instance.new("TextLabel")
		arrow.BackgroundTransparency = 1
		arrow.Font = Enum.Font.GothamBold
		arrow.Text = ">"
		arrow.TextColor3 = Color3.fromRGB(232, 232, 232)
		arrow.TextSize = 22
		arrow.TextTransparency = 0.12
		arrow.Position = UDim2.new(1, -48, 0, 21)
		arrow.Size = UDim2.new(0, 26, 0, 26)
		arrow.Parent = row
		dropdown.arrow = arrow

		local content = Instance.new("Frame")
		content.Name = "DropdownContent"
		content.BackgroundTransparency = 1
		content.Position = UDim2.new(0, 16, 0, 78)
		content.Size = UDim2.new(1, -32, 0, defaultExpandedHeight - 88)
		content.Parent = row
		dropdown.content = content

		local hitbox = Instance.new("TextButton")
		hitbox.Name = "DropdownInteract"
		hitbox.BackgroundTransparency = 1
		hitbox.Text = ""
		hitbox.AutoButtonColor = false
		hitbox.Position = UDim2.new(0, 0, 0, 0)
		hitbox.Size = UDim2.new(1, 0, 0, dropdown.collapsedHeight)
		hitbox.Parent = row

		hitbox.MouseEnter:Connect(function()
			tweenService:Create(row, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.05}):Play()
			tweenService:Create(stroke, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.35}):Play()
			tweenService:Create(titleLabel, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {TextTransparency = 0}):Play()
		end)

		hitbox.MouseLeave:Connect(function()
			tweenService:Create(row, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.1}):Play()
			tweenService:Create(stroke, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = dropdown.open and 0.28 or 0.52}):Play()
			tweenService:Create(titleLabel, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {TextTransparency = 0.08}):Play()
		end)

		function dropdown:SetExpandedHeight(height)
			self.expandedHeight = math.max(height, self.collapsedHeight + 60)
			self.content.Size = UDim2.new(1, -32, 0, self.expandedHeight - 88)

			if self.open then
				tweenService:Create(self.row, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Size = UDim2.new(0, 558, 0, self.expandedHeight)}):Play()
				task.delay(0.27, updateCanvas)
			else
				updateCanvas()
			end
		end

		local function closeDropdown(target)
			target.open = false
			tweenService:Create(target.row, TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Size = UDim2.new(0, 558, 0, target.collapsedHeight)}):Play()
			tweenService:Create(target.arrow, TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Rotation = 0}):Play()
			tweenService:Create(target.stroke, TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.52}):Play()
		end

		function dropdown:Open(forceOpen)
			if activeDropdown and activeDropdown ~= self then
				closeDropdown(activeDropdown)
			end

			if self.open and not forceOpen then
				closeDropdown(self)
				activeDropdown = nil
				task.delay(0.3, updateCanvas)
				return
			end

			self.open = true
			activeDropdown = self
			tweenService:Create(self.row, TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Size = UDim2.new(0, 558, 0, self.expandedHeight)}):Play()
			tweenService:Create(self.arrow, TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Rotation = 90}):Play()
			tweenService:Create(self.stroke, TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.18}):Play()
			task.delay(0.36, updateCanvas)
		end

		hitbox.MouseButton1Click:Connect(function()
			dropdown:Open()
		end)

		table.insert(dropdowns, dropdown)
		return dropdown
	end

	local serverDropdown = createDropdown("Server Search", "Scan public servers, sort by players, then join or copy JobIds.", 1, 230)
