	local function createServerMiniRow(parent, y, serverData, index, isHistory)
		local row = Instance.new("Frame")
		row.Name = serverData.id or "Server"
		row.BackgroundColor3 = Color3.fromRGB(22, 19, 25)
		row.BackgroundTransparency = isHistory and 0.14 or 0.1
		row.Position = UDim2.new(0, 0, 0, y)
		row.Size = UDim2.new(1, -4, 0, 44)
		row.Parent = parent
		styleMiniRow(row)

		local isCurrent = serverData.id == jobId
		local playingText = tostring(serverData.playing or "?").."/"..tostring(serverData.maxPlayers or "?")
		local title = isHistory and (serverData.label or "Previous server") or ("Server "..index)
		if isCurrent then title = title.."  CURRENT" end

		createLabel(row, title, UDim2.new(0, 12, 0, 5), UDim2.new(0, 250, 0, 17), 11, 0.1, true)
		createLabel(row, playingText.." players  id "..string.sub(tostring(serverData.id or ""), 1, 10), UDim2.new(0, 12, 0, 22), UDim2.new(0, 300, 0, 16), 10, 0.42)

		if originalSetClipboard then
			local copyButton = createButton(row, "Copy", UDim2.new(1, -142, 0, 8), UDim2.new(0, 54, 0, 28), Color3.fromRGB(44, 44, 44))
			copyButton.MouseButton1Click:Connect(function()
				originalSetClipboard(tostring(serverData.id or ""))
				queueNotification("Server ID Copied", "The server JobId is now on your clipboard.", 4400696294)
			end)
		end

		local joinButton = createButton(row, isCurrent and "Here" or "Join", UDim2.new(1, -80, 0, 8), UDim2.new(0, 64, 0, 28), isCurrent and Color3.fromRGB(42, 42, 42) or Color3.fromRGB(74, 58, 118))
		joinButton.MouseButton1Click:Connect(function()
			if isCurrent then
				setServerStatus("You are already in this server.")
				return
			end

			teleportToServer(serverData.id, "Joining server with "..playingText.." players.", serverData.playing, serverData.maxPlayers)
		end)
	end

	local function sortServers()
		table.sort(serverResults, function(a, b)
			local aPlayers = tonumber(a.playing) or 0
			local bPlayers = tonumber(b.playing) or 0

			if sortAscending then
				return aPlayers < bPlayers
			end

			return aPlayers > bPlayers
		end)
	end

	local function renderServers()
		clearChildren(serverRows)
		sortServers()

		local y = 0
		if #serverResults == 0 then
			createLabel(serverRows, "No server results yet.", UDim2.new(0, 0, 0, 0), UDim2.new(1, 0, 0, 28), 11, 0.45)
			y = 34
		else
			for index, serverData in ipairs(serverResults) do
				if index > 20 then break end
				createServerMiniRow(serverRows, y, serverData, index, false)
				y = y + 50
			end

			if #serverResults > 20 then
				createLabel(serverRows, "Showing first 20 of "..#serverResults.." results. Sort or rescan to refine.", UDim2.new(0, 0, 0, y), UDim2.new(1, 0, 0, 24), 10, 0.48)
				y = y + 28
			end
		end

		serverRows.Size = UDim2.new(1, 0, 0, y)
		serverDropdown:SetExpandedHeight(174 + y)
	end

	local function renderHistory()
		clearChildren(historyRows)
		local history = loadServerHistory()
		local y = 0

		if #history == 0 then
			historyStatus.Text = "No previous server hops yet."
			createLabel(historyRows, "Serverhop once and Sirius will remember the old session here.", UDim2.new(0, 0, 0, 0), UDim2.new(1, 0, 0, 34), 11, 0.45)
			y = 42
		else
			historyStatus.Text = "Tap a remembered session to rejoin it."
			for index, entry in ipairs(history) do
				if index > 6 then break end
				createServerMiniRow(historyRows, y, entry, index, true)
				y = y + 50
			end
		end

		historyRows.Size = UDim2.new(1, 0, 0, y)
		historyDropdown:SetExpandedHeight(120 + y)
	end

	local function scanServers(maxPages)
		serverDropdown:Open(true)
		activeScanId = activeScanId + 1
		local scanId = activeScanId
		serverResults = {}
		foundPlayerServer = nil
		setJoinFoundEnabled(false)
		renderServers()

		task.spawn(function()
			local cursor
			local page = 0

			while page < maxPages do
				page = page + 1
				if activeScanId ~= scanId then return end
				setServerStatus("Scanning page "..page.."...")

				local response, err = fetchServerPage(sortAscending and "Asc" or "Desc", cursor)
				if not response then
					setServerStatus("Server scan failed: "..tostring(err))
					return
				end

				for _, serverData in ipairs(response.data or {}) do
					if type(serverData) == "table" and serverData.id and serverData.id ~= jobId then
						table.insert(serverResults, serverData)
					end
				end

				renderServers()
				cursor = response.nextPageCursor

				if not cursor or cursor == "" then break end
				task.wait()
			end

			setServerStatus("Found "..#serverResults.." public servers.")
		end)
	end

	local function joinEmptyServer()
		emptyDropdown:Open(true)
		activeScanId = activeScanId + 1
		local scanId = activeScanId

		task.spawn(function()
			setEmptyStatus("Checking scanned results for a 0-player server...")

			for _, serverData in ipairs(serverResults) do
				if serverData.playing == 0 and serverData.id ~= jobId then
					return teleportToServer(serverData.id, "Joining a listed 0-player server.", serverData.playing, serverData.maxPlayers)
				end
			end

			local cursor
			for page = 1, 30 do
				if activeScanId ~= scanId then return end
				setEmptyStatus("Searching empty servers page "..page.."...")

				local response = fetchServerPage("Asc", cursor)
				if not response then break end

				for _, serverData in ipairs(response.data or {}) do
					if type(serverData) == "table" and serverData.id ~= jobId and serverData.playing == 0 then
						return teleportToServer(serverData.id, "Joining a listed 0-player server.", serverData.playing, serverData.maxPlayers)
					end
				end

				cursor = response.nextPageCursor
				if not cursor or cursor == "" then break end
				task.wait()
			end

			setEmptyStatus("No listed 0-player server found. Use Fresh Server instead.")
		end)
	end

	local function searchPlayer(username)
		username = string.gsub(username or "", "^%s*(.-)%s*$", "%1")

		if username == "" then
			playerDropdown:Open(true)
			setPlayerStatus("Type a username before searching.")
			return
		end

		playerDropdown:Open(true)
		activeScanId = activeScanId + 1
		local scanId = activeScanId
		foundPlayerServer = nil
		setJoinFoundEnabled(false)

		task.spawn(function()
			setPlayerStatus("Resolving username "..username.."...")
			local userId, resolvedName = getUserIdFromUsername(username)

			if not userId then
				setPlayerStatus("Could not find that Roblox username.")
				return
			end

			local targetHeadshot = getUserHeadshot(userId)
			if not targetHeadshot then
				setPlayerStatus("Could not load avatar data for "..resolvedName..".")
				return
			end

			local cursor
			local checkedServers = 0
			local batch = {}
			local batchMap = {}

			local function flushBatch()
				if #batch == 0 then return end

				local response = requestJson("https://thumbnails.roblox.com/v1/batch", "POST", batch)
				batch = {}

				if response and response.data then
					for _, thumb in ipairs(response.data) do
						if thumb.imageUrl == targetHeadshot and batchMap[thumb.requestId] then
							return batchMap[thumb.requestId]
						end
					end
				end

				batchMap = {}
			end

			for page = 1, 50 do
				if activeScanId ~= scanId then return end
				setPlayerStatus("Searching "..resolvedName.." on page "..page.."...")

				local response, err = fetchServerPage("Asc", cursor)
				if not response then
					setPlayerStatus("Player search failed: "..tostring(err))
					return
				end

				for _, serverData in ipairs(response.data or {}) do
					checkedServers = checkedServers + 1

					for tokenIndex, token in ipairs(serverData.playerTokens or {}) do
						local requestId = tostring(serverData.id).."|"..tokenIndex
						batchMap[requestId] = serverData
						table.insert(batch, {
							requestId = requestId,
							type = "AvatarHeadShot",
							targetId = 0,
							token = token,
							format = "Png",
							size = "48x48",
							isCircular = false
						})

						if #batch >= 100 then
							local found = flushBatch()
							if found then
								foundPlayerServer = found
								serverResults = {found}
								renderServers()
								setJoinFoundEnabled(true)
								setPlayerStatus("Player found in a server with "..tostring(found.playing).."/"..tostring(found.maxPlayers).." players.")
								return
							end
						end
					end
				end

				local found = flushBatch()
				if found then
					foundPlayerServer = found
					serverResults = {found}
					renderServers()
					setJoinFoundEnabled(true)
					setPlayerStatus("Player found in a server with "..tostring(found.playing).."/"..tostring(found.maxPlayers).." players.")
					return
				end

				cursor = response.nextPageCursor
				if not cursor or cursor == "" then break end
				task.wait()
			end

			setPlayerStatus("Could not find "..resolvedName.." after checking "..checkedServers.." servers.")
		end)
	end

	scanButton.MouseButton1Click:Connect(function()
		scanServers(12)
	end)

	sortButton.MouseButton1Click:Connect(function()
		sortAscending = not sortAscending
		sortButton.Text = sortAscending and "SORT: LOW" or "SORT: HIGH"
		renderServers()
	end)

	searchButton.MouseButton1Click:Connect(function()
		searchPlayer(playerSearch.Text)
	end)

	playerSearch.FocusLost:Connect(function(enterPressed)
		if enterPressed then
			searchPlayer(playerSearch.Text)
		end
	end)

	joinFoundButton.MouseButton1Click:Connect(function()
		if foundPlayerServer then
			teleportToServer(foundPlayerServer.id, "Joining the found player's public server.", foundPlayerServer.playing, foundPlayerServer.maxPlayers)
		else
			setPlayerStatus("Search for a player first.")
		end
	end)

	emptyButton.MouseButton1Click:Connect(joinEmptyServer)
	freshButton.MouseButton1Click:Connect(function()
		emptyDropdown:Open(true)
		setEmptyStatus("Creating fresh server...")
		teleportFreshServer()
	end)

	historyDropdown.row.DropdownInteract.MouseButton1Click:Connect(function()
		task.defer(renderHistory)
	end)

	setJoinFoundEnabled(false)
	renderServers()
	renderHistory()
	serverDropdown:Open(true)
	updateCanvas()
	]]
end

