		local function fadePromptObjects()
			local fadeMotion = TweenInfo.new(0.2, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)

			for _, object in ipairs(createdObjects) do
				if object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox") then
					tweenService:Create(object, fadeMotion, {TextTransparency = 1, BackgroundTransparency = 1}):Play()
				elseif object:IsA("ImageLabel") or object:IsA("ImageButton") then
					tweenService:Create(object, fadeMotion, {ImageTransparency = 1, BackgroundTransparency = 1}):Play()
				elseif object:IsA("ScrollingFrame") then
					tweenService:Create(object, fadeMotion, {BackgroundTransparency = 1, ScrollBarImageTransparency = 1}):Play()
				elseif object:IsA("Frame") then
					tweenService:Create(object, fadeMotion, {BackgroundTransparency = 1}):Play()
				elseif object:IsA("UIStroke") then
					tweenService:Create(object, fadeMotion, {Transparency = 1}):Play()
				end

				if object:FindFirstChildOfClass("UIStroke") then
					tweenService:Create(object:FindFirstChildOfClass("UIStroke"), fadeMotion, {Transparency = 1}):Play()
				end
