			if scriptSaveState.promptToken ~= morphToken then
				destroyPromptObjects()
				debounce = false
				promptClosed = true
				return
			end
			destroyPromptObjects()

			if decisionValue then
				scriptSearch.UIGradient.Color = previous.gradientColor
				scriptSearch.UIGradient.Offset = previous.gradientOffset
				scriptSearch.UIGradient.Rotation = previous.gradientRotation
				scriptSearch.UIGradient.Enabled = previous.gradientEnabled
				restoreMorphShadowGradient()
				scriptSearch.ClipsDescendants = previous.clips
				scriptSaveState.transition = "open"
				debounce = false
				promptClosed = true
				return
			end

			restoreSearchPanel()
			task.wait(0.42)
			scriptSearch.ClipsDescendants = previous.clips
			scriptSaveState.transition = "open"
			debounce = false
			promptClosed = true
		end

		backButton.MouseButton1Click:Connect(function()
			finishPrompt(false)
		end)

		local function createMorphButton(name, text, position, size, backgroundColor, decisionValue)
			local button = track(Instance.new("TextButton"))
			button.Name = "Morph"..name
			button.Parent = scriptSearch
			button.AutoButtonColor = false
			button.BackgroundColor3 = backgroundColor
			button.BackgroundTransparency = 1
			button.BorderSizePixel = 0
			button.Font = Enum.Font.GothamBold
			button.Position = position
			button.Size = size
			button.Text = text
			button.TextColor3 = Color3.fromRGB(255, 255, 255)
			button.TextSize = 15
			button.TextStrokeColor3 = Color3.fromRGB(0, 0, 0)
			button.TextStrokeTransparency = 0.82
			button.TextTransparency = 1
			button.ZIndex = 44

			local corner = Instance.new("UICorner")
			corner.CornerRadius = UDim.new(0, 8)
			corner.Parent = button

			local stroke = Instance.new("UIStroke")
			stroke.Color = decisionValue and accentColor:Lerp(Color3.fromRGB(255, 255, 255), 0.22) or scriptSearchBrand.stroke
			stroke.Transparency = 1
			stroke.Parent = button

			local buttonGradient = Instance.new("UIGradient")
			buttonGradient.Color = decisionValue and ColorSequence.new({
					ColorSequenceKeypoint.new(0, accentColor:Lerp(Color3.fromRGB(255, 255, 255), 0.08)),
					ColorSequenceKeypoint.new(1, accentColor:Lerp(Color3.fromRGB(5, 7, 9), 0.34))
			}) or ColorSequence.new({
				ColorSequenceKeypoint.new(0, Color3.fromRGB(27, 28, 31)),
				ColorSequenceKeypoint.new(1, Color3.fromRGB(18, 19, 21))
			})
			buttonGradient.Rotation = 90
			buttonGradient.Offset = Vector2.new(0, decisionValue and 0.25 or 0)
			buttonGradient.Parent = button
			buttonGradient.Enabled = false

			local buttonScale = Instance.new("UIScale")
			buttonScale.Scale = 1
			buttonScale.Parent = button

			button.MouseEnter:Connect(function()
				local hoverTween = TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
				button.TextColor3 = Color3.fromRGB(255, 255, 255)
				button.TextStrokeTransparency = 0.72
				tweenService:Create(button, hoverTween, {BackgroundTransparency = decisionValue and 0.04 or 0.08, TextTransparency = 0}):Play()
				tweenService:Create(stroke, hoverTween, {Transparency = decisionValue and 0.42 or 0.58}):Play()
				tweenService:Create(buttonGradient, hoverTween, {Offset = Vector2.new(0, decisionValue and -0.08 or -0.05)}):Play()
				tweenService:Create(buttonScale, hoverTween, {Scale = 1}):Play()
			end)

			button.MouseLeave:Connect(function()
				local idleTween = TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
				button.TextColor3 = Color3.fromRGB(255, 255, 255)
				button.TextStrokeTransparency = 0.82
				tweenService:Create(button, idleTween, {BackgroundTransparency = decisionValue and 0.1 or 0.16, TextTransparency = 0}):Play()
				tweenService:Create(stroke, idleTween, {Transparency = decisionValue and 0.58 or 0.72}):Play()
				tweenService:Create(buttonGradient, idleTween, {Offset = Vector2.new(0, decisionValue and 0.25 or 0)}):Play()
				tweenService:Create(buttonScale, idleTween, {Scale = 1}):Play()
			end)

			button.MouseButton1Click:Connect(function()
				if promptClosing or decision ~= nil then return end

				tweenService:Create(buttonScale, TweenInfo.new(0.08, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Scale = 0.94}):Play()
				task.wait(0.08)
				tweenService:Create(buttonScale, TweenInfo.new(0.18, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {Scale = 1}):Play()
				task.wait(0.05)
				finishPrompt(decisionValue)
			end)

			return button
		end

		local cancelButton = createMorphButton("Cancel", "Cancel", UDim2.new(1, -248, 1, -48), UDim2.new(0, 104, 0, 34), Color3.fromRGB(22, 23, 25), false)
		local runButton = createMorphButton("Run", "Run", UDim2.new(1, -132, 1, -48), UDim2.new(0, 104, 0, 34), accentColor, true)

		local openMotion = TweenInfo.new(0.58, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
		local contentMotion = TweenInfo.new(0.44, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
		tweenService:Create(scriptSearch, openMotion, {Position = UDim2.new(0.5, 0, 0.5, 0), Size = UDim2.new(0, 520, 0, 205), BackgroundTransparency = 0.02}):Play()
		tweenService:Create(scriptSearch.Shadow, openMotion, {ImageTransparency = 0.86}):Play()
		tweenService:Create(scriptSearch.UIGradient, openMotion, {Offset = Vector2.new(0, 0.5)}):Play()
		if morphShadowGradient then
			tweenService:Create(morphShadowGradient, openMotion, {Offset = Vector2.new(0, 0.38)}):Play()
		end

		task.wait(0.05)
		tweenService:Create(backButton.BackArrowIcon, contentMotion, {ImageTransparency = 0}):Play()
		tweenService:Create(title, contentMotion, {TextTransparency = 0}):Play()
		tweenService:Create(subtitle, contentMotion, {TextTransparency = 1}):Play()
		tweenService:Create(headerAccent, TweenInfo.new(0.52, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 1}):Play()
		tweenService:Create(panelStroke, TweenInfo.new(0.58, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.24}):Play()
		tweenService:Create(panelStrokeGradient, TweenInfo.new(0.72, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Offset = Vector2.new(-0.08, -0.04)}):Play()

		task.wait(0.05)
		for _, cardData in ipairs({
			{scriptCard, scriptCardStroke}
		}) do
			tweenService:Create(cardData[1], contentMotion, {BackgroundTransparency = 1}):Play()
			tweenService:Create(cardData[2], contentMotion, {Transparency = 1}):Play()
		end
		tweenService:Create(scriptCardGradient, TweenInfo.new(0.72, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Offset = Vector2.new(0, 0.3)}):Play()
		tweenService:Create(preview, contentMotion, {ImageTransparency = preview.Visible and 0.08 or 1, BackgroundTransparency = 0.84}):Play()
		tweenService:Create(previewStroke, contentMotion, {Transparency = preview.Visible and 0.72 or 1}):Play()
		tweenService:Create(scriptName, contentMotion, {TextTransparency = 0}):Play()
		tweenService:Create(description, contentMotion, {TextTransparency = 0.14}):Play()
		tweenService:Create(sourcePill, contentMotion, {BackgroundTransparency = 1}):Play()
		tweenService:Create(sourcePillStroke, contentMotion, {Transparency = 1}):Play()
		tweenService:Create(sourceLabel, contentMotion, {TextTransparency = 0.2}):Play()

		task.wait(0.08)
		cancelButton.TextColor3 = Color3.fromRGB(255, 255, 255)
		cancelButton.TextStrokeTransparency = 0.82
		runButton.TextColor3 = Color3.fromRGB(255, 255, 255)
		runButton.TextStrokeTransparency = 0.82
		tweenService:Create(cancelButton, contentMotion, {BackgroundTransparency = 0.16, TextTransparency = 0}):Play()
		tweenService:Create(cancelButton.UIStroke, contentMotion, {Transparency = 0.72}):Play()
		tweenService:Create(runButton, contentMotion, {BackgroundTransparency = 0.1, TextTransparency = 0}):Play()
		tweenService:Create(runButton.UIStroke, contentMotion, {Transparency = 0.58}):Play()

		repeat task.wait() until decision ~= nil or scriptSaveState.promptToken ~= morphToken or not scriptSearch.Visible
		if decision == nil then
			destroyPromptObjects()
			debounce = false
			return false
		end

		repeat task.wait() until promptClosed or scriptSaveState.promptToken ~= morphToken or not scriptSearch.Visible
		return decision
	end

end

local function confirmScriptRun(scriptTitle, providerName, imageUrl, result)
	if not checkSirius() then return true end
	if scriptSearch.Visible then
		local morphDecision = confirmScriptRunMorph(scriptTitle, providerName, imageUrl, result)
		if morphDecision ~= nil then
			return morphDecision
		end
	end

	local accentColor = Color3.fromRGB(166, 42, 58)
	local accentSoft = accentColor:Lerp(Color3.fromRGB(255, 255, 255), 0.22)
	local accentDeep = accentColor:Lerp(scriptSearchBrand.base, 0.58)

	local overlay = Instance.new("TextButton")
	overlay.Name = "RunScriptConfirmationOverlay"
	overlay.Parent = UI
	overlay.AutoButtonColor = false
	overlay.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
	overlay.BackgroundTransparency = 1
	overlay.BorderSizePixel = 0
	overlay.Size = UDim2.new(1, 0, 1, 0)
	overlay.Text = ""
	overlay.Visible = true
	overlay.ZIndex = 900

	local newPrompt = Instance.new("Frame")
	newPrompt.Name = "RunScriptConfirmation"
	newPrompt.Parent = overlay
	newPrompt.AnchorPoint = Vector2.new(0.5, 0.5)
	newPrompt.BackgroundColor3 = scriptSearchBrand.panel
	newPrompt.BackgroundTransparency = 1
	newPrompt.BorderSizePixel = 0
	newPrompt.ClipsDescendants = true
	newPrompt.Position = UDim2.new(0.5, 0, 0.5, 12)
	newPrompt.Size = UDim2.new(0, 500, 0, 0)
	newPrompt.ZIndex = 901

	local promptScale = Instance.new("UIScale")
	promptScale.Scale = 0.96
	promptScale.Parent = newPrompt

	local promptCorner = Instance.new("UICorner")
	promptCorner.CornerRadius = UDim.new(0, 14)
	promptCorner.Parent = newPrompt

	local promptStroke = Instance.new("UIStroke")
	promptStroke.Color = Color3.fromRGB(255, 255, 255)
	promptStroke.Transparency = 1
	promptStroke.Parent = newPrompt

	local promptStrokeGradient = Instance.new("UIGradient")
	promptStrokeGradient.Color = ColorSequence.new({
		ColorSequenceKeypoint.new(0, accentSoft),
		ColorSequenceKeypoint.new(1, Color3.fromRGB(30, 30, 30))
	})
	promptStrokeGradient.Rotation = 45
	promptStrokeGradient.Offset = Vector2.new(-0.42, -0.28)
	promptStrokeGradient.Parent = promptStroke

	local promptGradient = Instance.new("UIGradient")
	promptGradient.Color = ColorSequence.new({
		ColorSequenceKeypoint.new(0, scriptSearchBrand.panel),
		ColorSequenceKeypoint.new(0.55, scriptSearchBrand.base),
		ColorSequenceKeypoint.new(0.84, accentDeep),
		ColorSequenceKeypoint.new(1, accentColor:Lerp(Color3.fromRGB(0, 0, 0), 0.36))
	})
	promptGradient.Rotation = 92
	promptGradient.Offset = Vector2.new(0, 1.2)
	promptGradient.Parent = newPrompt

	local promptShadow = Instance.new("ImageLabel")
	promptShadow.Name = "Shadow"
	promptShadow.Parent = overlay
	promptShadow.AnchorPoint = Vector2.new(0.5, 0.5)
	promptShadow.BackgroundTransparency = 1
	promptShadow.Image = "rbxassetid://8992230677"
	promptShadow.ImageColor3 = Color3.fromRGB(255, 255, 255)
	promptShadow.ImageTransparency = 1
	promptShadow.Position = UDim2.new(0.5, 0, 0.5, 28)
	promptShadow.Size = UDim2.new(0, 590, 0, 260)
	promptShadow.ScaleType = Enum.ScaleType.Slice
	promptShadow.SliceCenter = Rect.new(99, 99, 99, 99)
	promptShadow.ZIndex = 899

	local promptShadowGradient = Instance.new("UIGradient")
	promptShadowGradient.Color = ColorSequence.new({
		ColorSequenceKeypoint.new(0, accentSoft),
		ColorSequenceKeypoint.new(1, Color3.fromRGB(30, 30, 30))
	})
	promptShadowGradient.Rotation = 45
	promptShadowGradient.Offset = Vector2.new(-0.52, -0.32)
	promptShadowGradient.Parent = promptShadow

	local preview = Instance.new("ImageLabel")
	preview.Name = "ScriptPreview"
	preview.Parent = newPrompt
	preview.BackgroundColor3 = Color3.fromRGB(26, 26, 30)
	preview.BackgroundTransparency = 1
	preview.ImageTransparency = 1
	preview.ScaleType = Enum.ScaleType.Crop
	preview.Size = UDim2.new(0, 86, 0, 86)
	preview.Position = UDim2.new(0, 24, 0, 72)
	preview.ZIndex = 902

	local previewCorner = Instance.new("UICorner")
	previewCorner.CornerRadius = UDim.new(0, 10)
	previewCorner.Parent = preview

	local previewStroke = Instance.new("UIStroke")
	previewStroke.Color = accentSoft
	previewStroke.Transparency = 1
	previewStroke.Parent = preview

	local title = Instance.new("TextLabel")
	title.Name = "Title"
	title.Parent = newPrompt
	title.BackgroundTransparency = 1
	title.Font = Enum.Font.GothamBold
	title.Position = UDim2.new(0, 24, 0, 22)
	title.Size = UDim2.new(1, -48, 0, 24)
	title.Text = "ScriptSearch"
	title.TextColor3 = Color3.fromRGB(255, 255, 255)
	title.TextSize = 19
	title.TextTransparency = 1
	title.TextXAlignment = Enum.TextXAlignment.Left
	title.ZIndex = 902

	local scriptName = Instance.new("TextLabel")
	scriptName.Name = "ScriptName"
	scriptName.Parent = newPrompt
	scriptName.BackgroundTransparency = 1
	scriptName.Font = Enum.Font.GothamBold
	scriptName.Position = UDim2.new(0, 132, 0, 70)
	scriptName.Size = UDim2.new(1, -158, 0, 28)
	scriptName.Text = scriptTitle
	scriptName.TextColor3 = Color3.fromRGB(235, 235, 240)
	scriptName.TextSize = 19
	scriptName.TextTransparency = 1
	scriptName.TextTruncate = Enum.TextTruncate.AtEnd
	scriptName.TextXAlignment = Enum.TextXAlignment.Left
	scriptName.ZIndex = 902

	local description = Instance.new("TextLabel")
	description.Name = "Description"
	description.Parent = newPrompt
	description.BackgroundTransparency = 1
	description.Font = Enum.Font.Gotham
	description.Position = UDim2.new(0, 132, 0, 101)
	description.Size = UDim2.new(1, -158, 0, 46)
	description.Text = "This will execute in the current Roblox session. Continue only when you trust the script and source."
	description.TextColor3 = Color3.fromRGB(178, 178, 186)
	description.TextSize = 13
	description.TextTransparency = 1
	description.TextWrapped = true
	description.TextXAlignment = Enum.TextXAlignment.Left
	description.TextYAlignment = Enum.TextYAlignment.Top
	description.ZIndex = 902

	local sourceLabel = Instance.new("TextLabel")
	sourceLabel.Name = "Source"
	sourceLabel.Parent = newPrompt
	sourceLabel.BackgroundTransparency = 1
	sourceLabel.Font = Enum.Font.GothamMedium
	sourceLabel.Position = UDim2.new(0, 132, 0, 150)
	sourceLabel.Size = UDim2.new(1, -158, 0, 20)
	sourceLabel.Text = "Source • "..providerName
	sourceLabel.TextColor3 = Color3.fromRGB(185, 185, 194)
	sourceLabel.TextSize = 12
	sourceLabel.TextTransparency = 1
	sourceLabel.TextXAlignment = Enum.TextXAlignment.Left
	sourceLabel.ZIndex = 902

	if imageUrl then
		preview.Image = imageUrl
		task.spawn(function()
			local cachedImage = getCachedScriptImage(imageUrl)

			if preview.Parent and cachedImage then
				preview.Image = cachedImage
			end
		end)
	else
		preview.Visible = false
		scriptName.Position = UDim2.new(0, 24, 0, 70)
		scriptName.Size = UDim2.new(1, -48, 0, 28)
		description.Position = UDim2.new(0, 24, 0, 101)
		description.Size = UDim2.new(1, -48, 0, 46)
		sourceLabel.Position = UDim2.new(0, 24, 0, 150)
		sourceLabel.Size = UDim2.new(1, -48, 0, 20)
	end

	local decision
	local promptClosing = false
	local promptClosed = false

	local function closePrompt()
		if promptClosing then return end
		promptClosing = true

		local closeMotion = TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut)
		local contentFade = TweenInfo.new(0.18, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)

		tweenService:Create(overlay, TweenInfo.new(0.3, Enum.EasingStyle.Quint), {BackgroundTransparency = 1}):Play()
		tweenService:Create(newPrompt, closeMotion, {Position = UDim2.new(0.5, 0, 0.5, 12), Size = UDim2.new(0, 500, 0, 178), BackgroundTransparency = 1}):Play()
		tweenService:Create(promptScale, closeMotion, {Scale = 0.96}):Play()
		tweenService:Create(promptGradient, TweenInfo.new(0.34, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 1.2)}):Play()
		tweenService:Create(promptStrokeGradient, TweenInfo.new(0.34, Enum.EasingStyle.Quint), {Offset = Vector2.new(-0.42, -0.28)}):Play()
		tweenService:Create(promptShadow, closeMotion, {Position = UDim2.new(0.5, 0, 0.5, 22), ImageTransparency = 1, Size = UDim2.new(0, 590, 0, 260)}):Play()
		tweenService:Create(promptShadowGradient, TweenInfo.new(0.34, Enum.EasingStyle.Quint), {Offset = Vector2.new(-0.52, -0.32)}):Play()
		tweenService:Create(promptStroke, TweenInfo.new(0.25, Enum.EasingStyle.Quint), {Transparency = 1}):Play()
		tweenService:Create(title, contentFade, {TextTransparency = 1}):Play()
		tweenService:Create(scriptName, contentFade, {TextTransparency = 1}):Play()
		tweenService:Create(description, contentFade, {TextTransparency = 1}):Play()
		tweenService:Create(sourceLabel, contentFade, {TextTransparency = 1}):Play()
		tweenService:Create(preview, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {ImageTransparency = 1, BackgroundTransparency = 1}):Play()
		tweenService:Create(previewStroke, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {Transparency = 1}):Play()

		for _, button in ipairs(newPrompt:GetChildren()) do
			if button.ClassName == "TextButton" then
				tweenService:Create(button, contentFade, {BackgroundTransparency = 1, TextTransparency = 1}):Play()
				if button:FindFirstChild("UIStroke") then
					tweenService:Create(button.UIStroke, contentFade, {Transparency = 1}):Play()
				end
			end
		end

		task.wait(0.34)
		overlay:Destroy()
		promptClosed = true
	end

	local function createActionButton(name, text, position, size, backgroundColor, decisionValue)
		local button = Instance.new("TextButton")
		button.Name = name
		button.Parent = newPrompt
		button.AutoButtonColor = false
		button.BackgroundColor3 = backgroundColor
		button.BackgroundTransparency = 1
		button.BorderSizePixel = 0
		button.Font = Enum.Font.GothamBold
		button.Position = position
		button.Size = size
		button.Text = text
		button.TextColor3 = Color3.fromRGB(255, 255, 255)
		button.TextSize = 15
		button.TextTransparency = 1
		button.ZIndex = 902

		local corner = Instance.new("UICorner")
			corner.CornerRadius = UDim.new(0, 10)
			corner.Parent = button

	local stroke = Instance.new("UIStroke")
	stroke.Color = decisionValue and accentSoft or scriptSearchBrand.stroke
	stroke.Transparency = 1
	stroke.Parent = button

		local buttonScale = Instance.new("UIScale")
		buttonScale.Scale = 1
		buttonScale.Parent = button

	button.MouseEnter:Connect(function()
		local hoverTween = TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
		tweenService:Create(button, hoverTween, {BackgroundTransparency = decisionValue and 0 or 0.04, TextColor3 = Color3.fromRGB(255, 255, 255), TextTransparency = 0}):Play()
		tweenService:Create(stroke, hoverTween, {Transparency = decisionValue and 0.46 or 0.64}):Play()
		tweenService:Create(buttonScale, hoverTween, {Scale = 1}):Play()
	end)

	button.MouseLeave:Connect(function()
		local idleTween = TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
		tweenService:Create(button, idleTween, {BackgroundTransparency = decisionValue and 0.08 or 0.14, TextColor3 = Color3.fromRGB(255, 255, 255), TextTransparency = 0}):Play()
		tweenService:Create(stroke, idleTween, {Transparency = decisionValue and 0.64 or 0.78}):Play()
		tweenService:Create(buttonScale, idleTween, {Scale = 1}):Play()
	end)

		button.MouseButton1Click:Connect(function()
			if promptClosing or decision ~= nil then return end

			local pressTween = TweenInfo.new(0.08, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
			local releaseTween = TweenInfo.new(0.18, Enum.EasingStyle.Back, Enum.EasingDirection.Out)
			tweenService:Create(buttonScale, pressTween, {Scale = 0.94}):Play()
			task.wait(0.08)
			tweenService:Create(buttonScale, releaseTween, {Scale = 1}):Play()
			task.wait(0.05)
			decision = decisionValue
			closePrompt()
		end)

		return button
	end

local cancelButton = createActionButton("Cancel", "Cancel", UDim2.new(1, -248, 1, -50), UDim2.new(0, 104, 0, 34), Color3.fromRGB(22, 23, 25), false)
local runButton = createActionButton("Run", "Run", UDim2.new(1, -132, 1, -50), UDim2.new(0, 112, 0, 34), accentColor, true)

	local openMotion = TweenInfo.new(0.58, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	local glowMotion = TweenInfo.new(0.72, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	local contentMotion = TweenInfo.new(0.44, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)

	tweenService:Create(overlay, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {BackgroundTransparency = 1}):Play()
	tweenService:Create(newPrompt, openMotion, {Position = UDim2.new(0.5, 0, 0.5, 0), Size = UDim2.new(0, 520, 0, 205), BackgroundTransparency = 0.04}):Play()
	tweenService:Create(promptScale, openMotion, {Scale = 1}):Play()
	tweenService:Create(promptGradient, glowMotion, {Offset = Vector2.new(0, 0.5)}):Play()
	tweenService:Create(promptStrokeGradient, glowMotion, {Offset = Vector2.new(-0.12, -0.06)}):Play()
	tweenService:Create(promptShadow, glowMotion, {Position = UDim2.new(0.5, 0, 0.5, 9), ImageTransparency = 0.72, Size = UDim2.new(0, 620, 0, 292)}):Play()
	tweenService:Create(promptShadowGradient, glowMotion, {Offset = Vector2.new(-0.16, -0.08)}):Play()
	tweenService:Create(promptStroke, openMotion, {Transparency = 0.18}):Play()
	task.wait(0.04)
	tweenService:Create(title, contentMotion, {TextTransparency = 0}):Play()
	tweenService:Create(scriptName, contentMotion, {TextTransparency = 0}):Play()
	tweenService:Create(description, contentMotion, {TextTransparency = 0.14}):Play()
	tweenService:Create(sourceLabel, contentMotion, {TextTransparency = 0.22}):Play()

	if preview.Visible then
		tweenService:Create(preview, contentMotion, {ImageTransparency = 0.08, BackgroundTransparency = 0.86}):Play()
		tweenService:Create(previewStroke, contentMotion, {Transparency = 0.68}):Play()
	end

	task.wait(0.08)

tweenService:Create(cancelButton, contentMotion, {BackgroundTransparency = 0.14, TextColor3 = Color3.fromRGB(255, 255, 255), TextTransparency = 0}):Play()
tweenService:Create(cancelButton.UIStroke, contentMotion, {Transparency = 0.78}):Play()
tweenService:Create(runButton, contentMotion, {BackgroundTransparency = 0.08, TextColor3 = Color3.fromRGB(255, 255, 255), TextTransparency = 0}):Play()
tweenService:Create(runButton.UIStroke, contentMotion, {Transparency = 0.64}):Play()

	repeat task.wait() until decision ~= nil
	repeat task.wait() until promptClosed or not overlay.Parent
	return decision
end

function scriptSaveState.getPath()
	return siriusValues.siriusFolder.."/"..siriusValues.scriptSavedFile
end

function scriptSaveState.getId(result)
	return tostring(result.provider or "ScriptBlox").."|"..tostring(result.slug or result.rawScriptUrl or result.detailUrl or result.title or result.name or "Untitled")
end

function scriptSaveState.serialise(result)
	return {
		provider = result.provider,
		title = result.title or result.name,
		description = result.description,
		author = result.author,
		verified = result.verified,
		likes = tonumber(result.likes) or 0,
		dislikes = tonumber(result.dislikes) or 0,
		slug = result.slug,
		script = result.script,
		rawScriptUrl = result.rawScriptUrl,
		detailUrl = result.detailUrl,
		image = result.image,
		thumbUrl = result.thumbUrl,
		thumb = result.thumb,
		isPatched = result.isPatched or false
	}
end

function scriptSaveState.rebuildIndex()
	scriptSaveState.index = {}

	for _, savedScript in ipairs(scriptSaveState.cache or {}) do
		scriptSaveState.index[scriptSaveState.getId(savedScript)] = true
	end
end

function scriptSaveState.load()
	if scriptSaveState.cache then
		return scriptSaveState.cache
	end

	scriptSaveState.cache = {}

	if isfile and readfile then
		local success, decoded = pcall(function()
			if isfile(scriptSaveState.getPath()) then
				return httpService:JSONDecode(readfile(scriptSaveState.getPath()))
			end
		end)

		if success and type(decoded) == "table" then
			scriptSaveState.cache = decoded
		end
	end

	scriptSaveState.rebuildIndex()
	return scriptSaveState.cache
end

function scriptSaveState.save()
	if writefile then
		return pcall(function()
			checkFolder()
			writefile(scriptSaveState.getPath(), httpService:JSONEncode(scriptSaveState.cache or {}))
		end)
	end

	return true
end

function scriptSaveState.isSaved(result)
	scriptSaveState.load()
	return scriptSaveState.index[scriptSaveState.getId(result)] == true
end

function scriptSaveState.toggle(result)
	local savedScripts = scriptSaveState.load()
	local scriptId = scriptSaveState.getId(result)

	for index, savedScript in ipairs(savedScripts) do
		if scriptSaveState.getId(savedScript) == scriptId then
			table.remove(savedScripts, index)
			scriptSaveState.rebuildIndex()
			scriptSaveState.save()
			return false
		end
	end

	table.insert(savedScripts, scriptSaveState.serialise(result))
	scriptSaveState.rebuildIndex()
	scriptSaveState.save()
	return true
end

function scriptSaveState.createLine(parent, name, position, size, rotation, color, zIndex)
	local line = Instance.new("Frame")
	line.Name = name
	line.Parent = parent
	line.BackgroundColor3 = color or Color3.fromRGB(255, 255, 255)
	line.BackgroundTransparency = 1
	line.BorderSizePixel = 0
	line.Position = position
	line.Rotation = rotation or 0
	line.Size = size
	line.ZIndex = zIndex

	local corner = Instance.new("UICorner")
	corner.CornerRadius = UDim.new(1, 0)
	corner.Parent = line

	return line
end

function scriptSaveState.createBookmarkVisual(parent, zIndex)
	local icon = Instance.new("ImageLabel")
	icon.Name = "BookmarkVisual"
	icon.Parent = parent
	icon.BackgroundTransparency = 1
	icon.Image = scriptSaveState.outlineIcon
	icon.ImageColor3 = Color3.fromRGB(255, 255, 255)
	icon.ImageTransparency = 1
	icon.ScaleType = Enum.ScaleType.Fit
	icon.Size = scriptSaveState.outlineIconSize
	icon.ZIndex = zIndex + 10

	return icon
end

function scriptSaveState.setBookmarkVisual(icon, saved, instant)
	if not icon then return end

	icon.Image = saved and scriptSaveState.filledIcon or scriptSaveState.outlineIcon
	icon.ImageColor3 = Color3.fromRGB(255, 255, 255)
	icon.Size = saved and scriptSaveState.filledIconSize or scriptSaveState.outlineIconSize
	icon.Visible = true
	icon.ZIndex = math.max(icon.ZIndex, (icon.Parent and icon.Parent.ZIndex or 1) + 10)

	if instant then
		icon.ImageTransparency = 0
	else
		tweenService:Create(icon, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {ImageTransparency = 0}):Play()
	end
end

function scriptSaveState.createBackArrow(parent, zIndex)
	local root = Instance.new("Frame")
	root.Name = "BackArrow"
	root.Parent = parent
	root.BackgroundTransparency = 1
	root.Position = UDim2.new(0.5, -13, 0.5, -12)
	root.Size = UDim2.new(0, 28, 0, 24)
	root.ZIndex = zIndex

	scriptSaveState.createLine(root, "Shaft", UDim2.new(0, 5, 0, 11), UDim2.new(0, 22, 0, 3), 0, nil, zIndex)
	scriptSaveState.createLine(root, "HeadTop", UDim2.new(0, 4, 0, 6), UDim2.new(0, 12, 0, 3), -38, nil, zIndex)
	scriptSaveState.createLine(root, "HeadBottom", UDim2.new(0, 4, 0, 16), UDim2.new(0, 12, 0, 3), 38, nil, zIndex)

	return root
end

function scriptSaveState.clearResults()
	for _, createdScript in ipairs(scriptSearch.List:GetChildren()) do
		if createdScript.Name ~= "Placeholder" and createdScript.Name ~= "Template" and createdScript.ClassName == "Frame" then
			createdScript:Destroy()
		end
	end
end

function scriptSaveState.setListPresentation(saved)
	local listLayout = scriptSearch.List:FindFirstChildOfClass("UIListLayout")

	if listLayout then
		listLayout.HorizontalAlignment = Enum.HorizontalAlignment.Center
		listLayout.VerticalAlignment = Enum.VerticalAlignment.Top
		listLayout.Padding = UDim.new(0, saved and 10 or 12)
	end
end

function scriptSaveState.nextViewToken()
	scriptSaveState.viewToken = (scriptSaveState.viewToken or 0) + 1
	scriptSaveState.refreshToken = (scriptSaveState.refreshToken or 0) + 1
	scriptSaveState.searchToken = (scriptSaveState.searchToken or 0) + 1
	scriptSaveState.promptToken = (scriptSaveState.promptToken or 0) + 1
	return scriptSaveState.viewToken
end

function scriptSaveState.isCurrentView(token)
	return scriptSaveState.viewToken == token and scriptSearch.Visible
end

function scriptSaveState.nextSearchToken()
	scriptSaveState.searchToken = (scriptSaveState.searchToken or 0) + 1
	return scriptSaveState.searchToken
end

function scriptSaveState.isCurrentSearch(token)
	return scriptSaveState.searchToken == token and scriptSearch.Visible and not scriptSaveState.savedMode and not scriptSaveState.runPromptActive
end

function scriptSaveState.nextPromptToken()
	scriptSaveState.promptToken = (scriptSaveState.promptToken or 0) + 1
	return scriptSaveState.promptToken
end

function scriptSaveState.beginViewSwitch()
	if scriptSaveState.viewSwitchLocked or scriptSaveState.runPromptActive or scriptSaveState.transition == "confirming" then
		return false
	end

	scriptSaveState.viewSwitchLocked = true
	scriptSaveState.viewSwitchToken = (scriptSaveState.viewSwitchToken or 0) + 1
	local switchToken = scriptSaveState.viewSwitchToken

	task.delay(0.72, function()
		if scriptSaveState.viewSwitchToken == switchToken then
			scriptSaveState.viewSwitchLocked = false
		end
	end)

	return true, switchToken
end

function scriptSaveState.finishViewSwitch(switchToken)
	if not switchToken or scriptSaveState.viewSwitchToken == switchToken then
		scriptSaveState.viewSwitchLocked = false
	end
end

function scriptSaveState.showSavedEmptyState()
	if not scriptSaveState.savedMode or not scriptSearch.Visible then return end
	if scriptSaveState.header and scriptSaveState.header:FindFirstChild("CountBadge") then
		scriptSaveState.header.CountBadge.Text = tostring(#scriptSaveState.load()).." saved"
	end

	local hasVisibleRow = false

	for _, createdScript in ipairs(scriptSearch.List:GetChildren()) do
		if createdScript.Name ~= "Placeholder" and createdScript.Name ~= "Template" and createdScript.ClassName == "Frame" then
			hasVisibleRow = true
			break
		end
	end

	if hasVisibleRow then return end

	scriptSearch.NoScriptsTitle.Text = "No Saved Scripts"
	scriptSearch.NoScriptsDesc.Text = "Tap the bookmark icon on any result and it will appear here."
	tweenService:Create(scriptSearch.NoScriptsTitle, TweenInfo.new(0.36, Enum.EasingStyle.Quint), {TextTransparency = 0}):Play()
	task.wait(0.06)
	if not scriptSaveState.savedMode or not scriptSearch.Visible then return end
	tweenService:Create(scriptSearch.NoScriptsDesc, TweenInfo.new(0.36, Enum.EasingStyle.Quint), {TextTransparency = 0}):Play()
end

