function scriptSaveState.showSearchView()
	scriptSaveState.ensureControls()
	local canSwitch, switchToken = scriptSaveState.beginViewSwitch()
	if not canSwitch then return end
	local viewToken = scriptSaveState.nextViewToken()
	scriptSaveState.transition = "saved-closing"
	scriptSaveState.savedMode = false
	scriptSaveState.setListPresentation(false)
	scriptSaveState.header.Visible = false
	scriptSaveState.topButton.Visible = true
	scriptSaveState.topButton.Position = UDim2.new(1, -48, 0, 5)
	scriptSaveState.topButton.Size = UDim2.new(0, 36, 0, 34)
	scriptSearch.Icon.Visible = true
	scriptSearch.SearchBox.Visible = true
	scriptSearch.SearchBox.PlaceholderText = "Search scripts"
	scriptSearch.SearchBox.Text = ""
	scriptSearch.List.Visible = false
	scriptSearch.List.Position = scriptSaveState.listPosition
	scriptSearch.List.Size = scriptSaveState.listSize
	scriptSaveState.clearResults()
	scriptSaveState.setBookmarkVisual(scriptSaveState.topButton.BookmarkVisual, false, false)
	scriptSearch.UIGradient.Color = scriptSaveState.searchGradientColor
	scriptSearch.UIGradient.Rotation = scriptSaveState.searchGradientRotation
	scriptSaveState.header.Title.TextTransparency = 1
	scriptSaveState.header.Description.TextTransparency = 1
	scriptSaveState.header.Back.BackArrowIcon.ImageTransparency = 1
	if scriptSaveState.header:FindFirstChild("HeaderAccent") then
		scriptSaveState.header.HeaderAccent.BackgroundTransparency = 1
		scriptSaveState.header.HeaderAccent.Size = UDim2.new(0, 0, 0, 2)
	end
	if scriptSaveState.header:FindFirstChild("CountBadge") then
		scriptSaveState.header.CountBadge.BackgroundTransparency = 1
		scriptSaveState.header.CountBadge.TextTransparency = 1
		if scriptSaveState.header.CountBadge:FindFirstChildOfClass("UIStroke") then
			scriptSaveState.header.CountBadge:FindFirstChildOfClass("UIStroke").Transparency = 1
		end
	end

	tweenService:Create(scriptSearch.NoScriptsTitle, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {TextTransparency = 1}):Play()
	tweenService:Create(scriptSearch.NoScriptsDesc, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {TextTransparency = 1}):Play()
	tweenService:Create(scriptSearch, TweenInfo.new(0.45, Enum.EasingStyle.Quint), {Size = UDim2.new(0, 580, 0, 43)}):Play()
	tweenService:Create(scriptSearch.Icon, TweenInfo.new(0.45, Enum.EasingStyle.Quint), {Position = UDim2.new(0.04, 0, 0.5, 0)}):Play()
	tweenService:Create(scriptSearch.SearchBox, TweenInfo.new(0.45, Enum.EasingStyle.Quint), {Position = UDim2.new(0.509, 0, 0.5, 0)}):Play()
	tweenService:Create(scriptSearch.UIGradient, TweenInfo.new(0.45, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 2)}):Play()
	task.wait(0.18)
	if not scriptSaveState.isCurrentView(viewToken) or scriptSaveState.savedMode then
		scriptSaveState.finishViewSwitch(switchToken)
		return
	end
	scriptSaveState.transition = "open"
	scriptSaveState.finishViewSwitch(switchToken)
	scriptSearch.SearchBox:CaptureFocus()
end

local function createScript(result, animationIndex, animationMode)
	local providerName = result.provider or "ScriptBlox"
	local scriptTitle = result.title or result.name or "Untitled Script"
	local savedAnimation = animationMode == "saved"
	local revealStep = savedAnimation and 0.16 or 0.085
	local settleDelay = savedAnimation and scriptSaveState.savedRevealSettleDelay or scriptSaveState.searchRevealSettleDelay
	local revealDelay = settleDelay + math.min(((animationIndex or 1) - 1) * revealStep, savedAnimation and 1.35 or 0.75)
	local newScript = UI.ScriptSearch.List.Template:Clone()
	newScript.Name = scriptTitle
	newScript.Parent = UI.ScriptSearch.List
	newScript.Visible = true
	local savedRowStroke = nil
	local savedRowAccent = nil
	local savedRowGradient = nil
	local savedExecuteStroke = nil
	local savedRowShadow = nil

	local rowScale = Instance.new("UIScale")
	rowScale.Scale = savedAnimation and 0.94 or 0.975
	rowScale.Parent = newScript

	for _, tag in ipairs(newScript.Tags:GetChildren()) do
		if tag.ClassName == "Frame" then
			tag.Shadow.ImageTransparency = 1
			tag.BackgroundTransparency = 1
			tag.Title.TextTransparency = 1
		end
	end

	local saveButton = Instance.new("TextButton")
