	saveButton.ZIndex = newScript.Execute.ZIndex + 20

	newScript.ClipsDescendants = true

	if savedAnimation then
		newScript.ClipsDescendants = false
		newScript.BackgroundColor3 = scriptSearchBrand.card
		newScript.BackgroundTransparency = 1
