		newScript.Execute.Size = UDim2.new(0, 70, 0, 34)
		newScript.Execute.BackgroundColor3 = Color3.fromRGB(35, 35, 37)
		newScript.Execute.TextColor3 = Color3.fromRGB(246, 248, 250)
		newScript.Execute.TextSize = 13
		saveButton.Size = UDim2.new(0, 34, 0, 34)
		saveButton.BackgroundColor3 = Color3.fromRGB(31, 31, 33)

		savedRowShadow = Instance.new("ImageLabel")
