		})
		savedRowAccentGradient.Rotation = 90
		savedRowAccentGradient.Parent = savedRowAccent
	end

	local function alignSaveButton()
		local executeAnchor = newScript.Execute.AnchorPoint
		local executePosition = newScript.Execute.Position
		local executeSize = newScript.Execute.Size

		saveButton.Position = UDim2.new(
			executePosition.X.Scale - (executeSize.X.Scale * executeAnchor.X),
			executePosition.X.Offset - (executeSize.X.Offset * executeAnchor.X) - 10,
			executePosition.Y.Scale + (executeSize.Y.Scale * (0.5 - executeAnchor.Y)),
			executePosition.Y.Offset + (executeSize.Y.Offset * (0.5 - executeAnchor.Y))
		)
	end

	alignSaveButton()

	local saveCorner = Instance.new("UICorner")
	saveCorner.CornerRadius = UDim.new(1, 0)
	saveCorner.Parent = saveButton

	local saveIcon = scriptSaveState.createBookmarkVisual(saveButton, saveButton.ZIndex + 1)
	saveIcon.AnchorPoint = Vector2.new(0.5, 0.5)
	saveIcon.Position = UDim2.new(0.5, 0, 0.5, 0)
	local saveClickLocked = false
	local rowToken = scriptSaveState.viewToken
	local rowRevealed = false
	local removingRow = false
	local originalRowSize = newScript.Size

	local function scriptRowActive()
		return newScript.Parent == UI.ScriptSearch.List and scriptSearch.Visible and scriptSaveState.viewToken == rowToken and not removingRow
	end

	local function fadeTag(tag, motion)
		if tag.ClassName == "Frame" then
			tweenService:Create(tag.Shadow, motion, {ImageTransparency = 1}):Play()
			tweenService:Create(tag, motion, {BackgroundTransparency = 1}):Play()
			tweenService:Create(tag.Title, motion, {TextTransparency = 1}):Play()
		end
	end

	local function removeSavedRow()
		if removingRow then return end
		removingRow = true
		rowRevealed = false

		saveButton.Active = false
		newScript.Execute.Active = false
		newScript.ClipsDescendants = true

		local fadeMotion = TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
		local collapseMotion = TweenInfo.new(0.18, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut)
		local rowStroke = newScript:FindFirstChildOfClass("UIStroke")

		saveIcon.Image = scriptSaveState.outlineIcon
		saveIcon.Size = scriptSaveState.outlineIconSize

		tweenService:Create(rowScale, fadeMotion, {Scale = 0.96}):Play()
		tweenService:Create(newScript, fadeMotion, {BackgroundTransparency = 1}):Play()
		tweenService:Create(newScript.ScriptName, fadeMotion, {TextTransparency = 1}):Play()
		tweenService:Create(newScript.ScriptDescription, fadeMotion, {TextTransparency = 1}):Play()
		tweenService:Create(newScript.ScriptAuthor, fadeMotion, {TextTransparency = 1}):Play()
		tweenService:Create(newScript.Execute, fadeMotion, {BackgroundTransparency = 1, TextTransparency = 1}):Play()
		tweenService:Create(saveButton, fadeMotion, {BackgroundTransparency = 1}):Play()
		tweenService:Create(saveIcon, fadeMotion, {ImageTransparency = 1, Rotation = 0}):Play()

		if rowStroke then
			tweenService:Create(rowStroke, fadeMotion, {Transparency = 1}):Play()
		end
		if savedRowShadow then
			tweenService:Create(savedRowShadow, fadeMotion, {ImageTransparency = 1}):Play()
		end
		if savedRowAccent then
			tweenService:Create(savedRowAccent, fadeMotion, {BackgroundTransparency = 1}):Play()
		end
		if savedExecuteStroke then
			tweenService:Create(savedExecuteStroke, fadeMotion, {Transparency = 1}):Play()
		end

		for _, tag in ipairs(newScript.Tags:GetChildren()) do
			fadeTag(tag, fadeMotion)
		end

		task.delay(0.24, function()
			if newScript.Parent then
				tweenService:Create(newScript, collapseMotion, {Size = UDim2.new(originalRowSize.X.Scale, originalRowSize.X.Offset, 0, 0)}):Play()
			end
		end)

		task.delay(0.44, function()
			if newScript.Parent then
				newScript:Destroy()
			end

			scriptSaveState.showSavedEmptyState()
		end)
	end

	local function updateSaveButton(instant)
		local saved = scriptSaveState.isSaved(result)
		saveButton.BackgroundColor3 = saved and (savedAnimation and Color3.fromRGB(42, 42, 44) or Color3.fromRGB(62, 62, 62)) or (savedAnimation and Color3.fromRGB(31, 31, 33) or Color3.fromRGB(48, 48, 48))
		scriptSaveState.setBookmarkVisual(saveIcon, saved, instant)
	end

	local function prepareSaveButton()
		local saved = scriptSaveState.isSaved(result)
		saveButton.BackgroundColor3 = saved and (savedAnimation and Color3.fromRGB(42, 42, 44) or Color3.fromRGB(62, 62, 62)) or (savedAnimation and Color3.fromRGB(31, 31, 33) or Color3.fromRGB(48, 48, 48))
		saveIcon.Image = saved and scriptSaveState.filledIcon or scriptSaveState.outlineIcon
		saveIcon.Size = saved and scriptSaveState.filledIconSize or scriptSaveState.outlineIconSize
		saveIcon.ImageTransparency = 1
	end

	prepareSaveButton()

	saveButton.MouseEnter:Connect(function()
		tweenService:Create(saveButton, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {BackgroundTransparency = savedAnimation and 0.42 or 0.58}):Play()
		scriptSaveState.setBookmarkVisual(saveIcon, scriptSaveState.isSaved(result), false)
	end)

	saveButton.MouseLeave:Connect(function()
		tweenService:Create(saveButton, TweenInfo.new(0.22, Enum.EasingStyle.Quint), {BackgroundTransparency = savedAnimation and 0.54 or 0.74}):Play()
		scriptSaveState.setBookmarkVisual(saveIcon, scriptSaveState.isSaved(result), false)
	end)

	if savedAnimation then
		newScript.MouseEnter:Connect(function()
			if not rowRevealed or removingRow then return end

			local hoverMotion = TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
			tweenService:Create(rowScale, hoverMotion, {Scale = 1}):Play()
			tweenService:Create(newScript, hoverMotion, {BackgroundTransparency = 0.06}):Play()
			tweenService:Create(newScript.Execute, hoverMotion, {BackgroundTransparency = 0.46}):Play()
			if savedRowStroke then
				tweenService:Create(savedRowStroke, hoverMotion, {Transparency = 0.38}):Play()
			end
			if savedRowShadow then
				tweenService:Create(savedRowShadow, hoverMotion, {ImageTransparency = 0.74, Position = UDim2.new(0.5, 0, 0.5, 8)}):Play()
			end
			if savedRowGradient then
				tweenService:Create(savedRowGradient, hoverMotion, {Offset = Vector2.new(0, 0.18)}):Play()
			end
			if savedExecuteStroke then
				tweenService:Create(savedExecuteStroke, hoverMotion, {Transparency = 0.58}):Play()
			end
		end)

		newScript.MouseLeave:Connect(function()
			if not rowRevealed or removingRow then return end

			local idleMotion = TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
			tweenService:Create(rowScale, idleMotion, {Scale = 1}):Play()
			tweenService:Create(newScript, idleMotion, {BackgroundTransparency = 0.1}):Play()
			tweenService:Create(newScript.Execute, idleMotion, {BackgroundTransparency = 0.54}):Play()
			if savedRowStroke then
				tweenService:Create(savedRowStroke, idleMotion, {Transparency = 0.5}):Play()
			end
			if savedRowShadow then
				tweenService:Create(savedRowShadow, idleMotion, {ImageTransparency = 0.8, Position = UDim2.new(0.5, 0, 0.5, 7)}):Play()
			end
			if savedRowGradient then
				tweenService:Create(savedRowGradient, idleMotion, {Offset = Vector2.new(0, 0.38)}):Play()
			end
			if savedExecuteStroke then
				tweenService:Create(savedExecuteStroke, idleMotion, {Transparency = 0.72}):Play()
			end
		end)
	end

	saveButton.MouseButton1Click:Connect(function()
		if saveClickLocked then return end
		saveClickLocked = true

		local success, saved = pcall(function()
			return scriptSaveState.toggle(result)
		end)

		if not success then
			saveClickLocked = false
			queueNotification("ScriptSearch", "Could not update saved scripts.", 4384402990)
			return
		end

		queueNotification("ScriptSearch", saved and "Saved script." or "Removed saved script.", 4384403532)

		if scriptSaveState.savedMode and not saved then
			removeSavedRow()
		else
			updateSaveButton(true)
		end

		task.delay(0.12, function()
			saveClickLocked = false
		end)
	end)

	task.spawn(function()
		local detail = {
			description = result.description or (providerName == "Rscripts.net" and "Powered by Rscripts.net" or (providerName == "Roscripts.io" and "Powered by Roscripts.io" or "Loading script details...")),
			author = result.author or providerName,
			verified = result.verified or false,
			likes = tonumber(result.likes) or 0,
			dislikes = tonumber(result.dislikes) or 0
		}

		if providerName == "ScriptBlox" and result.slug then
			local response

			local success = pcall(function()
				local responseRequest = httpRequest({
					Url = "https://www.scriptblox.com/api/script/"..result['slug'],
					Method = "GET"
				})

				response = httpService:JSONDecode(responseRequest.Body)
			end)

			if not success or not response or not response.script then return end

			detail.description = response.script.features or "No description."
			detail.likes = tonumber(response.script.likeCount) or 0
			detail.dislikes = tonumber(response.script.dislikeCount) or 0
			detail.author = response.script.owner and response.script.owner.username or "ScriptBlox"
			detail.verified = response.script.owner and response.script.owner.verified or false
		end

		if not scriptRowActive() then return end

		result.description = detail.description
		result.author = detail.author
		result.verified = detail.verified
		result.likes = detail.likes
		result.dislikes = detail.dislikes

		if savedAnimation then
			newScript.ScriptAuthor.Text = "by "..detail.author.." • "..providerName
			newScript.ScriptDescription.Visible = false
			newScript.Tags.Visible = false
			return
		end

		newScript.ScriptDescription.Text = detail.description or "No description."

		local likes = detail.likes
		local dislikes = detail.dislikes

		if likes ~= dislikes then
			newScript.Tags.Review.Title.Text = (likes > dislikes) and "Positive Reviews" or "Negative Reviews"
			newScript.Tags.Review.BackgroundColor3 = (likes > dislikes) and Color3.fromRGB(0, 139, 102) or Color3.fromRGB(180, 0, 0)
			newScript.Tags.Review.Size = (likes > dislikes) and UDim2.new(0, 145, 1, 0) or UDim2.new(0, 150, 1, 0)
		elseif likes > 0 then
			newScript.Tags.Review.Title.Text = "Mixed Reviews"
			newScript.Tags.Review.BackgroundColor3 = Color3.fromRGB(198, 132, 0)
			newScript.Tags.Review.Size = UDim2.new(0, 130, 1, 0)
		else
			newScript.Tags.Review.Visible = false
		end

		newScript.ScriptAuthor.Text = "uploaded by "..detail.author.." • "..providerName
		newScript.Tags.Verified.Visible = detail.verified or false
		newScript.Tags.Visible = rowRevealed
	end)

	wipeTransparency(newScript, 1, true)
	alignSaveButton()
	prepareSaveButton()

	newScript.ScriptName.Text = scriptTitle
	newScript.ScriptDescription.Text = result.description or (providerName == "Rscripts.net" and "Powered by Rscripts.net" or (providerName == "Roscripts.io" and "Powered by Roscripts.io" or "Loading script details..."))
	newScript.ScriptAuthor.Text = (savedAnimation and "by " or "uploaded by ")..tostring(result.author or providerName).." • "..providerName


	newScript.Tags.Visible = false
	newScript.ScriptDescription.Visible = not savedAnimation
	newScript.Tags.Patched.Visible = (not savedAnimation) and (result.isPatched or false)

	task.delay(revealDelay, function()
		if not scriptRowActive() then return end

		rowRevealed = true
		newScript.Size = originalRowSize
		alignSaveButton()
		newScript.Tags.Visible = not savedAnimation

		local rowMotion = TweenInfo.new(savedAnimation and 0.82 or 0.64, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
		tweenService:Create(rowScale, rowMotion, {Scale = 1}):Play()
		tweenService:Create(newScript, rowMotion,  {BackgroundTransparency = savedAnimation and 0.1 or 0.8}):Play()
		tweenService:Create(newScript.ScriptName, rowMotion,  {TextTransparency = 0}):Play()
		tweenService:Create(newScript.Execute, rowMotion,  {BackgroundTransparency = savedAnimation and 0.54 or 0.8}):Play()
		tweenService:Create(newScript.Execute, rowMotion,  {TextTransparency = 0}):Play()
		tweenService:Create(saveButton, rowMotion,  {BackgroundTransparency = savedAnimation and 0.54 or 0.74}):Play()
		scriptSaveState.setBookmarkVisual(saveIcon, scriptSaveState.isSaved(result), false)
		tweenService:Create(newScript.ScriptAuthor, rowMotion,  {TextTransparency = savedAnimation and 0.28 or 0.7}):Play()

		if savedRowStroke then
			tweenService:Create(savedRowStroke, rowMotion, {Transparency = 0.5}):Play()
		end
		if savedRowShadow then
			tweenService:Create(savedRowShadow, rowMotion, {ImageTransparency = 0.8}):Play()
		end
		if savedRowGradient then
			tweenService:Create(savedRowGradient, rowMotion, {Offset = Vector2.new(0, 0.38)}):Play()
		end
		if savedExecuteStroke then
			tweenService:Create(savedExecuteStroke, rowMotion, {Transparency = 0.72}):Play()
		end

		if not savedAnimation then
			tweenService:Create(newScript.ScriptDescription, rowMotion,  {TextTransparency = 0.3}):Play()

			for _, tag in ipairs(newScript.Tags:GetChildren()) do
				if tag.ClassName == "Frame" then
					tweenService:Create(tag.Shadow, rowMotion,  {ImageTransparency = 0.7}):Play()
					tweenService:Create(tag, rowMotion,  {BackgroundTransparency = 0}):Play()
					tweenService:Create(tag.Title, rowMotion,  {TextTransparency = 0}):Play()
				end
			end
		end
	end)

	newScript.Execute.MouseButton1Click:Connect(function()
		if scriptSaveState.runPromptActive or removingRow or not rowRevealed then return end

		scriptSaveState.runPromptActive = true
		local imageUrl = getScriptImageUrl(result)

		local confirmed = false
		local promptSuccess, promptResponse = pcall(function()
			return confirmScriptRun(scriptTitle, providerName, imageUrl, result)
		end)

		if promptSuccess then
			confirmed = promptResponse
		end

		if not promptSuccess then
			scriptSaveState.runPromptActive = false
			queueNotification("ScriptSearch", "Could not open run confirmation.", 4384402990)
			return
		end

		if not confirmed then
			scriptSaveState.runPromptActive = false
			return
		end

		if scriptSearch.Visible then
			closeScriptSearch()
		end

		local scriptToRun = result.script
		local rawScriptUrl = result.rawScriptUrl

		if not rawScriptUrl and providerName == "Roscripts.io" then
			local success, response = pcall(function()
				return fetchRoscriptsRawUrl(result)
			end)

			if success then
				rawScriptUrl = response
			end
		end

		if not scriptToRun and rawScriptUrl then
			local success, response = pcall(function()
				local responseRequest = httpRequest({
					Url = rawScriptUrl,
					Method = "GET"
				})

				return responseRequest and responseRequest.Body
			end)

			if success then
				scriptToRun = response
			end
		end

		if not scriptToRun or scriptToRun == "" then
			scriptSaveState.runPromptActive = false
			queueNotification("ScriptSearch", "Could not load "..providerName.." script source", 4384402990)
			return
		end

		local loadedScript, loadError = loadstring(scriptToRun)

		if not loadedScript then
			scriptSaveState.runPromptActive = false
			queueNotification("ScriptSearch", "Could not prepare script: "..tostring(loadError), 4384402990)
			return
		end

		queueNotification("ScriptSearch", "Running "..scriptTitle.. " via "..providerName , 4384403532)
		scriptSaveState.runPromptActive = false
		loadedScript()
	end)
end

function scriptSaveState.renderSavedResults()
	if not scriptSaveState.savedMode or not scriptSearch.Visible then return end

	local renderToken = scriptSaveState.viewToken
	scriptSaveState.setListPresentation(true)
	scriptSaveState.clearResults()

	if not scriptSaveState.isCurrentView(renderToken) or not scriptSaveState.savedMode then return end

	local savedScripts = scriptSaveState.load()
	if scriptSaveState.header and scriptSaveState.header:FindFirstChild("CountBadge") then
		scriptSaveState.header.CountBadge.Text = tostring(#savedScripts).." saved"
	end
	local created = false

	for index, savedScript in ipairs(savedScripts) do
		if not scriptSaveState.isCurrentView(renderToken) or not scriptSaveState.savedMode then return end

		local success = pcall(function()
			createScript(savedScript, index, "saved")
		end)

		if success then
			created = true
		end
	end

	if not scriptSaveState.isCurrentView(renderToken) or not scriptSaveState.savedMode then return end

	if not created then
		tweenService:Create(scriptSearch.NoScriptsTitle, TweenInfo.new(.35,Enum.EasingStyle.Quint),  {TextTransparency = 0}):Play()
		tweenService:Create(scriptSearch.NoScriptsDesc, TweenInfo.new(.35,Enum.EasingStyle.Quint),  {TextTransparency = 0}):Play()
	else
		tweenService:Create(scriptSearch.List, TweenInfo.new(.3,Enum.EasingStyle.Quint),  {ScrollBarImageTransparency = 1}):Play()
		task.defer(function()
			if not scriptSaveState.isCurrentView(renderToken) or not scriptSaveState.savedMode then return end

			local listLayout = scriptSearch.List:FindFirstChildOfClass("UIListLayout")
			if listLayout then
				local contentHeight = math.max(listLayout.AbsoluteContentSize.Y + 18, scriptSearch.List.AbsoluteWindowSize.Y)
				scriptSearch.List.CanvasSize = UDim2.new(0, 0, 0, contentHeight)
			end
		end)
	end
end

function scriptSaveState.scheduleSavedRefresh()
	scriptSaveState.refreshToken = (scriptSaveState.refreshToken or 0) + 1
	local refreshToken = scriptSaveState.refreshToken

	task.delay(0.08, function()
		if refreshToken ~= scriptSaveState.refreshToken then return end
		scriptSaveState.renderSavedResults()
	end)
end

function scriptSaveState.showSavedList()
	scriptSaveState.ensureControls()
	local canSwitch, switchToken = scriptSaveState.beginViewSwitch()
	if not canSwitch then return end
	local viewToken = scriptSaveState.nextViewToken()
	scriptSaveState.transition = "saved-opening"
	scriptSaveState.savedMode = true
	scriptSaveState.setListPresentation(true)
	scriptSearch.SearchBox:ReleaseFocus()
	scriptSearch.Icon.Visible = false
	scriptSearch.SearchBox.Visible = false
	scriptSearch.SearchBox.PlaceholderText = "Saved scripts"
	scriptSearch.SearchBox.Text = "Saved Scripts"
	scriptSearch.SearchBox.TextColor3 = Color3.fromRGB(150, 150, 150)
	scriptSaveState.topButton.Visible = true
	scriptSaveState.topButton.Position = UDim2.new(1, -48, 0, 5)
	scriptSaveState.topButton.Size = UDim2.new(0, 36, 0, 34)
	scriptSaveState.header.Visible = true
	scriptSearch.UIGradient.Color = scriptSaveState.searchGradientColor
	scriptSearch.UIGradient.Rotation = scriptSaveState.searchGradientRotation
	scriptSearch.UIGradient.Offset = Vector2.new(0, 2)
	scriptSearch.List.Visible = false
	scriptSearch.List.Position = UDim2.new(0, 28, 0, 146)
	scriptSearch.List.Size = UDim2.new(1, -56, 1, -164)
	scriptSearch.List.CanvasPosition = Vector2.new(0, 0)
	scriptSearch.List.ScrollBarImageTransparency = 1
	scriptSearch.NoScriptsTitle.Text = "No Saved Scripts"
	scriptSearch.NoScriptsDesc.Text = "Tap the bookmark icon on any result and it will appear here."
	scriptSaveState.setBookmarkVisual(scriptSaveState.topButton.BookmarkVisual, true, false)
	local savedCount = #scriptSaveState.load()
	if scriptSaveState.header:FindFirstChild("CountBadge") then
		scriptSaveState.header.CountBadge.Text = tostring(savedCount).." saved"
		scriptSaveState.header.CountBadge.BackgroundTransparency = 1
		scriptSaveState.header.CountBadge.TextTransparency = 1
		if scriptSaveState.header.CountBadge:FindFirstChildOfClass("UIStroke") then
			scriptSaveState.header.CountBadge:FindFirstChildOfClass("UIStroke").Transparency = 1
		end
	end
	if scriptSaveState.header:FindFirstChild("HeaderAccent") then
		scriptSaveState.header.HeaderAccent.Size = UDim2.new(0, 0, 0, 2)
		scriptSaveState.header.HeaderAccent.BackgroundTransparency = 1
	end
	scriptSaveState.header.Title.TextTransparency = 1
	scriptSaveState.header.Description.TextTransparency = 1
	scriptSaveState.header.Back.BackArrowIcon.ImageTransparency = 1

	tweenService:Create(scriptSearch.NoScriptsTitle, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {TextTransparency = 1}):Play()
	tweenService:Create(scriptSearch.NoScriptsDesc, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {TextTransparency = 1}):Play()

	for _, createdScript in ipairs(scriptSearch.List:GetChildren()) do
		if createdScript.Name ~= "Placeholder" and createdScript.Name ~= "Template" and createdScript.ClassName == "Frame" then
			wipeTransparency(createdScript, 1, true)
		end
	end

	task.wait(0.18)
	if not scriptSaveState.isCurrentView(viewToken) or not scriptSaveState.savedMode then
		scriptSaveState.finishViewSwitch(switchToken)
		return
	end

	local pageMotion = TweenInfo.new(0.54, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)

	tweenService:Create(scriptSearch, pageMotion, {Size = UDim2.new(0, 580, 0, 529)}):Play()
	tweenService:Create(scriptSearch.UIGradient, pageMotion, {Offset = Vector2.new(0, 0.6)}):Play()
	tweenService:Create(scriptSaveState.topButton, pageMotion, {Position = UDim2.new(1, -54, 0, 18), Size = UDim2.new(0, 38, 0, 38)}):Play()
	tweenService:Create(scriptSearch.List, pageMotion, {Position = UDim2.new(0, 28, 0, 146), Size = UDim2.new(1, -56, 1, -164)}):Play()
	tweenService:Create(scriptSaveState.header.Back.BackArrowIcon, pageMotion, {ImageTransparency = 0}):Play()
	tweenService:Create(scriptSaveState.header.Title, pageMotion, {TextTransparency = 0}):Play()
	tweenService:Create(scriptSaveState.header.Description, pageMotion, {TextTransparency = 0.12}):Play()
	if scriptSaveState.header:FindFirstChild("HeaderAccent") then
		scriptSaveState.header.HeaderAccent.Visible = false
	end
	if scriptSaveState.header:FindFirstChild("CountBadge") then
		scriptSaveState.header.CountBadge.Visible = false
	end

	task.wait(0.34)
	if not scriptSaveState.isCurrentView(viewToken) or not scriptSaveState.savedMode then
		scriptSaveState.finishViewSwitch(switchToken)
		return
	end

	scriptSearch.List.Visible = true
	scriptSaveState.renderSavedResults()
	scriptSaveState.transition = "saved"
	scriptSaveState.finishViewSwitch(switchToken)
end

local function extractDomain(link)
	link = tostring(link or "")
	local domainToReturn = link:match("([%w-_]+%.[%w-_%.]+)")
	return domainToReturn
end

local function securityDetection(title, content, link, gradient, actions)
	if not checkSirius() then return end

	link = tostring(link or "Unknown Link")
	actions = actions or {{"Allow", true}, {"Don't Allow", false}}

	local domain = extractDomain(link) or link
	checkFolder()
	local currentAllowlist = isfile and isfile(siriusValues.siriusFolder.."/".."allowedLinks.srs") and readfile(siriusValues.siriusFolder.."/".."allowedLinks.srs") or nil
	if currentAllowlist then
		local allowlistSuccess, allowlistData = pcall(function()
			return httpService:JSONDecode(currentAllowlist)
		end)

		currentAllowlist = allowlistSuccess and type(allowlistData) == "table" and allowlistData or {}
		if table.find(currentAllowlist, domain) then return true end
	end

	local newSecurityPrompt = securityPrompt:Clone()

	newSecurityPrompt.Parent = UI
	newSecurityPrompt.Name = "SecurityPrompt"

	wipeTransparency(newSecurityPrompt, 1, true)
	newSecurityPrompt.Size = UDim2.new(0, 478, 0, 150)

	newSecurityPrompt.Title.Text = title
	newSecurityPrompt.Subtitle.Text = content
	newSecurityPrompt.FoundLink.Text = domain

	newSecurityPrompt.Visible = true
	newSecurityPrompt.UIGradient.Color = gradient

	newSecurityPrompt.Buttons.Template.Visible = false

	local function closeSecurityPrompt()
		if not newSecurityPrompt or not newSecurityPrompt.Parent then return end

		tweenService:Create(newSecurityPrompt, TweenInfo.new(0.52, Enum.EasingStyle.Quint),  {Size = UDim2.new(0, 500, 0, 165)}):Play()
		tweenService:Create(newSecurityPrompt, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {BackgroundTransparency = 1}):Play()
		tweenService:Create(newSecurityPrompt.Title, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {TextTransparency = 1}):Play()
		tweenService:Create(newSecurityPrompt.Subtitle, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {TextTransparency = 1}):Play()
		tweenService:Create(newSecurityPrompt.FoundLink, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {TextTransparency = 1}):Play()


		for _, button in ipairs(newSecurityPrompt.Buttons:GetChildren()) do
			if button.Name ~= "Template" and button.ClassName == "TextButton" then
				tweenService:Create(button, TweenInfo.new(0.3, Enum.EasingStyle.Quint),  {BackgroundTransparency = 1}):Play()
				tweenService:Create(button, TweenInfo.new(0.3, Enum.EasingStyle.Quint),  {TextTransparency = 1}):Play()
			end
		end
		task.wait(0.55)
		newSecurityPrompt:Destroy()
	end

	local decision

	for _, action in ipairs(actions) do
		local newAction = newSecurityPrompt.Buttons.Template:Clone()
		newAction.Name = action[1]
		newAction.Text = action[1]
		newAction.Parent = newSecurityPrompt.Buttons
		newAction.Visible = true
		newAction.Size = UDim2.new(0, newAction.TextBounds.X + 50, 0, 36) -- textbounds

		newAction.MouseButton1Click:Connect(function()
			if action[2] then
				if action[3] then
					checkFolder()
					if currentAllowlist then
						table.insert(currentAllowlist, domain)
						pcall(function()
							writefile(siriusValues.siriusFolder.."/".."allowedLinks.srs", httpService:JSONEncode(currentAllowlist))
						end)
					else
						pcall(function()
							writefile(siriusValues.siriusFolder.."/".."allowedLinks.srs", httpService:JSONEncode({domain}))
						end)
					end
				end
				decision = true
			else
				decision = false
			end

			closeSecurityPrompt()
		end)
	end

	tweenService:Create(newSecurityPrompt, TweenInfo.new(0.4, Enum.EasingStyle.Quint),  {Size = UDim2.new(0, 576, 0, 181)}):Play()
	tweenService:Create(newSecurityPrompt, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {BackgroundTransparency = 0}):Play()
	tweenService:Create(newSecurityPrompt.Title, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {TextTransparency = 0}):Play()
	tweenService:Create(newSecurityPrompt.Subtitle, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {TextTransparency = 0.3}):Play()
	task.wait(0.03)
	tweenService:Create(newSecurityPrompt.FoundLink, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {TextTransparency = 0.2}):Play()

	task.wait(0.1)

	for _, button in ipairs(newSecurityPrompt.Buttons:GetChildren()) do
		if button.Name ~= "Template" and button.ClassName == "TextButton" then
			tweenService:Create(button, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {BackgroundTransparency = 0.7}):Play()
			tweenService:Create(button, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {TextTransparency = 0.05}):Play()
			task.wait(0.1)
		end
	end

	newSecurityPrompt.FoundLink.MouseEnter:Connect(function()
		newSecurityPrompt.FoundLink.Text = link
		tweenService:Create(newSecurityPrompt.FoundLink, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {TextTransparency = 0.4}):Play()
	end)

	newSecurityPrompt.FoundLink.MouseLeave:Connect(function()
		newSecurityPrompt.FoundLink.Text = domain
		tweenService:Create(newSecurityPrompt.FoundLink, TweenInfo.new(0.5, Enum.EasingStyle.Quint),  {TextTransparency = 0.2}):Play()
	end)

	repeat task.wait() until decision ~= nil or not newSecurityPrompt.Parent
	return decision
end

if Essential or Pro then
	if originalRequest then
		getgenv()[index] = function(data)
			data = type(data) == "table" and data or {Url = tostring(data or "Unknown Link")}

			if checkSirius() and checkSetting("Intelligent HTTP Interception").current then
				local title = "Do you trust this source?"
				local content = "Sirius has prevented data from being sent off-client, would you like to allow data to be sent or retrieved from this source?"
				local url = tostring(data.Url or data.url or "Unknown Link")
				local gradient = ColorSequence.new({ColorSequenceKeypoint.new(0, Color3.new(0, 0, 0)),ColorSequenceKeypoint.new(1, Color3.new(0.764706, 0.305882, 0.0941176))})
				local actions = {{"Always Allow", true, true}, {"Allow just this once", true}, {"Don't Allow", false}}

				if url == "http://127.0.0.1:6463/rpc?v=1" then
					local bodyDecoded
					pcall(function()
						bodyDecoded = httpService:JSONDecode(tostring(data.Body or data.body or "{}"))
					end)

					if type(bodyDecoded) == "table" and bodyDecoded.cmd == "INVITE_BROWSER" then
						title = "Would you like to join this Discord server?"
						content = "Sirius has prevented your Discord client from automatically joining this Discord server, would you like to continue and join, or block it?"
						url = bodyDecoded.args and bodyDecoded.args.code and "discord.gg/"..bodyDecoded.args.code or "Unknown Invite"
						gradient = ColorSequence.new({ColorSequenceKeypoint.new(0, Color3.new(0, 0, 0)),ColorSequenceKeypoint.new(1, Color3.new(0.345098, 0.396078, 0.94902))})
						actions = {{"Allow", true}, {"Don't Allow", false}}
					end
				end

				local answer = securityDetection(title, content, url, gradient, actions)


				if answer then 
					return originalRequest(data)
				else
					return
				end
			else
				return originalRequest(data)
			end
		end
	end

	if originalSetClipboard then
		getgenv()[indexSetClipboard] = function(data)
			if checkSirius() and checkSetting("Intelligent Clipboard Interception").current then
				local title = "Would you like to copy this to your clipboard?"
				local content = "Sirius has prevented a script from setting the below text to your clipboard, would you like to allow this, or prevent it from copying?"
				local url = tostring(data or "Unknown Clipboard")
				local gradient = ColorSequence.new({ColorSequenceKeypoint.new(0, Color3.new(0, 0, 0)),ColorSequenceKeypoint.new(1, Color3.new(0.776471, 0.611765, 0.529412))})
				local actions = {{"Allow", true}, {"Don't Allow", false}}

				local answer = securityDetection(title, content, url, gradient, actions)

				if answer then 
					return originalSetClipboard(data)
				else
					return
				end
			else
				return originalSetClipboard(data)
			end
		end
	end
end


local function scriptSourceEnabled(settingName)
	local setting = checkSetting(settingName)
	return not setting or setting.current
end

local function normaliseRscriptsResult(result)
	local user = result.user or {}
	local author = tostring(user.username or result.creator or "Rscripts.net")

	return {
		provider = "Rscripts.net",
		title = result.title or "Untitled Rscripts Script",
		description = result.description or "Powered by Rscripts.net",
		author = author,
		verified = user.verified or false,
		likes = tonumber(result.likes) or 0,
		dislikes = tonumber(result.dislikes) or 0,
		image = result.image or user.image,
		rawScriptUrl = result.rawScript,
		isPatched = false
	}
end

local function normaliseRoscriptsResult(result)
	local slug = result.slug

	return {
		provider = "Roscripts.io",
		title = result.title or "Untitled Roscripts.io Script",
		description = result.game and ("Game: "..tostring(result.game)) or "Powered by Roscripts.io",
		author = tostring(result.owner or "Roscripts.io"),
		verified = result.ownerVerified or false,
		likes = 0,
		dislikes = 0,
		thumbUrl = result.thumbUrl or result.thumb,
		detailUrl = slug and ("https://roscripts.io/s/"..slug) or nil,
		isPatched = false
	}
end

function searchScripts(query)
	local results = {}
	local enabledSources = 0
	local failedSources = 0
	query = tostring(query or ""):match("^%s*(.-)%s*$") or ""

	if scriptSaveState.savedMode or scriptSaveState.runPromptActive or scriptSaveState.transition == "confirming" then return end

	if query == "" then
		closeScriptSearch()
		return
	end

	scriptSaveState.viewSwitchLocked = false
	scriptSaveState.setListPresentation(false)
	if scriptSaveState.header then scriptSaveState.header.Visible = false end
	if scriptSaveState.topButton then
		scriptSaveState.topButton.Visible = true
		scriptSaveState.topButton.Position = UDim2.new(1, -48, 0, 5)
		scriptSaveState.topButton.Size = UDim2.new(0, 36, 0, 34)
	end
	scriptSearch.List.Position = scriptSaveState.listPosition
	scriptSearch.List.Size = scriptSaveState.listSize
	scriptSearch.List.CanvasPosition = Vector2.new(0, 0)

	local searchToken = scriptSaveState.nextSearchToken()

	local function currentSearch()
		return scriptSaveState.isCurrentSearch(searchToken)
	end

	local function expandSearchPanel()
		if not currentSearch() then return false end

		scriptSaveState.setListPresentation(false)
		if scriptSaveState.header then scriptSaveState.header.Visible = false end
		if scriptSaveState.topButton then
			scriptSaveState.topButton.Visible = true
			scriptSaveState.topButton.Position = UDim2.new(1, -48, 0, 5)
			scriptSaveState.topButton.Size = UDim2.new(0, 36, 0, 34)
			scriptSaveState.setBookmarkVisual(scriptSaveState.topButton.BookmarkVisual, false, false)
		end
		scriptSearch.Icon.Visible = true
		scriptSearch.SearchBox.Visible = true
		scriptSearch.List.Position = scriptSaveState.listPosition
		scriptSearch.List.Size = scriptSaveState.listSize
		scriptSearch.List.Visible = true
		tweenService:Create(scriptSearch, TweenInfo.new(.45,Enum.EasingStyle.Quint),  {Size = UDim2.new(0, 580, 0, 529)}):Play()
		tweenService:Create(scriptSearch.Icon, TweenInfo.new(.45,Enum.EasingStyle.Quint),  {Position = UDim2.new(0.054, 0, 0.056, 0)}):Play()
		tweenService:Create(scriptSearch.SearchBox, TweenInfo.new(.45,Enum.EasingStyle.Quint),  {Position = UDim2.new(0.523, 0, 0.056, 0)}):Play()
		tweenService:Create(scriptSearch.List, TweenInfo.new(.45,Enum.EasingStyle.Quint),  {Position = scriptSaveState.listPosition, Size = scriptSaveState.listSize}):Play()
		tweenService:Create(scriptSearch.UIGradient, TweenInfo.new(.45,Enum.EasingStyle.Quint),  {Offset = Vector2.new(0, 0.6)}):Play()

		return true
	end

	local function clearRenderedResults(fadeFirst)
		for _, createdScript in ipairs(scriptSearch.List:GetChildren()) do
			if createdScript.Name ~= "Placeholder" and createdScript.Name ~= "Template" and createdScript.ClassName == "Frame" then
				if fadeFirst then
					wipeTransparency(createdScript, 1, true)
				else
					createdScript:Destroy()
				end
			end
		end
	end

	local function showSearchState(title, description)
		if not expandSearchPanel() then return end

		clearRenderedResults(false)
		scriptSearch.List.CanvasPosition = Vector2.new(0,0)
		scriptSearch.NoScriptsTitle.Text = title
		scriptSearch.NoScriptsDesc.Text = description
		tweenService:Create(scriptSearch.NoScriptsTitle, TweenInfo.new(.35,Enum.EasingStyle.Quint),  {TextTransparency = 0}):Play()
		tweenService:Create(scriptSearch.NoScriptsDesc, TweenInfo.new(.35,Enum.EasingStyle.Quint),  {TextTransparency = 0}):Play()
	end

	if not httpRequest then
		showSearchState("Search Unavailable", "Your executor does not expose HTTP requests, so Sirius cannot contact script sources.")
		return
	end

	if not expandSearchPanel() then return end
	scriptSearch.NoScriptsTitle.Text = "Searching Scripts"
	scriptSearch.NoScriptsDesc.Text = "Checking selected sources..."
	tweenService:Create(scriptSearch.NoScriptsTitle, TweenInfo.new(.25,Enum.EasingStyle.Quint),  {TextTransparency = 0}):Play()
	tweenService:Create(scriptSearch.NoScriptsDesc, TweenInfo.new(.25,Enum.EasingStyle.Quint),  {TextTransparency = 0.1}):Play()
	clearRenderedResults(true)

	task.wait(0.18)
	if not currentSearch() then return end

	clearRenderedResults(false)
	scriptSearch.List.CanvasPosition = Vector2.new(0,0)

	if scriptSourceEnabled("ScriptBlox Script Source") then
		enabledSources += 1

		local success = pcall(function()
			local responseRequest = httpRequest({
				Url = "https://scriptblox.com/api/script/search?q="..httpService:UrlEncode(query).."&mode=free&max=20&page=1",
				Method = "GET"
			})

			local response = httpService:JSONDecode(responseRequest.Body)

			for _, scriptResult in pairs((response.result and response.result.scripts) or {}) do
				scriptResult.provider = "ScriptBlox"
				table.insert(results, scriptResult)
			end
		end)

		if not success then
			failedSources += 1
		end

		if not currentSearch() then return end
	end

	if scriptSourceEnabled("Rscripts.net Script Source") then
		enabledSources += 1

		local success = pcall(function()
			local responseRequest = httpRequest({
				Url = "https://rscripts.net/api/v2/scripts?page=1&orderBy=date&sort=desc&notPaid=true&q="..httpService:UrlEncode(query),
				Method = "GET"
			})

			local response = httpService:JSONDecode(responseRequest.Body)

			for _, scriptResult in pairs(response.scripts or {}) do
				table.insert(results, normaliseRscriptsResult(scriptResult))
			end
		end)

		if not success then
			failedSources += 1
		end

		if not currentSearch() then return end
	end

	if scriptSourceEnabled("Roscripts.io Script Source") then
		enabledSources += 1

		local success = pcall(function()
			local responseRequest = httpRequest({
				Url = "https://roscripts.io/api/search?q="..httpService:UrlEncode(query),
				Method = "GET"
			})

			local response = httpService:JSONDecode(responseRequest.Body)

			for _, scriptResult in pairs(response.results or {}) do
				table.insert(results, normaliseRoscriptsResult(scriptResult))
			end
		end)

		if not success then
			failedSources += 1
		end

		if not currentSearch() then return end
	end

	if enabledSources == 0 then
		showSearchState("No Sources Enabled", "Turn on at least one ScriptSearch source in General settings.")
		return
	end

	if enabledSources > 0 and failedSources == enabledSources then
		queueNotification("ScriptSearch", "ScriptSearch backend encountered an error, try again later", 4384402990)
		showSearchState("Search Failed", "Selected sources did not respond. Try again or switch sources in General settings.")
		return
	elseif failedSources > 0 then
		queueNotification("ScriptSearch", "One selected script source failed, showing the rest", 4384402990)
	end

	if not currentSearch() then return end

	tweenService:Create(scriptSearch.NoScriptsTitle, TweenInfo.new(.5,Enum.EasingStyle.Quint),  {TextTransparency = 1}):Play()
	tweenService:Create(scriptSearch.NoScriptsDesc, TweenInfo.new(.5,Enum.EasingStyle.Quint),  {TextTransparency = 1}):Play()

	scriptSearch.List.Visible = true
	scriptSearch.List.CanvasPosition = Vector2.new(0,0)
	expandSearchPanel()

	local scriptCreated = false
	local renderedIds = {}
	local renderIndex = 0
	for index, scriptResult in ipairs(results) do
		if not currentSearch() then return end
		local resultId = scriptSaveState.getId(scriptResult)

		if renderedIds[resultId] then
			continue
		end

		renderedIds[resultId] = true
		renderIndex += 1

		local success = pcall(function()
			createScript(scriptResult, renderIndex, "search")
		end)

		if success then
			scriptCreated = true
		end
	end

	if not currentSearch() then return end

	if not scriptCreated then
		showSearchState("No Scripts Found", "Try a different search or enable more sources in General settings.")
	else
		tweenService:Create(scriptSearch.List, TweenInfo.new(.3,Enum.EasingStyle.Quint),  {ScrollBarImageTransparency = 1}):Play()
	end
end

local function getSmartBarButtons()
	local buttons = smartBar.Buttons:GetChildren()
	table.sort(buttons, function(a, b)
		return a.Position.X.Scale < b.Position.X.Scale
	end)
	return buttons
end

function siriusValues.getSiriusViewportSize()
	local viewport = camera and camera.ViewportSize or Vector2.new(1280, 720)
	pcall(function()
		if UI.AbsoluteSize.X > 0 and UI.AbsoluteSize.Y > 0 then
			viewport = UI.AbsoluteSize
		end
	end)
	return viewport
end

function siriusValues.getResponsiveSmartBarSize(open)
	local width = open and 581 or 531
	local height = open and 70 or 64
	if siriusValues.betaControl and siriusValues.betaControl.adminEnabled then
		width += open and 76 or 62
	end
	local viewport = siriusValues.getSiriusViewportSize()
	width = math.min(width, math.max(336, viewport.X - 24))
	return UDim2.new(0, width, 0, height)
end

local function cancelSmartBarOptionTweens(button)
	if smartBarOptionTweens[button] then
		for _, tween in ipairs(smartBarOptionTweens[button]) do
			tween:Cancel()
		end
	end

	smartBarOptionTweens[button] = {}
end

local function playSmartBarOptionTween(button, object, tweenInfo, properties)
	if not smartBarOptionTweens[button] then
		smartBarOptionTweens[button] = {}
	end

	local tween = tweenService:Create(object, tweenInfo, properties)
	table.insert(smartBarOptionTweens[button], tween)
	tween:Play()
	return tween
end

local function openSmartBar()
	if siriusValues.betaControl and siriusValues.betaControl.disabled then
		siriusValues.showBetaControlOverlay("SIRIUS X Disabled", siriusValues.betaControl.message ~= "" and siriusValues.betaControl.message or "This beta build is temporarily disabled.", true)
		return
	end

	smartBarOpen = true
	smartBarAnimationId = smartBarAnimationId + 1
	local animationId = smartBarAnimationId

	coreGui.RobloxGui.Backpack.Position = UDim2.new(0,0,0,0)

	-- Set Values for frame properties
	smartBar.BackgroundTransparency = 1
	smartBar.Time.TextTransparency = 1
	smartBar.UIStroke.Transparency = 1
	smartBar.Shadow.ImageTransparency = 1
	smartBar.Visible = true
	smartBar.Position = UDim2.new(0.5, 0, 1.05, 0)
	smartBar.Size = siriusValues.getResponsiveSmartBarSize(false)
	if siriusValues.syncSmartBarCommandSearchLayout then
		siriusValues.syncSmartBarCommandSearchLayout()
	end
	toggle.Rotation = 180
	toggle.Visible = not checkSetting("Hide Toggle Button").current

	if checkTools() then
		toggle.Position = UDim2.new(0.5,0,1,-68)
	else
		toggle.Position = UDim2.new(0.5, 0, 1, -5)
	end

	for _, button in ipairs(getSmartBarButtons()) do
		cancelSmartBarOptionTweens(button)
		button.UIGradient.Rotation = -120
		button.UIStroke.UIGradient.Rotation = -120
		button.Size = UDim2.new(0,30,0,30)
		button.Position = UDim2.new(button.Position.X.Scale, 0, 1.3, 0)
		button.BackgroundTransparency = 1
		button.UIStroke.Transparency = 1
		applySharpIcon(button.Icon, 1)
	end

	tweenService:Create(coreGui.RobloxGui.Backpack, TweenInfo.new(0.6, Enum.EasingStyle.Quint), {Position = UDim2.new(-0.325,0,0,0)}):Play()

	tweenService:Create(toggle, TweenInfo.new(0.82, Enum.EasingStyle.Quint), {Rotation = 0}):Play()
	tweenService:Create(smartBar, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Position = UDim2.new(0.5, 0, 1, -12)}):Play()
	tweenService:Create(toastsContainer, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Position = UDim2.new(0.5, 0, 1, -110)}):Play()
	tweenService:Create(toggle, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Position = UDim2.new(0.5, 0, 1, -85)}):Play()
	tweenService:Create(smartBar, TweenInfo.new(0.6, Enum.EasingStyle.Quint), {Size = siriusValues.getResponsiveSmartBarSize(true)}):Play()
	tweenService:Create(smartBar, TweenInfo.new(0.8, Enum.EasingStyle.Quint), {BackgroundTransparency = 0.18}):Play()
	tweenService:Create(smartBar.Shadow, TweenInfo.new(0.8, Enum.EasingStyle.Quint), {ImageTransparency = 0.7}):Play()
	tweenService:Create(smartBar.Time, TweenInfo.new(0.8, Enum.EasingStyle.Quint), {TextTransparency = 0}):Play()
	tweenService:Create(smartBar.UIStroke, TweenInfo.new(0.8, Enum.EasingStyle.Quint), {Transparency = 0.85}):Play()
	tweenService:Create(toggle, TweenInfo.new(0.3, Enum.EasingStyle.Quint), {ImageTransparency = 0}):Play()

	for index, button in ipairs(getSmartBarButtons()) do
		task.delay((index - 1) * 0.026, function()
			if not smartBarOpen or animationId ~= smartBarAnimationId then return end
			cancelSmartBarOptionTweens(button)
			playSmartBarOptionTween(button, button.UIStroke, TweenInfo.new(0.72, Enum.EasingStyle.Quint), {Transparency = 0})
			playSmartBarOptionTween(button, button, TweenInfo.new(0.72, Enum.EasingStyle.Quint), {Size = UDim2.new(0, 36, 0, 36)})
			playSmartBarOptionTween(button, button.UIGradient, TweenInfo.new(0.9, Enum.EasingStyle.Quint), {Rotation = 50})
			playSmartBarOptionTween(button, button.UIStroke.UIGradient, TweenInfo.new(0.9, Enum.EasingStyle.Quint), {Rotation = 50})
			playSmartBarOptionTween(button, button, TweenInfo.new(0.72, Enum.EasingStyle.Exponential), {Position = UDim2.new(button.Position.X.Scale, 0, 0.5, 0)})
			playSmartBarOptionTween(button, button, TweenInfo.new(0.72, Enum.EasingStyle.Quint), {BackgroundTransparency = 0})
			playSmartBarOptionTween(button, button.Icon, TweenInfo.new(0.72, Enum.EasingStyle.Quint), {ImageColor3 = actionIconColor, ImageTransparency = 0})
		end)
	end
end

local function closeSmartBar()
	smartBarOpen = false
	smartBarAnimationId = smartBarAnimationId + 1
	local animationId = smartBarAnimationId

	for _, otherPanel in ipairs(UI:GetChildren()) do
		if smartBar.Buttons:FindFirstChild(otherPanel.Name) then
			if isPanel(otherPanel.Name) and otherPanel.Visible then
				task.spawn(closePanel, otherPanel.Name, true)
				task.wait()
			end
		end
	end

	tweenService:Create(smartBar.Time, TweenInfo.new(0.4, Enum.EasingStyle.Quint), {TextTransparency = 1}):Play()
	local smartBarButtons = getSmartBarButtons()
	for index, Button in ipairs(smartBarButtons) do
		task.delay((#smartBarButtons - index) * 0.012, function()
			if smartBarOpen or animationId ~= smartBarAnimationId then return end
			cancelSmartBarOptionTweens(Button)
			playSmartBarOptionTween(Button, Button.UIStroke, TweenInfo.new(0.28, Enum.EasingStyle.Quint), {Transparency = 1})
			playSmartBarOptionTween(Button, Button, TweenInfo.new(0.28, Enum.EasingStyle.Quint), {Size = UDim2.new(0, 30, 0, 30)})
			playSmartBarOptionTween(Button, Button, TweenInfo.new(0.28, Enum.EasingStyle.Quint), {BackgroundTransparency = 1})
			playSmartBarOptionTween(Button, Button.Icon, TweenInfo.new(0.28, Enum.EasingStyle.Quint), {ImageTransparency = 1})
		end)
	end

	tweenService:Create(coreGui.RobloxGui.Backpack, TweenInfo.new(0.6, Enum.EasingStyle.Quint), {Position = UDim2.new(0, 0, 0, 0)}):Play()

	tweenService:Create(smartBar, TweenInfo.new(0.3, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut), {BackgroundTransparency = 1}):Play()
	tweenService:Create(smartBar.UIStroke, TweenInfo.new(0.3, Enum.EasingStyle.Quint), {Transparency = 1}):Play()
	tweenService:Create(smartBar.Shadow, TweenInfo.new(0.3, Enum.EasingStyle.Quint), {ImageTransparency = 1}):Play()
	tweenService:Create(smartBar, TweenInfo.new(0.5, Enum.EasingStyle.Back), {Size = siriusValues.getResponsiveSmartBarSize(false)}):Play()
	tweenService:Create(smartBar, TweenInfo.new(0.5, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut), {Position = UDim2.new(0.5, 0,1, 73)}):Play()

	-- If tools, move the toggle
	if checkTools() then
		tweenService:Create(toggle, TweenInfo.new(0.5, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut), {Position = UDim2.new(0.5,0,1,-68)}):Play()
		tweenService:Create(toastsContainer, TweenInfo.new(0.5, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut), {Position = UDim2.new(0.5, 0, 1, -90)}):Play()
		tweenService:Create(toggle, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Rotation = 180}):Play()
	else
		tweenService:Create(toastsContainer, TweenInfo.new(0.5, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut), {Position = UDim2.new(0.5, 0, 1, -28)}):Play()
		tweenService:Create(toggle, TweenInfo.new(0.45, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut), {Position = UDim2.new(0.5, 0, 1, -5)}):Play()
		tweenService:Create(toggle, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Rotation = 180}):Play()
	end
end

local function windowFocusChanged(value)
	if checkSirius() then
		if value then -- Window Focused
			setfpscap(tonumber(checkSetting("Artificial FPS Limit").current))
			removeReverbs(0.5)
		else          -- Window unfocused
			if checkSetting("Muffle audio while unfocused").current then createReverb(0.7) end
			if checkSetting("Limit FPS while unfocused").current then setfpscap(60) end
		end
	end
end

function siriusValues.parseDetectionList(raw)
	local list = {}
	raw = tostring(raw or "")
	raw = string.gsub(raw, "[\r\n;|]+", ",")

	for token in string.gmatch(raw, "([^,]+)") do
		token = string.lower(string.gsub(token, "^%s*(.-)%s*$", "%1"))
		if string.sub(token, 1, 1) == "@" then
			token = string.sub(token, 2)
		end
		token = string.gsub(token, "^user:", "")
		token = string.gsub(token, "^username:", "")
		token = string.gsub(token, "^display:", "")
		token = string.gsub(token, "^id:", "")
		if token ~= "" then
			table.insert(list, token)
		end
	end

	return list
end

function siriusValues.matchWatchlistUser(player)
	if not player then return nil end

	local watchlistSetting = checkSetting("Watchlist Users")
	local watchlist = siriusValues.parseDetectionList(watchlistSetting and watchlistSetting.current or "")
	local username = string.lower(tostring(player.Name or ""))
	local displayName = string.lower(tostring(player.DisplayName or ""))
	local userId = tostring(player.UserId or "")

	for _, token in ipairs(watchlist) do
		local partial = string.sub(token, 1, 1) == "*" and string.sub(token, -1) == "*"
		local cleanToken = partial and string.sub(token, 2, -2) or token

		if cleanToken ~= "" and (cleanToken == username or cleanToken == displayName or cleanToken == userId) then
			return token
		end

		if partial and cleanToken ~= "" and (string.find(username, cleanToken, 1, true) or string.find(displayName, cleanToken, 1, true)) then
			return token
		end
	end

	return nil
end

function siriusValues.checkKnownUserWatchlist(player)
	local setting = checkSetting("Known User Watchlist")
	if not setting or not setting.current or not player or player == localPlayer then return end

	siriusValues.knownUserWatchlistSeen = siriusValues.knownUserWatchlistSeen or {}
	if siriusValues.knownUserWatchlistSeen[player.UserId] then return end

	local matchedToken = siriusValues.matchWatchlistUser(player)
	if not matchedToken then return end

	siriusValues.knownUserWatchlistSeen[player.UserId] = true
	local protectionSetting = checkSetting("Watchlist Protection Mode")
	if protectionSetting and protectionSetting.current then
		if siriusValues.stopActiveAbilitiesForModeratorDetection then
			siriusValues.stopActiveAbilitiesForModeratorDetection()
		end
		promptModerator(player, "Watchlist Match: "..matchedToken, "Watchlist User Joined", "Sirius matched your watchlist and disabled active abilities.")
		queueNotification("Watchlist User Joined", player.DisplayName.." (@"..player.Name..") matched your watchlist. Active abilities were stopped.", 3944670656)
	else
		queueNotification("Watchlist User Joined", player.DisplayName.." (@"..player.Name..") matched your watchlist.", 3944670656)
	end
end

function siriusValues.detectChatKeyword(player, message)
	local setting = checkSetting("Chat Keyword Detection")
	if not setting or not setting.current or not player or player == localPlayer or not message then return end

	local keywordSetting = checkSetting("Chat Keywords")
	local keywords = siriusValues.parseDetectionList(keywordSetting and keywordSetting.current or "")
	if #keywords == 0 then return end

	local rawMessage = tostring(message or "")
	local lowerMessage = string.lower(rawMessage)
	local wordMessage = " "..string.gsub(lowerMessage, "[%p%c%s]+", " ").." "

	for _, keyword in ipairs(keywords) do
		local matched = false

		if #keyword <= 3 and string.match(keyword, "^%w+$") then
			matched = string.find(wordMessage, " "..keyword.." ", 1, true) ~= nil
		else
			matched = string.find(lowerMessage, keyword, 1, true) ~= nil
		end

		if matched then
			siriusValues.chatKeywordDetectionSeen = siriusValues.chatKeywordDetectionSeen or {}
			local key = tostring(player.UserId)..":"..keyword
			local now = os.clock()
			local cooldownSetting = checkSetting("Detection Alert Cooldown")
			local cooldown = math.clamp(tonumber(cooldownSetting and cooldownSetting.current) or 10, 3, 60)
			if siriusValues.chatKeywordDetectionSeen[key] and now - siriusValues.chatKeywordDetectionSeen[key] < cooldown then
				return
			end
			siriusValues.chatKeywordDetectionSeen[key] = now

			local snippet = string.gsub(rawMessage, "[\r\n]+", " ")
			if string.len(snippet) > 80 then
				snippet = string.sub(snippet, 1, 77).."..."
			end

			local protectionSetting = checkSetting("Chat Keyword Protection Mode")
			if protectionSetting and protectionSetting.current then
				if siriusValues.stopActiveAbilitiesForModeratorDetection then
					siriusValues.stopActiveAbilitiesForModeratorDetection()
				end
				promptModerator(player, "Keyword: "..keyword, "Chat Keyword Detected", "Sirius matched a watched chat keyword and disabled active abilities.")
				queueNotification("Chat Keyword Detected", player.DisplayName.." matched \""..keyword.."\". Active abilities were stopped.", 3944670656)
			else
				queueNotification("Chat Keyword Detected", player.DisplayName.." matched \""..keyword.."\": "..snippet, 3944670656)
			end
			return
		end
	end
end

function siriusValues.checkModeratorAdminJoin(player)
	if not player or player == localPlayer then return end
	if not Pro or siriusValues.currentCreator ~= "group" then return end

	local setting = checkSetting("Moderator / Admin Join Detection")
	if not setting or not setting.current then return end

	siriusValues.moderatorDetectionSeen = siriusValues.moderatorDetectionSeen or {}
	if siriusValues.moderatorDetectionSeen[player.UserId] then return end

	local roleSuccess, roleFound = pcall(function()
		return player:GetRoleInGroup(creatorId)
	end)

	if not roleSuccess or type(roleFound) ~= "string" or roleFound == "" or roleFound == "Guest" then return end

	local roleLower = string.lower(roleFound)
	for _, role in pairs(siriusValues.administratorRoles) do 
		role = string.lower(tostring(role))

		if role ~= "" and string.find(roleLower, role, 1, true) then
			siriusValues.moderatorDetectionSeen[player.UserId] = true
			if siriusValues.stopActiveAbilitiesForModeratorDetection then
				siriusValues.stopActiveAbilitiesForModeratorDetection()
			end
			promptModerator(player, roleFound)
			queueNotification("Moderator / Admin Joined", siriusValues.currentGroup .." "..roleFound.." ".. player.DisplayName .." has joined your session. Active abilities were stopped.", 3944670656)
			break
		end
	end
end

local function onChatted(player, message)
	if not message or not checkSirius() then return end

	if siriusValues.spamGuard and siriusValues.spamGuard.evaluate then
		local flagged, reason = siriusValues.spamGuard:evaluate(player, message)
		if flagged then
			if reason ~= "repeat" then
				siriusValues.spamGuard:report(player and player.UserId)
			end
			siriusValues.spamGuard:notify()
			task.spawn(function()
				siriusValues.spamGuard:scrub()
			end)
		end
	end

	siriusValues.detectChatKeyword(player, message)

	if checkSetting("Log Messages").current then
		local logData = {
			["content"] = message,
			["avatar_url"] = "https://www.roblox.com/headshot-thumbnail/image?userId="..player.UserId.."&width=420&height=420&format=png",
			["username"] = player.DisplayName,
			["allowed_mentions"] = {parse = {}}
		}

		logData = httpService:JSONEncode(logData)

		pcall(function()
			local req = originalRequest({
				Url = checkSetting("Message Webhook URL").current,
				Method = 'POST',
				Headers = {
					['Content-Type'] = 'application/json',
				},
				Body = logData
			})
		end)
	end
end

if game:FindFirstChildOfClass("TextChatService") then
	game:FindFirstChildOfClass("TextChatService").MessageReceived:Connect(function(message)
		if not message or not message.TextSource then return end

		local speaker = players:GetPlayerByUserId(message.TextSource.UserId)
		if speaker then
			siriusValues.detectChatKeyword(speaker, message.Text or "")
		end
	end)
end

local function sortPlayers()
	local newTable = playerlistPanel.Interactions.List:GetChildren()

	for index, player in ipairs(newTable) do
		if player.ClassName ~= "Frame" or player.Name == "Placeholder" then
			table.remove(newTable, index)
		end
	end

	table.sort(newTable, function(playerA, playerB)
		return playerA.Name < playerB.Name
	end)

	for index, frame in ipairs(newTable) do
		if frame.ClassName == "Frame" then
			if frame.Name ~= "Placeholder" then
				frame.LayoutOrder = index 
			end
		end
	end
end

