local function teleportTo(player)
	local targetCharacter = workspace:FindFirstChild(player.Name)
	local targetRoot = targetCharacter and targetCharacter:FindFirstChild("HumanoidRootPart")
	local localCharacter = localPlayer.Character
	local localRoot = localCharacter and localCharacter:FindFirstChild("HumanoidRootPart")

	if players:FindFirstChild(player.Name) and targetRoot and localRoot then
		queueNotification("Teleportation", "Teleporting to "..player.DisplayName..".")
		localRoot.CFrame = CFrame.new(targetRoot.Position.X, targetRoot.Position.Y, targetRoot.Position.Z)
	else
		queueNotification("Teleportation Error", player.DisplayName.." cannot be teleported to right now.")
	end
end

local function createPlayer(player)
	if not checkSirius() then return end

	if playerlistPanel.Interactions.List:FindFirstChild(player.Name) then return end

	local newPlayer = playerlistPanel.Interactions.List.Template:Clone()
	newPlayer.Name = player.Name
	newPlayer.Parent = playerlistPanel.Interactions.List
	newPlayer.Visible = not searchingForPlayer

	newPlayer.NoActions.Visible = false
	newPlayer.PlayerInteractions.Visible = false
	newPlayer.Role.Visible = false

	newPlayer.Size = UDim2.new(0, 539, 0, 45)
	newPlayer.DisplayName.Position = UDim2.new(0, 53, 0.5, 0)
	newPlayer.DisplayName.Size = UDim2.new(0, 224, 0, 16)
	newPlayer.Avatar.Size = UDim2.new(0, 30, 0, 30)

	sortPlayers()

	newPlayer.DisplayName.TextTransparency = 0
	newPlayer.DisplayName.TextScaled = true
	newPlayer.DisplayName.FontFace.Weight = Enum.FontWeight.Medium
	newPlayer.DisplayName.Text = player.DisplayName
	newPlayer.Avatar.Image = "https://www.roblox.com/headshot-thumbnail/image?userId="..player.UserId.."&width=420&height=420&format=png"

	if creatorType == Enum.CreatorType.Group then
		task.spawn(function()
			local role = player:GetRoleInGroup(creatorId)
			if role == "Guest" then
				newPlayer.Role.Text = "Group Rank: None"
			else
				newPlayer.Role.Text = "Group Rank: "..role
			end

			newPlayer.Role.Visible = true
			newPlayer.Role.TextTransparency = 1
		end)
	end

	local selectAction
	local clearPlayerActions
	local preservingSelectedAction = false
	local function prepareActionSlot()
		local actionParent = newPlayer.PlayerInteractions

		actionParent.AnchorPoint = Vector2.new(1, 0.5)
		actionParent.Position = UDim2.new(1, -28, 0.5, 0)
		actionParent.Size = UDim2.new(0, 112, 0, 40)
		actionParent.BackgroundColor3 = Color3.fromRGB(24, 24, 24)
		actionParent.BackgroundTransparency = 1
		actionParent.BorderSizePixel = 0
		actionParent.ClipsDescendants = false
		actionParent.ZIndex = newPlayer.ZIndex + 10
		pcall(function()
			actionParent.Image = ""
			actionParent.ImageTransparency = 1
		end)

		for _, action in ipairs(actionParent:GetChildren()) do
			if action:IsA("GuiObject") and action.Name ~= "Select" then
				action.Visible = false
				pcall(function()
					action.BackgroundTransparency = 1
					action.ImageTransparency = 1
				end)
			elseif action:IsA("UIStroke") then
				action.Transparency = 1
			end
		end
	end

	local function ensureSelectAction()
		prepareActionSlot()

		if selectAction and selectAction.Parent then
			selectAction.BackgroundColor3 = Color3.fromRGB(35, 35, 35)
			selectAction.BorderSizePixel = 0
			selectAction.TextColor3 = Color3.fromRGB(255, 255, 255)
			selectAction.TextStrokeTransparency = 1
			selectAction.ZIndex = newPlayer.PlayerInteractions.ZIndex + 1
			if selectAction:FindFirstChild("UIStroke") then
				selectAction.UIStroke.Color = Color3.fromRGB(58, 58, 58)
			end
			return selectAction
		end

		selectAction = Instance.new("TextButton")
		selectAction.Name = "Select"
		selectAction.AnchorPoint = Vector2.new(0.5, 0.5)
		selectAction.Position = UDim2.new(0.5, 0, 0.5, 0)
		selectAction.Size = UDim2.new(0, 96, 0, 36)
		selectAction.BackgroundColor3 = Color3.fromRGB(35, 35, 35)
		selectAction.BackgroundTransparency = 1
		selectAction.BorderSizePixel = 0
		selectAction.AutoButtonColor = false
		selectAction.Text = "Select"
		selectAction.TextColor3 = Color3.fromRGB(255, 255, 255)
		selectAction.TextTransparency = 1
		selectAction.TextStrokeTransparency = 1
		selectAction.TextSize = 15
		selectAction.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.SemiBold)
		selectAction.ZIndex = newPlayer.PlayerInteractions.ZIndex + 1
		selectAction.Visible = false
		selectAction.Parent = newPlayer.PlayerInteractions

		local corner = Instance.new("UICorner")
		corner.CornerRadius = UDim.new(1, 0)
		corner.Parent = selectAction

		local stroke = Instance.new("UIStroke")
		stroke.Name = "UIStroke"
		stroke.Color = Color3.fromRGB(58, 58, 58)
		stroke.Thickness = 1
		stroke.Transparency = 1
		stroke.Parent = selectAction

		selectAction.MouseEnter:Connect(function()
			if not selectAction.Visible then return end
			tweenService:Create(selectAction, TweenInfo.new(0.18, Enum.EasingStyle.Quint), {BackgroundColor3 = Color3.fromRGB(44, 44, 44)}):Play()
			tweenService:Create(stroke, TweenInfo.new(0.18, Enum.EasingStyle.Quint), {Color = Color3.fromRGB(74, 74, 74)}):Play()
		end)

		selectAction.MouseLeave:Connect(function()
			tweenService:Create(selectAction, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {BackgroundColor3 = Color3.fromRGB(35, 35, 35)}):Play()
			tweenService:Create(stroke, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {Color = Color3.fromRGB(58, 58, 58)}):Play()
		end)

		selectAction.MouseButton1Click:Connect(function()
			if debounce or not playerlistPanel.Visible then return end
			if playerActionSystem.openPicker then
				preservingSelectedAction = true
				local sourceSnapshot = {
					AbsolutePosition = selectAction.AbsolutePosition,
					AbsoluteSize = selectAction.AbsoluteSize
				}

				task.spawn(function()
					tweenService:Create(toggle, TweenInfo.new(0.45, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut), {Position = UDim2.new(0.5, 0, 1, -85)}):Play()
					closePanel("Playerlist", true)
					preservingSelectedAction = false
					clearPlayerActions()
					newPlayer.Size = UDim2.new(0, 539, 0, 45)
					newPlayer.DisplayName.Position = UDim2.new(0, 53, 0.5, 0)
					newPlayer.Avatar.Size = UDim2.new(0, 30, 0, 30)
					newPlayer.Role.TextTransparency = 1

					if not players:FindFirstChild(player.Name) then return end

					playerActionSystem.openPicker(player, sourceSnapshot, function()
						if not checkSirius() then return end
						if not smartBarOpen or playerlistPanel.Visible or debounce then return end
						task.spawn(openPanel, "Playerlist")
					end)
				end)
			end
		end)

		return selectAction
	end

	clearPlayerActions = function()
		prepareActionSlot()
		newPlayer.PlayerInteractions.Visible = false

		if selectAction then
			selectAction.Visible = false
			selectAction.BackgroundTransparency = 1
			selectAction.TextTransparency = 1
			if selectAction:FindFirstChild("UIStroke") then
				selectAction.UIStroke.Transparency = 1
			end
		end
	end

	clearPlayerActions()

	local function openInteractions()
		if player == localPlayer then
			clearPlayerActions()
			return
		end

		local action = ensureSelectAction()
		prepareActionSlot()
		newPlayer.PlayerInteractions.Visible = true
		newPlayer.PlayerInteractions.BackgroundTransparency = 1
		action.Visible = true
		action.BackgroundColor3 = Color3.fromRGB(35, 35, 35)
		action.BackgroundTransparency = 1
		action.TextColor3 = Color3.fromRGB(255, 255, 255)
		action.TextTransparency = 1
		action.TextStrokeTransparency = 1
		if action:FindFirstChild("UIStroke") then
			action.UIStroke.Color = Color3.fromRGB(58, 58, 58)
			action.UIStroke.Transparency = 1
		end

		tweenService:Create(action, TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0}):Play()
		tweenService:Create(action, TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {TextTransparency = 0}):Play()
		if action:FindFirstChild("UIStroke") then
			tweenService:Create(action.UIStroke, TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0}):Play()
		end
	end

	local function closeInteractions()
		if preservingSelectedAction then return end

		if not newPlayer.PlayerInteractions.Visible or not selectAction then
			clearPlayerActions()
			return
		end

		tweenService:Create(selectAction, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 1, TextTransparency = 1}):Play()
		if selectAction:FindFirstChild("UIStroke") then
			tweenService:Create(selectAction.UIStroke, TweenInfo.new(0.22, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 1}):Play()
		end

		task.wait(0.24)
		clearPlayerActions()
	end

	newPlayer.MouseEnter:Connect(function()
		if debounce or not playerlistPanel.Visible then return end
		tweenService:Create(newPlayer.UIStroke, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Transparency = 1}):Play()
		tweenService:Create(newPlayer.DisplayName, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {TextTransparency = 0.3}):Play()
	end)

	newPlayer.MouseLeave:Connect(function()
		if debounce or not playerlistPanel.Visible then return end
		if preservingSelectedAction then return end
		task.spawn(closeInteractions)
		tweenService:Create(newPlayer.DisplayName, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Position = UDim2.new(0, 53, 0.5, 0)}):Play()
		tweenService:Create(newPlayer, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Size = UDim2.new(0, 539, 0, 45)}):Play()
		tweenService:Create(newPlayer.Avatar, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Size = UDim2.new(0, 30, 0, 30)}):Play()
		tweenService:Create(newPlayer.UIStroke, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Transparency = 0}):Play()
		tweenService:Create(newPlayer.DisplayName, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {TextTransparency = 0}):Play()
		tweenService:Create(newPlayer.Role, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {TextTransparency = 1}):Play()
	end)

	newPlayer.Interact.MouseButton1Click:Connect(function()
		if debounce or not playerlistPanel.Visible then return end
		if creatorType == Enum.CreatorType.Group then
			tweenService:Create(newPlayer.DisplayName, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Position = UDim2.new(0, 73, 0.39, 0)}):Play()
			tweenService:Create(newPlayer.Role, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {TextTransparency = 0.3}):Play()
		else
			tweenService:Create(newPlayer.DisplayName, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Position = UDim2.new(0, 73, 0.5, 0)}):Play()
		end

		if player ~= localPlayer then openInteractions() end

		tweenService:Create(newPlayer, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Size = UDim2.new(0, 539, 0, 75)}):Play()

		tweenService:Create(newPlayer.DisplayName, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {TextTransparency = 0}):Play()
		tweenService:Create(newPlayer.Avatar, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Size = UDim2.new(0, 50, 0, 50)}):Play()
		tweenService:Create(newPlayer.UIStroke, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Transparency = 0}):Play()
	end)

end

local function removePlayer(player)
	if not checkSirius() then return end

	if playerActionSystem.getPickerTarget and playerActionSystem.getPickerTarget() == player and playerActionSystem.closePicker then
		playerActionSystem.closePicker()
	end

	if playerActionSystem.getSpectateTarget and playerActionSystem.getSpectateTarget() == player and playerActionSystem.stopSpectating then
		playerActionSystem.stopSpectating(player.DisplayName.." left the server.")
	end

	local entry = playerlistPanel.Interactions.List:FindFirstChild(player.Name)
	if entry then
		entry:Destroy()
	end
end

local settingsAnimationId = 0
local dylanfocBackgroundAsset = nil

local function getDylanfocUtilityBackgroundImage()
	if dylanfocBackgroundAsset then
		return dylanfocBackgroundAsset
	end

	local image = siriusValues.dylanfocUtilityBackgroundImage

	if image and getCachedScriptImage then
		local success, cachedImage = pcall(getCachedScriptImage, image)
		if success and cachedImage then
			image = cachedImage
		end
	end

	dylanfocBackgroundAsset = image
	return image
end

function getDylanfocUtilityBackground()
	local background = settingsPanel:FindFirstChild("DylanfocUtilityBackground")
	if background then
		background.Image = getDylanfocUtilityBackgroundImage()
		return background
	end

	background = Instance.new("ImageLabel")
	background.Name = "DylanfocUtilityBackground"
	background.Parent = settingsPanel
	background.AnchorPoint = Vector2.new(0.5, 0.5)
	background.Position = UDim2.fromScale(0.5, 0.5)
	background.Size = UDim2.fromScale(1, 1)
	background.BackgroundTransparency = 1
	background.Image = getDylanfocUtilityBackgroundImage()
	background.ScaleType = Enum.ScaleType.Crop
	background.ImageTransparency = 1
	background.Visible = false
	background.ZIndex = math.max(0, settingsPanel.SettingLists.ZIndex - 1)

	local corner = Instance.new("UICorner")
	corner.Name = "DylanfocUtilityBackgroundCorner"
	corner.Parent = background
	corner.CornerRadius = settingsPanel:FindFirstChildOfClass("UICorner") and settingsPanel:FindFirstChildOfClass("UICorner").CornerRadius or UDim.new(0, 18)

	local fade = Instance.new("UIGradient")
	fade.Name = "DylanfocUtilityBackgroundFade"
	fade.Parent = background
	fade.Rotation = 90
	fade.Transparency = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.18),
		NumberSequenceKeypoint.new(0.5, 0.42),
		NumberSequenceKeypoint.new(1, 0.74)
	})

	return background
end

function setDylanfocUtilityBackgroundVisible(visible)
	local background = getDylanfocUtilityBackground()
	local tweenInfo = TweenInfo.new(visible and 0.34 or 0.18, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)

	if visible then
		background.Visible = true
		background.ImageTransparency = math.min(background.ImageTransparency, 1)
		tweenService:Create(background, tweenInfo, {ImageTransparency = 0.42}):Play()
	else
		tweenService:Create(background, tweenInfo, {ImageTransparency = 1}):Play()
		task.delay(0.2, function()
			if background.ImageTransparency >= 0.98 then
				background.Visible = false
			end
		end)
	end
end

local function openSettings()
	debounce = true
	settingsAnimationId += 1
	local animationId = settingsAnimationId

	settingsPanel.BackgroundTransparency = 1
	settingsPanel.Title.TextTransparency = 1
	settingsPanel.Subtitle.TextTransparency = 1
	settingsPanel.Back.ImageTransparency = 1
	settingsPanel.Shadow.ImageTransparency = 1

	local dylanfocBackground = settingsPanel:FindFirstChild("DylanfocUtilityBackground")
		if dylanfocBackground then
			dylanfocBackground.Visible = false
			dylanfocBackground.ImageTransparency = 1
		end

		ensureSettingsCategoryScroller()
		wipeTransparency(settingsPanel.SettingTypes, 1, true)

		settingsPanel.Visible = true
	settingsPanel.UIGradient.Enabled = true
	settingsPanel.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
		settingsPanel.UIGradient.Color = ColorSequence.new({ColorSequenceKeypoint.new(0, Color3.new(0.0470588, 0.0470588, 0.0470588)),ColorSequenceKeypoint.new(1, Color3.new(0.0470588, 0.0470588, 0.0470588))})
		settingsPanel.UIGradient.Offset = Vector2.new(0, 1.7)
		settingsPanel.SettingTypes.Visible = true
		settingsPanel.SettingLists.Visible = false
		if settingsPanel.SettingTypes:IsA("ScrollingFrame") then
			settingsPanel.SettingTypes.CanvasPosition = Vector2.new(0, 0)
			settingsPanel.SettingTypes.ScrollBarImageTransparency = 1
		end
		refreshSettingsCategoryScroll()
		settingsPanel.Size = UDim2.new(0, 552, 0, 346)
		settingsPanel.Title.Position = UDim2.new(0.045, 0, 0.057, 0)

	settingsPanel.Title.Text = "Settings"
	settingsPanel.Subtitle.Text = "Adjust your preferences, set new keybinds, test out new features and more."

	local panelOpenTween = TweenInfo.new(0.48, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	local panelFadeTween = TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	local contentTween = TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	local cardTween = TweenInfo.new(0.4, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)

	tweenService:Create(settingsPanel, panelOpenTween, {Size = UDim2.new(0, 613, 0, 384)}):Play()
	tweenService:Create(settingsPanel, panelFadeTween, {BackgroundTransparency = 0}):Play()
	tweenService:Create(settingsPanel.UIGradient, TweenInfo.new(0.58, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Offset = Vector2.new(0, 1.05)}):Play()
	tweenService:Create(settingsPanel.Shadow, panelOpenTween, {ImageTransparency = 0.66}):Play()
		tweenService:Create(settingsPanel.Title, contentTween, {TextTransparency = 0}):Play()
		tweenService:Create(settingsPanel.Subtitle, contentTween, {TextTransparency = 0}):Play()
		task.defer(refreshSettingsCategoryScroll)
		task.delay(0.12, refreshSettingsCategoryScroll)
		task.delay(0.32, refreshSettingsCategoryScroll)
		task.delay(0.52, refreshSettingsCategoryScroll)

	task.wait(0.04)

	local cardIndex = 0
	for _, settingType in ipairs(settingsPanel.SettingTypes:GetChildren()) do
		if settingType.ClassName == "Frame" then
			cardIndex = cardIndex + 1
			local gradientRotation = math.random(78, 95)

			task.delay(cardIndex * 0.018, function()
				if animationId ~= settingsAnimationId or not settingsPanel.Visible then return end

				tweenService:Create(settingType.UIGradient, cardTween, {Rotation = gradientRotation}):Play()
				tweenService:Create(settingType.Shadow.UIGradient, cardTween, {Rotation = gradientRotation}):Play()
				tweenService:Create(settingType.UIStroke.UIGradient, cardTween, {Rotation = gradientRotation}):Play()
				tweenService:Create(settingType, cardTween, {BackgroundTransparency = 0}):Play()
				tweenService:Create(settingType.Shadow, cardTween, {ImageTransparency = 0.66}):Play()
				tweenService:Create(settingType.UIStroke, cardTween, {Transparency = 0}):Play()
				tweenService:Create(settingType.Title, cardTween, {TextTransparency = 0.2}):Play()
			end)
		end
	end

	task.wait(0.26)
	if animationId ~= settingsAnimationId then return end

	for _, settingList in ipairs(settingsPanel.SettingLists:GetChildren()) do
		if settingList.ClassName == "ScrollingFrame" then
			for _, setting in ipairs(settingList:GetChildren()) do
				if setting.ClassName == "Frame" then
					if settingList.Name == "Servers" and setting.Name == "Placeholder" then
						setting.Visible = false
						setting.Size = UDim2.new(0, 0, 0, 0)
					else
						setting.Visible = true
					end
				end
			end
		end
	end

	debounce = false
end

local function closeSettings()
	debounce = true
	settingsAnimationId += 1
	local animationId = settingsAnimationId
	settingsPanel.ClipsDescendants = true

	local contentFadeTween = TweenInfo.new(0.14, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	local panelCloseTween = TweenInfo.new(0.3, Enum.EasingStyle.Quint, Enum.EasingDirection.InOut)
	local panelFadeTween = TweenInfo.new(0.24, Enum.EasingStyle.Quint, Enum.EasingDirection.In)

	for _, settingType in ipairs(settingsPanel.SettingTypes:GetChildren()) do
		if settingType.ClassName == "Frame" then
			tweenService:Create(settingType, contentFadeTween, {BackgroundTransparency = 1}):Play()
			tweenService:Create(settingType.Shadow, contentFadeTween, {ImageTransparency = 1}):Play()
			tweenService:Create(settingType.UIStroke, contentFadeTween, {Transparency = 1}):Play()
			tweenService:Create(settingType.Title, contentFadeTween, {TextTransparency = 1}):Play()
		end
	end

	tweenService:Create(settingsPanel.Shadow, panelFadeTween, {ImageTransparency = 1}):Play()
	tweenService:Create(settingsPanel.Back, contentFadeTween, {ImageTransparency = 1}):Play()
	tweenService:Create(settingsPanel.Title, contentFadeTween, {TextTransparency = 1}):Play()
	tweenService:Create(settingsPanel.Subtitle, contentFadeTween, {TextTransparency = 1}):Play()
	tweenService:Create(settingsPanel.UIGradient, panelCloseTween, {Offset = Vector2.new(0, 1.65)}):Play()

	local dylanfocBackground = settingsPanel:FindFirstChild("DylanfocUtilityBackground")
	if dylanfocBackground then
		tweenService:Create(dylanfocBackground, contentFadeTween, {ImageTransparency = 1}):Play()
	end

	for _, settingList in ipairs(settingsPanel.SettingLists:GetChildren()) do
		if settingList.ClassName == "ScrollingFrame" then
			tweenService:Create(settingList, contentFadeTween, {ScrollBarImageTransparency = 1}):Play()
		end
	end

	tweenService:Create(settingsPanel, panelCloseTween, {Size = UDim2.new(0, 584, 0, 18)}):Play()
	tweenService:Create(settingsPanel, panelFadeTween, {BackgroundTransparency = 1}):Play()

	task.wait(0.3)
	if animationId ~= settingsAnimationId then return end

	for _, settingList in ipairs(settingsPanel.SettingLists:GetChildren()) do
		if settingList.ClassName == "ScrollingFrame" then
			for _, setting in ipairs(settingList:GetChildren()) do
				if setting.ClassName == "Frame" then
					setting.Visible = false
				end
			end
		end
	end

	settingsPanel.SettingLists.Visible = false
	if dylanfocBackground then
		dylanfocBackground.Visible = false
	end
	settingsPanel.Visible = false
	debounce = false
end

local function saveSettings()
	checkFolder()

	if typeof(writefile) == "function" then
		pcall(writefile, siriusValues.siriusFolder.."/"..siriusValues.settingsFile, httpService:JSONEncode(siriusSettings))
	end
end

siriusValues.keybindRows = siriusValues.keybindRows or {}
siriusValues.keybindDefaults = siriusValues.keybindDefaults or {}

function siriusValues.normaliseKeybind(value)
	if value == nil then
		return nil
	end

	value = tostring(value)
	if value == "" or value == "No Keybind" or value == "Press any key..." then
		return nil
	end

	local parts = {}
	for part in string.gmatch(value, "[^+]+") do
		part = string.gsub(part, "%s+", "")
		if part ~= "" then
			table.insert(parts, part)
		end
	end

	if #parts == 0 then
		return nil
	end

	return table.concat(parts, "+")
end

function siriusValues.formatKeybind(value)
	local normalised = siriusValues.normaliseKeybind(value)
	if not normalised then
		return "No Keybind"
	end

	return string.gsub(normalised, "+", " + ")
end

function siriusValues.isKeybindModifier(keyName)
	return keyName == "LeftControl"
		or keyName == "RightControl"
		or keyName == "LeftShift"
		or keyName == "RightShift"
		or keyName == "LeftAlt"
		or keyName == "RightAlt"
		or keyName == "LeftMeta"
		or keyName == "RightMeta"
end

function siriusValues.keybindSettingKey(setting)
	return setting and (setting.id or setting.name)
end

function siriusValues.captureKeybindDefaults()
	if siriusValues.keybindDefaultsCaptured then
		return
	end

	for _, category in ipairs(siriusSettings) do
		if category.name == keybindCategoryName then
			for _, setting in ipairs(category.categorySettings) do
				if setting.settingType == "Key" then
					siriusValues.keybindDefaults[siriusValues.keybindSettingKey(setting)] = setting.current
				end
			end
			break
		end
	end

	siriusValues.keybindDefaultsCaptured = true
end

function siriusValues.updateKeybindRow(setting)
	local row = siriusValues.keybindRows[siriusValues.keybindSettingKey(setting)]
	if not row or not row:FindFirstChild("InputFrame") then
		return
	end

	local inputBox = row.InputFrame:FindFirstChild("InputBox")
	if not inputBox then
		return
	end

	inputBox.Text = siriusValues.formatKeybind(setting.current)
	row.InputFrame.Size = UDim2.new(0, inputBox.TextBounds.X + 24, 0, 30)
end

function siriusValues.updateAllKeybindRows()
	for _, category in ipairs(siriusSettings) do
		if category.name == keybindCategoryName then
			for _, setting in ipairs(category.categorySettings) do
				if setting.settingType == "Key" then
					siriusValues.updateKeybindRow(setting)
				end
			end
			break
		end
	end
end

function siriusValues.findKeybindConflict(value, currentSetting)
	local target = siriusValues.normaliseKeybind(value)
	if not target then
		return nil
	end

	for _, category in ipairs(siriusSettings) do
		if category.name == keybindCategoryName then
			for _, setting in ipairs(category.categorySettings) do
				if setting.settingType == "Key" and setting ~= currentSetting then
					if siriusValues.normaliseKeybind(setting.current) == target then
						return setting
					end
				end
			end
			break
		end
	end

	return nil
end

function siriusValues.buildKeybindFromInput(input, storedModifiers)
	if input.KeyCode == Enum.KeyCode.Unknown then
		return nil
	end

	local keyName = input.KeyCode.Name
	local parts = {}
	local added = {}

	local function addModifier(modifierName)
		if modifierName ~= keyName and Enum.KeyCode[modifierName] and not added[modifierName] then
			table.insert(parts, modifierName)
			added[modifierName] = true
		end
	end

	if storedModifiers then
		for _, modifierName in ipairs(storedModifiers) do
			addModifier(modifierName)
		end
	end

	for _, modifierName in ipairs({"LeftControl", "RightControl", "LeftShift", "RightShift", "LeftAlt", "RightAlt", "LeftMeta", "RightMeta"}) do
		if Enum.KeyCode[modifierName] and userInputService:IsKeyDown(Enum.KeyCode[modifierName]) then
			addModifier(modifierName)
		end
	end

	table.insert(parts, keyName)
	return table.concat(parts, "+")
end

function siriusValues.keybindMatchesInput(value, input)
	local normalised = siriusValues.normaliseKeybind(value)
	if not normalised or input.KeyCode == Enum.KeyCode.Unknown then
		return false
	end

	local parts = {}
	for part in string.gmatch(normalised, "[^+]+") do
		table.insert(parts, part)
	end

	if #parts == 0 then
		return false
	end

	local mainKey = parts[#parts]
	if input.KeyCode.Name ~= mainKey then
		return false
	end

	for index = 1, #parts - 1 do
		local modifierName = parts[index]
		if Enum.KeyCode[modifierName] and not userInputService:IsKeyDown(Enum.KeyCode[modifierName]) then
			return false
		end
	end

	return true
end

function siriusValues.keybindSection(setting)
	local name = setting.name or ""

	if name == "Toggle Players Panel" then
		return "Players"
	elseif name == "Toggle Music Panel" then
		return "Music"
	elseif string.find(name, "Ghost", 1, true) then
		return "Ghost Mode"
	elseif name == "Toggle Character Panel"
		or name == "NoClip"
		or name == "Flight"
		or name == "Fly Up Key"
		or name == "Fly Down Key"
		or name == "Refresh"
		or name == "Respawn"
		or name == "Fling"
		or name == "ESP"
		or name == "Night and Day"
		or name == "Global Audio"
		or name == "Infinite Jump"
		or name == "Walk in Air"
		or name == "Anti Void"
		or name == "Auto Find [works with auto aim]"
		or name == "click teleport tool"
		or name == "Shaders"
		or name == "Invisibility" then
		return "Character"
	end

	return "UI"
end

function siriusValues.getKeybindRenderSettings(settings)
	local sectionOrder = {"UI", "Character", "Ghost Mode", "Players", "Music"}
	local descriptions = {
		UI = "Menu, search, panel, reset, and emergency controls.",
		Character = "Character actions and movement ability controls.",
		["Ghost Mode"] = "Spectate and free-camera movement controls.",
		Players = "Player list and player-focused controls.",
		Music = "Music panel controls."
	}
	local groups = {}
	local rendered = {}

	for _, sectionName in ipairs(sectionOrder) do
		groups[sectionName] = {}
	end

	for _, setting in ipairs(settings) do
		local sectionName = siriusValues.keybindSection(setting)
		table.insert(groups[sectionName] or groups.UI, setting)
	end

	for _, sectionName in ipairs(sectionOrder) do
		local group = groups[sectionName]
		if group and #group > 0 then
			table.insert(rendered, {
				name = sectionName,
				description = descriptions[sectionName],
				settingType = "Info"
			})

			for _, setting in ipairs(group) do
				table.insert(rendered, setting)
			end
		end
	end

	return rendered
end

function siriusValues.resetKeybinds()
	siriusValues.captureKeybindDefaults()

	for _, category in ipairs(siriusSettings) do
		if category.name == keybindCategoryName then
			for _, setting in ipairs(category.categorySettings) do
				if setting.settingType == "Key" then
					setting.current = siriusValues.keybindDefaults[siriusValues.keybindSettingKey(setting)]
					siriusValues.updateKeybindRow(setting)
				end
			end
			break
		end
	end

	saveSettings()
	queueNotification("Keybinds Reset", "All keybinds were restored to their Sirius defaults.", 4400696294)
end

local dylanfocClient = {
	infoRows = {},
	inputRows = {}
}

function dylanfocClient.getEnv()
	if getgenv then
		local success, env = pcall(getgenv)
		if success and env then
			return env
		end
	end

	return _G
end

function dylanfocClient.shortValue(value, limit)
	value = tostring(value or "Unavailable")
	limit = limit or 160

	if string.len(value) > limit then
		return string.sub(value, 1, limit - 3).."..."
	end

	return value
end

function dylanfocClient.getValue(valueKey)
	if valueKey == "hwid" then
		if gethwid then
			local success, value = pcall(gethwid)
			if success then
				return value
			end
		end

		return "Unavailable"
	elseif valueKey == "clientId" then
		local success, value = pcall(function()
			return game:GetService("RbxAnalyticsService"):GetClientId()
		end)

		return success and value or "Unavailable"
	elseif valueKey == "executor" then
		if identifyexecutor then
			local success, value = pcall(identifyexecutor)
			if success then
				return value
			end
		end

		return "Unknown executor"
	elseif valueKey == "userId" then
		return localPlayer and localPlayer.UserId or "Unavailable"
	elseif valueKey == "username" then
		return localPlayer and localPlayer.Name or "Unavailable"
	end

	return "Unavailable"
end

function dylanfocClient.setRowDescription(row, text)
	if not row or not row:FindFirstChild("Description") then
		return
	end

	row.Description.Visible = true
	row.Description.TextWrapped = true
	row.Description.Size = UDim2.new(0, 333, 0, 999)
	row.Description.Text = tostring(text or "")
	row.Description.Size = UDim2.new(0, 333, 0, math.max(row.Description.TextBounds.Y + 10, 28))
	row.Size = UDim2.new(0, 558, 0, math.max(row.Description.TextBounds.Y + 44, 68))
end

function dylanfocClient.registerInfoRow(setting, row)
	if setting.valueKey then
		dylanfocClient.infoRows[setting.valueKey] = row
		dylanfocClient.setRowDescription(row, dylanfocClient.shortValue(dylanfocClient.getValue(setting.valueKey), 170))
	elseif setting.description then
		dylanfocClient.setRowDescription(row, setting.description)
	end
end

function dylanfocClient.registerInputRow(setting, row)
	if setting.id then
		dylanfocClient.inputRows[setting.id] = row
	end
end

function dylanfocClient.refreshInfoRows()
	for valueKey, row in pairs(dylanfocClient.infoRows) do
		dylanfocClient.setRowDescription(row, dylanfocClient.shortValue(dylanfocClient.getValue(valueKey), 170))
	end
end

function dylanfocClient.getSettingValue(settingName)
	local setting = checkSetting(settingName, dylanfocCategoryName)
	if setting and setting.current ~= nil then
		return tostring(setting.current)
	end

	return ""
end

function dylanfocClient.notify(title, description, image)
	queueNotification(title, description, image or 4400696294)
end

function dylanfocClient.copyValue(label, valueKey)
	local value = dylanfocClient.getValue(valueKey)

	if not setclipboard then
		dylanfocClient.notify("Clipboard Unavailable", "Your executor does not expose setclipboard, so Sirius could not copy "..label..".", 4370336704)
		return
	end

	local success = pcall(function()
		setclipboard(tostring(value))
	end)

	if success then
		dylanfocClient.notify(label.." Copied", "Sirius copied the current "..label.." to your clipboard.", 4400696294)
	else
		dylanfocClient.notify("Copy Failed", "Sirius could not copy "..label.." to your clipboard.", 4370336704)
	end
end

function dylanfocClient.spoofClientId()
	local spoofValue = dylanfocClient.getSettingValue("Spoof ClientID Value")

	if spoofValue == "" then
		dylanfocClient.notify("Missing ClientID", "Enter a spoofed ClientID value before applying this hook.", 4370336704)
		return
	end

	if not (hookmetamethod and newcclosure and getnamecallmethod) then
		dylanfocClient.notify("Hook Unavailable", "Your executor does not expose the metamethod tools needed to spoof ClientID.", 4370336704)
		return
	end

	local env = dylanfocClient.getEnv()
	env.spoofedshit = spoofValue

	if not env.SiriusDylanfocClientIdHooked then
		local oldNamecall
		oldNamecall = hookmetamethod(game, "__namecall", newcclosure(LPH_NO_VIRTUALIZE(function(self, ...)
			if getnamecallmethod() == "GetClientId" and env.spoofedshit then
				return env.spoofedshit
			end

			return oldNamecall(self, ...)
		end)))

		env.SiriusDylanfocClientIdHooked = true
	end

	dylanfocClient.notify("ClientID Spoofed", "GetClientId now returns your selected ClientID value.", 4400699701)
	dylanfocClient.refreshInfoRows()
end

function dylanfocClient.spoofHwid()
	local spoofValue = dylanfocClient.getSettingValue("Spoof HWID Value")

	if spoofValue == "" then
		dylanfocClient.notify("Missing HWID", "Enter a spoofed HWID value before applying this hook.", 4370336704)
		return
	end

	if not (hookfunction and gethwid) then
		dylanfocClient.notify("Hook Unavailable", "Your executor does not expose hookfunction or gethwid.", 4370336704)
		return
	end

	local env = dylanfocClient.getEnv()
	env.spoofhwid = spoofValue

	if not env.SiriusDylanfocHwidHooked then
		hookfunction(gethwid, LPH_NO_VIRTUALIZE(function(...)
			return env.spoofhwid
		end))

		env.SiriusDylanfocHwidHooked = true
	end

	dylanfocClient.notify("HWID Spoofed", "gethwid now returns your selected HWID value.", 4400699701)
	dylanfocClient.refreshInfoRows()
end

function dylanfocClient.spoofExecutor()
	local spoofValue = dylanfocClient.getSettingValue("Spoof Executor Value")

	if spoofValue == "" then
		dylanfocClient.notify("Missing Executor", "Enter or select an executor name before applying this hook.", 4370336704)
		return
	end

	if not (hookfunction and identifyexecutor) then
		dylanfocClient.notify("Hook Unavailable", "Your executor does not expose hookfunction or identifyexecutor.", 4370336704)
		return
	end

	local env = dylanfocClient.getEnv()
	env.spoofedexec = spoofValue

	if not env.SiriusDylanfocExecutorHooked then
		hookfunction(identifyexecutor, LPH_NO_VIRTUALIZE(function(...)
			return env.spoofedexec
		end))

		env.SiriusDylanfocExecutorHooked = true
	end

	dylanfocClient.notify("Executor Spoofed", "identifyexecutor now returns "..dylanfocClient.shortValue(spoofValue, 48)..".", 4400699701)
	dylanfocClient.refreshInfoRows()
end

function dylanfocClient.spoofUserId()
	local spoofValue = tonumber(dylanfocClient.getSettingValue("Spoof UserID Value"))

	if not spoofValue then
		dylanfocClient.notify("Invalid UserID", "Enter a numeric UserId before applying this spoof.", 4370336704)
		return
	end

	local success = pcall(function()
		localPlayer.UserId = spoofValue
	end)

	if success then
		dylanfocClient.getEnv().spoofuserID = spoofValue
		dylanfocClient.notify("UserID Spoofed", "Sirius wrote the LocalPlayer UserId for this session.", 4400699701)
		dylanfocClient.refreshInfoRows()
	else
		dylanfocClient.notify("UserID Locked", "Roblox blocked writing LocalPlayer.UserId in this environment.", 4370336704)
	end
end

function dylanfocClient.spoofUsername()
	local spoofValue = dylanfocClient.getSettingValue("Spoof Username Value")

	if spoofValue == "" then
		dylanfocClient.notify("Missing Username", "Enter a spoofed username before applying this spoof.", 4370336704)
		return
