	end)

	if success then
		dylanfocClient.getEnv().spoofuser = spoofValue
		dylanfocClient.notify("Username Spoofed", "Sirius wrote the LocalPlayer name for this session.", 4400699701)
		dylanfocClient.refreshInfoRows()
	else
		dylanfocClient.notify("Username Locked", "Roblox blocked writing LocalPlayer.Name in this environment.", 4370336704)
	end
end

function dylanfocClient.disableRestoreFunction()
	if not (hookfunction and restorefunction) then
		dylanfocClient.notify("Restore Hook Unavailable", "Your executor does not expose restorefunction or hookfunction.", 4370336704)
		return
	end

	local env = dylanfocClient.getEnv()
	if env.SiriusDylanfocRestoreDisabled then
		dylanfocClient.notify("Already Disabled", "restorefunction is already blocked in this session.", 4400696294)
		return
	end

	hookfunction(restorefunction, LPH_NO_VIRTUALIZE(function(...)
		return "no."
	end))

	env.SiriusDylanfocRestoreDisabled = true
	dylanfocClient.notify("restorefunction Disabled", "Hook rollback has been blocked for this session. Rejoin to fully reset.", 4370336704)
end

function dylanfocClient.resetUtilityState()
	local env = dylanfocClient.getEnv()
	env.SpoofLoaded = false
	env.spoofedshit = nil
	env.spoofhwid = nil
	env.spoofedexec = nil
	env.spoofuserID = nil
	env.spoofuser = nil

	dylanfocClient.notify("Utility State Reset", "Stored spoof values were cleared. Existing hooks may need a rejoin to fully restore.", 4400696294)
	dylanfocClient.refreshInfoRows()
end

function dylanfocClient.runOriginalScript()
	local success, result = pcall(function()
		return loadstring(game:HttpGet("https://raw.githubusercontent.com/Dylanfoc2/spoofer/refs/heads/main/spoof"))()
	end)

	if success then
		dylanfocClient.notify("Pine Protect Started", "Sirius launched the original Pine Protect script.", 4400699701)
	else
		dylanfocClient.notify("Pine Protect Failed", "Sirius could not run the original Pine Protect script.", 4370336704)
		warn("[Sirius] Pine Protect original script failed:", result)
	end
end

function dylanfocClient.runAction(setting)
	local action = setting.action

	if action == "copy_hwid" then
		dylanfocClient.copyValue("HWID", "hwid")
	elseif action == "copy_clientid" then
		dylanfocClient.copyValue("ClientID", "clientId")
	elseif action == "copy_executor" then
		dylanfocClient.copyValue("Executor", "executor")
	elseif action == "copy_userid" then
		dylanfocClient.copyValue("UserID", "userId")
	elseif action == "copy_username" then
		dylanfocClient.copyValue("Username", "username")
	elseif action == "refresh_client_info" then
		dylanfocClient.refreshInfoRows()
		dylanfocClient.notify("Client Info Refreshed", "Sirius updated the client values shown in this page.", 4400696294)
	elseif action == "run_original_dylanfoc" then
		dylanfocClient.runOriginalScript()
	elseif action == "spoof_clientid" then
		dylanfocClient.spoofClientId()
	elseif action == "spoof_hwid" then
		dylanfocClient.spoofHwid()
	elseif action == "spoof_executor" then
		dylanfocClient.spoofExecutor()
	elseif action == "spoof_userid" then
		dylanfocClient.spoofUserId()
	elseif action == "spoof_username" then
		dylanfocClient.spoofUsername()
	elseif action == "disable_restorefunction" then
		dylanfocClient.disableRestoreFunction()
	elseif action == "reset_utility_state" then
		dylanfocClient.resetUtilityState()
	end
end

function dylanfocClient.updateInputRow(setting)
	local row = dylanfocClient.inputRows[setting.id]
	if not row or not row:FindFirstChild("InputFrame") then
		return
	end

	local value = tostring(setting.current or "")
	row.InputFrame.InputBox.Text = string.len(value) > 24 and string.sub(value, 1, 22)..".." or value
	row.InputFrame.Size = UDim2.new(0, row.InputFrame.InputBox.TextBounds.X + 24, 0, 30)
end

function dylanfocClient.cycleDropdown(setting, row)
	if not setting.values or #setting.values == 0 then
		return
	end

	local currentIndex = 1
	for index, value in ipairs(setting.values) do
		if value == setting.current then
			currentIndex = index
			break
		end
	end

	currentIndex += 1
	if currentIndex > #setting.values then
		currentIndex = 1
	end

	setting.current = setting.values[currentIndex]

	if setting.targetSetting then
		local targetSetting = checkSetting(setting.targetSetting, dylanfocCategoryName)
		if targetSetting then
			targetSetting.current = setting.current
			dylanfocClient.updateInputRow(targetSetting)
		end
	end

	saveSettings()
	dylanfocClient.setRowDescription(row, "Current: "..dylanfocClient.shortValue(setting.current, 96))
end

local function assembleSettings()
	if siriusValues.captureKeybindDefaults then
		siriusValues.captureKeybindDefaults()
	end

	if isfile and isfile(siriusValues.siriusFolder.."/"..siriusValues.settingsFile) then
		local currentSettings

		local success, response = pcall(function()
			currentSettings = httpService:JSONDecode(readfile(siriusValues.siriusFolder.."/"..siriusValues.settingsFile))
		end)

		if success then
			for _, liveCategory in ipairs(siriusSettings) do
				for _, liveSetting in ipairs(liveCategory.categorySettings) do
					for _, category in ipairs(currentSettings) do
						for _, setting in ipairs(category.categorySettings) do
							if liveSetting.id == setting.id then
								liveSetting.current = setting.current
							end
						end
					end
				end
			end

			writefile(siriusValues.siriusFolder.."/"..siriusValues.settingsFile, httpService:JSONEncode(siriusSettings)) -- Update file with any new settings added
		end
	else
		if writefile then
			checkFolder()
			if not isfile(siriusValues.siriusFolder.."/"..siriusValues.settingsFile) then
				writefile(siriusValues.siriusFolder.."/"..siriusValues.settingsFile, httpService:JSONEncode(siriusSettings))
			end
		end 
	end

	bindSettingsCategoryScroll()
	refreshSettingsCategoryScroll()

	settingsPanel.Back.MouseButton1Click:Connect(function()
		setDylanfocUtilityBackgroundVisible(false)
		tweenService:Create(settingsPanel.Back, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {ImageTransparency = 1}):Play()
		tweenService:Create(settingsPanel.Back, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Position = UDim2.new(0.002, 0, 0.052, 0)}):Play()
		tweenService:Create(settingsPanel.Title, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Position = UDim2.new(0.045, 0, 0.057, 0)}):Play()
		tweenService:Create(settingsPanel.UIGradient, TweenInfo.new(1, Enum.EasingStyle.Exponential), {Offset = Vector2.new(0, 1.3)}):Play()
		settingsPanel.Title.Text = "Settings"
		settingsPanel.Subtitle.Text = "Adjust your preferences, set new keybinds, test out new features and more"

		for _, settingList in ipairs(settingsPanel.SettingLists:GetChildren()) do
			if settingList:IsA("ScrollingFrame") then
				settingList.ScrollBarImageTransparency = 1
			end
		end

		settingsPanel.SettingTypes.Visible = true
		settingsPanel.SettingLists.Visible = false

		if settingsPanel.SettingTypes:IsA("ScrollingFrame") then
			settingsPanel.SettingTypes.CanvasPosition = Vector2.new(0, 0)
			settingsPanel.SettingTypes.ScrollBarImageTransparency = 1
		end
		refreshSettingsCategoryScroll()
		task.delay(0.12, refreshSettingsCategoryScroll)
		task.delay(0.32, refreshSettingsCategoryScroll)
	end)

	for _, category in siriusSettings do
		local newCategory = settingsPanel.SettingTypes.Template:Clone()
		newCategory.Name = category.name
		newCategory.Title.Text = string.upper(category.name)
		newCategory.Parent = settingsPanel.SettingTypes
		newCategory.UIGradient.Color = ColorSequence.new({ColorSequenceKeypoint.new(0, Color3.new(0.0392157, 0.0392157, 0.0392157)),ColorSequenceKeypoint.new(1, category.color)})

		newCategory.Visible = true

		local hue, sat, val = Color3.toHSV(category.color)

		hue = math.clamp(hue + 0.01, 0, 1) sat = math.clamp(sat + 0.1, 0, 1) val = math.clamp(val + 0.2, 0, 1)

		local newColor = Color3.fromHSV(hue, sat, val)
		newCategory.UIStroke.UIGradient.Color = ColorSequence.new({ColorSequenceKeypoint.new(0, Color3.new(0.117647, 0.117647, 0.117647)),ColorSequenceKeypoint.new(1, newColor)})
		newCategory.Shadow.UIGradient.Color = ColorSequence.new({ColorSequenceKeypoint.new(0, Color3.new(0.117647, 0.117647, 0.117647)),ColorSequenceKeypoint.new(1, newColor)})

		local newList = settingsPanel.SettingLists.Template:Clone()
		newList.Name = category.name
		newList.Parent = settingsPanel.SettingLists
		attachScrollbarFade(newList, 0.55, 0.65)

		newList.Visible = true

		for _, obj in ipairs(newList:GetChildren()) do if obj.Name ~= "Placeholder" and obj.Name ~= "UIListLayout" then obj:Destroy() end end 

		newCategory.Interact.MouseButton1Click:Connect(function()
			if settingsPanel.SettingLists:FindFirstChild(category.name) then
				local selectedList = settingsPanel.SettingLists[category.name]
				setDylanfocUtilityBackgroundVisible(category.name == dylanfocCategoryName)
				settingsPanel.UIGradient.Color = ColorSequence.new({ColorSequenceKeypoint.new(0, Color3.new(0.0470588, 0.0470588, 0.0470588)),ColorSequenceKeypoint.new(1, category.color)})
				settingsPanel.SettingTypes.Visible = false
				settingsPanel.SettingLists.Visible = true
				settingsPanel.SettingLists.UIPageLayout:JumpTo(selectedList)
				settingsPanel.Subtitle.Text = category.description
				settingsPanel.Back.Visible = true
				settingsPanel.Title.Text = category.name

				if selectedList:IsA("ScrollingFrame") then
					selectedList.CanvasPosition = Vector2.new(0, 0)
					selectedList.ScrollBarImageTransparency = 1

					for _, child in ipairs(selectedList:GetChildren()) do
						if child:IsA("Frame") then
							if selectedList.Name == "Servers" and child.Name == "Placeholder" then
								child.Visible = false
								child.Size = UDim2.new(0, 0, 0, 0)
							else
								child.Visible = true
							end
						end
					end

					if category.name == dylanfocCategoryName then
						dylanfocClient.refreshInfoRows()
					end

					task.defer(function()
						selectedList.CanvasPosition = Vector2.new(0, 0)

						local listLayout = selectedList:FindFirstChildOfClass("UIListLayout")
						if listLayout then
							local contentHeight = math.max(listLayout.AbsoluteContentSize.Y + 26, 340)
							selectedList.CanvasSize = UDim2.new(0, 0, 0, contentHeight)
							selectedList.ScrollBarImageTransparency = contentHeight > selectedList.AbsoluteWindowSize.Y + 8 and 0.55 or 1
						end
					end)
				end

				local gradientRotation = math.random(78, 95)
				settingsPanel.UIGradient.Rotation = gradientRotation
				tweenService:Create(settingsPanel.UIGradient, TweenInfo.new(0.5, Enum.EasingStyle.Exponential), {Offset = Vector2.new(0, 0.65)}):Play()
				tweenService:Create(settingsPanel.Back, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {ImageTransparency = 0}):Play()
				tweenService:Create(settingsPanel.Back, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Position = UDim2.new(0.041, 0, 0.052, 0)}):Play()
				tweenService:Create(settingsPanel.Title, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {Position = UDim2.new(0.091, 0, 0.057, 0)}):Play()
			else
				-- error
				closeSettings()
			end
		end)

		newCategory.MouseEnter:Connect(function()
			tweenService:Create(newCategory.Title, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {TextTransparency = 0}):Play()
			tweenService:Create(newCategory.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.4)}):Play()
			tweenService:Create(newCategory.UIStroke.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.2)}):Play()
			tweenService:Create(newCategory.Shadow.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.2)}):Play()
		end)

		newCategory.MouseLeave:Connect(function()
			tweenService:Create(newCategory.Title, TweenInfo.new(0.5, Enum.EasingStyle.Quint), {TextTransparency = 0.2}):Play()
			tweenService:Create(newCategory.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.65)}):Play()
			tweenService:Create(newCategory.UIStroke.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.4)}):Play()
			tweenService:Create(newCategory.Shadow.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0, 0.4)}):Play()
		end)

		local settingsToRender = category.categorySettings
		if category.name == keybindCategoryName and siriusValues.getKeybindRenderSettings then
			settingsToRender = siriusValues.getKeybindRenderSettings(category.categorySettings)
		end

		for _, setting in ipairs(settingsToRender) do
			if not setting.hidden then
				local settingType = setting.settingType
				local minimumLicense = setting.minimumLicense
				local object = nil

				if settingType == "Info" then
					local newInfo = settingsPanel.SettingLists.Template.SwitchTemplate:Clone()
					object = newInfo
					newInfo.Name = setting.name
					newInfo.Parent = newList
					newInfo.Visible = true
					newInfo.Title.Text = setting.name

					if newInfo:FindFirstChild("Switch") then
						newInfo.Switch.Visible = false
					end

					dylanfocClient.registerInfoRow(setting, newInfo)

				elseif settingType == "Action" then
					local newAction = settingsPanel.SettingLists.Template.SwitchTemplate:Clone()
					object = newAction
					newAction.Name = setting.name
					newAction.Parent = newList
					newAction.Visible = true
					newAction.Title.Text = setting.name

					if newAction:FindFirstChild("Switch") then
						if setting.action == "run_original_dylanfoc" then
							local runButton = newAction.Switch
							runButton.Visible = true
							runButton.Size = UDim2.new(0, 88, 0, 36)
							runButton.BackgroundColor3 = Color3.fromRGB(34, 34, 34)
							runButton.BackgroundTransparency = 0.06

							if runButton:FindFirstChild("Indicator") then
								runButton.Indicator.Visible = false
							end

							local runStroke = runButton:FindFirstChildOfClass("UIStroke") or Instance.new("UIStroke")
							runStroke.Parent = runButton
							runStroke.Color = category.color
							runStroke.Thickness = 1
							runStroke.Transparency = 0.58

							local runCorner = runButton:FindFirstChildOfClass("UICorner") or Instance.new("UICorner")
							runCorner.Parent = runButton
							runCorner.CornerRadius = UDim.new(1, 0)

							local runLabel = runButton:FindFirstChild("RunLabel") or Instance.new("TextLabel")
							runLabel.Name = "RunLabel"
							runLabel.Parent = runButton
							runLabel.BackgroundTransparency = 1
							runLabel.Size = UDim2.new(1, 0, 1, 0)
							runLabel.Font = Enum.Font.GothamSemibold
							runLabel.Text = "Run"
							runLabel.TextColor3 = Color3.fromRGB(255, 255, 255)
							runLabel.TextSize = 16
							runLabel.TextTransparency = 0
							runLabel.ZIndex = runButton.ZIndex + 1
						else
							newAction.Switch.Visible = false
						end
					end

					newAction.Interact.MouseButton1Click:Connect(function()
						if setting.callback then
							task.spawn(setting.callback)
						else
							dylanfocClient.runAction(setting)
						end
					end)

				elseif settingType == "Dropdown" then
					local newDropdown = settingsPanel.SettingLists.Template.SwitchTemplate:Clone()
					object = newDropdown
					newDropdown.Name = setting.name
					newDropdown.Parent = newList
					newDropdown.Visible = true
					newDropdown.Title.Text = setting.name

					if newDropdown:FindFirstChild("Switch") then
						newDropdown.Switch.Visible = false
					end

					dylanfocClient.setRowDescription(newDropdown, "Current: "..dylanfocClient.shortValue(setting.current, 96).."\nTap this row to cycle presets.")

					newDropdown.Interact.MouseButton1Click:Connect(function()
						dylanfocClient.cycleDropdown(setting, newDropdown)
					end)

				elseif settingType == "Boolean" then
					local newSwitch = settingsPanel.SettingLists.Template.SwitchTemplate:Clone()
					object = newSwitch
					newSwitch.Name = setting.name
					newSwitch.Parent = newList
					newSwitch.Visible = true
					newSwitch.Title.Text = setting.name

					if setting.current == true then
						newSwitch.Switch.Indicator.Position = UDim2.new(1, -20, 0.5, 0)
						newSwitch.Switch.Indicator.UIStroke.Color = Color3.fromRGB(220, 220, 220)
						newSwitch.Switch.Indicator.BackgroundColor3 = Color3.fromRGB(255, 255, 255)			
						newSwitch.Switch.Indicator.BackgroundTransparency = 0.6
					end


					if minimumLicense then
						if (minimumLicense == "Pro" and not Pro) or (minimumLicense == "Essential" and not (Pro or Essential)) then
							newSwitch.Switch.Indicator.Position = UDim2.new(1, -40, 0.5, 0)
							newSwitch.Switch.Indicator.UIStroke.Color = Color3.fromRGB(255, 255, 255)
							newSwitch.Switch.Indicator.BackgroundColor3 = Color3.fromRGB(235, 235, 235)			
							newSwitch.Switch.Indicator.BackgroundTransparency = 0.75
						end
					end

					newSwitch.Interact.MouseButton1Click:Connect(function()
						if minimumLicense then
							if (minimumLicense == "Pro" and not Pro) or (minimumLicense == "Essential" and not (Pro or Essential)) then
								queueNotification("This feature is locked", "You must be "..minimumLicense.." or higher to use "..setting.name..". \n\nUpgrade at https://sirius.menu.", 4483345875)
								return
							end
						end

						setting.current = not setting.current
						saveSettings()
						if setting.current == true then
							tweenService:Create(newSwitch.Switch.Indicator, TweenInfo.new(0.5, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {Position = UDim2.new(1, -20, 0.5, 0)}):Play()
							tweenService:Create(newSwitch.Switch.Indicator, TweenInfo.new(0.4, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {Size = UDim2.new(0,12,0,12)}):Play()
							tweenService:Create(newSwitch.Switch.Indicator.UIStroke, TweenInfo.new(0.55, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Color = Color3.fromRGB(200, 200, 200)}):Play()
							tweenService:Create(newSwitch.Switch.Indicator, TweenInfo.new(0.8, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundColor3 = Color3.fromRGB(255, 255, 255)}):Play()
							tweenService:Create(newSwitch.Switch.Indicator.UIStroke, TweenInfo.new(0.55, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.5}):Play()
							tweenService:Create(newSwitch.Switch.Indicator, TweenInfo.new(0.55, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.6}):Play()
							task.wait(0.05)
							tweenService:Create(newSwitch.Switch.Indicator, TweenInfo.new(0.45, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {Size = UDim2.new(0,17,0,17)}):Play()							
						else
							tweenService:Create(newSwitch.Switch.Indicator, TweenInfo.new(0.45, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {Position = UDim2.new(1, -40, 0.5, 0)}):Play()
							tweenService:Create(newSwitch.Switch.Indicator, TweenInfo.new(0.4, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {Size = UDim2.new(0,12,0,12)}):Play()
							tweenService:Create(newSwitch.Switch.Indicator.UIStroke, TweenInfo.new(0.55, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Color = Color3.fromRGB(255, 255, 255)}):Play()
							tweenService:Create(newSwitch.Switch.Indicator.UIStroke, TweenInfo.new(0.55, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.7}):Play()
							tweenService:Create(newSwitch.Switch.Indicator, TweenInfo.new(0.8, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundColor3 = Color3.fromRGB(235, 235, 235)}):Play()
							tweenService:Create(newSwitch.Switch.Indicator, TweenInfo.new(0.55, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.75}):Play()
							task.wait(0.05)
							tweenService:Create(newSwitch.Switch.Indicator, TweenInfo.new(0.4, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {Size = UDim2.new(0,17,0,17)}):Play()
						end
					end)

				elseif settingType == "Input" then
					local newInput = settingsPanel.SettingLists.Template.InputTemplate:Clone()
					object = newInput
					dylanfocClient.registerInputRow(setting, newInput)

					newInput.Name = setting.name
					newInput.InputFrame.InputBox.Text = setting.current
					newInput.InputFrame.InputBox.PlaceholderText = setting.placeholder or "input"
					newInput.Parent = newList

					if string.len(setting.current) > 19 then
						newInput.InputFrame.InputBox.Text = string.sub(tostring(setting.current), 1,17)..".."
					else
						newInput.InputFrame.InputBox.Text = setting.current
					end

					newInput.Visible = true
					newInput.Title.Text = setting.name
					newInput.InputFrame.InputBox.TextWrapped = false
					newInput.InputFrame.Size = UDim2.new(0, newInput.InputFrame.InputBox.TextBounds.X + 24, 0, 30)

					newInput.InputFrame.InputBox.FocusLost:Connect(function()
						if minimumLicense then
							if (minimumLicense == "Pro" and not Pro) or (minimumLicense == "Essential" and not (Pro or Essential)) then
								queueNotification("This feature is locked", "You must be "..minimumLicense.." or higher to use "..setting.name..". \n\nUpgrade at https://sirius.menu.", 4483345875)
								newInput.InputFrame.InputBox.Text = setting.current
								return
							end
						end

						if newInput.InputFrame.InputBox.Text ~= nil and newInput.InputFrame.InputBox.Text ~= "" then
							setting.current = newInput.InputFrame.InputBox.Text
							saveSettings()
						end
						if string.len(setting.current) > 24 then
							newInput.InputFrame.InputBox.Text = string.sub(tostring(setting.current), 1,22)..".."
						else
							newInput.InputFrame.InputBox.Text = setting.current
						end
					end)

					newInput.InputFrame.InputBox:GetPropertyChangedSignal("Text"):Connect(function()
						tweenService:Create(newInput.InputFrame, TweenInfo.new(0.5, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Size = UDim2.new(0, newInput.InputFrame.InputBox.TextBounds.X + 24, 0, 30)}):Play()
					end)

				elseif settingType == "Number" then
					local newInput = settingsPanel.SettingLists.Template.InputTemplate:Clone()
					object = newInput

					newInput.Name = setting.name
					newInput.InputFrame.InputBox.Text = tostring(setting.current)
					newInput.InputFrame.InputBox.PlaceholderText = setting.placeholder or "number"
					newInput.Parent = newList

					if string.len(setting.current) > 19 then
						newInput.InputFrame.InputBox.Text = string.sub(tostring(setting.current), 1,17)..".."
					else
						newInput.InputFrame.InputBox.Text = setting.current
					end

					newInput.Visible = true
					newInput.Title.Text = setting.name
					newInput.InputFrame.InputBox.TextWrapped = false
					newInput.InputFrame.Size = UDim2.new(0, newInput.InputFrame.InputBox.TextBounds.X + 24, 0, 30)

					newInput.InputFrame.InputBox.FocusLost:Connect(function()

						if minimumLicense then
							if (minimumLicense == "Pro" and not Pro) or (minimumLicense == "Essential" and not (Pro or Essential)) then
								queueNotification("This feature is locked", "You must be "..minimumLicense.." or higher to use "..setting.name..". \n\nUpgrade at https://sirius.menu.", 4483345875)
								newInput.InputFrame.InputBox.Text = setting.current
								return
							end
						end

						local inputValue = tonumber(newInput.InputFrame.InputBox.Text)

						if inputValue then
							if setting.values then
								local minValue = setting.values[1]
								local maxValue = setting.values[2]

								if inputValue < minValue then
									setting.current = minValue
								elseif inputValue > maxValue then
									setting.current = maxValue
								else
									setting.current = inputValue
								end

								saveSettings()
							else
								setting.current = inputValue
								saveSettings()
							end
						else
							newInput.InputFrame.InputBox.Text = tostring(setting.current)
						end

						if string.len(setting.current) > 24 then
							newInput.InputFrame.InputBox.Text = string.sub(tostring(setting.current), 1,22)..".."
						else
							newInput.InputFrame.InputBox.Text = tostring(setting.current)
						end
					end)

					newInput.InputFrame.InputBox:GetPropertyChangedSignal("Text"):Connect(function()
						tweenService:Create(newInput.InputFrame, TweenInfo.new(0.5, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Size = UDim2.new(0, newInput.InputFrame.InputBox.TextBounds.X + 24, 0, 30)}):Play()
					end)

				elseif settingType == "Key" then
					local newKeybind = settingsPanel.SettingLists.Template.InputTemplate:Clone()
					object = newKeybind
					newKeybind.Name = setting.name
					newKeybind.InputFrame.InputBox.PlaceholderText = setting.placeholder or "Press any key..."
					newKeybind.InputFrame.InputBox.Text = siriusValues.formatKeybind(setting.current)
					newKeybind.Parent = newList
					siriusValues.keybindRows[siriusValues.keybindSettingKey(setting)] = newKeybind

					newKeybind.Visible = true
					newKeybind.Title.Text = setting.name
					newKeybind.InputFrame.InputBox.TextWrapped = false
					newKeybind.InputFrame.Size = UDim2.new(0, newKeybind.InputFrame.InputBox.TextBounds.X + 24, 0, 30)

					newKeybind.InputFrame.InputBox.FocusLost:Connect(function()
						checkingForKey = false

						if minimumLicense then
							if (minimumLicense == "Pro" and not Pro) or (minimumLicense == "Essential" and not (Pro or Essential)) then
								queueNotification("This feature is locked", "You must be "..minimumLicense.." or higher to use "..setting.name..". \n\nUpgrade at https://sirius.menu.", 4483345875)
								newKeybind.InputFrame.InputBox.Text = siriusValues.formatKeybind(setting.current)
								return
							end
						end

						local keybindText = newKeybind.InputFrame.InputBox.Text
						if keybindText == nil or keybindText == "" then
							newKeybind.InputFrame.InputBox.Text = "No Keybind"
							setting.current = nil
							newKeybind.InputFrame.InputBox:ReleaseFocus()
							saveSettings()
						elseif keybindText == "Press any key..." or string.find(keybindText, "%.%.%.") then
							newKeybind.InputFrame.InputBox.Text = siriusValues.formatKeybind(setting.current)
						end
					end)

					newKeybind.InputFrame.InputBox.Focused:Connect(function()
						checkingForKey = {data = setting, object = newKeybind, modifiers = {}}
						newKeybind.InputFrame.InputBox.Text = "Press any key..."
					end)

					newKeybind.InputFrame.InputBox:GetPropertyChangedSignal("Text"):Connect(function()
						tweenService:Create(newKeybind.InputFrame, TweenInfo.new(0.5, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Size = UDim2.new(0, newKeybind.InputFrame.InputBox.TextBounds.X + 24, 0, 30)}):Play()
					end)

				elseif settingType == "Servers" then
					createServersBrowser(newList)

				end

				if object then
					if setting.description and settingType ~= "Dropdown" then
						object.Description.Visible = true
						object.Description.TextWrapped = true
						object.Description.Size = UDim2.new(0, 333, 5, 0)
						object.Description.Size = UDim2.new(0, 333, 0, 999)
						object.Description.Text = setting.description
						object.Description.Size = UDim2.new(0, 333, 0, object.Description.TextBounds.Y + 10)
						object.Size = UDim2.new(0, 558, 0, object.Description.TextBounds.Y + 44)
					end

					if minimumLicense then
						object.LicenseDisplay.Visible = true
						object.Title.Position = UDim2.new(0, 18, 0, 26)
						object.Description.Position = UDim2.new(0, 18, 0, 43)
						object.Size = UDim2.new(0, 558, 0, object.Size.Y.Offset + 13)
						object.LicenseDisplay.Text = string.upper(minimumLicense).." FEATURE"
					end

					local objectTouching
					object.MouseEnter:Connect(function()
						objectTouching = true
						tweenService:Create(object.UIStroke, TweenInfo.new(0.35, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.45}):Play()
						tweenService:Create(object, TweenInfo.new(0.35, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.83}):Play()
					end)

					object.MouseLeave:Connect(function()
						objectTouching = false
						tweenService:Create(object.UIStroke, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.6}):Play()
						tweenService:Create(object, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.9}):Play()
					end)

					if object:FindFirstChild('Interact') then
						object.Interact.MouseButton1Click:Connect(function()
							tweenService:Create(object.UIStroke, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 1}):Play()
							tweenService:Create(object, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.8}):Play()
							task.wait(0.1)
							if objectTouching then
								tweenService:Create(object.UIStroke, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.45}):Play()
								tweenService:Create(object, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.83}):Play()
							else
								tweenService:Create(object.UIStroke, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.6}):Play()
								tweenService:Create(object, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.9}):Play()
							end
						end)
					end
				end
			end
		end
	end

	refreshSettingsCategoryScroll()
end

local function initialiseAntiKick()
	if checkSetting("Client-Based Anti Kick").current then
		if hookmetamethod and getnamecallmethod then 
			local originalIndex
			local originalNamecall

			originalIndex = hookmetamethod(game, "__index", LPH_NO_VIRTUALIZE(function(self, method)
				if self == localPlayer and method:lower() == "kick" and checkSetting("Client-Based Anti Kick").current and checkSirius() then
					queueNotification("Kick Prevented", "Sirius has prevented you from being kicked by the client.", 4400699701)
					return error("Expected ':' not '.' calling member function Kick", 2)
				end
				return originalIndex(self, method)
			end))

			originalNamecall = hookmetamethod(game, "__namecall", LPH_NO_VIRTUALIZE(function(self, ...)
				if self == localPlayer and getnamecallmethod():lower() == "kick" and checkSetting("Client-Based Anti Kick").current and checkSirius() then
					queueNotification("Kick Prevented", "Sirius has prevented you from being kicked by the client.", 4400699701)
					return
				end
				return originalNamecall(self, ...)
			end))
		end
	end
end

local function boost()
	local success, result = pcall(function()
		loadstring(game:HttpGet('https://raw.githubusercontent.com/SiriusSoftwareLtd/Sirius/refs/heads/request/boost.lua'))()
	end)

	if not success then
		print('Error with boost file.')
		print(result)
	end
end

siriusValues.runKeybindAction = function(actionName)
	actionName = tostring(actionName or "")

	if siriusValues.betaControl and siriusValues.betaControl.disabled and actionName ~= "close" then
		siriusValues.showBetaControlOverlay("SIRIUS X Disabled", siriusValues.betaControl.message ~= "" and siriusValues.betaControl.message or "This beta build is temporarily disabled.", true)
		return
	end

	if actionName == "stopabilities" then
		if siriusValues.stopActiveAbilitiesForModeratorDetection then
			siriusValues.stopActiveAbilitiesForModeratorDetection("the stop keybind was used")
		end
		return
	end

	if actionName == "panic" then
		if siriusValues.stopActiveAbilitiesForModeratorDetection then
			siriusValues.stopActiveAbilitiesForModeratorDetection("the panic keybind was used")
		end

		if not debounce then
			siriusValues.runKeybindAction("close")
		end

		queueNotification("Panic Keybind", "Stopped active abilities and closed available Sirius panels.", 4400696294)
		return
	end

	if actionName == "commandsearch" then
		if debounce then return end

		local function focusCommandSearch()
			if not CmdInput then return end

			if CmdInput:IsFocused() then
				CmdInput:ReleaseFocus()
			else
				CmdInput:CaptureFocus()
				task.wait()
				CmdInput.Text = ""
			end
		end

		if not smartBarOpen then
			openSmartBar()
			task.delay(0.55, focusCommandSearch)
		else
			focusCommandSearch()
		end
		return
	end

	if debounce then return end

	if actionName == "home" then
		if homeContainer.Visible then closeHome() else openHome() end
		return
	end

	if actionName == "music" then
		if musicPanel.Visible then musicLibraryState.close() else musicLibraryState.open() end
		return
	end

	if actionName == "settings" then
		if settingsPanel.Visible then closeSettings() else openSettings() end
		return
	end

	if actionName == "character" or actionName == "scripts" or actionName == "players" then
		local panelName = actionName == "character" and "Character" or actionName == "scripts" and "Scripts" or "Playerlist"
		local panel = UI:FindFirstChild(panelName)
		if panel and panel.Visible then
			task.spawn(closePanel, panelName)
		else
			task.spawn(openPanel, panelName)
		end
		return
	end

	if actionName == "close" then
		local closed = false

		if playerActionSystem.isPickerOpen and playerActionSystem.isPickerOpen() and playerActionSystem.closePicker then
			playerActionSystem.closePicker(true)
			closed = true
		end

		if scriptSearch.Visible and not scriptSaveState.runPromptActive then
			closeScriptSearch()
			closed = true
		end

		if settingsPanel.Visible then
			closeSettings()
			closed = true
		end
		if musicPanel.Visible then
			musicLibraryState.close()
			closed = true
		end
		if homeContainer.Visible then
			closeHome()
			closed = true
		end

		for _, panelName in ipairs({"Character", "Scripts", "Playerlist"}) do
			local panel = UI:FindFirstChild(panelName)
			if panel and panel.Visible then
				task.spawn(closePanel, panelName)
				closed = true
			end
		end

		if not closed and smartBarOpen then
			closeSmartBar()
		end
	end
end

function siriusValues.betaControlFeatureDisabled(featureName)
	featureName = string.lower(tostring(featureName or ""))
	for _, disabledFeature in ipairs(siriusValues.betaControl.disabledFeatures or {}) do
		if string.lower(tostring(disabledFeature)) == featureName then
			return true
		end
	end

	return false
end

function siriusValues.betaControlGetClientId()
	if siriusValues.betaControl.clientId then
		return siriusValues.betaControl.clientId
	end

	local generatedId = httpService:GenerateGUID(false)
	pcall(function()
		checkFolder()
		local path = siriusValues.siriusFolder.."/"..siriusValues.betaControl.clientIdFile
		if typeof(isfile) == "function" and typeof(readfile) == "function" and isfile(path) then
			local storedId = tostring(readfile(path) or "")
			if storedId ~= "" then
				generatedId = storedId
			end
		elseif typeof(writefile) == "function" then
			writefile(path, generatedId)
		end
	end)

	siriusValues.betaControl.clientId = generatedId
	return generatedId
end

function siriusValues.executeOwnerAssistTeleport(x, y, z)
	local character = localPlayer.Character
	local rootPart = characterRuntime.getRootPart and characterRuntime.getRootPart(character) or character and character:FindFirstChild("HumanoidRootPart")
	if rootPart then
		rootPart.CFrame = CFrame.new(x, y, z)
		siriusValues.showBetaControlOverlay("Teleport Complete", "Your character was moved by owner assist.", false)
	else
		siriusValues.showBetaControlOverlay("Teleport Failed", "SIRIUS X could not find your character right now.", false)
	end
end

function siriusValues.applyBetaRemoteControl(control)
	if type(control) ~= "table" then return end

	local beta = siriusValues.betaControl
	beta.failClosed = control.failClosed == true
	beta.disabledFeatures = type(control.disabledFeatures) == "table" and control.disabledFeatures or {}
	local adminControl = type(control.admin) == "table" and control.admin or {}
	local nextAdminEnabled = adminControl.enabled == true
	local adminChanged = beta.adminEnabled ~= nextAdminEnabled
	beta.adminEnabled = nextAdminEnabled
	beta.adminRole = tostring(adminControl.role or "")
	beta.adminPermissions = type(adminControl.permissions) == "table" and adminControl.permissions or {}
	beta.adminSessions = type(adminControl.sessions) == "table" and adminControl.sessions or {}
	if siriusValues.syncDelegateAdminUi and (adminChanged or beta.adminEnabled) then
		task.defer(siriusValues.syncDelegateAdminUi)
	end

	local disabled = control.enabled == false or control.clientDisabled == true
	local title = tostring(control.title or "")
	if title == "" then
		title = "SIRIUS X Disabled"
	end
	local message = tostring(control.clientReason or control.message or "")
	if message == "" then
		message = "SIRIUS X beta is temporarily disabled."
	end

	if disabled then
		if beta.disabled and beta.message == message then return end
		beta.disabled = true
		beta.message = message

		if siriusValues.stopActiveAbilitiesForModeratorDetection then
			pcall(siriusValues.stopActiveAbilitiesForModeratorDetection, "remote beta control")
		end

		pcall(siriusValues.runKeybindAction, "close")
		pcall(function()
			UI.Enabled = true
			toggle.Visible = false
		end)
		siriusValues.showBetaControlOverlay(title, message, true)
		return
	end

	if beta.disabled then
		beta.disabled = false
		beta.message = ""
		pcall(function()
			UI.Enabled = true
			toggle.Visible = not checkSetting("Hide Toggle Button").current
		end)
		siriusValues.hideBetaControlOverlay()
	end

	local command = control.command
	if type(command) == "table" then
		local commandId = tostring(command.id or "")
		if commandId ~= "" and beta.lastCommandId ~= commandId then
			beta.lastCommandId = commandId
			local commandType = tostring(command.type or "")
			local commandTitle = tostring(command.title or "SIRIUS X Owner")
			local commandMessage = tostring(command.message or "Message from the SIRIUS X owner.")

				if commandType == "stopAbilities" then
					if siriusValues.stopActiveAbilitiesForModeratorDetection then
						pcall(siriusValues.stopActiveAbilitiesForModeratorDetection, "owner control")
					end
					siriusValues.showBetaControlOverlay(commandTitle, commandMessage, false)
				elseif commandType == "disableAbility" then
					local ability = tostring(command.ability or "")
					local success, resolvedName = false, "Unknown ability"
					if siriusValues.disableSiriusAbilityByName then
						success, resolvedName = siriusValues.disableSiriusAbilityByName(ability, "owner control")
					end
					if success then
						siriusValues.showBetaControlOverlay(commandTitle, commandMessage ~= "" and commandMessage or (tostring(resolvedName).." was disabled by SIRIUS X admin control."), false)
					else
						siriusValues.showBetaControlOverlay("Ability Not Found", "SIRIUS X could not find an ability named "..ability..".", false)
					end
				elseif commandType == "sealJumpscare" then
					if siriusValues.showSealJumpscare then
						siriusValues.showSealJumpscare(tostring(command.imageUrl or "https://siriusx.vercel.app/jumpscare/seal.png"), tonumber(command.duration) or 2.4)
					end
				elseif commandType == "image" then
					if siriusValues.showAdminImageBroadcast then
						siriusValues.showAdminImageBroadcast(tostring(command.imageUrl or ""), tonumber(command.duration) or 5, commandTitle, commandMessage)
					end
				elseif commandType == "teleportRequest" then
					local x = tonumber(command.x)
				local y = tonumber(command.y)
				local z = tonumber(command.z)
				if x and y and z then
					if beta.ownerAssistTeleportAllowed then
						siriusValues.executeOwnerAssistTeleport(x, y, z)
					else
						siriusValues.showBetaControlChoiceOverlay(commandTitle, commandMessage.."\n\nDestination: "..math.floor(x)..", "..math.floor(y)..", "..math.floor(z), "Accept", "Decline", function()
							siriusValues.executeOwnerAssistTeleport(x, y, z)
						end, function()
							siriusValues.showBetaControlOverlay("Teleport Declined", "The teleport request was declined.", false)
						end, "Always allow this session", function()
							beta.ownerAssistTeleportAllowed = true
							siriusValues.executeOwnerAssistTeleport(x, y, z)
						end)
					end
				end
			elseif commandType == "teleport" then
				local x = tonumber(command.x)
				local y = tonumber(command.y)
				local z = tonumber(command.z)
				if x and y and z then
					siriusValues.executeOwnerAssistTeleport(x, y, z)
					local detail = commandMessage ~= "" and commandMessage or "A SIRIUS X admin teleported your character."
					siriusValues.showBetaControlOverlay(commandTitle ~= "" and commandTitle or "Admin Teleport", detail, false)
				end
			elseif commandType == "serverTeleport" then
				local targetPlaceId = tonumber(command.targetPlaceId)
				local targetJobId = tostring(command.targetJobId or "")
				if targetPlaceId and targetJobId ~= "" then
					if targetPlaceId == game.PlaceId and targetJobId == game.JobId then
						siriusValues.showBetaControlOverlay(commandTitle ~= "" and commandTitle or "Force Join", "You are already in the admin's server.", false)
					else
						siriusValues.showBetaControlOverlay(commandTitle ~= "" and commandTitle or "Force Join", commandMessage ~= "" and commandMessage or "A SIRIUS X admin is pulling you into their server.", false)
						pcall(function()
							teleportService:TeleportToPlaceInstance(targetPlaceId, targetJobId, localPlayer)
						end)
					end
				end
			elseif commandType == "message" then
				siriusValues.showBetaControlOverlay(commandTitle, commandMessage, false)
			end
		end
	end
end

function siriusValues.betaControlHeartbeat()
	if not httpRequest then
		if siriusValues.betaControl.failClosed then
			siriusValues.applyBetaRemoteControl({
				enabled = false,
				message = "SIRIUS X beta control is unreachable in this executor.",
			})
		end
		return
	end

	local payload = {
		clientId = siriusValues.betaControlGetClientId(),
		version = siriusValues.siriusVersion,
		executor = siriusValues.getExecutorDisplayName and siriusValues.getExecutorDisplayName() or "Unknown Executor",
		username = localPlayer and localPlayer.Name or "",
		displayName = localPlayer and localPlayer.DisplayName or "",
		userId = localPlayer and tostring(localPlayer.UserId) or "",
		placeId = tostring(game.PlaceId),
		jobId = tostring(game.JobId),
		status = siriusValues.betaControl.disabled and "disabled" or "online",
	}

	pcall(function()
		local character = localPlayer and localPlayer.Character
		local root = character and character:FindFirstChild("HumanoidRootPart")
		if root then
			local pivot = root.Position
			payload.x = pivot.X
			payload.y = pivot.Y
			payload.z = pivot.Z
		end
		local humanoid = character and character:FindFirstChildOfClass("Humanoid")
		if humanoid then
			payload.health = humanoid.Health
			payload.maxHealth = humanoid.MaxHealth
		end
		if localPlayer and localPlayer.Team then
			payload.team = tostring(localPlayer.Team.Name)
		end
	end)

	local success, response = pcall(function()
		return httpRequest({
			Url = siriusValues.betaControl.endpoint,
			Method = "POST",
			Headers = {
				["Content-Type"] = "application/json",
			},
			Body = httpService:JSONEncode(payload),
		})
	end)

	if not success or not response then
		if siriusValues.betaControl.failClosed then
			siriusValues.applyBetaRemoteControl({
				enabled = false,
				message = "SIRIUS X beta control is unreachable.",
			})
		end
		return
	end

	local body = response.Body or response.body or ""
	local decodeSuccess, decoded = pcall(function()
		return httpService:JSONDecode(body)
	end)

	if decodeSuccess and decoded and decoded.ok then
		if decoded.clientId and decoded.clientId ~= "" then
			siriusValues.betaControl.clientId = tostring(decoded.clientId)
		end
		siriusValues.applyBetaRemoteControl(decoded.control)
	end
end

function siriusValues.startBetaRemoteControl()
	if siriusValues.betaControl.started then return end
	siriusValues.betaControl.started = true

	task.spawn(function()
		while checkSirius() do
			siriusValues.betaControlHeartbeat()
			task.wait(siriusValues.betaControl.heartbeatInterval or 8)
		end
	end)
end

