local smartBarClickAnimationId = {}
local smartBarClickTweens = {}
local smartBarClickPressed = {}

local function cancelSmartBarClickTweens(button)
	if smartBarClickTweens[button] then
		for _, tween in ipairs(smartBarClickTweens[button]) do
			tween:Cancel()
		end
	end

	smartBarClickTweens[button] = {}
end

local function playSmartBarClickTween(button, object, tweenInfo, properties)
	local tween = tweenService:Create(object, tweenInfo, properties)
	table.insert(smartBarClickTweens[button], tween)
	tween:Play()
end

local function playSmartBarDecline(button)
	smartBarClickAnimationId[button] = (smartBarClickAnimationId[button] or 0) + 1
	local declineId = smartBarClickAnimationId[button]
	cancelSmartBarClickTweens(button)

	local originalStrokeColor = button.UIStroke and button.UIStroke.Color
	button.Rotation = 0

	if button.UIStroke then
		tweenService:Create(button.UIStroke, TweenInfo.new(0.12, Enum.EasingStyle.Quint), {Transparency = 0, Color = Color3.fromRGB(255, 116, 80)}):Play()
	end

	tweenService:Create(button, TweenInfo.new(0.08, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {Size = UDim2.new(0, 32, 0, 32), BackgroundTransparency = 0.18, Rotation = 0}):Play()
	tweenService:Create(button.Icon, TweenInfo.new(0.08, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {ImageTransparency = 0.12}):Play()

	task.delay(0.11, function()
		if smartBarClickAnimationId[button] ~= declineId then return end
		tweenService:Create(button, TweenInfo.new(0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {Size = UDim2.new(0, 36, 0, 36), BackgroundTransparency = 0, Rotation = 0}):Play()
		tweenService:Create(button.Icon, TweenInfo.new(0.18, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {ImageTransparency = 0}):Play()
		if button.UIStroke and originalStrokeColor then
			tweenService:Create(button.UIStroke, TweenInfo.new(0.22, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {Color = originalStrokeColor, Transparency = 0}):Play()
		end
	end)
end

for _, button in ipairs(smartBar.Buttons:GetChildren()) do
	if UI:FindFirstChild(button.Name) and button:FindFirstChild("Interact") then
		button.Interact.MouseButton1Click:Connect(function()
			if button.Name == "Playerlist" and playerActionSystem.isPickerOpen and playerActionSystem.isPickerOpen() then
				playSmartBarDecline(button)
				queueNotification("Select Actions Still Open", "Close the Select Actions panel before reopening Players.")
				return
			end

			if isPanel(button.Name) then
				if not debounce and UI:FindFirstChild(button.Name).Visible then
					task.spawn(closePanel, button.Name)
				else
					task.spawn(openPanel, button.Name)
				end
			end

			button.Rotation = 0
			smartBarClickAnimationId[button] = (smartBarClickAnimationId[button] or 0) + 1
			local clickAnimationId = smartBarClickAnimationId[button]

			if not smartBarClickPressed[button] then
				smartBarClickPressed[button] = true
				cancelSmartBarClickTweens(button)
				playSmartBarClickTween(button, button, TweenInfo.new(0.11, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {Size = UDim2.new(0,28,0,28), BackgroundTransparency = 0.6})
				playSmartBarClickTween(button, button.Icon, TweenInfo.new(0.1, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {ImageTransparency = 0.3})
			else
				playSmartBarClickTween(button, button.Icon, TweenInfo.new(0.08, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {ImageTransparency = 0.24})
			end

			task.delay(0.115, function()
				if smartBarClickAnimationId[button] ~= clickAnimationId then return end
				smartBarClickPressed[button] = false
				cancelSmartBarClickTweens(button)
				playSmartBarClickTween(button, button, TweenInfo.new(0.26, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {Size = UDim2.new(0,36,0,36), BackgroundTransparency = 0, Rotation = 0})
				playSmartBarClickTween(button, button.Icon, TweenInfo.new(0.22, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {ImageColor3 = actionIconColor, ImageTransparency = 0})
			end)
		end)

		button.MouseEnter:Connect(function()
			tweenService:Create(button.UIGradient, TweenInfo.new(1.4, Enum.EasingStyle.Quint), {Rotation = 360}):Play()
			tweenService:Create(button.UIStroke.UIGradient, TweenInfo.new(1.4, Enum.EasingStyle.Quint), {Rotation = 360}):Play()
			tweenService:Create(button.UIStroke, TweenInfo.new(0.8, Enum.EasingStyle.Quint), {Transparency = 1}):Play()
			tweenService:Create(button.Icon, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {ImageColor3 = actionIconColor, ImageTransparency = 0}):Play()
			tweenService:Create(button.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0,-0.5)}):Play()
		end)

		button.MouseLeave:Connect(function()
			tweenService:Create(button.UIStroke.UIGradient, TweenInfo.new(0.6, Enum.EasingStyle.Quint), {Rotation = 50}):Play()
			tweenService:Create(button.UIGradient, TweenInfo.new(0.9, Enum.EasingStyle.Quint), {Rotation = 50}):Play()
			tweenService:Create(button.UIStroke, TweenInfo.new(0.6, Enum.EasingStyle.Quint), {Transparency = 0}):Play()
			tweenService:Create(button.Icon, TweenInfo.new(0.2, Enum.EasingStyle.Quint), {ImageColor3 = actionIconColor, ImageTransparency = 0}):Play()
			tweenService:Create(button.UIGradient, TweenInfo.new(0.7, Enum.EasingStyle.Quint), {Offset = Vector2.new(0,0)}):Play()
		end)
	end
end

userInputService.InputBegan:Connect(function(input, processed)
	if not checkSirius() then return end

	if checkingForKey then
		if input.KeyCode ~= Enum.KeyCode.Unknown then
			local inputBox = checkingForKey.object.InputFrame.InputBox
			local setting = checkingForKey.data
			local keyName = input.KeyCode.Name

			if input.KeyCode == Enum.KeyCode.Escape then
				checkingForKey = false
				inputBox.Text = siriusValues.formatKeybind(setting.current)
				inputBox:ReleaseFocus()
				return
			end

			if input.KeyCode == Enum.KeyCode.Backspace or input.KeyCode == Enum.KeyCode.Delete then
				setting.current = nil
				checkingForKey = false
				inputBox.Text = "No Keybind"
				inputBox:ReleaseFocus()
				saveSettings()
				return
			end

			if siriusValues.isKeybindModifier(keyName) then
				checkingForKey.modifiers = checkingForKey.modifiers or {}

				if not table.find(checkingForKey.modifiers, keyName) then
					table.insert(checkingForKey.modifiers, keyName)
				end

				inputBox.Text = siriusValues.formatKeybind(table.concat(checkingForKey.modifiers, "+").."+...")
				return
			end

			local newKeybind = siriusValues.buildKeybindFromInput(input, checkingForKey.modifiers)
			local conflict = siriusValues.findKeybindConflict(newKeybind, setting)

			if conflict then
				queueNotification("Keybind Conflict", siriusValues.formatKeybind(newKeybind).." is already used by "..conflict.name..".", 4370336704)
				checkingForKey = false
				inputBox.Text = siriusValues.formatKeybind(setting.current)
				inputBox:ReleaseFocus()
				return
			end

			setting.current = siriusValues.normaliseKeybind(newKeybind)
			checkingForKey = false
			inputBox.Text = siriusValues.formatKeybind(setting.current)
			inputBox:ReleaseFocus()
			saveSettings()
		end

		return
	end

	if siriusValues.betaControl and siriusValues.betaControl.disabled then
		if not processed then
			siriusValues.showBetaControlOverlay("SIRIUS X Disabled", siriusValues.betaControl.message ~= "" and siriusValues.betaControl.message or "This beta build is temporarily disabled.", true)
		end
		return
	end

	for _, category in ipairs(siriusSettings) do
		for _, setting in ipairs(category.categorySettings) do
			if setting.settingType == "Key" then
				if setting.current ~= nil and setting.current ~= "" then
					if siriusValues.keybindMatchesInput(setting.current, input) and not processed then
						if setting.callback then
							task.spawn(setting.callback)

								local action = checkAction(setting.name) or nil
								if action and action.action and action.object then
									local object = action.object
									action = action.action

								if action.enabled then
									transitionActionIcon(object.Icon, action.images[1], actionIconActiveTransparency)
									playActionVisualTween(object, "surface", TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.1})
									playActionVisualTween(object.UIStroke, "stroke", TweenInfo.new(0.34, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 1})

									if action.disableAfter then
										task.delay(action.disableAfter, function()
											action.enabled = false
											transitionActionIcon(object.Icon, action.images[2], actionIconIdleTransparency)
											playActionVisualTween(object, "surface", TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.55})
											playActionVisualTween(object.UIStroke, "stroke", TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.4})
										end)
									end

									if action.rotateWhileEnabled then
										repeat
											object.Icon.Rotation = 0
											tweenService:Create(object.Icon, TweenInfo.new(0.75, Enum.EasingStyle.Quint), {Rotation = 360}):Play()
											task.wait(1)
										until not action.enabled
										object.Icon.Rotation = 0
									end
								else
									transitionActionIcon(object.Icon, action.images[2], actionIconIdleTransparency)
									playActionVisualTween(object, "surface", TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {BackgroundTransparency = 0.55})
									playActionVisualTween(object.UIStroke, "stroke", TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Transparency = 0.4})
								end
							end
						end
					end
				end
			end
		end
	end

	local scriptSearchKeybind = checkSetting("Open ScriptSearch")
	if scriptSearchKeybind and siriusValues.keybindMatchesInput(scriptSearchKeybind.current, input) and not processed and not debounce and not scriptSaveState.runPromptActive then
		if scriptSearch.Visible then
			closeScriptSearch()
		else
			openScriptSearch()
		end
	end

	local smartBarKeybind = checkSetting("Toggle smartBar")
	if smartBarKeybind and siriusValues.keybindMatchesInput(smartBarKeybind.current, input) and not processed and not debounce then
		if smartBarOpen then 
			closeSmartBar()
		else
			openSmartBar()
		end
	end
end)

userInputService.InputEnded:Connect(function(input, processed)
	if not checkSirius() then return end

	if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
		for _, slider in pairs(siriusValues.sliders) do
			if slider.activeInput and slider.activeInput.UserInputType == Enum.UserInputType.Touch and input ~= slider.activeInput then
				continue
