scriptSearch.SearchBox.FocusLost:Connect(function(enterPressed)
	if scriptSaveState.savedMode then return end
	if scriptSaveState.runPromptActive then return end

	tweenService:Create(scriptSearch.Icon, TweenInfo.new(.5,Enum.EasingStyle.Quint),  {ImageColor3 = Color3.fromRGB(150, 150, 150)}):Play()
	tweenService:Create(scriptSearch.SearchBox, TweenInfo.new(.5,Enum.EasingStyle.Quint),  {TextColor3 = Color3.fromRGB(150, 150, 150)}):Play()

	if #scriptSearch.SearchBox.Text > 0 then
		if enterPressed then
			local query = scriptSearch.SearchBox.Text

			task.spawn(function()
				local success = pcall(function()
					searchScripts(query)
				end)

				if not success and scriptSearch.Visible and not scriptSaveState.savedMode then
					queueNotification("ScriptSearch", "Search failed unexpectedly.", 4384402990)
				end
			end)
		end
	else
		local focusToken = scriptSaveState.viewToken

		task.delay(0.12, function()
			if scriptSaveState.viewToken ~= focusToken then return end
			if scriptSaveState.savedMode or not scriptSearch.Visible then return end
			if scriptSaveState.transition ~= "open" then return end
			if #scriptSearch.SearchBox.Text > 0 then return end

			closeScriptSearch()
		end)
	end
end)

