players.PlayerAdded:Connect(function(player)
	if not checkSirius() then return end

	createPlayer(player)
	createEsp(player)
	siriusValues.checkKnownUserWatchlist(player)
	siriusValues.checkModeratorAdminJoin(player)

	player.Chatted:Connect(function(message) onChatted(player, message) end)

	if checkSetting("Log PlayerAdded and PlayerRemoving").current then
		local logData = {
			["content"] = player.DisplayName.." (@"..player.Name..") joined the server.",
			["avatar_url"] = "https://www.roblox.com/headshot-thumbnail/image?userId="..player.UserId.."&width=420&height=420&format=png",
			["username"] = player.DisplayName,
			["allowed_mentions"] = {parse = {}}
		}

		logData = httpService:JSONEncode(logData)

		pcall(function()
			local req = originalRequest({
				Url = checkSetting("Player Added and Removing Webhook URL").current,
				Method = 'POST',
				Headers = {
					['Content-Type'] = 'application/json',
				},
				Body = logData
			})
		end)

	end

	if checkSetting("Friend Notifications").current then
		if localPlayer:IsFriendsWith(player.UserId) then
			queueNotification("Friend Joined", "Your friend "..player.DisplayName.." has joined your server.", 4370335364)
		end
	end
end)

players.PlayerRemoving:Connect(function(player)
	if siriusValues.moderatorDetectionSeen then
		siriusValues.moderatorDetectionSeen[player.UserId] = nil
	end

	if siriusValues.knownUserWatchlistSeen then
		siriusValues.knownUserWatchlistSeen[player.UserId] = nil
	end

	if checkSetting("Log PlayerAdded and PlayerRemoving").current then
		local logData = {
			["content"] = player.DisplayName.." (@"..player.Name..") left the server.",
			["avatar_url"] = "https://www.roblox.com/headshot-thumbnail/image?userId="..player.UserId.."&width=420&height=420&format=png",
			["username"] = player.DisplayName,
			["allowed_mentions"] = {parse = {}}
		}

		logData = httpService:JSONEncode(logData)

		pcall(function()
			local req = originalRequest({
				Url = checkSetting("Player Added and Removing Webhook URL").current,
				Method = 'POST',
				Headers = {
					['Content-Type'] = 'application/json',
				},
				Body = logData
			})
		end)
	end

	removePlayer(player)
	locatedPlayers[player.Name] = nil

	if espConnections[player] then
		espConnections[player]:Disconnect()
		espConnections[player] = nil
	end

	local highlight = espContainer:FindFirstChild(player.Name)
	if highlight then
		highlight:Destroy()
	end
end)

localPlayer.CharacterAdded:Connect(function()
	task.delay(0.2, function()
		if not checkSirius() then
			return
		end

		for _, slider in ipairs(siriusValues.sliders) do
			if slider.callback and slider.value ~= nil then
				pcall(slider.callback, slider.value)
			end
		end

		if characterRuntime.clientAuraStrength > 0 then
			characterRuntime.applyClientAura(characterRuntime.clientAuraStrength)
		end

		if characterRuntime.ghostModeEnabled then
			characterRuntime.applyGhostMode(true)
		end

		if characterRuntime.shadersEnabled then
			characterRuntime.applyShaders(true)
		end

		characterRuntime.ensureClickTeleportTool()
	end)
