userInputService.InputChanged:Connect(function(input, gameProcessed)
	if gameProcessed or not characterRuntime.ghostModeEnabled then
		return
	end

	if input.UserInputType ~= Enum.UserInputType.MouseWheel then
		return
	end

	local wheelDelta = 0
	if input.Position then
		wheelDelta = input.Position.Z
	end
	if wheelDelta == 0 and input.Delta then
		wheelDelta = input.Delta.Z
	end
	if wheelDelta == 0 then
		return
	end

	local zoomStep = characterRuntime.ghostZoomStep or 1
	local zoomMin = characterRuntime.ghostZoomMin or 0
	local zoomMax = characterRuntime.ghostZoomMax or 18
	local currentZoom = characterRuntime.ghostThirdPersonDistance or 8

	if wheelDelta > 0 then
		currentZoom -= zoomStep
	else
		currentZoom += zoomStep
	end

	characterRuntime.ghostThirdPersonDistance = math.clamp(currentZoom, zoomMin, zoomMax)
end)

runService.RenderStepped:Connect(function(deltaTime)
	if not checkSirius() then
		return
	end

	characterRuntime.updateGhostMode(deltaTime)

	local character = localPlayer.Character

	if not characterRuntime.ghostModeEnabled and characterRuntime.autoAimAssistStrength > 0 then
		local targetData = characterRuntime.scanTargetData
		characterRuntime.currentAutoAimTarget = targetData and targetData.player or nil
		local closestHeadTip = targetData and characterRuntime.getPredictedAimPoint(targetData) or nil
		if closestHeadTip then
			local desiredCFrame = CFrame.lookAt(camera.CFrame.Position, closestHeadTip)
			if characterRuntime.autoAimAssistStrength >= 100 then
				camera.CFrame = desiredCFrame
			else
				local speedAlpha = characterRuntime.autoAimAssistStrength / 100
				local blend = math.clamp((speedAlpha ^ 1.7) * deltaTime * 32, 0, 1)
				camera.CFrame = camera.CFrame:Lerp(desiredCFrame, blend)
			end
		end
	else
		characterRuntime.currentAutoAimTarget = nil
	end

	if characterRuntime.clientAuraStrength > 0 then
		local auraObjects = characterRuntime.ensureAuraObjects()
		if auraObjects then
			local now = os.clock()
			if now - characterRuntime.auraLastTick >= 0.06 then
				characterRuntime.auraLastTick = now

				local alpha = characterRuntime.clientAuraStrength / 100
				local pulse = 0.5 + (0.5 * math.sin(now * 3.4))
				local hueA = (0.56 + now * 0.065) % 1
				local hueB = (hueA + 0.12) % 1
				local hueC = (hueA + 0.23) % 1
				local colorA = Color3.fromHSV(hueA, 0.72, 1)
				local colorB = Color3.fromHSV(hueB, 0.68, 1)
				local colorC = Color3.fromHSV(hueC, 0.62, 1)

				auraObjects.sparkEmitter.Color = ColorSequence.new({
					ColorSequenceKeypoint.new(0, colorA),
					ColorSequenceKeypoint.new(0.45, colorB),
					ColorSequenceKeypoint.new(1, colorC),
				})
				auraObjects.mistEmitter.Color = ColorSequence.new({
					ColorSequenceKeypoint.new(0, colorB),
					ColorSequenceKeypoint.new(1, colorC),
				})
				auraObjects.starEmitter.Color = ColorSequence.new({
					ColorSequenceKeypoint.new(0, colorC),
					ColorSequenceKeypoint.new(1, colorA),
				})
				auraObjects.auraBeam.Color = ColorSequence.new({
					ColorSequenceKeypoint.new(0, colorA),
					ColorSequenceKeypoint.new(0.5, colorB),
					ColorSequenceKeypoint.new(1, colorC),
				})
				auraObjects.auraBeam.Width0 = 0.9 + (alpha * 1.5) + (pulse * 0.22)
				auraObjects.auraBeam.Width1 = 0.24 + (alpha * 0.65) + (pulse * 0.08)
				auraObjects.auraLight.Color = colorB
				auraObjects.auraLight.Brightness = 2.4 + (alpha * 6.5) + (pulse * 1.6)
				auraObjects.auraLight.Range = 11 + (alpha * 24) + (pulse * 4)
				auraObjects.auraHighlight.FillColor = colorA:Lerp(colorB, 0.35)
				auraObjects.auraHighlight.OutlineColor = colorB:Lerp(colorC, 0.45)
			end
		end
	end
end)

runService.RenderStepped:Connect(function(frame)
	if not checkSirius() then return end
	local fps = math.round(1/frame)

	table.insert(siriusValues.frameProfile.fpsQueue, fps)
	siriusValues.frameProfile.totalFPS += fps

	if #siriusValues.frameProfile.fpsQueue > siriusValues.frameProfile.fpsQueueSize then
		siriusValues.frameProfile.totalFPS -= siriusValues.frameProfile.fpsQueue[1]
		table.remove(siriusValues.frameProfile.fpsQueue, 1)
	end
end)

runService.Stepped:Connect(function()
	if not checkSirius() then return end

	local character = localPlayer.Character
	if character then
			-- No Clip
			local noclipEnabled = siriusValues.actions[1].enabled
			local flingEnabled = siriusValues.actions[5].enabled

			for _, part in ipairs(character:GetDescendants()) do
				if part:IsA("BasePart") then
					if noclipDefaults[part] == nil then
						task.wait()
						noclipDefaults[part] = part.CanCollide
					else
						if noclipEnabled or flingEnabled then
							part.CanCollide = false
						else
							part.CanCollide = noclipDefaults[part]
						end
					end
				end
			end
	end
end)

runService.Heartbeat:Connect(function(frame)
	if not checkSirius() then return end

	local character = localPlayer.Character
	local rootPart = character and characterRuntime.getRootPart(character)
	local humanoid = character and character:FindFirstChildOfClass("Humanoid")
	local flightEnabled = siriusValues.actions[2] and siriusValues.actions[2].enabled
	characterRuntime.updateTargetScan(frame)
	characterRuntime.updateWalkInAir(character, rootPart)
	characterRuntime.updateAutoFind(character, humanoid, rootPart, flightEnabled, frame)
	characterRuntime.ensureClickTeleportTool()
	local primaryPart = character and (character.PrimaryPart or rootPart)
	if primaryPart then
		local bodyVelocity, bodyGyro = unpack(movers)

		-- Drop cached movers if the old character was destroyed and took them with it.
		-- Setting Parent on a destroyed instance throws, so probe before using.
		if bodyVelocity then
			local alive = pcall(function() bodyVelocity.Parent = bodyVelocity.Parent end)
			if not alive then
				movers = {}
				bodyVelocity, bodyGyro = nil, nil
			end
		end

		if not bodyVelocity then
			bodyVelocity = Instance.new("BodyVelocity")
			bodyVelocity.MaxForce = Vector3.one * 9e9

			bodyGyro = Instance.new("BodyGyro")
			bodyGyro.MaxTorque = Vector3.one * 9e9
			bodyGyro.P = 9e4

			local bodyAngularVelocity = Instance.new("BodyAngularVelocity")
			bodyAngularVelocity.AngularVelocity = Vector3.yAxis * 9e9
			bodyAngularVelocity.MaxTorque = Vector3.yAxis * 9e9
			bodyAngularVelocity.P = 9e9

			movers = { bodyVelocity, bodyGyro, bodyAngularVelocity }
		end

		-- Fly
		if flightEnabled then
			local camCFrame = camera.CFrame
			local velocity = Vector3.zero
			local rotation = camCFrame.Rotation

			if userInputService:IsKeyDown(Enum.KeyCode.W) then
				velocity += camCFrame.LookVector
				rotation *= CFrame.Angles(math.rad(-40), 0, 0)
			end
			if userInputService:IsKeyDown(Enum.KeyCode.S) then
				velocity -= camCFrame.LookVector
				rotation *= CFrame.Angles(math.rad(40), 0, 0)
			end
				if userInputService:IsKeyDown(Enum.KeyCode.D) then
					velocity += camCFrame.RightVector
					rotation *= CFrame.Angles(0, 0, math.rad(-40))
				end
				if userInputService:IsKeyDown(Enum.KeyCode.A) then
					velocity -= camCFrame.RightVector
					rotation *= CFrame.Angles(0, 0, math.rad(40))
				end
				local flyUpKey, flyDownKey = getFlyVerticalControlKeys()
				if userInputService:IsKeyDown(flyUpKey) then
					velocity += Vector3.yAxis
				end
				if userInputService:IsKeyDown(flyDownKey) then
					velocity -= Vector3.yAxis
				end

				local tweenInfo = TweenInfo.new(0.5)
			tweenService:Create(bodyVelocity, tweenInfo, { Velocity = velocity * siriusValues.sliders[3].value * 45 }):Play()
			bodyVelocity.Parent = primaryPart

				if not siriusValues.actions[5].enabled then
					tweenService:Create(bodyGyro, tweenInfo, { CFrame = rotation }):Play()
					bodyGyro.Parent = primaryPart
				end
		else
			bodyVelocity.Parent = nil
			bodyGyro.Parent = nil
		end
	end
end)

-- Anonymous Client throttle/transition state
local anonymousTickCounter = 0
local anonymousWasEnabled = false
local ANONYMOUS_TICK_INTERVAL = 15 -- run roughly 4x/sec instead of every frame

runService.Heartbeat:Connect(function(frame)
	if not checkSirius() then return end
	if Pro then
		if checkSetting("Spatial Shield").current and tonumber(checkSetting("Spatial Shield Threshold").current) then
			local threshold = math.clamp(tonumber(checkSetting("Spatial Shield Threshold").current) or 300, 100, 1000)
			-- iterate backwards so table.remove doesn't skip entries
			for i = #soundInstances, 1, -1 do
				local sound = soundInstances[i]
				if not sound then
					table.remove(soundInstances, i)
				elseif not sound.Parent then
					cachedIds[sound] = nil
					table.remove(soundInstances, i)
				elseif sound.Name == "SiriusMusicAudio" or sound:IsDescendantOf(UI) then
					cachedIds[sound] = nil
					table.remove(soundInstances, i)
				elseif sound.IsPlaying and sound.Volume > 0 and gameSettings.MasterVolume * sound.PlaybackLoudness * sound.Volume >= threshold then
					local soundId = tostring(sound.SoundId or "")

					if sound.Volume > 0.55 then
						if soundId ~= "" then suppressedSounds[soundId] = "S" end
						sound.Volume = 0.5
					elseif sound.Volume > 0.2 and sound.Volume < 0.55 then
						if soundId ~= "" then suppressedSounds[soundId] = "S2" end
						sound.Volume = 0.1
					elseif sound.Volume < 0.2 then
						if soundId ~= "" then suppressedSounds[soundId] = "Mute" end
						sound.Volume = 0
					end
					if soundSuppressionNotificationCooldown == 0 then
						queueNotification("Spatial Shield","A high-volume audio is being played ("..sound.Name..") and it has been suppressed.", 4483362458)
						soundSuppressionNotificationCooldown = 15
					end
					cachedIds[sound] = nil
					table.remove(soundInstances, i)
				end
			end
		end

		if soundSuppressionNotificationCooldown > 0 then
			soundSuppressionNotificationCooldown -= 1
		end
	end

	local anonymousEnabled = checkSetting("Anonymous Client [Client]").current

	if anonymousEnabled then
		-- Throttle: do the scan on every Nth heartbeat rather than every frame.
		anonymousTickCounter += 1
		if anonymousTickCounter >= ANONYMOUS_TICK_INTERVAL then
			anonymousTickCounter = 0

			for i = #cachedText, 1, -1 do
				local text = cachedText[i]
				if not text or not text.Parent then
					-- Drop destroyed/orphaned labels so we stop scanning them.
					table.remove(cachedText, i)
				elseif originalTextValues[text] == nil then
					-- Only inspect labels we haven't already anonymized.
					local raw = text.Text
					local lowerText = string.lower(raw)
					if string.find(lowerText, lowerName, 1, true) or string.find(lowerText, lowerDisplayName, 1, true) then
						storeOriginalText(text)
						local newText = string.gsub(string.gsub(lowerText, lowerName, randomUsername), lowerDisplayName, randomUsername)
						text.Text = string.gsub(newText, "^%l", string.upper)
					end
				end
			end
		end
	elseif anonymousWasEnabled then
		-- Only undo once on the off-transition, not every frame.
		undoAnonymousChanges()
		table.clear(originalTextValues)
	end

	anonymousWasEnabled = anonymousEnabled
end)

for _, instance in next, game:GetDescendants() do
	if instance:IsA("Sound") then
		if instance.Name == "SiriusMusicAudio" or instance:IsDescendantOf(UI) then
			continue
		elseif suppressedSounds[instance.SoundId] then
			if suppressedSounds[instance.SoundId] == "S" then
				instance.Volume = 0.5
			elseif suppressedSounds[instance.SoundId] == "S2" then
				instance.Volume = 0.1
			else
				instance.Volume = 0
			end
		else
			if not cachedIds[instance] then
				table.insert(soundInstances, instance)
				cachedIds[instance] = true
			end
		end
	elseif instance:IsA("TextLabel") or instance:IsA("TextButton") then
		if not table.find(cachedText, instance) then
			table.insert(cachedText, instance)
		end
	end
end

