				end
			end
		elseif instance:IsA("TextLabel") or instance:IsA("TextButton") then
			if not table.find(cachedText, instance) then
				table.insert(cachedText, instance)
			end
		end
	end
end)


task.spawn(function()
while task.wait(1) do
	if not checkSirius() then
		if espContainer then espContainer:Destroy() end
		if descendantAddedConn then descendantAddedConn:Disconnect() descendantAddedConn = nil end
		for player, conn in pairs(espConnections) do
			conn:Disconnect()
			espConnections[player] = nil
		end
		undoAnonymousChanges()
		break
	end

	smartBar.Time.Text = os.date("%H")..":"..os.date("%M")
	task.spawn(UpdateHome)

	if getconnections then
		for _, connection in getconnections(localPlayer.Idled) do
			if not checkSetting("Anti Idle").current then connection:Enable() else connection:Disable() end
		end
	end

	toggle.Visible = not checkSetting("Hide Toggle Button").current

	-- Disconnected Check
	local disconnectedRobloxUI = coreGui.RobloxPromptGui.promptOverlay:FindFirstChild("ErrorPrompt")

		if disconnectedRobloxUI and not promptedDisconnected then
			local reasonPrompt = disconnectedRobloxUI.MessageArea.ErrorFrame.ErrorMessage.Text

			promptedDisconnected = true
			disconnectedPrompt.Parent = coreGui.RobloxPromptGui
			disconnectedPrompt.ZIndex = 10000
			for _, promptObject in ipairs(disconnectedPrompt:GetDescendants()) do
				pcall(function()
					promptObject.ZIndex = math.max(promptObject.ZIndex, 10001)
				end)
			end

			local disconnectType
			local foundString

		for _, preDisconnectType in ipairs(siriusValues.disconnectTypes) do
			for _, typeString in pairs(preDisconnectType[2]) do
				if string.find(reasonPrompt, typeString) then
					disconnectType = preDisconnectType[1]
					foundString = true
					break
				end
			end
		end

		if not foundString then disconnectType = "kick" end

		wipeTransparency(disconnectedPrompt, 1, true)
		disconnectedPrompt.Visible = true

		if disconnectType == "ban" then
			disconnectedPrompt.Content.Text = "You've been banned, would you like to leave this server?"
			disconnectedPrompt.Action.Text = "Leave"
			disconnectedPrompt.Action.Size = UDim2.new(0, 77, 0, 36) -- use textbounds

			disconnectedPrompt.UIGradient.Color = ColorSequence.new({
				ColorSequenceKeypoint.new(0, Color3.new(0,0,0)),
				ColorSequenceKeypoint.new(1, Color3.new(0.819608, 0.164706, 0.164706))
			})
		elseif disconnectType == "kick" then
			disconnectedPrompt.Content.Text = "You've been kicked, would you like to serverhop?"
			disconnectedPrompt.Action.Text = "Serverhop"
			disconnectedPrompt.Action.Size = UDim2.new(0, 114, 0, 36)

			disconnectedPrompt.UIGradient.Color = ColorSequence.new({
				ColorSequenceKeypoint.new(0, Color3.new(0,0,0)),
				ColorSequenceKeypoint.new(1, Color3.new(0.0862745, 0.596078, 0.835294))
			})
		elseif disconnectType == "network" then
			disconnectedPrompt.Content.Text = "You've lost connection, would you like to rejoin?"
			disconnectedPrompt.Action.Text = "Rejoin"
			disconnectedPrompt.Action.Size = UDim2.new(0, 82, 0, 36)

			disconnectedPrompt.UIGradient.Color = ColorSequence.new({
				ColorSequenceKeypoint.new(0, Color3.new(0,0,0)),
				ColorSequenceKeypoint.new(1, Color3.new(0.862745, 0.501961, 0.0862745))
			})
		end

		tweenService:Create(disconnectedPrompt, TweenInfo.new(.5,Enum.EasingStyle.Quint),  {BackgroundTransparency = 0}):Play()
		tweenService:Create(disconnectedPrompt.Title, TweenInfo.new(.5,Enum.EasingStyle.Quint),  {TextTransparency = 0}):Play()
		tweenService:Create(disconnectedPrompt.Content, TweenInfo.new(.5,Enum.EasingStyle.Quint),  {TextTransparency = 0.3}):Play()
		tweenService:Create(disconnectedPrompt.Action, TweenInfo.new(.5,Enum.EasingStyle.Quint),  {BackgroundTransparency = 0.7}):Play()
		tweenService:Create(disconnectedPrompt.Action, TweenInfo.new(.5,Enum.EasingStyle.Quint),  {TextTransparency = 0}):Play()

		disconnectedPrompt.Action.MouseButton1Click:Connect(function()
			if disconnectType == "ban" then
				game:Shutdown() -- leave
			elseif disconnectType == "kick" then
				serverhop()
			elseif disconnectType == "network" then
				rejoin()
			end
		end)
	end

	if Pro then
		-- all Pro checks here!

		-- Two-Way Adaptive Latency Checks
		if checkHighPing() then
			if siriusValues.pingProfile.pingNotificationCooldown <= 0 then
				if checkSetting("Adaptive Latency Warning").current then
					queueNotification("High Latency Warning","We've noticed your latency has reached a higher value than usual, you may find that you are lagging or your actions are delayed in-game. Consider checking for any background downloads on your machine.", 4370305588)
					siriusValues.pingProfile.pingNotificationCooldown = 120
				end
			end
		end

		if siriusValues.pingProfile.pingNotificationCooldown > 0 then
			siriusValues.pingProfile.pingNotificationCooldown -= 1
		end

		-- Adaptive frame time checks
		if siriusValues.frameProfile.frameNotificationCooldown <= 0 then
			if #siriusValues.frameProfile.fpsQueue > 0 then
				local avgFPS = siriusValues.frameProfile.totalFPS / #siriusValues.frameProfile.fpsQueue

				if avgFPS < siriusValues.frameProfile.lowFPSThreshold then
					if checkSetting("Adaptive Performance Warning").current then
						queueNotification("Degraded Performance","We've noticed your client's frames per second have decreased. Consider checking for any background tasks or programs on your machine.", 4384400106)
						siriusValues.frameProfile.frameNotificationCooldown = 120	
					end
				end
			end
		end

	if siriusValues.frameProfile.frameNotificationCooldown > 0 then
		siriusValues.frameProfile.frameNotificationCooldown -= 1
	end
end
end
end)



--[[ ==========================================================================
	Sirius X - NextGen
	Real Sirius X (above) running underneath, presented through the
	Rayfield Gen 3 Concept UI. This front-end drives Sirius's own feature
	tables (exposed via the bridge injected above), so every toggle/slider
	fires the exact same callback path Sirius uses internally.
============================================================================ ]]

task.spawn(function()

	-- Wait for the Sirius bridge that was injected into siriusValues
	local bridge
	do
		local t0 = os.clock()
		repeat
			bridge = getgenv and getgenv().__SIRIUSX_BRIDGE or _G.__SIRIUSX_BRIDGE
			if bridge then break end
			task.wait(0.1)
		until (os.clock() - t0) > 20
	end

	if not bridge or not bridge.actions or not bridge.sliders then
		warn("[Sirius X - NextGen] Could not reach the Sirius feature bridge; native Sirius UI is still available.")
		return
	end

	-- Load the Gen3 Rayfield concept UI library
	local ok, Rayfield = pcall(function()
		return loadstring(game:HttpGet(
			"https://raw.githubusercontent.com/SyncOfficialSpec/Rayfield_Gen_3_Concept/main/source.lua"
		))()
	end)
	if not ok or not Rayfield then
		warn("[Sirius X - NextGen] Failed to load Gen3 UI library:", Rayfield)
		return
	end

	-- Helpers -----------------------------------------------------------------
	local function findAction(name)
		local target = tostring(name):lower()
		for _, a in ipairs(bridge.actions) do
			if a.name and a.name:lower():find(target, 1, true) then return a end
		end
	end
	local function findSlider(name)
		local target = tostring(name):lower()
		for _, s in ipairs(bridge.sliders) do
			if s.name and s.name:lower():find(target, 1, true) then return s end
		end
	end

	-- Drive a toggle exactly like Sirius's own keybind path does
	local function setToggle(action, value)
		if not action then return end
		if action.enabled ~= value then
			action.enabled = value
			pcall(action.callback, value)
		end
	end
	-- Momentary action (Refresh / Respawn style). Sirius resets .enabled after
	-- `disableAfter` inside its own click handler, which the bridge path skips,
	-- so we must replicate that reset or the native keybinds get stuck.
	local function fireAction(action)
		if not action then return end
		action.enabled = true
		pcall(action.callback) -- Sirius invokes these with no argument
		local after = action.disableAfter or 0
		task.delay(after, function() action.enabled = false end)
	end
	-- Drive a slider value + callback like Sirius does
	local function setSlider(slider, value)
		if not slider then return end
		slider.value = value
		pcall(slider.callback, value)
	end

	-- Native Sirius ScreenGui. Sirius parents it under gethui() when available,
	-- otherwise CoreGui, so resolve it the same way or hiding it silently fails.
	local nativeGui
	do
		local name = bridge.siriusName or "Sirius"
		local guiParent = (typeof(gethui) == "function" and gethui()) or game:GetService("CoreGui")
		nativeGui = guiParent:FindFirstChild(name)
		if not nativeGui then
			nativeGui = game:GetService("CoreGui"):FindFirstChild(name) -- fallback
		end
		if nativeGui and nativeGui:IsA("ScreenGui") then
			nativeGui.Enabled = false -- hide native, Gen3 is the face now
		end
	end
	local function showNative(state)
		if nativeGui then nativeGui.Enabled = state end
	end

	-- Window ------------------------------------------------------------------
	local Window = Rayfield:CreateWindow({
		Name = "Sirius X - NextGen",
		Subtitle = "Rayfield Gen3",
		Icon = "sparkles",
		Badge = {Text = "sirius-x", Icon = "shield"},
		LoadingTitle = "Sirius X - NextGen",
		LoadingSubtitle = "Sirius X reskinned in Gen3",
		ToggleUIKeybind = "K",
		-- Config saving is intentionally OFF: restoring saved state would
		-- force-apply features on load (auto-noclip, or overriding a game's
		-- own WalkSpeed/JumpPower/gravity), which is unsafe for exploit toggles.
		ConfigurationSaving = {
			Enabled = false,
		},
	})

	-- Character tab (all 16 action toggles) -----------------------------------
	local Character = Window:CreateTab("Character", "user")
	Character:CreateSection("Movement")

	local toggleSpecs = {
		{key = "Noclip",                 icon = "ghost"},
		{key = "Flight",                 icon = "plane"},
		{key = "Infinite Jump",          icon = "arrow-up"},
		{key = "Walk in Air",            icon = "footprints"},
		{key = "Anti Void",              icon = "shield"},
		{key = "Ghost Mode",             icon = "eye"},   -- "Ghost Mode / Spectate"
		{key = "Invisibility",           icon = "eye-off"},
	}
	for _, spec in ipairs(toggleSpecs) do
		local a = findAction(spec.key)
		if a then
			Character:CreateToggle({
				Name = a.name,
				Icon = spec.icon,
				CurrentValue = a.enabled == true,
				Flag = "SX_" .. a.name,
				Callback = function(v) setToggle(a, v) end,
			})
		end
	end

	Character:CreateSection("Combat & Visuals")
	local combatSpecs = {
		{key = "Extrasensory",  icon = "radar"},   -- ESP
		{key = "Auto Find",     icon = "crosshair"},
		{key = "Fling",         icon = "wind"},
		{key = "Shaders",       icon = "sun"},
	}
	for _, spec in ipairs(combatSpecs) do
		local a = findAction(spec.key)
		if a then
			Character:CreateToggle({
				Name = a.name,
				Icon = spec.icon,
				CurrentValue = a.enabled == true,
				Flag = "SX_" .. a.name,
				Callback = function(v) setToggle(a, v) end,
			})
		end
	end

	Character:CreateSection("World")
	for _, spec in ipairs({
		{key = "Night and Day", icon = "moon"},
		{key = "Global Audio",  icon = "volume-2"},
	}) do
		local a = findAction(spec.key)
		if a then
			Character:CreateToggle({
				Name = a.name,
				Icon = spec.icon,
				CurrentValue = a.enabled == true,
				Flag = "SX_" .. a.name,
				Callback = function(v) setToggle(a, v) end,
			})
		end
	end

	Character:CreateSection("Actions")
	do
		local refresh = findAction("Refresh")
		if refresh then
			Character:CreateButton({ Name = "Refresh Character", Icon = "refresh-cw",
				Callback = function() fireAction(refresh) end })
		end
		local respawn = findAction("Respawn")
		if respawn then
			Character:CreateButton({ Name = "Respawn", Icon = "rotate-ccw",
				Callback = function() fireAction(respawn) end })
		end
		local clickTp = findAction("click teleport")
		if clickTp then
			Character:CreateToggle({ Name = clickTp.name, Icon = "mouse-pointer-click",
				CurrentValue = clickTp.enabled == true, Flag = "SX_ClickTP",
				Callback = function(v) setToggle(clickTp, v) end })
		end
	end

	-- Tuning tab (all 7 sliders) ----------------------------------------------
	local Tuning = Window:CreateTab("Tuning", "sliders-horizontal")
	Tuning:CreateSection("Character Tuning")

	local sliderSpecs = {
		{key = "player speed",       icon = "gauge",     suffix = ""},
		-- Sirius renames this slider "jump height" at runtime on JumpHeight-based
		-- games, so match the shared "jump" substring, not "jump power".
		{key = "jump",               icon = "arrow-up",  suffix = ""},
		{key = "flight speed",       icon = "plane",     suffix = ""},
		{key = "field of view",      icon = "eye",       suffix = "\194\176"},
		{key = "gravity",            icon = "arrow-down",suffix = ""},
		{key = "smooth screen blur", icon = "droplet",   suffix = ""},
		{key = "auto aim",           icon = "crosshair", suffix = "%"},
	}
	for _, spec in ipairs(sliderSpecs) do
		local s = findSlider(spec.key)
		if s then
			local range = s.values or {0, 100}
			-- Snap the initial value to the (integer) increment so the label,
			-- stored value and slider agree. gravity defaults to 196.2.
			local initial = s.value or s.default or range[1] or 0
			initial = math.floor(initial + 0.5)
			Tuning:CreateSlider({
				Name = s.name:gsub("^%l", string.upper),
				Icon = spec.icon,
				Range = {range[1] or 0, range[2] or 100},
				Increment = 1,
				Suffix = spec.suffix,
				CurrentValue = initial,
				Flag = "SX_" .. s.name,
				Callback = function(v) setSlider(s, v) end,
			})
		end
	end

	-- Interface tab -----------------------------------------------------------
	local Interface = Window:CreateTab("Interface", "layout-grid")

	-- Forward reference so the panel buttons can sync the toggle's visual.
	local nativeToggle

	-- These panels (Scripts / Players / Music etc.) live inside Sirius's own
	-- ScreenGui, which we hid on load. Opening one must re-show native first,
	-- otherwise the button is a silent no-op.
	local function openNativePanel(action)
		showNative(true)
		if nativeToggle then pcall(function() nativeToggle:Set(true) end) end
		if bridge.runKeybindAction then pcall(bridge.runKeybindAction, action) end
	end

	Interface:CreateSection("Sirius Panels")
	local keybindActions = {
		{label = "Home",           action = "home",     icon = "home"},
		{label = "Character",      action = "character", icon = "user"},
		{label = "Scripts",        action = "scripts",  icon = "code"},
		{label = "Players",        action = "players",  icon = "users"},
		{label = "Music",          action = "music",    icon = "music"},
		{label = "Settings",       action = "settings", icon = "settings"},
		{label = "Command Search", action = "commandsearch", icon = "search"},
	}
	for _, ka in ipairs(keybindActions) do
		Interface:CreateButton({
			Name = "Open " .. ka.label,
			Icon = ka.icon,
			Callback = function() openNativePanel(ka.action) end,
		})
	end

	Interface:CreateSection("Safety")
	Interface:CreateButton({
		Name = "Panic (stop abilities)",
		Icon = "octagon-x",
		Callback = function()
			if bridge.runKeybindAction then pcall(bridge.runKeybindAction, "stopabilities") end
		end,
	})

	Interface:CreateSection("Native UI")
	nativeToggle = Interface:CreateToggle({
		Name = "Show original Sirius X UI",
		Icon = "panel-top",
		CurrentValue = false,
		Flag = "SX_ShowNative",
		Description = "Bring back Sirius X's built in interface. Note: it shares state with this panel, so a native button may look stale after you flip the same feature here.",
		Callback = function(v)
			showNative(v)
		end,
	})

	Rayfield:Notify({
		Title = "Sirius X - NextGen",
		Content = "Loaded. Every toggle here drives real Sirius X features. Press K to hide.",
		Duration = 6,
		Image = "sparkles",
	})
end)
